                                    var expanded by remember { mutableStateOf(false) }

                                    Card(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .testTag("food_entry_card_${entry.id}")
                                            .clickable { selectedLogForBreakdown = entry },
                                        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)),
                                        border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.05f))
                                    ) {
                                        Column(modifier = Modifier.padding(12.dp)) {
                                            Row(
                                                modifier = Modifier.fillMaxWidth(),
                                                horizontalArrangement = Arrangement.SpaceBetween,
                                                verticalAlignment = Alignment.CenterVertically
                                            ) {
                                                Column(modifier = Modifier.weight(1f)) {
                                                    Text(
                                                        text = entry.foodName,
                                                        style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                                        color = MaterialTheme.colorScheme.onSurface,
                                                        maxLines = 1,
                                                        overflow = TextOverflow.Ellipsis
                                                    )
                                                    Text(
                                                        text = "1 portion/serving",
                                                        style = MaterialTheme.typography.bodySmall,
                                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                                    )
                                                }

                                                Row(verticalAlignment = Alignment.CenterVertically) {
                                                    Text(
                                                        text = "${((entry.nutrients["calories"] ?: 0.0) * entry.quantity).toInt()} kcal",
                                                        style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                                        color = MaterialTheme.colorScheme.primary
                                                    )
                                                    Spacer(modifier = Modifier.width(12.dp))
                                                    
                                                    val favoriteFoods by viewModel.allFavoriteFoods.collectAsState()
                                                    val isFavorited = favoriteFoods.any { it.foodName.equals(entry.foodName, ignoreCase = true) }
                                                    Box(
                                                        modifier = Modifier
                                                            .size(36.dp)
                                                            .clip(CircleShape)
                                                            .background(
                                                                if (isFavorited) MaterialTheme.colorScheme.tertiaryContainer.copy(alpha = 0.6f)
                                                                else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)
                                                            )
                                                            .border(
                                                                1.2.dp,
                                                                if (isFavorited) MaterialTheme.colorScheme.tertiary
                                                                else MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.4f),
                                                                CircleShape
                                                            )
                                                            .clickable {
                                                                viewModel.toggleFavoriteFood(
                                                                    foodName = entry.foodName,
                                                                    quantity = entry.quantity,
                                                                    unit = entry.unit,
                                                                    nutrients = entry.nutrients
                                                                )
                                                            }
                                                            .testTag("toggle_favorite_food_button_${entry.id}"),
                                                        contentAlignment = Alignment.Center
                                                    ) {
                                                        Icon(
                                                            imageVector = if (isFavorited) Icons.Default.Favorite else Icons.Default.FavoriteBorder,
                                                            contentDescription = "Toggle Favorite",
                                                            tint = if (isFavorited) MaterialTheme.colorScheme.tertiary else MaterialTheme.colorScheme.onSurfaceVariant,
                                                            modifier = Modifier.size(16.dp)
                                                        )
                                                    }
                                                    Spacer(modifier = Modifier.width(8.dp))

                                                    Box(
                                                        modifier = Modifier
                                                            .size(36.dp)
                                                            .clip(CircleShape)
                                                            .background(MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.6f))
                                                            .border(1.2.dp, MaterialTheme.colorScheme.primary, CircleShape)
                                                            .clickable { editingEntry = entry }
                                                            .testTag("edit_food_button_${entry.id}"),
                                                        contentAlignment = Alignment.Center
                                                    ) {
                                                        Icon(
                                                            imageVector = Icons.Default.Edit,
                                                            contentDescription = "Edit entry",
                                                            tint = MaterialTheme.colorScheme.primary,
                                                            modifier = Modifier.size(16.dp)
                                                        )
                                                    }
                                                    Spacer(modifier = Modifier.width(8.dp))
                                                    Box(
                                                        modifier = Modifier
                                                            .size(36.dp)
                                                            .clip(CircleShape)
                                                            .background(MaterialTheme.colorScheme.errorContainer.copy(alpha = 0.6f))
                                                            .border(1.2.dp, MaterialTheme.colorScheme.error, CircleShape)
                                                            .clickable { entryToDelete = entry }
                                                            .testTag("delete_food_button_${entry.id}"),
                                                        contentAlignment = Alignment.Center
                                                    ) {
                                                        Icon(
                                                            imageVector = Icons.Default.Delete,
                                                            contentDescription = "Delete entry",
                                                            tint = MaterialTheme.colorScheme.error,
                                                            modifier = Modifier.size(16.dp)
                                                        )
                                                    }
                                                }
                                            }

                                            // Extended nutrient view on item tap
                                            AnimatedVisibility(
                                                visible = expanded,
                                                enter = fadeIn() + slideInVertically(),
                                                exit = fadeOut() + shrinkVertically()
                                            ) {
                                                Column(modifier = Modifier.padding(top = 8.dp)) {
                                                    Text(
                                                        "Major Nutrients Breakdowns:",
                                                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                                    )
                                                    Spacer(modifier = Modifier.height(4.dp))
                                                    NutrientMiniGrid(entry = entry)
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
        }
    }

    editingEntry?.let { entry ->
        EditFoodDialog(
            entry = entry,
            onDismiss = { editingEntry = null },
            onConfirmManual = { updated ->
                viewModel.updateFoodLogEntry(updated)
                editingEntry = null
            },
            onConfirmReanalyze = { id, text, meal, date ->
                viewModel.reanalyzeAndReplaceEntry(id, text, meal, date)
                editingEntry = null
            }
        )
    }

    entryToDelete?.let { entry ->
        AlertDialog(
            onDismissRequest = { entryToDelete = null },
            title = {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Icon(
                        imageVector = Icons.Default.Warning,
                        contentDescription = "Warning",
                        tint = MaterialTheme.colorScheme.error
                    )
                    Text(
                        text = "Delete Food Log Entry",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold)
                    )
                }
            },
            text = {
                Text("Are you sure you want to delete \"${entry.foodName}\" for ${entry.mealType}? This action will permanently remove this item from your daily journal and reduce your nutrient levels accordingly.")
            },
            confirmButton = {
                Button(
                    onClick = {
                        viewModel.deleteLog(entry)
                        entryToDelete = null
                    },
                    modifier = Modifier.testTag("confirm_delete_dialog_button"),
                    colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.error)
                ) {
                    Text("Delete")
                }
            },
            dismissButton = {
                TextButton(
                    onClick = { entryToDelete = null },
                    modifier = Modifier.testTag("cancel_delete_dialog_button")
                ) {
                    Text("Cancel")
                }
            }
        )
    }

    selectedLogForBreakdown?.let { entry ->
        FoodNutrientBreakdownBottomSheet(
            entry = entry,
            viewModel = viewModel,
            onDismiss = { selectedLogForBreakdown = null }
        )
    }
}

@OptIn(ExperimentalLayoutApi::class)
@Composable
fun NutrientMiniGrid(entry: FoodLogEntry) {
    val itemsToShow = listOf(
        Pair("carbohydrates", "Carbs"),
        Pair("protein", "Protein"),
        Pair("fat", "Fat"),
        Pair("fiber", "Fiber"),
        Pair("saturated_fat", "Sat Fat"),
        Pair("sodium", "Sodium"),
        Pair("vitamin_c", "Vit C"),
        Pair("calcium", "Calcium")
    )

    FlowRow(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.spacedBy(8.dp, Alignment.Start),
        maxItemsInEachRow = 4
    ) {
        itemsToShow.forEach { (key, label) ->
            val value = entry.nutrients[key] ?: 0.0
            val def = Nutrients.getByKey(key)
            val unit = def?.unit ?: "g"

            Card(
                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                modifier = Modifier.padding(vertical = 4.dp),
                border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.06f))
            ) {
                Column(modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)) {
                    Text(
                        text = label,
                        style = MaterialTheme.typography.labelSmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                    Text(
                        text = "${value.formatInt()} $unit",
                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                }
            }
        }
    }
}

@Composable
fun CopyDayLogDialog(
    currentDate: String,
    datesList: List<Pair<String, String>>,
    onDismiss: () -> Unit,
    onCopy: (source: String, target: String) -> Unit
) {
    var copyDirectionIsToTarget by remember { mutableStateOf(false) } // Default: Pull in logs to current date
    var selectedOtherDate by remember { mutableStateOf(datesList.firstOrNull { it.first != currentDate }?.first ?: "") }

    Dialog(onDismissRequest = onDismiss) {
        Surface(
            shape = RoundedCornerShape(16.dp),
            tonalElevation = 8.dp,
            modifier = Modifier.fillMaxWidth()
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(20.dp),
                verticalArrangement = Arrangement.spacedBy(16.dp)
            ) {
                Text(
                    text = "Copy Day Journal Log",
                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.primary
                )

                Text(
                    text = "Replicate entire breakfast, lunch, dinner, or snack lists across different dates to keep logging fast and easy.",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )

                // Direction selection cards
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text(
                        text = "Copy Operation Mode:",
                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.onSurface
                    )
                    
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        // Option 1: Copy from other day to current day
                        Card(
                            modifier = Modifier
                                .weight(1f)
                                .clickable { copyDirectionIsToTarget = false }
                                .testTag("direction_copy_in"),
                            colors = CardDefaults.cardColors(
                                containerColor = if (!copyDirectionIsToTarget) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)
                            ),
                            border = BorderStroke(
                                width = 1.dp,
                                color = if (!copyDirectionIsToTarget) MaterialTheme.colorScheme.primary else Color.Transparent
                            )
                        ) {
                            Column(
                                modifier = Modifier.padding(10.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Text(
                                    text = "Pull In Log",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = if (!copyDirectionIsToTarget) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurface
                                )
                                Spacer(modifier = Modifier.height(2.dp))
                                Text(
                                    text = "Another Day ➔ Today",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = if (!copyDirectionIsToTarget) MaterialTheme.colorScheme.onPrimaryContainer.copy(alpha = 0.8f) else MaterialTheme.colorScheme.onSurfaceVariant,
                                    textAlign = TextAlign.Center
                                )
                            }
                        }

                        // Option 2: Copy current day to another day
                        Card(
                            modifier = Modifier
                                .weight(1f)
                                .clickable { copyDirectionIsToTarget = true }
                                .testTag("direction_copy_out"),
                            colors = CardDefaults.cardColors(
                                containerColor = if (copyDirectionIsToTarget) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)
                            ),
                            border = BorderStroke(
                                width = 1.dp,
                                color = if (copyDirectionIsToTarget) MaterialTheme.colorScheme.primary else Color.Transparent
                            )
                        ) {
                            Column(
                                modifier = Modifier.padding(10.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Text(
                                    text = "Push Out Log",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = if (copyDirectionIsToTarget) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurface
                                )
                                Spacer(modifier = Modifier.height(2.dp))
                                Text(
                                    text = "Today ➔ Another Day",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = if (copyDirectionIsToTarget) MaterialTheme.colorScheme.onPrimaryContainer.copy(alpha = 0.8f) else MaterialTheme.colorScheme.onSurfaceVariant,
                                    textAlign = TextAlign.Center
                                )
                            }
                        }
                    }
                }

                // Selected Target/Source Date List
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Text(
                        text = if (copyDirectionIsToTarget) "Select Destination Date:" else "Select Source Date:",
                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.onSurface
                    )

                    Column(
                        verticalArrangement = Arrangement.spacedBy(6.dp),
                        modifier = Modifier.padding(vertical = 4.dp)
                    ) {
                        datesList.forEach { (dateStr, label) ->
                            if (dateStr != currentDate) {
                                val isSelected = selectedOtherDate == dateStr
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .clip(RoundedCornerShape(8.dp))
                                        .background(
                                            if (isSelected) MaterialTheme.colorScheme.secondaryContainer 
                                            else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.15f)
                                        )
                                        .clickable { selectedOtherDate = dateStr }
                                        .padding(horizontal = 12.dp, vertical = 8.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Box(
                                        modifier = Modifier
                                            .size(16.dp)
                                            .background(
                                                if (isSelected) MaterialTheme.colorScheme.primary 
                                                else Color.Transparent, 
                                                CircleShape
                                            )
                                            .border(
                                                width = 1.5.dp, 
                                                color = if (isSelected) MaterialTheme.colorScheme.primary 
                                                        else MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.5f), 
                                                shape = CircleShape
                                            )
                                    )
                                    Spacer(modifier = Modifier.width(10.dp))
                                    Text(
                                        text = "$label ($dateStr)",
                                        style = MaterialTheme.typography.bodySmall.copy(
                                            fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal
                                        ),
                                        color = if (isSelected) MaterialTheme.colorScheme.onSecondaryContainer else MaterialTheme.colorScheme.onSurface
                                    )
                                }
                            }
                        }
                    }
                }

                // Footer Buttons
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(10.dp, Alignment.End)
                ) {
                    TextButton(
                        onClick = onDismiss,
                        modifier = Modifier.testTag("dismiss_copy_log_dialog")
                    ) {
                        Text("Cancel")
                    }
                    Button(
                        onClick = {
                            if (selectedOtherDate.isNotEmpty()) {
                                if (copyDirectionIsToTarget) {
                                    onCopy(currentDate, selectedOtherDate)
                                } else {
                                    onCopy(selectedOtherDate, currentDate)
                                }
                                onDismiss()
                            }
                        },
                        enabled = selectedOtherDate.isNotEmpty(),
                        modifier = Modifier.testTag("confirm_copy_log_button")
                    ) {
                        Text("Copy Entries")
                    }
                }
            }
        }
    }
}

private fun Double.format(digits: Int): String {
    if (!this.isFinite()) return "0"
    return String.format(Locale.US, "%.${digits}f", this)
}

@OptIn(ExperimentalLayoutApi::class, ExperimentalMaterial3Api::class)
@Composable
fun PeriodicReportsTab(viewModel: NutritionViewModel) {
    val allLogEntries by viewModel.allLogEntries.collectAsState()
    val context = androidx.compose.ui.platform.LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    
    var selectedDays by remember { mutableStateOf(7) }
    var selectedLabel by remember { mutableStateOf("Weekly") }
    
    val report = remember(allLogEntries, selectedDays, selectedLabel) {
        viewModel.getPeriodicReport(selectedDays, selectedLabel)
    }

    var pendingHtmlReportText by remember { mutableStateOf<String?>(null) }
    var pendingCsvReportText by remember { mutableStateOf<String?>(null) }

    val csvReportLauncher = rememberLauncherForActivityResult(
        contract = SafeCreateDocument("text/csv")
    ) { uri ->
        if (uri != null) {
            val csvToWrite = pendingCsvReportText
            if (csvToWrite != null) {
                coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                    try {
                        context.contentResolver.openOutputStream(uri)?.use { outputStream ->
                            outputStream.write(csvToWrite.toByteArray(Charsets.UTF_8))
                        }
                        withContext(kotlinx.coroutines.Dispatchers.Main) {
                            Toast.makeText(context, "Monthly CSV Report exported successfully!", Toast.LENGTH_SHORT).show()
                        }
                    } catch (e: Exception) {
                        e.printStackTrace()
                        withContext(kotlinx.coroutines.Dispatchers.Main) {
                            Toast.makeText(context, "Failed to write CSV: ${e.localizedMessage}", Toast.LENGTH_LONG).show()
                        }
                    } finally {
                        pendingCsvReportText = null
                    }
                }
            }
        }
    }

    val htmlReportLauncher = rememberLauncherForActivityResult(
        contract = SafeCreateDocument("text/html")
    ) { uri ->
        if (uri != null) {
            val htmlToWrite = pendingHtmlReportText
            if (htmlToWrite != null) {
                coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                    try {
                        context.contentResolver.openOutputStream(uri)?.use { outputStream ->
                            outputStream.write(htmlToWrite.toByteArray(Charsets.UTF_8))
                        }
                    } catch (e: Exception) {
                        e.printStackTrace()
                    } finally {
                        pendingHtmlReportText = null
                    }
                }
            } else {
                // fallback if callback happens but state was lost or not set yet
                val htmlString = viewModel.generateHtmlReport(report)
                coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                    try {
                        context.contentResolver.openOutputStream(uri)?.use { outputStream ->
                            outputStream.write(htmlString.toByteArray(Charsets.UTF_8))
                        }
                    } catch (e: Exception) {
                        e.printStackTrace()
                    }
                }
            }
        }
    }

    val pdfReportLauncher = rememberLauncherForActivityResult(
        contract = SafeCreateDocument("application/pdf")
    ) { uri ->
        if (uri != null) {
            coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                try {
                    context.contentResolver.openOutputStream(uri)?.use { outputStream ->
                        viewModel.generatePdfReport(context, report, outputStream)
                    }
                    withContext(kotlinx.coroutines.Dispatchers.Main) {
                        Toast.makeText(context, "PDF Report exported successfully!", Toast.LENGTH_SHORT).show()
                    }
                } catch (e: Exception) {
                    e.printStackTrace()
                    withContext(kotlinx.coroutines.Dispatchers.Main) {
                        Toast.makeText(context, "Failed to export PDF: ${e.localizedMessage}", Toast.LENGTH_LONG).show()
                    }
                }
            }
        }
    }
    
    Column(
        modifier = Modifier
            .fillMaxSize()
            .verticalScroll(rememberScrollState())
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // 1. Period switcher headers
        Text(
            text = "Periodic Health Reports",
            style = MaterialTheme.typography.headlineSmall.copy(fontWeight = FontWeight.Bold),
            color = MaterialTheme.colorScheme.primary
        )
        Text(
            text = "Analyze your macro and micronutrient patterns across long-term durations to pinpoint consistent deficiencies or cumulative excesses.",
            style = MaterialTheme.typography.bodyMedium,
            color = MaterialTheme.colorScheme.onSurfaceVariant
        )
        
        // Custom segmented pill selectors
        Card(
            modifier = Modifier.fillMaxWidth(),
            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)),
            border = BorderStroke(1.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.12f))
        ) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(8.dp),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                listOf(
                    Triple(7, "Weekly", "Weekly"),
                    Triple(30, "Monthly", "Monthly"),
                    Triple(365, "Annual", "Annual")
                ).forEach { (days, label, dispText) ->
                    val isSelected = selectedDays == days
                    val containerColor = if (isSelected) MaterialTheme.colorScheme.primary else Color.Transparent
                    val contentColor = if (isSelected) MaterialTheme.colorScheme.onPrimary else MaterialTheme.colorScheme.onSurface
                    
                    Box(
                        modifier = Modifier
                            .weight(1f)
                            .clip(RoundedCornerShape(8.dp))
                            .background(containerColor)
                            .clickable {
                                selectedDays = days
                                selectedLabel = label
                            }
                            .padding(vertical = 12.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = dispText,
                            style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                            color = contentColor
                        )
                    }
                }
            }
        }
        
        if (report.daysWithLogs == 0) {
            // High quality empty state
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(vertical = 24.dp)
                    .testTag("reports_empty_card"),
                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.15f)),
                border = BorderStroke(1.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.15f))
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(24.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    Icon(
                        imageVector = Icons.Default.Info,
                        contentDescription = "No Logs Found",
                        tint = MaterialTheme.colorScheme.primary,
                        modifier = Modifier.size(48.dp)
                    )
                    Text(
                        text = "No Nutrition Logs Prepared",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.onSurface
                    )
                    Text(
                        text = "We couldn't detect any logged items in the selected past $selectedDays days. Change the date range or log some food entries on the 'Log Journal' tab.",
                        style = MaterialTheme.typography.bodyMedium,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                        textAlign = TextAlign.Center
                    )
                }
            }
        } else {
            // 2. Overview Stats Card
            Card(
                modifier = Modifier.fillMaxWidth().testTag("periodic_report_summary_card"),
                elevation = CardDefaults.cardElevation(defaultElevation = 2.dp)
            ) {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column(modifier = Modifier.weight(1f)) {
                        Text(
                            text = "$selectedLabel Assessment Overview",
                            style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.primary
                        )
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            text = "Values are averaged across ${report.daysWithLogs} day(s) that had logged food items in your journal, exposing your actual dietary behaviors.",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                        Button(
                            onClick = {
                                try {
                                    pdfReportLauncher.launch("nutriscribe-report-$selectedLabel.pdf")
                                } catch (e: ActivityNotFoundException) {
                                    Toast.makeText(context, "System File Picker not available. PDF export aborted.", Toast.LENGTH_LONG).show()
                                } catch (e: Exception) {
                                    Toast.makeText(context, "Could not open File Picker: ${e.localizedMessage}", Toast.LENGTH_SHORT).show()
                                }
                            },
                            modifier = Modifier.testTag("button_export_pdf_report"),
                            colors = ButtonDefaults.buttonColors(
                                containerColor = MaterialTheme.colorScheme.primary,
                                contentColor = MaterialTheme.colorScheme.onPrimary
                            )
                        ) {
                            Icon(
                                imageVector = Icons.Default.Share,
                                contentDescription = "Export PDF Summary Report",
                                modifier = Modifier.size(16.dp)
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text("Export PDF Summary Report", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold))
                        }
                        Spacer(modifier = Modifier.height(8.dp))
                        OutlinedButton(
                            onClick = {
                                try {
                                    pendingHtmlReportText = viewModel.generateHtmlReport(report)
                                    htmlReportLauncher.launch("nutriscribe-report-$selectedLabel.html")
                                } catch (e: ActivityNotFoundException) {
                                    Toast.makeText(context, "System File Picker not available. Please use 'Copy HTML to Clipboard' instead.", Toast.LENGTH_LONG).show()
                                } catch (e: Exception) {
                                    Toast.makeText(context, "Could not open File Picker: ${e.localizedMessage}", Toast.LENGTH_SHORT).show()
                                }
                            },
                            modifier = Modifier.testTag("button_export_html_report"),
                            border = BorderStroke(1.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.4f))
                        ) {
                            Icon(
                                imageVector = Icons.Default.Share,
                                contentDescription = "Export HTML Report",
                                modifier = Modifier.size(16.dp)
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text("Export Desktop HTML", style = MaterialTheme.typography.labelSmall)
                        }
                        Spacer(modifier = Modifier.height(8.dp))
                        OutlinedButton(
                            onClick = {
                                try {
                                    val htmlString = viewModel.generateHtmlReport(report)
                                    val clipboard = context.getSystemService(android.content.Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                    val clip = android.content.ClipData.newPlainText("NutriScribe HTML Report", htmlString)
                                    clipboard.setPrimaryClip(clip)
                                    Toast.makeText(context, "HTML Report copied to clipboard!", Toast.LENGTH_SHORT).show()
                                } catch (e: Exception) {
                                    Toast.makeText(context, "Cloud / System Clipboard error: ${e.localizedMessage}", Toast.LENGTH_LONG).show()
                                }
                            },
                            modifier = Modifier.testTag("button_copy_html_report"),
                            border = BorderStroke(1.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.4f))
                        ) {
                            Icon(
                                imageVector = Icons.Default.Share,
                                contentDescription = "Copy HTML",
                                modifier = Modifier.size(16.dp)
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text("Copy HTML to Clipboard", style = MaterialTheme.typography.labelSmall)
                        }
                        Spacer(modifier = Modifier.height(8.dp))
                        OutlinedButton(
                            onClick = {
                                try {
                                    pendingCsvReportText = viewModel.generateMonthlyCsvReport()
                                    csvReportLauncher.launch("nutriscribe-30day-history.csv")
                                } catch (e: ActivityNotFoundException) {
                                    Toast.makeText(context, "System File Picker not available. CSV export aborted.", Toast.LENGTH_LONG).show()
                                } catch (e: Exception) {
                                    Toast.makeText(context, "Could not open File Picker: ${e.localizedMessage}", Toast.LENGTH_SHORT).show()
                                }
                            },
                            modifier = Modifier.testTag("button_export_csv_report"),
                            border = BorderStroke(1.dp, MaterialTheme.colorScheme.primary)
                        ) {
                            Icon(
                                imageVector = Icons.Default.Share,
                                contentDescription = "Download 30-Day CSV History",
                                modifier = Modifier.size(16.dp),
                                tint = MaterialTheme.colorScheme.primary
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text("Download 30-Day CSV History", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold), color = MaterialTheme.colorScheme.primary)
                        }
                    }
                    
                    Spacer(modifier = Modifier.width(16.dp))
                    
                    Column(horizontalAlignment = Alignment.End) {
                        Text(
                            text = "${report.avgCaloriesPerDay.toInt()} kcal",
                            style = MaterialTheme.typography.titleLarge.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.primary
                        )
                        Text(
                            text = "daily average",
                            style = MaterialTheme.typography.labelSmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            }
            
            // 3. Macronutrient Energy Pie Chart
            Card(
                modifier = Modifier.fillMaxWidth().testTag("periodic_report_macro_pie_card"),
                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.25f)),
                border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f))
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(16.dp),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    Text(
                        text = "Average Energy Balance Spread",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.onSurface,
                        modifier = Modifier.align(Alignment.Start)
                    )
                    Text(
                        text = "Weekly/Monthly ratio of carbs, protein, and fat based on calories",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                        modifier = Modifier.align(Alignment.Start)
                    )

                    Spacer(modifier = Modifier.height(16.dp))

                    val carbsW = report.avgMacros.carbsPercent.toFloat().safeCoerce(0f, 1f)
                    val protW = report.avgMacros.proteinPercent.toFloat().safeCoerce(0f, 1f)
                    val fatW = report.avgMacros.fatPercent.toFloat().safeCoerce(0f, 1f)
                    val totalProp = carbsW + protW + fatW

                    Box(
                        contentAlignment = Alignment.Center,
                        modifier = Modifier.size(140.dp)
                    ) {
                        Canvas(modifier = Modifier.size(130.dp)) {
                            if (totalProp > 0f) {
                                val carbsAngle = (carbsW / totalProp) * 360f
                                val protAngle = (protW / totalProp) * 360f
                                val fatAngle = (fatW / totalProp) * 360f

                                var startAngle = -90f

                                // Carbohydrates segment (Blue)
                                drawArc(
                                    color = Color(0xFF3897F5),
                                    startAngle = startAngle,
                                    sweepAngle = carbsAngle,
                                    useCenter = true
                                )
                                startAngle += carbsAngle

                                // Protein segment (Orange)
                                drawArc(
                                    color = Color(0xFFFF9800),
                                    startAngle = startAngle,
                                    sweepAngle = protAngle,
                                    useCenter = true
                                )
                                startAngle += protAngle

                                // Total Fat segment (Green)
                                drawArc(
                                    color = Color(0xFF4CAF50),
                                    startAngle = startAngle,
                                    sweepAngle = fatAngle,
                                    useCenter = true
                                )
                            } else {
                                drawCircle(
                                    color = Color.LightGray.copy(alpha = 0.5f),
                                    radius = size.minDimension / 2f
                                )
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween
                    ) {
                        MacroIndicator(
                            label = "Carbs",
                            grams = report.avgMacros.carbsGrams,
                            calories = report.avgMacros.carbsGrams * 4.0,
                            percent = report.avgMacros.carbsPercent * 100,
                            color = Color(0xFF3897F5)
                        )
                        MacroIndicator(
                            label = "Protein",
                            grams = report.avgMacros.proteinGrams,
                            calories = report.avgMacros.proteinGrams * 4.0,
                            percent = report.avgMacros.proteinPercent * 100,
                            color = Color(0xFFFF9800)
                        )
                        MacroIndicator(
                            label = "Fat",
                            grams = report.avgMacros.fatGrams,
                            calories = report.avgMacros.fatGrams * 9.0,
                            percent = report.avgMacros.fatPercent * 100,
                            color = Color(0xFF4CAF50)
                        )
                    }
                }
            }
            
            // 4. Trend Diagnostic Warnings
            Card(
                modifier = Modifier.fillMaxWidth().testTag("periodic_report_diagnostics_card"),
                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f))
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text(
                        text = "$selectedLabel Diagnostics & Insights",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    Text(
                        text = "Exposing recurring dietary risks or deficiencies observed over the past $selectedDays days",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )

                    Spacer(modifier = Modifier.height(12.dp))

                    if (report.insights.isEmpty()) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                            modifier = Modifier.padding(vertical = 12.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Default.CheckCircle,
                                contentDescription = "Perfect Status",
                                tint = Color(0xFF2E7D32)
                            )
                            Text(
                                text = "Perfect balance: Your daily averages are completely compliant with all tracked nutritional recommendation benchmarks!",
                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                color = Color(0xFF2E7D32)
                            )
                        }
                    } else {
                        Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                            report.insights.forEach { insight ->
                                Column(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .clip(RoundedCornerShape(8.dp))
                                        .background(
                                            if (insight.isExcess) Color(0xFFFFEBEE) else Color(0xFFFFF3E0)
                                        )
                                        .padding(12.dp)
                                ) {
                                    Row(
                                        modifier = Modifier.fillMaxWidth(),
                                        horizontalArrangement = Arrangement.SpaceBetween,
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        Text(
                                            text = "${insight.name} -> ${if (insight.isExcess) "Excess Warning" else "Deficit Warning"}",
                                            style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                            color = if (insight.isExcess) Color(0xFFC62828) else Color(0xFFEF6C00)
                                        )
                                        Text(
                                            text = "${insight.intakeString}/day vs target ${insight.rdaString}",
                                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                            color = MaterialTheme.colorScheme.onSurfaceVariant
                                        )
                                    }

                                    Spacer(modifier = Modifier.height(6.dp))

                                    Text(
                                        text = "• Short-term Effect:\n  ${insight.shortTermRisk}",
                                        style = MaterialTheme.typography.bodySmall,
                                        color = MaterialTheme.colorScheme.onSurface
                                    )

                                    Spacer(modifier = Modifier.height(4.dp))

                                    Text(
                                        text = "• Long-term Cumulative Risk:\n  ${insight.longTermRisk}",
                                        style = MaterialTheme.typography.bodySmall,
                                        color = MaterialTheme.colorScheme.onSurface
                                    )
                                }
                            }
                        }
                    }
                }
            }
            
            // 5. Nutrient List
            var showAllNutrients by remember { mutableStateOf(false) }
            var filterWarningsOnly by remember { mutableStateOf(false) }

            val primaryKeys = remember {
                listOf(
                    "calories", "protein", "carbohydrates", "fat", "fiber", "water", 
                    "sodium", "sugars", "saturated_fat", "trans_fat", "cholesterol",
                    "vitamin_c", "vitamin_d", "calcium", "iron", "potassium", "vitamin_a", "vitamin_b12"
                )
            }

            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        text = "Nutrient Daily Averages",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp),
                        modifier = Modifier
                            .clip(RoundedCornerShape(8.dp))
                            .clickable { filterWarningsOnly = !filterWarningsOnly }
                            .padding(horizontal = 8.dp, vertical = 4.dp)
                    ) {
                        Box(
                            modifier = Modifier
                                .size(12.dp)
                                .border(1.5.dp, MaterialTheme.colorScheme.primary, CircleShape)
                                .padding(2.dp)
                                .background(if (filterWarningsOnly) MaterialTheme.colorScheme.primary else Color.Transparent, CircleShape)
                        )
                        Text(
                            text = "Warnings only",
                            style = MaterialTheme.typography.labelMedium,
                            color = MaterialTheme.colorScheme.onSurface
                        )
                    }
                }

                val listedNutrients = remember(report.averageNutrients, filterWarningsOnly) {
                    if (filterWarningsOnly) {
                        report.averageNutrients.filter { 
                            it.status == StatusColor.RED || (it.definition.isMaxLimit && it.intake > it.definition.rda)
                        }
                    } else {
                        report.averageNutrients
                    }
                }

                val itemsToDisplay = remember(listedNutrients, showAllNutrients) {
                    if (showAllNutrients) {
                        listedNutrients
                    } else {
                        listedNutrients.filter { primaryKeys.contains(it.definition.key) }
                    }
                }

                if (itemsToDisplay.isEmpty()) {
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.2f))
                    ) {
                        Box(modifier = Modifier.padding(16.dp), contentAlignment = Alignment.Center) {
                            Text(
                                "No warnings in evaluated nutrients!",
                                style = MaterialTheme.typography.bodyMedium,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }
                    }
                } else {
                    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                        itemsToDisplay.forEach { status ->
                            val unitStr = status.definition.unit
                            val formattedIntake = if (status.definition.key == "calories") status.intake.toInt().toString() else status.intake.format(1)
                            val formattedRda = status.definition.rda.toInt().toString()

                            val colorStyle = when (status.status) {
                                StatusColor.GREEN -> Color(0xFF2E7D32)
                                StatusColor.YELLOW -> Color(0xFFEF6C00)
                                StatusColor.RED -> Color(0xFFC62828)
                            }

                            val backgroundStyle = when (status.status) {
                                StatusColor.GREEN -> Color(0xFFE8F5E9)
                                StatusColor.YELLOW -> Color(0xFFFFF3E0)
                                StatusColor.RED -> Color(0xFFFFEBEE)
                            }

                            Card(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .testTag("report_nutrient_${status.definition.key}"),
                                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                                border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f))
                            ) {
                                Column(modifier = Modifier.padding(12.dp)) {
                                    Row(
                                        modifier = Modifier.fillMaxWidth(),
                                        horizontalArrangement = Arrangement.SpaceBetween,
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        Column {
                                            Text(
                                                text = status.definition.name,
                                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                                color = MaterialTheme.colorScheme.onSurface
                                            )
                                            Text(
                                                text = status.definition.group.name,
                                                style = MaterialTheme.typography.labelSmall,
                                                color = MaterialTheme.colorScheme.onSurfaceVariant
                                            )
                                        }

                                        Row(
                                            verticalAlignment = Alignment.CenterVertically,
                                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                                        ) {
                                            Text(
                                                text = "$formattedIntake / $formattedRda $unitStr",
                                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                                color = MaterialTheme.colorScheme.onSurface
                                            )
                                            Box(
                                                modifier = Modifier
                                                    .clip(RoundedCornerShape(4.dp))
                                                    .background(backgroundStyle)
                                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                                            ) {
                                                Text(
                                                    text = if (status.definition.isMaxLimit) {
                                                        if (status.intake > status.definition.rda) "Over Limit" else "Within Limit"
                                                    } else {
                                                        "${status.percentage.toInt()}%"
                                                    },
                                                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                                    color = colorStyle
                                                )
                                            }
                                        }
                                    }

                                    Spacer(modifier = Modifier.height(8.dp))

                                    val pct = (status.percentage / 100.0).toFloat().safeCoerce(0f, 1f)
                                    val barColor = when (status.status) {
                                        StatusColor.GREEN -> MaterialTheme.colorScheme.primary
                                        StatusColor.YELLOW -> Color(0xFFFF9800)
                                        StatusColor.RED -> MaterialTheme.colorScheme.error
                                    }
                                    
                                    Box(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .height(8.dp)
                                            .clip(RoundedCornerShape(4.dp))
                                            .background(MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f))
                                    ) {
                                        Box(
                                            modifier = Modifier
                                                .fillMaxHeight()
                                                .fillMaxWidth(pct)
                                                .clip(RoundedCornerShape(4.dp))
                                                .background(barColor)
                                        )
                                    }
                                }
                            }
                        }
                    }

                    if (!filterWarningsOnly) {
                        Button(
                            onClick = { showAllNutrients = !showAllNutrients },
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(top = 8.dp)
                                .testTag("report_toggle_all_nutrients_btn"),
                            colors = ButtonDefaults.buttonColors(
                                containerColor = MaterialTheme.colorScheme.secondaryContainer,
                                contentColor = MaterialTheme.colorScheme.onSecondaryContainer
                            )
                        ) {
                            Text(if (showAllNutrients) "Collapse to Key Minerals & Vitamins" else "Display All 41 Evaluated Nutrients")
                        }
                    }
                }
            }
        }
    }
}

private fun Double.formatInt(): String {
    if (!this.isFinite()) return "0"
    return if (this % 1.0 == 0.0) this.toInt().toString() else String.format(Locale.US, "%.1f", this)
}

@Composable
fun NutrientsListTab(viewModel: NutritionViewModel) {
    val dailyNutrients by viewModel.dailyNutrients.collectAsState()
    var searchQuery by remember { mutableStateOf("") }
    var selectedGroup by remember { mutableStateOf<NutrientGroup?>(null) }

    var selectedNutrientKey by remember { mutableStateOf<String?>(null) }

    val filteredList = dailyNutrients.filter { status ->
        val matchQuery = status.definition.name.contains(searchQuery, ignoreCase = true)
        val matchGroup = selectedGroup == null || status.definition.group == selectedGroup
        matchQuery && matchGroup
    }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp)
    ) {
        // Search Input
        OutlinedTextField(
            value = searchQuery,
            onValueChange = { searchQuery = it },
            label = { Text("Search 41 tracked nutrients...") },
            modifier = Modifier.fillMaxWidth(),
            singleLine = true,
            trailingIcon = {
                if (searchQuery.isNotEmpty()) {
                    IconButton(onClick = { searchQuery = "" }) {
                        Icon(Icons.Default.Close, contentDescription = "Clear")
                    }
                }
            },
            colors = OutlinedTextFieldDefaults.colors(
                focusedBorderColor = MaterialTheme.colorScheme.primary,
                unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.4f),
                focusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.15f),
                unfocusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.10f)
            )
        )

        Spacer(modifier = Modifier.height(12.dp))

        // Category filter chips
        Row(
            modifier = Modifier.fillMaxWidth().padding(bottom = 8.dp),
            horizontalArrangement = Arrangement.spacedBy(6.dp)
        ) {
            val groupsList = listOf(null) + NutrientGroup.values().toList()
            groupsList.forEach { grp ->
                val label = grp?.displayName ?: "All"
                val isSelected = selectedGroup == grp

                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(14.dp))
                        .background(
                            if (isSelected) MaterialTheme.colorScheme.primary
                            else MaterialTheme.colorScheme.surfaceVariant
                        )
                        .clickable { selectedGroup = grp }
                        .padding(horizontal = 12.dp, vertical = 6.dp)
                ) {
                    Text(
                        text = label,
                        color = if (isSelected) MaterialTheme.colorScheme.onPrimary
                        else MaterialTheme.colorScheme.onSurfaceVariant,
                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold)
                    )
                }
            }
        }

        Spacer(modifier = Modifier.height(8.dp))

        // Nutrient List Grid
        LazyVerticalGrid(
            columns = GridCells.Fixed(2),
            horizontalArrangement = Arrangement.spacedBy(10.dp),
            verticalArrangement = Arrangement.spacedBy(10.dp),
            modifier = Modifier.weight(1f)
        ) {
            items(filteredList) { status ->
                val isLimit = status.definition.isMaxLimit
                val colorHex = when (status.status) {
                    StatusColor.GREEN -> Color(0xFF2E7D32)
                    StatusColor.YELLOW -> Color(0xFFEF6C00)
                    StatusColor.RED -> Color(0xFFC62828)
                }

                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .testTag("nutrient_row_${status.definition.key}")
                        .clickable { selectedNutrientKey = status.definition.key },
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.25f)),
                    border = BorderStroke(1.dp, colorHex.copy(alpha = 0.2f))
                ) {
                    Column(modifier = Modifier.padding(12.dp)) {
                        Row(
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.Top,
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Text(
                                text = status.definition.name,
                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.onSurface,
                                maxLines = 1,
                                overflow = TextOverflow.Ellipsis,
                                modifier = Modifier.weight(1f)
                            )
                            Icon(
                                imageVector = Icons.Default.Info,
                                contentDescription = "info",
                                tint = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.4f),
                                modifier = Modifier.size(16.dp)
                            )
                        }

                        Spacer(modifier = Modifier.height(6.dp))

                        Row(
                            verticalAlignment = Alignment.Bottom,
                            horizontalArrangement = Arrangement.SpaceBetween,
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Column {
                                Text(
                                    text = "${status.intake.formatInt()} ${status.definition.unit}",
                                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                                    color = colorHex
                                )
                                Text(
                                    text = if (isLimit) "Limit: ${status.definition.rda.toInt()}" else "Goal: ${status.definition.rda.toInt()}",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }

                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(4.dp))
                                    .background(colorHex.copy(alpha = 0.12f))
                                    .padding(horizontal = 4.dp, vertical = 2.dp)
                            ) {
                                Text(
                                    text = "${status.percentage.toInt()}%",
                                    color = colorHex,
                                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold)
                                )
                            }
                        }
                    }
                }
            }
        }
    }

    // Detail Bottom Sheet modal on grid click
    val activeStatus = remember(selectedNutrientKey, dailyNutrients) {
        selectedNutrientKey?.let { key ->
            dailyNutrients.find { it.definition.key == key }
        }
    }
    if (activeStatus != null) {
        NutrientDetailBottomSheet(
            status = activeStatus,
            onDismiss = { selectedNutrientKey = null },
            onSaveTarget = { viewModel.updateCustomRda(activeStatus.definition.key, it) }
        )
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun NutrientDetailBottomSheet(
    status: NutrientStatus,
    onDismiss: () -> Unit,
    onSaveTarget: (Double) -> Unit
) {
    val state = rememberModalBottomSheetState(skipPartiallyExpanded = true)
    val def = status.definition
    val isLimit = def.isMaxLimit
    val colorHex = when (status.status) {
        StatusColor.GREEN -> Color(0xFF2E7D32)
        StatusColor.YELLOW -> Color(0xFFEF6C00)
        StatusColor.RED -> Color(0xFFC62828)
    }

    ModalBottomSheet(
        onDismissRequest = onDismiss,
        sheetState = state,
        shape = RoundedCornerShape(topStart = 20.dp, topEnd = 20.dp),
        dragHandle = {
            Box(
                modifier = Modifier
                    .width(40.dp)
                    .height(4.dp)
                    .clip(CircleShape)
                    .background(MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.4f))
                    .padding(vertical = 8.dp)
            )
        }
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(24.dp)
                .navigationBarsPadding()
        ) {
            Text(
                text = def.group.displayName.uppercase(),
                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                color = MaterialTheme.colorScheme.primary
            )
            Text(
                text = def.name,
                style = MaterialTheme.typography.titleLarge.copy(fontWeight = FontWeight.Bold),
                color = MaterialTheme.colorScheme.onSurface
            )

            Spacer(modifier = Modifier.height(16.dp))

            // RDA analysis box
            Card(
                colors = CardDefaults.cardColors(containerColor = colorHex.copy(alpha = 0.08f)),
                border = BorderStroke(1.dp, colorHex.copy(alpha = 0.15f))
            ) {
                Column(modifier = Modifier.padding(16.dp).fillMaxWidth()) {
                    Row(
                        horizontalArrangement = Arrangement.SpaceBetween,
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Column {
                            Text(
                                "Your Daily Intake",
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                            Text(
                                "${status.intake.formatInt()} ${def.unit}",
                                style = MaterialTheme.typography.headlineMedium.copy(fontWeight = FontWeight.Bold),
                                color = colorHex
                            )
                        }

                        Column(horizontalAlignment = Alignment.End) {
                            Text(
                                if (isLimit) "Recommended Limit" else "Target Allowance (RDA)",
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                            Text(
                                "${def.rda.toInt()} ${def.unit}",
                                style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.onSurface
                            )
                        }
                    }

                    Spacer(modifier = Modifier.height(12.dp))

                    LinearProgressIndicator(
                        progress = { (status.percentage / 100).toFloat().safeCoerce(0f, 1f) },
                        color = colorHex,
                        trackColor = colorHex.copy(alpha = 0.1f),
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(10.dp)
                            .clip(RoundedCornerShape(5.dp))
                    )

                    Spacer(modifier = Modifier.height(8.dp))

                    Text(
                        text = "Achieved ${status.percentage.toInt()}% of the standard baseline daily reference constraint.",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }

            Spacer(modifier = Modifier.height(20.dp))

            Text(
                text = "Biomedical Role & Importance",
                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                color = MaterialTheme.colorScheme.onSurface
            )
            Spacer(modifier = Modifier.height(6.dp))
            Text(
                text = def.description,
                style = MaterialTheme.typography.bodyMedium,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )

            Spacer(modifier = Modifier.height(20.dp))
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(1.dp)
                    .background(MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.15f))
            )
            Spacer(modifier = Modifier.height(16.dp))

            Text(
                text = "Customize Daily Target / Limit",
                style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                color = MaterialTheme.colorScheme.primary
            )
            Spacer(modifier = Modifier.height(4.dp))
            Text(
                text = "Tailor this value to your personalized health goals (e.g., lowering Sodium target for a zero/low salt diet, adjusting Carbohydrates range, or raising Potassium target for KCl replacements).",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )

            Spacer(modifier = Modifier.height(12.dp))

            var targetInputValue by remember(def.key) { mutableStateOf(def.rda.formatInt()) }

            val parsedValue = remember(targetInputValue) {
                targetInputValue.replace(",", "")
                    .replace(Regex("(?i)[a-z\\s/]"), "")
                    .toDoubleOrNull()
            }

            val standardRda = remember(def.key) {
                Nutrients.getByKey(def.key)?.rda ?: def.rda
            }

            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(12.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                OutlinedTextField(
                    value = targetInputValue,
                    onValueChange = { targetInputValue = it },
                    label = { Text("Daily target (${def.unit})") },
                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                    modifier = Modifier.weight(1f).testTag("custom_target_input"),
                    singleLine = true
                )

                Button(
                    onClick = {
                        val parsedVal = parsedValue
                        if (parsedVal != null && parsedVal >= 0.0) {
                            onSaveTarget(parsedVal)
                            onDismiss()
                        }
                    },
                    modifier = Modifier.testTag("save_custom_target_button"),
                    enabled = parsedValue != null
                ) {
                    Text("Save")
                }
            }

            if (def.rda != standardRda) {
                Spacer(modifier = Modifier.height(10.dp))
                OutlinedButton(
                    onClick = {
                        onSaveTarget(0.0) // Clears the custom override in repository
                        onDismiss()
                    },
                    modifier = Modifier.fillMaxWidth().testTag("reset_custom_target_button"),
                    colors = ButtonDefaults.outlinedButtonColors(contentColor = MaterialTheme.colorScheme.error),
                    border = BorderStroke(1.dp, MaterialTheme.colorScheme.error.copy(alpha = 0.5f))
                ) {
                    Text("Reset to Standard Baseline (${standardRda.formatInt()} ${def.unit})")
                }
            }

            Spacer(modifier = Modifier.height(24.dp))

            OutlinedButton(
                onClick = onDismiss,
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Dismiss Details")
            }
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun AddFoodDialog(
    viewModel: NutritionViewModel,
    onDismiss: () -> Unit,
    onConfirm: (String, String) -> Unit,
    onConfirmBulk: (String) -> Unit,
    onConfirmBarcode: (String, String, Double) -> Unit
) {
    val coroutineScope = rememberCoroutineScope()
    var isSearchingBarcode by remember { mutableStateOf(false) }
    var isMultiDayMode by remember { mutableStateOf(false) }
    var foodDescription by remember { mutableStateOf("") }
    val mealTypes = listOf("Breakfast", "Lunch", "Dinner", "Snack", "Supplement")
    var selectedMeal by remember { mutableStateOf("Lunch") }
    var expandedMealDropdown by remember { mutableStateOf(false) }
    var showScanner by remember { mutableStateOf(false) }

    var bulkDescription by remember { mutableStateOf("") }
    var logLengthDays by remember { mutableStateOf(3f) }

    var scannedBarcode by remember { mutableStateOf<String?>(null) }
    var scannedFoodName by remember { mutableStateOf("") }
    var scannedFoodDosage by remember { mutableStateOf("") }
    var servingSizeQuantity by remember { mutableStateOf(1.0) }

    Dialog(onDismissRequest = onDismiss) {
        if (showScanner) {
            BarcodeQRScannerScreen(
                onDismiss = { showScanner = false },
                onBarcodeScanned = { barcode ->
                    scannedBarcode = barcode
                    isSearchingBarcode = true
                    showScanner = false
                    
                    val defaultMeal = when (barcode) {
                        "885101234567", "8851012345678", "190111222333", "1901112223334", "301234567890", "3012345678901" -> "Supplement"
                        "012000000133", "0120000001335" -> "Breakfast"
                        else -> "Lunch"
                    }
                    selectedMeal = defaultMeal

                    coroutineScope.launch {
                        try {
                            val usdaResults = viewModel.usdaCacheService.searchFoods(barcode)
                            if (usdaResults.isNotEmpty()) {
                                val match = usdaResults.first()
                                scannedFoodName = match.name
                                scannedFoodDosage = "${match.servingSize} ${match.servingSizeUnit}"
                            } else {
                                val (localMatch, defaultDosage) = when (barcode) {
                                    "041500000251", "0415000002511" -> Pair("Greek Yogurt with Chia & Honey", "1 container (150g)")
                                    "885101234567", "8851012345678" -> Pair("Premium Whey Protein", "1 scoop (30g)")
                                    "190111222333", "1901112223334" -> Pair("Daily Multivitamin Tablet", "1 tablet")
                                    "301234567890", "3012345678901" -> Pair("Pure Magnesium Glycinate", "2 capsules")
                                    "012000000133", "0120000001335" -> Pair("Organic Rolled Oats with Banana", "1 cup (40g cooked)")
                                    "490000004433", "4900000044331" -> Pair("Matcha Green Tea", "1 serving")
                                    else -> Pair("Scanned Product: $barcode", "1 serving")
                                }
                                scannedFoodName = localMatch
                                scannedFoodDosage = defaultDosage
                            }
                        } catch (e: Exception) {
                            val (localMatch, defaultDosage) = when (barcode) {
                                "041500000251", "0415000002511" -> Pair("Greek Yogurt with Chia & Honey", "1 container (150g)")
                                "885101234567", "8851012345678" -> Pair("Premium Whey Protein", "1 scoop (30g)")
                                "190111222333", "1901112223334" -> Pair("Daily Multivitamin Tablet", "1 tablet")
                                "301234567890", "3012345678901" -> Pair("Pure Magnesium Glycinate", "2 capsules")
                                "012000000133", "0120000001335" -> Pair("Organic Rolled Oats with Banana", "1 cup (40g cooked)")
                                "490000004433", "4900000044331" -> Pair("Matcha Green Tea", "1 serving")
                                else -> Pair("Scanned Product: $barcode", "1 serving")
                            }
                            scannedFoodName = localMatch
                            scannedFoodDosage = defaultDosage
                        } finally {
                            isSearchingBarcode = false
                        }
                    }
                }
            )
        } else if (scannedBarcode != null) {
            Surface(
                shape = RoundedCornerShape(16.dp),
                tonalElevation = 8.dp,
                modifier = Modifier.fillMaxWidth()
            ) {
                Column(
                    modifier = Modifier.padding(20.dp)
                ) {
                    // Success Badge Header
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        modifier = Modifier.fillMaxWidth().padding(bottom = 12.dp)
                    ) {
                        Box(
                            modifier = Modifier
                                .size(36.dp)
                                .clip(CircleShape)
                                .background(MaterialTheme.colorScheme.primaryContainer),
                            contentAlignment = Alignment.Center
                        ) {
                            Icon(
                                imageVector = Icons.Default.QrCode,
                                contentDescription = null,
                                tint = MaterialTheme.colorScheme.primary,
                                modifier = Modifier.size(20.dp)
                            )
                        }
                        Spacer(modifier = Modifier.width(12.dp))
                        Column {
                            Text(
                                text = "Barcode Verified!",
                                style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.primary
                            )
                            Text(
                                text = "Code: $scannedBarcode",
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f)
                            )
                        }
                    }

                    // Product Card / Loading Area
                    if (isSearchingBarcode) {
                        Card(
                            modifier = Modifier.fillMaxWidth().padding(bottom = 16.dp),
                            colors = CardDefaults.cardColors(
                                containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f)
                            ),
                            border = BorderStroke(1.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.15f))
                        ) {
                            Column(
                                modifier = Modifier.padding(24.dp).fillMaxWidth(),
                                horizontalAlignment = Alignment.CenterHorizontally,
                                verticalArrangement = Arrangement.Center
                            ) {
                                CircularProgressIndicator(
                                    modifier = Modifier.size(28.dp),
                                    strokeWidth = 3.dp,
                                    color = MaterialTheme.colorScheme.primary
                                )
                                Spacer(modifier = Modifier.height(12.dp))
                                Text(
                                    text = "Searching USDA Food Database...",
                                    style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Medium),
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }
                        }
                    } else {
                        Card(
                            modifier = Modifier.fillMaxWidth().padding(bottom = 16.dp),
                            colors = CardDefaults.cardColors(
                                containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f)
                            ),
                            border = BorderStroke(1.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.2f))
                        ) {
                            Column(modifier = Modifier.padding(16.dp)) {
                                Text(
                                    text = scannedFoodName,
                                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )
                                Spacer(modifier = Modifier.height(6.dp))
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Icon(
                                        imageVector = Icons.Default.Info,
                                        contentDescription = null,
                                        tint = MaterialTheme.colorScheme.secondary,
                                        modifier = Modifier.size(16.dp)
                                    )
                                    Spacer(modifier = Modifier.width(6.dp))
                                    Text(
                                        text = "Standard Portion: $scannedFoodDosage",
                                        style = MaterialTheme.typography.bodyMedium,
                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                            }
                        }
                    }

                    // Meal category choosing
                    Text(
                        text = "Meal Category",
                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary,
                        modifier = Modifier.padding(bottom = 6.dp)
                    )
                    Row(
                        modifier = Modifier.fillMaxWidth().padding(bottom = 16.dp),
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        mealTypes.forEach { type ->
                            val isSelected = selectedMeal == type
                            val containerColor = if (isSelected) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
                            val contentColor = if (isSelected) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                            val borderColor = if (isSelected) MaterialTheme.colorScheme.primary else Color.Transparent

                            Surface(
                                onClick = { selectedMeal = type },
                                modifier = Modifier.weight(1f).height(38.dp).testTag("scan_meal_chip_$type"),
                                shape = RoundedCornerShape(8.dp),
                                color = containerColor,
                                contentColor = contentColor,
                                border = if (isSelected) BorderStroke(1.dp, borderColor) else null
                            ) {
                                Box(
                                    contentAlignment = Alignment.Center,
                                    modifier = Modifier.fillMaxSize()
                                ) {
                                    Text(
                                        text = type,
                                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold)
                                    )
                                }
                            }
                        }
                    }

                    // Serving multiplier interactive controls
                    Card(
                        modifier = Modifier.fillMaxWidth().padding(bottom = 16.dp),
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.1f)
                        ),
                        border = BorderStroke(1.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.3f))
                    ) {
                        Column(
                            modifier = Modifier.padding(14.dp),
                            horizontalAlignment = Alignment.CenterHorizontally
                        ) {
                            Text(
                                text = "Adjust Servings",
                                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.primary
                            )
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                modifier = Modifier.padding(vertical = 4.dp)
                            ) {
                                Text(
                                    text = "%.1f".format(servingSizeQuantity),
                                    style = MaterialTheme.typography.displayMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.primary
                                )
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(
                                    text = if (servingSizeQuantity == 1.0) "serving" else "servings",
                                    style = MaterialTheme.typography.titleMedium,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }

                            // Slider
                            Slider(
                                value = servingSizeQuantity.toFloat(),
                                onValueChange = { servingSizeQuantity = Math.round(it * 10.0) / 10.0 },
                                valueRange = 0.1f..5.0f,
                                steps = 49,
                                modifier = Modifier.fillMaxWidth()
                            )

                            Spacer(modifier = Modifier.height(8.dp))

                            // Fast selection preset chips
                            Text(
                                text = "Or pick preset:",
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f),
                                modifier = Modifier.padding(bottom = 6.dp)
                            )
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceEvenly
                            ) {
                                val presets = listOf(0.5, 1.0, 1.5, 2.0, 3.0)
                                presets.forEach { preset ->
                                    val isSelectedPreset = Math.abs(servingSizeQuantity - preset) < 0.05
                                    Surface(
                                        onClick = { servingSizeQuantity = preset },
                                        shape = RoundedCornerShape(16.dp),
                                        color = if (isSelectedPreset) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant,
                                        contentColor = if (isSelectedPreset) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant,
                                        modifier = Modifier.padding(horizontal = 4.dp)
                                    ) {
                                        Text(
                                            text = "${preset}x",
                                            modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp),
                                            style = MaterialTheme.typography.labelMedium
                                        )
                                    }
                                }
                            }
                        }
                    }

                    // Row action buttons
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.End
                    ) {
                        TextButton(onClick = { scannedBarcode = null }) {
                            Text("Cancel Scan")
                        }
                        Spacer(modifier = Modifier.width(8.dp))
                        Button(
                            onClick = {
                                onConfirmBarcode(scannedBarcode!!, selectedMeal, servingSizeQuantity)
                            },
                            modifier = Modifier.testTag("submit_scanned_serving_button")
                        ) {
                            Text("Confirm & Log")
                        }
                    }
                }
            }
        } else {
            Surface(
            shape = RoundedCornerShape(16.dp),
            tonalElevation = 8.dp,
            modifier = Modifier.fillMaxWidth()
        ) {
            Column(
                modifier = Modifier.padding(20.dp)
            ) {
                Text(
                    text = "Log Food via AI Engine",
                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.primary
                )
                Text(
                    text = "Scribe details using our precise AI parser to calculate all 41 vitamins & nutrients.",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant,
                    modifier = Modifier.padding(bottom = 12.dp)
                )

                // Tab Switcher between Single Meal and Multi-day Logging
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(bottom = 16.dp)
                        .clip(RoundedCornerShape(8.dp))
                        .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f))
                ) {
                    Box(
                        modifier = Modifier
                            .weight(1f)
                            .clip(RoundedCornerShape(8.dp))
                            .background(if (!isMultiDayMode) MaterialTheme.colorScheme.primaryContainer else Color.Transparent)
                            .clickable { isMultiDayMode = false }
                            .padding(vertical = 10.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            "Single Meal",
                            style = MaterialTheme.typography.labelLarge,
                            fontWeight = FontWeight.Bold,
                            color = if (!isMultiDayMode) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                    Box(
                        modifier = Modifier
                            .weight(1f)
                            .clip(RoundedCornerShape(8.dp))
                            .background(if (isMultiDayMode) MaterialTheme.colorScheme.primaryContainer else Color.Transparent)
                            .clickable { isMultiDayMode = true }
                            .padding(vertical = 10.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            "Multi-Day Log",
                            style = MaterialTheme.typography.labelLarge,
                            fontWeight = FontWeight.Bold,
                            color = if (isMultiDayMode) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }

                if (isMultiDayMode) {
                    Text(
                        text = "Specify multiple days of meals. Relative time phrases (e.g. 'Yesterday Breakfast', 'May 23 Lunch') will automatically map to actual calendar dates.",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                        modifier = Modifier.padding(bottom = 12.dp)
                    )

                    // Distinct heavy bordered Card surrounding the Command Input Area for Batch Logging
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 4.dp),
                        colors = CardDefaults.cardColors(
                            containerColor = DistinctColorTheme.getCommandContainerColor()
                        ),
                        border = BorderStroke(2.dp, DistinctColorTheme.getCommandBorderColor())
                    ) {
                        Column(modifier = Modifier.padding(12.dp)) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                modifier = Modifier.padding(bottom = 8.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Edit,
                                    contentDescription = "Batch Command",
                                    tint = DistinctColorTheme.getCommandContentColor(),
                                    modifier = Modifier.size(16.dp)
                                )
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(
                                    text = "Batch AI Command Parser Input",
                                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                    color = DistinctColorTheme.getCommandContentColor()
                                )
                            }
                            OutlinedTextField(
                                value = bulkDescription,
                                onValueChange = { bulkDescription = it },
                                placeholder = { Text("e.g.\nYesterday Breakfast: eggs and bacon\nYesterday Lunch: grilled salmon\nToday Lunch: turkey sandwich") },
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(130.dp)
                                    .testTag("bulk_food_input_field"),
                                maxLines = 8,
                                colors = OutlinedTextFieldDefaults.colors(
                                    focusedBorderColor = DistinctColorTheme.getCommandBorderColor(),
                                    unfocusedBorderColor = DistinctColorTheme.getCommandBorderColor().copy(alpha = 0.5f),
                                    focusedContainerColor = MaterialTheme.colorScheme.surface,
                                    unfocusedContainerColor = MaterialTheme.colorScheme.surface
                                )
                            )
                        }
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    Text(
                        text = "Suggested Log Span: ${logLengthDays.toInt()} Days",
                        style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    Slider(
                        value = logLengthDays,
                        onValueChange = { logLengthDays = it },
                        valueRange = 1f..14f,
                        steps = 12,
                        modifier = Modifier.fillMaxWidth().testTag("log_length_slider")
                    )

                } else {
                    // Distinct heavy bordered Card surrounding the Command Input Area for Single Meal Logging
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 4.dp),
                        colors = CardDefaults.cardColors(
                            containerColor = DistinctColorTheme.getCommandContainerColor()
                        ),
                        border = BorderStroke(2.dp, DistinctColorTheme.getCommandBorderColor())
                    ) {
                        Column(modifier = Modifier.padding(12.dp)) {
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                modifier = Modifier.padding(bottom = 8.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Edit,
                                    contentDescription = "Single Command",
                                    tint = DistinctColorTheme.getCommandContentColor(),
                                    modifier = Modifier.size(16.dp)
                                )
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(
                                    text = "AI Command Parser Input",
                                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                    color = DistinctColorTheme.getCommandContentColor()
                                )
                            }
                            OutlinedTextField(
                                value = foodDescription,
                                onValueChange = { foodDescription = it },
                                placeholder = { Text("e.g., 1 medium banana and a cup of yogurt") },
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(100.dp)
                                    .testTag("food_input_field"),
                                maxLines = 4,
                                colors = OutlinedTextFieldDefaults.colors(
                                    focusedBorderColor = DistinctColorTheme.getCommandBorderColor(),
                                    unfocusedBorderColor = DistinctColorTheme.getCommandBorderColor().copy(alpha = 0.5f),
                                    focusedContainerColor = MaterialTheme.colorScheme.surface,
                                    unfocusedContainerColor = MaterialTheme.colorScheme.surface
                                )
                            )
                            Spacer(modifier = Modifier.height(8.dp))
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Text(
                                    text = "Or scan label:",
                                    style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.8f)
                                )
                                Button(
                                    onClick = { showScanner = true },
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = MaterialTheme.colorScheme.primary.copy(alpha = 0.1f),
                                        contentColor = MaterialTheme.colorScheme.primary
                                    ),
                                    contentPadding = PaddingValues(horizontal = 12.dp, vertical = 4.dp),
                                    modifier = Modifier.height(34.dp).testTag("dialog_scan_food_button")
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.QrCode,
                                        contentDescription = "Scan Barcode",
                                        modifier = Modifier.size(16.dp)
                                    )
                                    Spacer(modifier = Modifier.width(6.dp))
                                    Text("Scan QR/Barcode", style = MaterialTheme.typography.labelSmall)
                                }
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(12.dp))

                    // Segmented Meal Selection
                    Text(
                        text = "Meal Category",
                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary,
                        modifier = Modifier.padding(bottom = 6.dp)
                    )
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        mealTypes.forEach { type ->
                            val isSelected = selectedMeal == type
                            val containerColor = if (isSelected) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
                            val contentColor = if (isSelected) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                            val borderColor = if (isSelected) MaterialTheme.colorScheme.primary else Color.Transparent

                            Surface(
                                onClick = { selectedMeal = type },
                                modifier = Modifier.weight(1f).height(38.dp).testTag("meal_chip_$type"),
                                shape = RoundedCornerShape(8.dp),
                                color = containerColor,
                                contentColor = contentColor,
                                border = if (isSelected) BorderStroke(1.dp, borderColor) else null
                            ) {
                                Box(
                                    contentAlignment = Alignment.Center,
                                    modifier = Modifier.fillMaxSize()
                                ) {
                                    Text(
                                        text = type,
                                        style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold)
                                    )
                                }
                            }
                        }
                    }
                }

                Spacer(modifier = Modifier.height(24.dp))

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.End
                ) {
                    TextButton(onClick = onDismiss) {
                        Text("Cancel")
                    }
                    Spacer(modifier = Modifier.width(8.dp))
                    Button(
                        onClick = {
                            if (isMultiDayMode) {
                                if (bulkDescription.isNotBlank()) {
                                    onConfirmBulk(bulkDescription)
                                }
                            } else {
                                if (foodDescription.isNotBlank()) {
                                    onConfirm(foodDescription, selectedMeal)
                                }
                            }
                        },
                        enabled = if (isMultiDayMode) bulkDescription.isNotBlank() else foodDescription.isNotBlank(),
                        modifier = Modifier.testTag("submit_food_button")
                    ) {
                        Text(if (isMultiDayMode) "Analyze & Import" else "Analyze & Log")
                    }
                }
            }
        }
    }
}
}

@OptIn(ExperimentalLayoutApi::class, ExperimentalMaterial3Api::class)
@Composable
fun EditFoodDialog(
    entry: FoodLogEntry,
    onDismiss: () -> Unit,
    onConfirmManual: (FoodLogEntry) -> Unit,
    onConfirmReanalyze: (Int, String, String, String) -> Unit
) {
    var foodName by remember { mutableStateOf(entry.foodName) }
    val mealTypes = listOf("Breakfast", "Lunch", "Dinner", "Snack", "Supplement")
    var selectedMeal by remember { mutableStateOf(entry.mealType) }
    var expandedMealDropdown by remember { mutableStateOf(false) }
    var quantity by remember { mutableStateOf(entry.quantity) }
    var quantityInputStr by remember { mutableStateOf(String.format(Locale.US, "%.2f", entry.quantity)) }

    // Direct nutrients
    var calories by remember { mutableStateOf(entry.nutrients["calories"]?.formatInt() ?: "0") }
    var protein by remember { mutableStateOf(entry.nutrients["protein"]?.formatInt() ?: "0") }
    var carbs by remember { mutableStateOf(entry.nutrients["carbohydrates"]?.formatInt() ?: "0") }
    var fat by remember { mutableStateOf(entry.nutrients["fat"]?.formatInt() ?: "0") }
    var fiber by remember { mutableStateOf(entry.nutrients["fiber"]?.formatInt() ?: "0") }
    var water by remember { mutableStateOf(entry.nutrients["water"]?.formatInt() ?: "0") }
    var sodium by remember { mutableStateOf(entry.nutrients["sodium"]?.formatInt() ?: "0") }
    var sugars by remember { mutableStateOf(entry.nutrients["sugars"]?.formatInt() ?: "0") }

    Dialog(onDismissRequest = onDismiss) {
        Surface(
            shape = RoundedCornerShape(16.dp),
            tonalElevation = 8.dp,
            modifier = Modifier.fillMaxWidth()
        ) {
            Column(
                modifier = Modifier
                    .padding(20.dp)
                    .verticalScroll(rememberScrollState())
            ) {
                Text(
                    text = "Edit Log Entry",
                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.primary
                )
                Text(
                    text = "Update the details, customize portion size, or manually edit key metrics. Alternatively, edit the description and select 'Re-Analyze with AI' to re-calculate.",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant,
                    modifier = Modifier.padding(bottom = 12.dp)
                )

                // Distinct heavy bordered Card surrounding the Command Input Area for Editing Log
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 4.dp),
                    colors = CardDefaults.cardColors(
                        containerColor = DistinctColorTheme.getCommandContainerColor()
                    ),
                    border = BorderStroke(2.dp, DistinctColorTheme.getCommandBorderColor())
                ) {
                    Column(modifier = Modifier.padding(12.dp)) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            modifier = Modifier.padding(bottom = 8.dp)
                        ) {
                            Icon(
                                imageVector = Icons.Default.Edit,
                                contentDescription = "Edit Command",
                                tint = DistinctColorTheme.getCommandContentColor(),
                                modifier = Modifier.size(16.dp)
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text(
                                text = "Edit AI Command Parser Input",
                                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                color = DistinctColorTheme.getCommandContentColor()
                            )
                        }
                        OutlinedTextField(
                            value = foodName,
                            onValueChange = { foodName = it },
                            modifier = Modifier.fillMaxWidth().testTag("edit_food_name_input"),
                            singleLine = true,
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedBorderColor = DistinctColorTheme.getCommandBorderColor(),
                                unfocusedBorderColor = DistinctColorTheme.getCommandBorderColor().copy(alpha = 0.5f),
                                focusedContainerColor = MaterialTheme.colorScheme.surface,
                                unfocusedContainerColor = MaterialTheme.colorScheme.surface
                            )
                        )
                    }
                }

                Spacer(modifier = Modifier.height(12.dp))

                // Segmented Meal Selection
                Text(
                    text = "Meal Category",
                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.primary,
                    modifier = Modifier.padding(bottom = 6.dp)
                )
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    mealTypes.forEach { type ->
                        val isSelected = selectedMeal == type
                        val containerColor = if (isSelected) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
                        val contentColor = if (isSelected) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                        val borderColor = if (isSelected) MaterialTheme.colorScheme.primary else Color.Transparent

                        Surface(
                            onClick = { selectedMeal = type },
                            modifier = Modifier.weight(1f).height(38.dp).testTag("edit_meal_chip_$type"),
                            shape = RoundedCornerShape(8.dp),
                            color = containerColor,
                            contentColor = contentColor,
                            border = if (isSelected) BorderStroke(1.dp, borderColor) else null
                        ) {
                            Box(
                                contentAlignment = Alignment.Center,
                                modifier = Modifier.fillMaxSize()
                              ) {
                                Text(
                                    text = type,
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold)
                                )
                            }
                        }
                    }
                }

                Spacer(modifier = Modifier.height(12.dp))

                // Portion Size & Quantity Edit Box
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 4.dp)
                ) {
                    Text(
                        text = "Portion Size / Quantity",
                        style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.SemiBold),
                        color = MaterialTheme.colorScheme.onSurface,
                        modifier = Modifier.padding(bottom = 6.dp)
                    )
                    
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        IconButton(
                            onClick = {
                                val curVal = quantityInputStr.toDoubleOrNull() ?: quantity
                                if (curVal > 0.25) {
                                    val newVal = curVal - 0.25
                                    quantity = newVal
                                    quantityInputStr = String.format(Locale.US, "%.2f", newVal)
                                }
                            },
                            modifier = Modifier
                                .size(36.dp)
                                .background(MaterialTheme.colorScheme.secondaryContainer, CircleShape)
                                .testTag("edit_qty_dec")
                        ) {
                            Text(
                                "-",
                                style = MaterialTheme.typography.titleMedium,
                                color = MaterialTheme.colorScheme.onSecondaryContainer,
                                fontWeight = FontWeight.Bold
                            )
                        }

                        OutlinedTextField(
                            value = quantityInputStr,
                            onValueChange = { text ->
                                quantityInputStr = text
                                val parsed = text.toDoubleOrNull()
                                if (parsed != null && parsed > 0.0) {
                                    quantity = parsed
                                }
                            },
                            singleLine = true,
                            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                            modifier = Modifier
                                .weight(1f)
                                .height(52.dp)
                                .testTag("edit_quantity_input_field"),
                            textStyle = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedBorderColor = MaterialTheme.colorScheme.primary,
                                unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.4f),
                                focusedContainerColor = MaterialTheme.colorScheme.surface,
                                unfocusedContainerColor = MaterialTheme.colorScheme.surface
                            )
                        )

                        IconButton(
                            onClick = {
                                val curVal = quantityInputStr.toDoubleOrNull() ?: quantity
                                val newVal = curVal + 0.25
                                quantity = newVal
                                quantityInputStr = String.format(Locale.US, "%.2f", newVal)
                            },
                            modifier = Modifier
                                .size(36.dp)
                                .background(MaterialTheme.colorScheme.secondaryContainer, CircleShape)
                                .testTag("edit_qty_inc")
                        ) {
                            Text(
                                "+",
                                style = MaterialTheme.typography.titleMedium,
                                color = MaterialTheme.colorScheme.onSecondaryContainer,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }
                }

                Spacer(modifier = Modifier.height(16.dp))

                // Key nutrients direct edit fields
                Text(
                    text = "Manual Nutrient Overrides",
                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.primary,
                    modifier = Modifier.padding(bottom = 8.dp)
                )

                // Render fields in nice Grid form
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                        OutlinedTextField(
                            value = calories,
                            onValueChange = { calories = it },
                            label = { Text("Calories (kcal)") },
                            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                            modifier = Modifier.weight(1f).testTag("edit_calories_input"),
                            singleLine = true
                        )
                        OutlinedTextField(
                            value = protein,
                            onValueChange = { protein = it },
                            label = { Text("Protein (g)") },
                            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                            modifier = Modifier.weight(1f).testTag("edit_protein_input"),
                            singleLine = true
                        )
                    }

                    Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                        OutlinedTextField(
                            value = carbs,
                            onValueChange = { carbs = it },
                            label = { Text("Carbs (g)") },
                            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                            modifier = Modifier.weight(1f).testTag("edit_carbs_input"),
                            singleLine = true
                        )
                        OutlinedTextField(
                            value = fat,
                            onValueChange = { fat = it },
                            label = { Text("Fat (g)") },
                            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                            modifier = Modifier.weight(1f).testTag("edit_fat_input"),
                            singleLine = true
                        )
                    }

                    Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                        OutlinedTextField(
                            value = fiber,
                            onValueChange = { fiber = it },
                            label = { Text("Fiber (g)") },
                            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                            modifier = Modifier.weight(1f).testTag("edit_fiber_input"),
                            singleLine = true
                        )
                        OutlinedTextField(
                            value = water,
                            onValueChange = { water = it },
                            label = { Text("Water (ml)") },
                            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                            modifier = Modifier.weight(1f).testTag("edit_water_input"),
                            singleLine = true
                        )
                    }

                    Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                        OutlinedTextField(
                            value = sodium,
                            onValueChange = { sodium = it },
                            label = { Text("Sodium (mg)") },
                            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                            modifier = Modifier.weight(1f).testTag("edit_sodium_input"),
                            singleLine = true
                        )
                        OutlinedTextField(
                            value = sugars,
                            onValueChange = { sugars = it },
                            label = { Text("Sugars (g)") },
                            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                            modifier = Modifier.weight(1f).testTag("edit_sugars_input"),
                            singleLine = true
                        )
                    }
                }

                Spacer(modifier = Modifier.height(20.dp))

                // Save or re-analyze triggers
                Column(
                    modifier = Modifier.fillMaxWidth(),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    OutlinedButton(
                        onClick = {
                            if (foodName.isNotBlank()) {
                                onConfirmReanalyze(entry.id, foodName, selectedMeal, entry.date)
                            }
                        },
                        modifier = Modifier.fillMaxWidth().testTag("edit_reanalyze_button"),
                        enabled = foodName.isNotBlank() && foodName != entry.foodName,
                        border = BorderStroke(1.dp, MaterialTheme.colorScheme.primary)
                    ) {
                        Icon(Icons.Default.CheckCircle, contentDescription = null, modifier = Modifier.size(16.dp))
                        Spacer(modifier = Modifier.width(6.dp))
                        Text("Re-Analyze prompt with AI")
                    }

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.End
                    ) {
                        TextButton(onClick = onDismiss) {
                            Text("Cancel")
                        }
                        Spacer(modifier = Modifier.width(8.dp))
                        Button(
                            onClick = {
                                if (foodName.isNotBlank()) {
                                    val updatedNutrients = entry.nutrients.toMutableMap().apply {
                                        put("calories", calories.toDoubleOrNull() ?: 0.0)
                                        put("protein", protein.toDoubleOrNull() ?: 0.0)
                                        put("carbohydrates", carbs.toDoubleOrNull() ?: 0.0)
                                        put("fat", fat.toDoubleOrNull() ?: 0.0)
                                        put("fiber", fiber.toDoubleOrNull() ?: 0.0)
                                        put("water", water.toDoubleOrNull() ?: 0.0)
                                        put("sodium", sodium.toDoubleOrNull() ?: 0.0)
                                        put("sugars", sugars.toDoubleOrNull() ?: 0.0)
                                    }
                                    val updatedEntry = entry.copy(
                                        foodName = foodName,
                                        mealType = selectedMeal,
                                        quantity = quantity,
                                        nutrients = updatedNutrients
                                    )
                                    onConfirmManual(updatedEntry)
                                }
                            },
                            enabled = foodName.isNotBlank(),
                            modifier = Modifier.testTag("save_edit_button")
                        ) {
                            Text("Save Changes")
                        }
                    }
                }
            }
        }
    }
}

private fun Double.safeCoerce(minimumValue: Double, maximumValue: Float): Double {
    if (this.isNaN()) return minimumValue
    return this.coerceIn(minimumValue, maximumValue.toDouble())
}

data class DiagnosticInsight(
    val name: String,
    val intakeString: String,
    val rdaString: String,
    val isExcess: Boolean,
    val shortTermRisk: String,
    val longTermRisk: String
)

@OptIn(ExperimentalLayoutApi::class, ExperimentalMaterial3Api::class)
@Composable
fun DayReportDialog(
    currentDate: String,
    dailyNutrients: List<NutrientStatus>,
    macroSpread: MacroSpreadRatio,
    currentDateEntries: List<FoodLogEntry>,
    viewModel: NutritionViewModel,
    onDismiss: () -> Unit
) {
    var filterWarningsOnly by remember { mutableStateOf(false) }

    val context = androidx.compose.ui.platform.LocalContext.current
    val coroutineScope = rememberCoroutineScope()

    var pendingJsonContent by remember { mutableStateOf<String?>(null) }
    var pendingCsvContent by remember { mutableStateOf<String?>(null) }

    val jsonLauncher = rememberLauncherForActivityResult(
        contract = SafeCreateDocument("application/json")
    ) { uri ->
        if (uri != null && pendingJsonContent != null) {
            coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                try {
                    context.contentResolver.openOutputStream(uri)?.use { output ->
                        output.write(pendingJsonContent!!.toByteArray(Charsets.UTF_8))
                    }
                    withContext(kotlinx.coroutines.Dispatchers.Main) {
                        android.widget.Toast.makeText(context, "Daily JSON report saved successfully!", android.widget.Toast.LENGTH_SHORT).show()
                    }
                } catch (e: Exception) {
                    withContext(kotlinx.coroutines.Dispatchers.Main) {
                        android.widget.Toast.makeText(context, "Save failed: ${e.localizedMessage}", android.widget.Toast.LENGTH_SHORT).show()
                    }
                } finally {
                    pendingJsonContent = null
                }
            }
        }
    }

    val csvLauncher = rememberLauncherForActivityResult(
        contract = SafeCreateDocument("text/csv")
    ) { uri ->
        if (uri != null && pendingCsvContent != null) {
            coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                try {
                    context.contentResolver.openOutputStream(uri)?.use { output ->
                        output.write(pendingCsvContent!!.toByteArray(Charsets.UTF_8))
                    }
                    withContext(kotlinx.coroutines.Dispatchers.Main) {
                        android.widget.Toast.makeText(context, "Daily CSV report saved successfully!", android.widget.Toast.LENGTH_SHORT).show()
                    }
                } catch (e: Exception) {
                    withContext(kotlinx.coroutines.Dispatchers.Main) {
                        android.widget.Toast.makeText(context, "Save failed: ${e.localizedMessage}", android.widget.Toast.LENGTH_SHORT).show()
                    }
                } finally {
                    pendingCsvContent = null
                }
            }
        }
    }

    val insights = remember(dailyNutrients) {
        getInsights(dailyNutrients)
    }

    val displayDateFormatted = remember(currentDate) {
        try {
            val parser = SimpleDateFormat("yyyy-MM-dd", Locale.US)
            val formatter = SimpleDateFormat("EEEE, MMMM d, yyyy", Locale.US)
            parser.parse(currentDate)?.let { formatter.format(it) } ?: currentDate
        } catch (e: Exception) {
            currentDate
        }
    }

    Dialog(onDismissRequest = onDismiss) {
        Surface(
            shape = RoundedCornerShape(16.dp),
            tonalElevation = 8.dp,
            modifier = Modifier
                .fillMaxWidth()
                .heightIn(max = 580.dp)
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(16.dp)
            ) {
                // Header
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column(modifier = Modifier.weight(1f)) {
                        Text(
                            text = "Daily Nutrient Report",
                            style = MaterialTheme.typography.titleLarge.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.primary
                        )
                        Text(
                            text = displayDateFormatted,
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                    IconButton(
                        onClick = onDismiss,
                        modifier = Modifier.testTag("close_report_dialog_btn")
                    ) {
                        Icon(imageVector = Icons.Default.Close, contentDescription = "Close Report")
                    }
                }

                Spacer(modifier = Modifier.height(10.dp))

                // Scrollable content
                Column(
                    modifier = Modifier
                        .weight(1f)
                        .verticalScroll(rememberScrollState()),
                    verticalArrangement = Arrangement.spacedBy(16.dp)
                ) {
                    // 0. Download report card
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .testTag("day_report_download_card"),
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.secondaryContainer.copy(alpha = 0.35f)
                        ),
                        border = BorderStroke(1.dp, MaterialTheme.colorScheme.secondary.copy(alpha = 0.25f))
                    ) {
                        Column(modifier = Modifier.padding(12.dp)) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Share,
                                    contentDescription = "Download Report",
                                    tint = MaterialTheme.colorScheme.secondary,
                                    modifier = Modifier.size(20.dp)
                                )
                                Text(
                                    text = "Download Record-Keeping Reports",
                                    style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSecondaryContainer
                                )
                            }
                            Spacer(modifier = Modifier.height(4.dp))
                            Text(
                                text = "Export today's logs & 41-nutrient RDA analysis as digital records.",
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                            Spacer(modifier = Modifier.height(10.dp))
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                Button(
                                    onClick = {
                                        try {
                                            val jsonString = viewModel.generateDailyReportJson(currentDate, currentDateEntries, dailyNutrients)
                                            pendingJsonContent = jsonString
                                            jsonLauncher.launch("nutriscribe-report-$currentDate.json")
                                        } catch (e: Exception) {
                                            android.widget.Toast.makeText(context, "Error: ${e.localizedMessage}", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                    },
                                    modifier = Modifier
                                        .weight(1f)
                                        .testTag("button_download_json"),
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = MaterialTheme.colorScheme.secondary,
                                        contentColor = MaterialTheme.colorScheme.onSecondary
                                    ),
                                    contentPadding = androidx.compose.foundation.layout.PaddingValues(horizontal = 8.dp, vertical = 6.dp)
                                ) {
                                    Row(
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                                    ) {
                                        Icon(
                                            imageVector = Icons.Default.ArrowDropDown,
                                            contentDescription = null,
                                            modifier = Modifier.size(16.dp)
                                        )
                                        Text(
                                            text = "JSON File",
                                            style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold)
                                        )
                                    }
                                }

                                Button(
                                    onClick = {
                                        try {
                                            val csvString = viewModel.generateDailyReportCsv(currentDate, currentDateEntries, dailyNutrients)
                                            pendingCsvContent = csvString
                                            csvLauncher.launch("nutriscribe-report-$currentDate.csv")
                                        } catch (e: Exception) {
                                            android.widget.Toast.makeText(context, "Error: ${e.localizedMessage}", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                    },
                                    modifier = Modifier
                                        .weight(1f)
                                        .testTag("button_download_csv"),
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = MaterialTheme.colorScheme.tertiary,
                                        contentColor = MaterialTheme.colorScheme.onTertiary
                                    ),
                                    contentPadding = androidx.compose.foundation.layout.PaddingValues(horizontal = 8.dp, vertical = 6.dp)
                                ) {
                                    Row(
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                                    ) {
                                        Icon(
                                            imageVector = Icons.Default.ArrowDropDown,
                                            contentDescription = null,
                                            modifier = Modifier.size(16.dp)
                                        )
                                        Text(
                                            text = "CSV Sheet",
                                            style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold)
                                        )
                                    }
                                }
                            }
                        }
                    }

                    // 1. Pie Chart of Macro Spread
                    Card(
                        modifier = Modifier.fillMaxWidth().testTag("day_report_macro_pie_card"),
                        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.25f)),
                        border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f))
                    ) {
                        Column(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(16.dp),
                            horizontalAlignment = Alignment.CenterHorizontally
                        ) {
                            Text(
                                text = "Macronutrient Energy Spread Pie",
                                style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.onSurface,
                                modifier = Modifier.align(Alignment.Start)
                            )
                            Text(
                                text = "Proportional contribution based on logged calories",
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant,
                                modifier = Modifier.align(Alignment.Start)
                            )

                            Spacer(modifier = Modifier.height(16.dp))

                            // Pie Chart Draw
                            val carbsW = macroSpread.carbsPercent.toFloat().safeCoerce(0f, 1f)
                            val protW = macroSpread.proteinPercent.toFloat().safeCoerce(0f, 1f)
                            val fatW = macroSpread.fatPercent.toFloat().safeCoerce(0f, 1f)
                            val totalProp = carbsW + protW + fatW

                            Box(
                                contentAlignment = Alignment.Center,
                                modifier = Modifier.size(140.dp)
                            ) {
                                Canvas(modifier = Modifier.size(130.dp)) {
                                    if (totalProp > 0f) {
                                        val carbsAngle = (carbsW / totalProp) * 360f
                                        val protAngle = (protW / totalProp) * 360f
                                        val fatAngle = (fatW / totalProp) * 360f

                                        var startAngle = -90f

                                        // Carbohydrates segment (Blue)
                                        drawArc(
                                            color = Color(0xFF3897F5),
                                            startAngle = startAngle,
                                            sweepAngle = carbsAngle,
                                            useCenter = true
                                        )
                                        startAngle += carbsAngle

                                        // Protein segment (Orange)
                                        drawArc(
                                            color = Color(0xFFFF9800),
                                            startAngle = startAngle,
                                            sweepAngle = protAngle,
                                            useCenter = true
                                        )
                                        startAngle += protAngle

                                        // Total Fat segment (Green)
                                        drawArc(
                                            color = Color(0xFF4CAF50),
                                            startAngle = startAngle,
                                            sweepAngle = fatAngle,
                                            useCenter = true
                                        )
                                    } else {
                                        // Empty neutral state circle
                                        drawCircle(
                                            color = Color.LightGray.copy(alpha = 0.5f),
                                            radius = size.minDimension / 2f
                                        )
                                    }
                                }
                            }

                            Spacer(modifier = Modifier.height(16.dp))

                            // Custom Legend with metrics
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                MacroIndicator(
                                    label = "Carbs",
                                    grams = macroSpread.carbsGrams,
                                    calories = macroSpread.carbsGrams * 4.0,
                                    percent = macroSpread.carbsPercent * 100,
                                    color = Color(0xFF3897F5)
                                )
                                MacroIndicator(
                                    label = "Protein",
                                    grams = macroSpread.proteinGrams,
                                    calories = macroSpread.proteinGrams * 4.0,
                                    percent = macroSpread.proteinPercent * 100,
                                    color = Color(0xFFFF9800)
                                )
                                MacroIndicator(
                                    label = "Fat",
                                    grams = macroSpread.fatGrams,
                                    calories = macroSpread.fatGrams * 9.0,
                                    percent = macroSpread.fatPercent * 100,
                                    color = Color(0xFF4CAF50)
                                )
                            }
                        }
                    }

                    // 2. Short & Long-Term Trend Risks
                    Card(
                        modifier = Modifier.fillMaxWidth().testTag("day_report_trend_card"),
                        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                        border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f))
                    ) {
                        Column(modifier = Modifier.padding(16.dp)) {
                            Text(
                                text = "Trend Health Warnings & Risks",
                                style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.primary
                            )
                            Text(
                                text = "Evaluating short and long-term diagnostic alerts based on intake deviations",
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )

                            Spacer(modifier = Modifier.height(12.dp))

                            if (insights.isEmpty()) {
                                Row(
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                                    modifier = Modifier.padding(vertical = 12.dp)
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.CheckCircle,
                                        contentDescription = "Perfect Status",
                                        tint = Color(0xFF2E7D32)
                                    )
                                    Text(
                                        text = "Excellent balance: All evaluated primary nutrients are within healthy ranges!",
                                        style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                        color = Color(0xFF2E7D32)
                                    )
                                }
                            } else {
                                Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                                    insights.forEach { insight ->
                                        Column(
                                            modifier = Modifier
                                                .fillMaxWidth()
                                                .clip(RoundedCornerShape(8.dp))
                                                .background(
                                                    if (insight.isExcess) Color(0xFFFFEBEE) else Color(0xFFFFF3E0)
                                                )
                                                .padding(12.dp)
                                        ) {
                                            Row(
                                                modifier = Modifier.fillMaxWidth(),
                                                horizontalArrangement = Arrangement.SpaceBetween,
                                                verticalAlignment = Alignment.CenterVertically
                                            ) {
                                                Text(
                                                    text = "${insight.name} -> ${if (insight.isExcess) "Excess Warning" else "Deficit Warning"}",
                                                    style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                                    color = if (insight.isExcess) Color(0xFFC62828) else Color(0xFFEF6C00)
                                                )
                                                Text(
                                                    text = "${insight.intakeString} vs Target ${insight.rdaString}",
                                                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                                )
                                            }

                                            Spacer(modifier = Modifier.height(6.dp))

                                            Text(
                                                text = "• Short-term Effect:\n  ${insight.shortTermRisk}",
                                                style = MaterialTheme.typography.bodySmall,
                                                color = MaterialTheme.colorScheme.onSurface
                                            )

                                            Spacer(modifier = Modifier.height(4.dp))

                                            Text(
                                                text = "• Long-term Risk:\n  ${insight.longTermRisk}",
                                                style = MaterialTheme.typography.bodySmall,
                                                color = MaterialTheme.colorScheme.onSurface
                                            )
                                        }
                                    }
                                }
                            }
                        }
                    }

                    // 3. Complete List of All Nutrients (Colorized by Consumption)
                    Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Text(
                                text = "All 41 Evaluated Nutrients",
                                style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.onSurface
                            )
                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                modifier = Modifier.clickable { filterWarningsOnly = !filterWarningsOnly }
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(16.dp)
                                        .border(1.dp, MaterialTheme.colorScheme.primary, RoundedCornerShape(2.dp))
                                        .background(if (filterWarningsOnly) MaterialTheme.colorScheme.primary else Color.Transparent)
                                )
                                Spacer(modifier = Modifier.width(6.dp))
                                Text(
                                    text = "Alerts Only",
                                    style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }
                        }

                        val listedNutrients = remember(dailyNutrients, filterWarningsOnly) {
                            if (filterWarningsOnly) {
                                dailyNutrients.filter { it.status == StatusColor.RED || it.percentage > 180.0 }
                            } else {
                                dailyNutrients
                            }
                        }

                        if (listedNutrients.isEmpty()) {
                            Text(
                                text = "No matching nutrients with alerts currently.",
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant,
                                modifier = Modifier.padding(vertical = 12.dp)
                            )
                        } else {
                            listedNutrients.forEach { status ->
                                val def = status.definition
                                val statusColor = when (status.status) {
                                    StatusColor.GREEN -> Color(0xFF2E7D32)
                                    StatusColor.YELLOW -> Color(0xFFEF6C00)
                                    StatusColor.RED -> Color(0xFFC62828)
                                }
                                val statusBg = when (status.status) {
                                    StatusColor.GREEN -> Color(0xFFE8F5E9)
                                    StatusColor.YELLOW -> Color(0xFFFFF3E0)
                                    StatusColor.RED -> Color(0xFFFFEBEE)
                                }

                                Card(
                                    modifier = Modifier.fillMaxWidth(),
                                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.background),
                                    border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.05f))
                                ) {
                                    Row(
                                        modifier = Modifier.padding(12.dp),
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.SpaceBetween
                                    ) {
                                        Column(modifier = Modifier.weight(1.3f)) {
                                            Row(verticalAlignment = Alignment.CenterVertically) {
                                                Box(
                                                    modifier = Modifier
                                                        .size(8.dp)
                                                        .clip(CircleShape)
                                                        .background(statusColor)
                                                )
                                                Spacer(modifier = Modifier.width(6.dp))
                                                Text(
                                                    text = def.name,
                                                    style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                                    color = MaterialTheme.colorScheme.onSurface
                                                )
                                            }
                                            Text(
                                                text = def.description,
                                                style = MaterialTheme.typography.labelSmall,
                                                color = MaterialTheme.colorScheme.onSurfaceVariant,
                                                fontSize = 11.sp
                                            )
                                        }

                                        Column(
                                            modifier = Modifier.weight(1f),
                                            horizontalAlignment = Alignment.End
                                        ) {
                                            Text(
                                                text = "${status.intake.formatInt()} / ${def.rda.formatInt()} ${def.unit}",
                                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                                color = statusColor
                                            )
                                            Spacer(modifier = Modifier.height(4.dp))
                                            Box(
                                                modifier = Modifier
                                                    .clip(RoundedCornerShape(4.dp))
                                                    .background(statusBg)
                                                    .padding(horizontal = 6.dp, vertical = 2.dp)
                                            ) {
                                                Text(
                                                    text = if (def.isMaxLimit) {
                                                        if (status.intake > def.rda) "Over Limit" else "Within Limit"
                                                    } else {
                                                        "${status.percentage.toInt()}% met"
                                                    },
                                                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                                    color = statusColor,
                                                    fontSize = 10.sp
                                                )
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                Spacer(modifier = Modifier.height(12.dp))

                Button(
                    onClick = onDismiss,
                    modifier = Modifier.fillMaxWidth().testTag("close_day_report_button")
                ) {
                    Text("OK, Keep tracking")
                }
            }
        }
    }
}

fun getInsights(dailyNutrients: List<NutrientStatus>): List<DiagnosticInsight> {
    val list = mutableListOf<DiagnosticInsight>()
    for (status in dailyNutrients) {
        val def = status.definition
        val key = def.key
        val intake = status.intake
        val pct = status.percentage

        if (def.isMaxLimit) {
            if (intake > def.rda) {
                val insight = when (key) {
                    "sodium" -> DiagnosticInsight(
                        name = "Sodium (Excess)",
                        intakeString = "${intake.toInt()} mg",
                        rdaString = "${def.rda.toInt()} mg",
                        isExcess = true,
                        shortTermRisk = "Causes temporary water retention, peripheral bloating, elevated circulatory volume, and sudden blood pressure spikes.",
                        longTermRisk = "Chronic excess sodium intake promotes elevated arterial hypertension, blood vessel thickening, high kidney filtration strain, kidney stones, and chronic stroke risk."
                    )
                    "saturated_fat" -> DiagnosticInsight(
                        name = "Saturated Fat (Excess)",
                        intakeString = "${intake.formatInt()} g",
                        rdaString = "${def.rda.formatInt()} g",
                        isExcess = true,
                        shortTermRisk = "Slows general digestion and transiently spikes circulating triglycerides and lipids.",
                        longTermRisk = "Gradually elevates Atherosclerotic Cardiovascular Disease (ASCVD) risks, raises total blood LDL cholesterol levels, and drives arterial wall plaque buildup."
                    )
                    "sugars" -> DiagnosticInsight(
                        name = "Sugars (Excess)",
                        intakeString = "${intake.formatInt()} g",
                        rdaString = "${def.rda.formatInt()} g",
                        isExcess = true,
                        shortTermRisk = "Creates rapid system blood glucose spikes followed by steep crash-induced drowsiness and sugar cravings.",
                        longTermRisk = "Promotes chronic low-grade cellular inflammation, progressive insulin resistance (Diabetes Type 2 risk), and fat accumulation in the liver."
                    )
                    "trans_fat" -> DiagnosticInsight(
                        name = "Trans Fat (Excess)",
                        intakeString = "${intake.formatInt()} g",
                        rdaString = "${def.rda.formatInt()} g",
                        isExcess = true,
                        shortTermRisk = "Spikes immediate vascular inflammatory responses.",
                        longTermRisk = "Drastically alters cholesterol ratios (lowering beneficial HDL and raising hazardous LDL), significantly escalating overall long-term coronary heart disease hazards."
                    )
                    else -> null
                }
                if (insight != null) list.add(insight)
            }
        } else {
            if (pct < 50.0 && intake > 0.0) {
                val insight = when (key) {
                    "vitamin_a" -> DiagnosticInsight(
                        name = "Vitamin A (Deficient)",
                        intakeString = "${intake.toInt()} mcg",
                        rdaString = "${def.rda.toInt()} mcg",
                        isExcess = false,
                        shortTermRisk = "Dry, itchy eyes, dry skin, and mild impairment of night adaptation.",
                        longTermRisk = "May lead to xerophthalmia (cornea damage/scarring), progressive night blindness, and structural scaling of mucous membranes."
                    )
                    "vitamin_b12" -> DiagnosticInsight(
                        name = "Vitamin B12 (Deficient)",
                        intakeString = "${String.format(Locale.US, "%.1f", intake)} mcg",
                        rdaString = "${def.rda.formatInt()} mcg",
                        isExcess = false,
                        shortTermRisk = "Temporary cognitive slowness, mild fatigue, and potential pins-and-needles feelings.",
                        longTermRisk = "Shortage of Vitamin B12 over a long time causes neurological risks like irreversible myelination loss (nerve damage), pernicious anemia, memory deficits, and neurological decay."
                    )
                    "vitamin_c" -> DiagnosticInsight(
                        name = "Vitamin C (Deficient)",
                        intakeString = "${intake.toInt()} mg",
                        rdaString = "${def.rda.toInt()} mg",
                        isExcess = false,
                        shortTermRisk = "Easy bleeding/bruising, skin dryness, and lowered antioxidant protection.",
                        longTermRisk = "Severe deficit leads to Scurvy, characterized by bleeding gums, general tissue breakdown of collagen support, tooth loss, and severe painful joints."
                    )
                    "vitamin_d" -> DiagnosticInsight(
                        name = "Vitamin D (Deficient)",
                        intakeString = "${intake.formatInt()} mcg",
                        rdaString = "${def.rda.formatInt()} mcg",
                        isExcess = false,
                        shortTermRisk = "Lower muscle tone, mild fatigue, and poorer immune defense against cold/viruses.",
                        longTermRisk = "Progressive bone softening (osteomalacia), osteoporosis (severe skeletal porousness), and rickets in growing children due to failed calcium integration."
                    )
                    "iron" -> DiagnosticInsight(
                        name = "Iron (Deficient)",
                        intakeString = "${intake.formatInt()} mg",
                        rdaString = "${def.rda.formatInt()} mg",
                        isExcess = false,
                        shortTermRisk = "Poor body heat regulation (permanently cold extremities), shortness of breath, and tiredness.",
                        longTermRisk = "Chronic microcytic Iron Deficiency Anemia, severely starving skeletal muscles and organs of necessary oxygen delivery."
                    )
                    "calcium" -> DiagnosticInsight(
                        name = "Calcium (Deficient)",
                        intakeString = "${intake.toInt()} mg",
                        rdaString = "${def.rda.toInt()} mg",
                        isExcess = false,
                        shortTermRisk = "Muscle twitches, finger tremors, and painful cramps.",
                        longTermRisk = "Chronic extraction of minerals from bones to stabilize blood chemistry, triggering severe osteopenia, teeth rotting, and osteoporosis."
                    )
                    "potassium" -> DiagnosticInsight(
                        name = "Potassium (Deficient)",
                        intakeString = "${intake.toInt()} mg",
                        rdaString = "${def.rda.toInt()} mg",
                        isExcess = false,
                        shortTermRisk = "Early physical exhaustion, cramp episodes, and muscle sluggishness.",
                        longTermRisk = "Chronic cardiac rhythm vulnerabilities, elevated arterial blood pressure, and a high frequency of kidney stone formation."
                    )
                    "fiber" -> DiagnosticInsight(
                        name = "Dietary Fiber (Deficient)",
                        intakeString = "${intake.formatInt()} g",
                        rdaString = "${def.rda.formatInt()} g",
                        isExcess = false,
                        shortTermRisk = "Constipation, sluggish gut motility, and rapid post-prandial blood sugar spikes.",
                        longTermRisk = "Long-term low fiber elevates vulnerability to colon disorders, hemorrhoidal distress, and raises circulating plasma cholesterol."
                    )
                    "water" -> DiagnosticInsight(
                        name = "Water/Hydration (Deficient)",
                        intakeString = "${intake.toInt()} ml",
                        rdaString = "${def.rda.toInt()} ml",
                        isExcess = false,
                        shortTermRisk = "Headaches, thirst, high core temp during exercise, and dry mouth.",
                        longTermRisk = "Worsens renal kidney stone hazard, impairs optimal glomerular filtration, and causes chronic skin dehydration."
                    )
                    else -> null
                }
                if (insight != null) list.add(insight)
            } else if (pct > 250.0 && !def.isMaxLimit) {
                if (key == "vitamin_a") {
                    list.add(
                        DiagnosticInsight(
                            name = "Vitamin A (Excessive)",
                            intakeString = "${intake.toInt()} mcg",
                            rdaString = "${def.rda.toInt()} mcg",
                            isExcess = true,
                            shortTermRisk = "Dizziness and system head pressure at high acute doses.",
                            longTermRisk = "⚠️ Vitamin A excess over a long time is stored in the liver. It cannot be easily excreted and can cause chronic liver damage, bone pain, hair loss, and visual changes."
                        )
                    )
                } else if (key == "vitamin_d") {
                    list.add(
                        DiagnosticInsight(
                            name = "Vitamin D (Excessive)",
                            intakeString = "${intake.formatInt()} mcg",
                            rdaString = "${def.rda.formatInt()} mcg",
                            isExcess = true,
                            shortTermRisk = "Could cause temporary nausea or mild loss of appetite.",
                            longTermRisk = "⚠️ Chronic high levels can cause hypercalcemia, which is excessive calcium loading in the blood, potentially calcium-depositing in the kidneys or cardiovascular arteries."
                        )
                    )
                }
            }
        }
    }
    return list
}

private fun Float.safeCoerce(minimumValue: Float, maximumValue: Float): Float {
    if (this.isNaN()) return minimumValue
    return this.coerceIn(minimumValue, maximumValue)
}

private fun Double.safeCoerce(minimumValue: Double, maximumValue: Double): Double {
    if (this.isNaN()) return minimumValue
    return this.coerceIn(minimumValue, maximumValue)
}

@Composable
fun ImportExportSection(viewModel: NutritionViewModel, modifier: Modifier = Modifier) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val coroutineScope = rememberCoroutineScope()
    var clipboardText by remember { mutableStateOf("") }
    var pasteInputVisible by remember { mutableStateOf(false) }

    var pendingExportJson by remember { mutableStateOf<String?>(null) }

    // SAF CreateDocument Launcher for Export
    val exportLauncher = rememberLauncherForActivityResult(
        contract = SafeCreateDocument("application/json")
    ) { uri ->
        if (uri != null) {
            val jsonToWrite = pendingExportJson
            if (jsonToWrite != null) {
                coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                    try {
                        context.contentResolver.openOutputStream(uri)?.use { outputStream ->
                            outputStream.write(jsonToWrite.toByteArray(Charsets.UTF_8))
                        }
                    } catch (e: Exception) {
                        e.printStackTrace()
                    } finally {
                        pendingExportJson = null
                    }
                }
            } else {
                // fallback
                viewModel.exportLogs { jsonString ->
                    coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                        try {
                            context.contentResolver.openOutputStream(uri)?.use { outputStream ->
                                outputStream.write(jsonString.toByteArray(Charsets.UTF_8))
                            }
                        } catch (e: Exception) {
                            e.printStackTrace()
                        }
                    }
                }
            }
        }
    }

    // SAF OpenDocument Launcher for Import
    val importLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.OpenDocument()
    ) { uri ->
        if (uri != null) {
            coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                try {
                    context.contentResolver.openInputStream(uri)?.use { inputStream ->
                        val jsonString = inputStream.bufferedReader().use { it.readText() }
                        viewModel.importLogs(jsonString) { _, _ -> }
                    }
                } catch (e: Exception) {
                    e.printStackTrace()
                }
            }
        }
    }

    Card(
        modifier = modifier
            .fillMaxWidth()
            .testTag("import_export_section_card"),
        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.25f)),
        border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f))
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                Icon(
                    imageVector = Icons.Default.Share,
                    contentDescription = "Data Transfer",
                    tint = MaterialTheme.colorScheme.primary,
                    modifier = Modifier.size(20.dp)
                )
                Text(
                    text = "Backup, Import & Export Logs",
                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.onSurface
                )
            }
            Spacer(modifier = Modifier.height(6.dp))
            Text(
                text = "Back up or migrate your entire historical journals securely. Choose between complete JSON files or portable clipboard text backups.",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )

            Spacer(modifier = Modifier.height(16.dp))

            // Section: File Backups
            Text(
                text = "Backup Files (JSON)",
                style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                color = MaterialTheme.colorScheme.primary
            )
            Spacer(modifier = Modifier.height(8.dp))
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                Button(
                    onClick = {
                        coroutineScope.launch {
                            try {
                                pendingExportJson = viewModel.getExportString()
                                exportLauncher.launch("nutriscribe-journal-backup.json")
                            } catch (e: ActivityNotFoundException) {
                                Toast.makeText(context, "System File Picker not available. Please use 'Copy Code' under Portable Clipboard Backups instead.", Toast.LENGTH_LONG).show()
                            } catch (e: Exception) {
                                Toast.makeText(context, "Could not open File Picker: ${e.localizedMessage}", Toast.LENGTH_SHORT).show()
                            }
                        }
                    },
                    modifier = Modifier.weight(1f).testTag("button_export_file"),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = MaterialTheme.colorScheme.primaryContainer,
                        contentColor = MaterialTheme.colorScheme.onPrimaryContainer
                    )
                ) {
                    Text("Export file", style = MaterialTheme.typography.labelSmall)
                }
                OutlinedButton(
                    onClick = {
                        try {
                            importLauncher.launch(arrayOf("application/json", "text/plain", "*/*"))
                        } catch (e: ActivityNotFoundException) {
                            Toast.makeText(context, "System File Picker not available. Please use 'Paste Code' under Portable Clipboard Backups instead.", Toast.LENGTH_LONG).show()
                        } catch (e: Exception) {
                            Toast.makeText(context, "Could not open File Picker: ${e.localizedMessage}", Toast.LENGTH_SHORT).show()
                        }
                    },
                    modifier = Modifier.weight(1f).testTag("button_import_file"),
                    border = BorderStroke(1.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.5f))
                ) {
                    Text("Import file", style = MaterialTheme.typography.labelSmall)
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            // Section: Copy / Paste Tab Actions
            Text(
                text = "Portable Clipboard Backups",
                style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                color = MaterialTheme.colorScheme.primary
            )
            Spacer(modifier = Modifier.height(8.dp))
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                Button(
                    onClick = {
                        viewModel.exportLogs { jsonString ->
                            try {
                                val clipboard = context.getSystemService(android.content.Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                val clip = android.content.ClipData.newPlainText("NutriScribe Log Journal Backup", jsonString)
                                clipboard.setPrimaryClip(clip)
                                Toast.makeText(context, "Journal backup copied to clipboard!", Toast.LENGTH_SHORT).show()
                            } catch (e: Exception) {
                                Toast.makeText(context, "Cloud / System Clipboard error: ${e.localizedMessage}", Toast.LENGTH_LONG).show()
                            }
                        }
                    },
                    modifier = Modifier.weight(1f).testTag("button_export_clipboard"),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = MaterialTheme.colorScheme.secondaryContainer,
                        contentColor = MaterialTheme.colorScheme.onSecondaryContainer
                    )
                ) {
                    Text("Copy Code", style = MaterialTheme.typography.labelSmall)
                }
                OutlinedButton(
                    onClick = { pasteInputVisible = !pasteInputVisible },
                    modifier = Modifier.weight(1f).testTag("button_toggle_paste"),
                    border = BorderStroke(1.dp, MaterialTheme.colorScheme.secondary.copy(alpha = 0.5f))
                ) {
                    Text(if (pasteInputVisible) "Close Paste" else "Paste Code", style = MaterialTheme.typography.labelSmall)
                }
            }

            if (pasteInputVisible) {
                Spacer(modifier = Modifier.height(12.dp))
                OutlinedTextField(
                    value = clipboardText,
                    onValueChange = { clipboardText = it },
                    label = { Text("Paste exported JSON journal logs here") },
                    textStyle = MaterialTheme.typography.bodySmall,
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(110.dp)
                        .testTag("paste_logs_input_field"),
                    maxLines = 5,
                    placeholder = { Text("[ { \"date\": \"2026-05-26\", ... } ]") }
                )
                Spacer(modifier = Modifier.height(8.dp))
                Button(
                    onClick = {
                        if (clipboardText.isNotBlank()) {
                            viewModel.importLogs(clipboardText) { success, message ->
                                if (success) {
                                    clipboardText = ""
                                    pasteInputVisible = false
                                    Toast.makeText(context, "Journal logs imported successfully!", Toast.LENGTH_SHORT).show()
                                } else {
                                    Toast.makeText(context, "Import failed: $message", Toast.LENGTH_LONG).show()
                                }
                            }
                        }
                    },
                    modifier = Modifier.fillMaxWidth().testTag("button_submit_pasted_logs"),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = MaterialTheme.colorScheme.primary
                    )
                ) {
                    Text("Parse & Restore Logs List", style = MaterialTheme.typography.labelMedium)
                }
            }
        }
    }
}

@OptIn(ExperimentalLayoutApi::class, ExperimentalMaterial3Api::class)
@Composable
fun ObservationsTab(viewModel: NutritionViewModel) {
    val context = androidx.compose.ui.platform.LocalContext.current
    val selectedKey by viewModel.selectedObservationNutrientKey.collectAsState()
    val limitDays by viewModel.observationDaysLimit.collectAsState()
    val observations by viewModel.nutrientObservations.collectAsState()
    val customRdaOverrides by viewModel.customRdaOverrides.collectAsState()

    val currentDef = remember(selectedKey) { Nutrients.getByKey(selectedKey) } ?: Nutrients.DEFINITIONS.first()
    val expectedVal = customRdaOverrides[selectedKey] ?: currentDef.rda

    // Compute running totals for the given period
    val totalExpected = remember(observations) { observations.sumOf { it.expected } }
    val totalAchieved = remember(observations) { observations.sumOf { it.achieved } }
    val totalDiff = remember(observations) { observations.sumOf { it.difference } }
    val fastingDays = remember(observations) { observations.count { it.isFasting } }
    val feastingDays = remember(observations) { observations.count { !it.isFasting } }

    var dropdownExpanded by remember { mutableStateOf(false) }

    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp)
            .testTag("observations_tab_container"),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // 1. Header & Title Card
        item {
            Card(
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.4f)
                ),
                shape = RoundedCornerShape(16.dp)
            ) {
                Column(
                    modifier = Modifier.padding(16.dp)
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Icon(
                            imageVector = Icons.Default.CheckCircle,
                            contentDescription = "Observations Icon",
                            tint = MaterialTheme.colorScheme.primary,
                            modifier = Modifier.size(28.dp)
                        )
                        Spacer(modifier = Modifier.width(8.dp))
                        Text(
                            text = "Nutrient Observation Log",
                            style = MaterialTheme.typography.titleLarge.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.primary
                        )
                    }
                    Spacer(modifier = Modifier.height(6.dp))
                    Text(
                        text = "Tracks expected vs achieved intakes over a configurable duration. Labeled as Fasting if below RDA and Feasting if reached or exceeded.",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }
        }

        // 2. Configuration & Selectors Panel
        item {
            Card(
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.surface
                ),
                border = BorderStroke(1.dp, MaterialTheme.colorScheme.outlineVariant),
                shape = RoundedCornerShape(12.dp)
            ) {
                Column(
                    modifier = Modifier.padding(16.dp),
                    verticalArrangement = Arrangement.spacedBy(16.dp)
                ) {
                    Text(
                        text = "Observation Configuration",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.onSurface
                    )

                    // EXPOSED DROPDOWN MENU FOR NUTRIENTS GROUP SELECTION
                    Column {
                        Text(
                            text = "Select Nutrient to Analyze",
                            style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.secondary,
                            modifier = Modifier.padding(bottom = 6.dp)
                        )
                        ExposedDropdownMenuBox(
                            expanded = dropdownExpanded,
                            onExpandedChange = { dropdownExpanded = it },
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            OutlinedTextField(
                                value = "${currentDef.name} (${currentDef.unit}) - Target: ${expectedVal.toInt()} ${currentDef.unit}",
                                onValueChange = {},
                                readOnly = true,
                                trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(expanded = dropdownExpanded) },
                                colors = ExposedDropdownMenuDefaults.outlinedTextFieldColors(),
                                modifier = Modifier
                                    .menuAnchor(MenuAnchorType.PrimaryNotEditable, true)
                                    .fillMaxWidth()
                                    .testTag("nutrient_select_textfield")
                            )
                            ExposedDropdownMenu(
                                expanded = dropdownExpanded,
                                onDismissRequest = { dropdownExpanded = false }
                            ) {
                                Nutrients.DEFINITIONS.forEach { def ->
                                    val rda = customRdaOverrides[def.key] ?: def.rda
                                    DropdownMenuItem(
                                        text = { Text("${def.name} (${def.unit}) - Target: ${rda.toInt()}") },
                                        onClick = {
                                            viewModel.selectObservationNutrient(def.key)
                                            dropdownExpanded = false
                                        },
                                        modifier = Modifier.testTag("dropdown_item_${def.key}")
                                    )
                                }
                            }
                        }
                    }

                    // PERIOD DAYS LIMIT CONTROLLER
                    Column {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            Column {
                                Text(
                                    text = "Observation Period History Limit",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.secondary
                                )
                                Text(
                                    text = "Set limit for running total tracks",
                                    style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }
                            Surface(
                                color = MaterialTheme.colorScheme.primaryContainer,
                                shape = RoundedCornerShape(8.dp)
                            ) {
                                Text(
                                    text = "$limitDays Days",
                                    style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onPrimaryContainer,
                                    modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp)
                                )
                            }
                        }
                        
                        Spacer(modifier = Modifier.height(8.dp))
                        
                        // Slider control for exact adjustments (1 to 90 days, defaulting to 30)
                        Slider(
                            value = limitDays.toFloat(),
                            onValueChange = { viewModel.updateObservationDaysLimit(it.toInt()) },
                            valueRange = 1f..90f,
                            steps = 89,
                            modifier = Modifier
                                .fillMaxWidth()
                                .testTag("observation_limit_slider")
                        )

                        // Stepper presets to quickly jump values
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            listOf(7, 14, 30, 45, 60, 90).forEach { days ->
                                val isSelected = limitDays == days
                                OutlinedButton(
                                    onClick = { viewModel.updateObservationDaysLimit(days) },
                                    modifier = Modifier
                                        .weight(1f)
                                        .height(36.dp)
                                        .testTag("stepper_preset_$days"),
                                    contentPadding = PaddingValues(0.dp),
                                    colors = ButtonDefaults.outlinedButtonColors(
                                        containerColor = if (isSelected) MaterialTheme.colorScheme.secondaryContainer else Color.Transparent,
                                        contentColor = if (isSelected) MaterialTheme.colorScheme.onSecondaryContainer else MaterialTheme.colorScheme.primary
                                    ),
                                    border = BorderStroke(
                                        width = 1.dp,
                                        color = if (isSelected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.outline.copy(alpha = 0.4f)
                                    )
                                ) {
                                    Text(
                                        text = "${days}d",
                                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold)
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }

        // 3. Overall Cumulative Totals Card (Running Period Totals)
        item {
            Card(
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)
                ),
                shape = RoundedCornerShape(12.dp),
                border = BorderStroke(1.dp, MaterialTheme.colorScheme.outlineVariant)
            ) {
                Column(
                    modifier = Modifier.padding(16.dp),
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    Text(
                        text = "Cumulative Period Running Totals",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )

                    // 3-way Grid of stats
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        // Expected Total
                        Card(
                            modifier = Modifier.weight(1f),
                            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface)
                        ) {
                            Column(
                                modifier = Modifier.padding(10.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Text("Total Expected", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                                Spacer(modifier = Modifier.height(4.dp))
                                Text(
                                    text = "${String.format(Locale.US, "%.1f", totalExpected)} ${currentDef.unit}",
                                    style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.primary,
                                    textAlign = TextAlign.Center
                                )
                            }
                        }

                        // Achieved Total
                        Card(
                            modifier = Modifier.weight(1f),
                            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface)
                        ) {
                            Column(
                                modifier = Modifier.padding(10.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Text("Total Achieved", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                                Spacer(modifier = Modifier.height(4.dp))
                                Text(
                                    text = "${String.format(Locale.US, "%.1f", totalAchieved)} ${currentDef.unit}",
                                    style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.primary,
                                    textAlign = TextAlign.Center
                                )
                            }
                        }

                        // Net Difference Total
                        Card(
                            modifier = Modifier.weight(1f),
                            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface)
                        ) {
                            Column(
                                modifier = Modifier.padding(10.dp),
                                horizontalAlignment = Alignment.CenterHorizontally
                            ) {
                                Text("Net Total Diff (D)", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                                Spacer(modifier = Modifier.height(4.dp))
                                val sign = if (totalDiff >= 0) "+" else ""
                                Text(
                                    text = "$sign${String.format(Locale.US, "%.1f", totalDiff)} ${currentDef.unit}",
                                    style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                                    color = if (totalDiff >= 0) MaterialTheme.colorScheme.error else MaterialTheme.colorScheme.primary,
                                    textAlign = TextAlign.Center
                                )
                            }
                        }
                    }

                    // Fasting vs Feasting count summaries
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        // Fasting days counter
                        Row(
                            modifier = Modifier
                                .weight(1f)
                                .clip(RoundedCornerShape(8.dp))
                                .background(MaterialTheme.colorScheme.errorContainer.copy(alpha = 0.4f))
                                .padding(8.dp),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.Center
                        ) {
                            Box(
                                modifier = Modifier
                                    .size(10.dp)
                                    .clip(CircleShape)
                                    .background(MaterialTheme.colorScheme.error)
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text(
                                text = "Fasting: $fastingDays Days",
                                style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.onErrorContainer
                            )
                        }

                        // Feasting days counter
                        Row(
                            modifier = Modifier
                                .weight(1f)
                                .clip(RoundedCornerShape(8.dp))
                                .background(Color(0xFFE0F2F1))
                                .padding(8.dp),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.Center
                        ) {
                            Box(
                                modifier = Modifier
                                    .size(10.dp)
                                    .clip(CircleShape)
                                    .background(Color(0xFF00796B))
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text(
                                text = "Feasting: $feastingDays Days",
                                style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                                color = Color(0xFF004D40)
                            )
                        }
                    }
                }
            }
        }

        // 4. Observation Table Daily Header
        item {
            Column {
                Text(
                    text = "Daily Tracker Timeline",
                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.onSurface,
                    modifier = Modifier.padding(bottom = 8.dp)
                )

                // Standard desktop/tablet table headers styled as a beautiful sticky header equivalent
                Surface(
                    color = MaterialTheme.colorScheme.primary,
                    shape = RoundedCornerShape(topStart = 8.dp, topEnd = 8.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 10.dp, horizontal = 12.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "DATE",
                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onPrimary,
                            modifier = Modifier.weight(1.8f)
                        )
                        Text(
                            text = "ACHIEVED",
                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onPrimary,
                            modifier = Modifier.weight(1.2f),
                            textAlign = TextAlign.End
                        )
                        Text(
                            text = "DIFF (D)",
                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onPrimary,
                            modifier = Modifier.weight(1.3f),
                            textAlign = TextAlign.End
                        )
                        Text(
                            text = "STATUS",
                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onPrimary,
                            modifier = Modifier.weight(1.4f),
                            textAlign = TextAlign.Center
                        )
                    }
                }
            }
        }

        // 5. Daily Observations List Rows
        if (observations.isEmpty()) {
            item {
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 8.dp),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.1f))
                ) {
                    Column(
                        modifier = Modifier.padding(32.dp),
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.Center
                    ) {
                        Icon(
                            imageVector = Icons.Default.Info,
                            contentDescription = "No logs",
                            tint = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.5f),
                            modifier = Modifier.size(48.dp)
                        )
                        Spacer(modifier = Modifier.height(10.dp))
                        Text(
                            "No log data within this observation range. Log some food to run metrics!",
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant,
                            textAlign = TextAlign.Center
                        )
                    }
                }
            }
        } else {
            items(observations) { obs ->
                // Row card containing the metrics for each day
                Surface(
                    color = MaterialTheme.colorScheme.surface,
                    modifier = Modifier
                        .fillMaxWidth()
                        .testTag("observation_row_${obs.dateString}"),
                    border = BorderStroke(1.dp, MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.5f))
                ) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 12.dp, horizontal = 12.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        // Date column
                        Column(modifier = Modifier.weight(1.8f)) {
                            Text(
                                text = obs.displayDate,
                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.onSurface
                            )
                            Text(
                                text = "Running T.: ${String.format(Locale.US, "%.1f", obs.runningTotalDiff)}",
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.primary
                            )
                        }

                        // Achieved / Expected column
                        Column(
                            modifier = Modifier.weight(1.2f),
                            horizontalAlignment = Alignment.End
                        ) {
                            Text(
                                text = "${obs.achieved.toInt()}",
                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.onSurface
                            )
                            Text(
                                text = "/ ${obs.expected.toInt()}",
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }

                        // Target Difference Column
                        val sign = if (obs.difference >= 0) "+" else ""
                        Column(
                            modifier = Modifier.weight(1.3f),
                            horizontalAlignment = Alignment.End
                        ) {
                            Text(
                                text = "$sign${String.format(Locale.US, "%.1f", obs.difference)}",
                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                color = if (obs.difference >= 0) MaterialTheme.colorScheme.error else Color(0xFF00796B)
                            )
                            Text(
                                text = currentDef.unit,
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }

                        // Status Badge Pill
                        Box(
                            modifier = Modifier
                                .weight(1.4f)
                                .padding(start = 6.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            val badgeBg = if (obs.isFasting) MaterialTheme.colorScheme.errorContainer else Color(0xFFE0F2F1)
                            val badgeTextColor = if (obs.isFasting) MaterialTheme.colorScheme.onErrorContainer else Color(0xFF004D40)
                            val statusLabelTxt = if (obs.isFasting) "Fasting" else "Feasting"

                            Surface(
                                color = badgeBg,
                                shape = RoundedCornerShape(12.dp),
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .testTag("status_badge_${obs.dateString}")
                            ) {
                                Text(
                                    text = statusLabelTxt,
                                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                    color = badgeTextColor,
                                    modifier = Modifier.padding(vertical = 4.dp),
                                    textAlign = TextAlign.Center
                                )
                            }
                        }
                    }
                }
            }
        }
        
        // Added some padding spacer at bottom of table
        item {
            Spacer(modifier = Modifier.height(30.dp))
        }
    }
}

@Composable
fun SupplementsTab(viewModel: NutritionViewModel) {
    val supplements by viewModel.allSupplements.collectAsState()
    val currentDateEntries by viewModel.currentDateEntries.collectAsState()
    var showAddDialog by remember { mutableStateOf(false) }
    var showBackupImportDialog by remember { mutableStateOf(false) }
    val context = androidx.compose.ui.platform.LocalContext.current
    val coroutineScope = rememberCoroutineScope()

    var initialDialogName by remember { mutableStateOf("") }
    var initialDialogDosage by remember { mutableStateOf("") }
    var initialDialogNotes by remember { mutableStateOf("") }
    var initialDialogNutrients by remember { mutableStateOf<Map<String, Double>>(emptyMap()) }

    var pendingExportJson by remember { mutableStateOf<String?>(null) }

    val exportLauncher = rememberLauncherForActivityResult(
        contract = SafeCreateDocument("application/json")
    ) { uri ->
        if (uri != null && pendingExportJson != null) {
            coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                try {
                    context.contentResolver.openOutputStream(uri)?.use { outputStream ->
                        outputStream.write(pendingExportJson!!.toByteArray(Charsets.UTF_8))
                    }
                } catch (e: Exception) {
                    e.printStackTrace()
                } finally {
                    pendingExportJson = null
                }
            }
        }
    }

    val importLauncher = rememberLauncherForActivityResult(
        contract = androidx.activity.result.contract.ActivityResultContracts.OpenDocument()
    ) { uri ->
        if (uri != null) {
            coroutineScope.launch(kotlinx.coroutines.Dispatchers.IO) {
                try {
                    context.contentResolver.openInputStream(uri)?.use { inputStream ->
                        val jsonString = inputStream.bufferedReader().use { it.readText() }
                        viewModel.importSupplements(jsonString) { success, msg ->
                            coroutineScope.launch(kotlinx.coroutines.Dispatchers.Main) {
                                if (success) {
                                    android.widget.Toast.makeText(context, msg, android.widget.Toast.LENGTH_SHORT).show()
                                    showBackupImportDialog = false
                                } else {
                                    android.widget.Toast.makeText(context, msg, android.widget.Toast.LENGTH_LONG).show()
                                }
                            }
                        }
                    }
                } catch (e: Exception) {
                    e.printStackTrace()
                }
            }
        }
    }

    Box(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp)
            .testTag("supplements_tab_container")
    ) {
        LazyColumn(
            modifier = Modifier.fillMaxSize(),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            item {
                // Header card
                Card(
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.4f)
                    ),
                    shape = RoundedCornerShape(16.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text(
                            text = "Daily Supplements Scheduler",
                            style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onPrimaryContainer
                        )
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            text = "Register active vitamins, minerals, or other clinical supplements. When active, they automatically sync and pre-fill your nutrition calendar targets on their scheduled days.",
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            }

            item {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        text = "Your Supplement Regiment",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    
                    Button(
                        onClick = { viewModel.triggerAutoLog() },
                        colors = ButtonDefaults.buttonColors(
                            containerColor = MaterialTheme.colorScheme.secondaryContainer,
                            contentColor = MaterialTheme.colorScheme.onSecondaryContainer
                        ),
                        modifier = Modifier.testTag("sync_supplements_button")
                    ) {
                        Icon(
                            imageVector = Icons.Default.CheckCircle,
                            contentDescription = "Sync Now",
                            modifier = Modifier.size(16.dp)
                        )
                        Spacer(modifier = Modifier.width(6.dp))
                        Text("Sync Today", style = MaterialTheme.typography.labelMedium)
                    }
                }
            }

            if (supplements.isEmpty()) {
                item {
                    Card(
                        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Column(
                            modifier = Modifier.padding(24.dp),
                            horizontalAlignment = Alignment.CenterHorizontally
                        ) {
                            Icon(
                                imageVector = Icons.Default.Info,
                                contentDescription = null,
                                modifier = Modifier.size(48.dp),
                                tint = MaterialTheme.colorScheme.primary.copy(alpha = 0.6f)
                            )
                            Spacer(modifier = Modifier.height(12.dp))
                            Text(
                                text = "No Supplements Registered Yet",
                                style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold)
                            )
                            Spacer(modifier = Modifier.height(4.dp))
                            Text(
                                text = "Click the 'Add Supplement' button below to configure your first daily dosage guidelines.",
                                style = MaterialTheme.typography.bodyMedium,
                                textAlign = TextAlign.Center,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }
                    }
                }
            } else {
                items(supplements) { supplement ->
                    Card(
                        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                        elevation = CardDefaults.cardElevation(defaultElevation = 2.dp),
                        shape = RoundedCornerShape(12.dp),
                        modifier = Modifier.fillMaxWidth().testTag("supplement_card_${supplement.id}")
                    ) {
                        Row(
                            modifier = Modifier.padding(16.dp),
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            // Checkbox/Toggle to log/unlog supplement
                            val isTaken = currentDateEntries.any { 
                                it.mealType == "Supplement" && 
                                (it.foodName.equals(supplement.name, ignoreCase = true) || 
                                 it.foodName.startsWith(supplement.name, ignoreCase = true))
                            }
                            
                            IconButton(
                                onClick = {
                                    if (isTaken) {
                                        viewModel.unlogSupplementManual(supplement)
                                    } else {
                                        viewModel.logSupplementManual(supplement)
                                    }
                                },
                                modifier = Modifier
                                    .size(40.dp)
                                    .testTag("toggle_supplement_logged_${supplement.id}")
                            ) {
                                Icon(
                                    imageVector = Icons.Default.CheckCircle,
                                    contentDescription = if (isTaken) "Logged" else "Not Logged",
                                    tint = if (isTaken) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface.copy(alpha = 0.2f),
                                    modifier = Modifier.size(28.dp)
                                )
                            }

                            Spacer(modifier = Modifier.width(12.dp))

                            Column(modifier = Modifier.weight(1.0f)) {
                                Text(
                                    text = supplement.name,
                                    style = MaterialTheme.typography.bodyLarge.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )
                                Spacer(modifier = Modifier.height(2.dp))
                                Row(
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Text(
                                        text = supplement.dosage,
                                        style = MaterialTheme.typography.bodyMedium,
                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                    Spacer(modifier = Modifier.width(8.dp))
                                    Surface(
                                        color = MaterialTheme.colorScheme.secondaryContainer,
                                        shape = RoundedCornerShape(6.dp)
                                    ) {
                                        Text(
                                            text = supplement.frequency,
                                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                            color = MaterialTheme.colorScheme.onSecondaryContainer,
                                            modifier = Modifier.padding(horizontal = 6.dp, vertical = 2.dp)
                                        )
                                    }
                                }

                                if (supplement.frequency == "Weekly" && supplement.daysOfWeek.isNotEmpty()) {
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Text(
                                        text = "On days: ${supplement.daysOfWeek}",
                                        style = MaterialTheme.typography.labelSmall,
                                        color = MaterialTheme.colorScheme.primary
                                    )
                                }

                                if (supplement.notes.isNotEmpty()) {
                                    Spacer(modifier = Modifier.height(2.dp))
                                    Text(
                                        text = "Note: ${supplement.notes}",
                                        style = MaterialTheme.typography.bodySmall,
                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                            }

                            IconButton(
                                onClick = { viewModel.deleteSupplement(supplement) },
                                modifier = Modifier.testTag("delete_supplement_${supplement.id}")
                            ) {
                                Icon(
                                    imageVector = Icons.Default.Delete,
                                    contentDescription = "Delete",
                                    tint = MaterialTheme.colorScheme.error
                                )
                            }
                        }
                    }
                }
            }

            item {
                var showSupplementScanner by remember { mutableStateOf(false) }

                if (showSupplementScanner) {
                    BarcodeQRScannerScreen(
                        onDismiss = { showSupplementScanner = false },
                        onBarcodeScanned = { barcode ->
                            val resolvedProduct = viewModel.repository.getProductByBarcode(barcode)
                            if (resolvedProduct != null) {
                                initialDialogName = resolvedProduct.name
                                initialDialogDosage = resolvedProduct.dosage
                                initialDialogNotes = "Scanned: $barcode"
                                initialDialogNutrients = resolvedProduct.nutrients
                            } else {
                                val isNumeric = barcode.trim().all { it.isDigit() }
                                initialDialogName = if (isNumeric) "Supplement ($barcode)" else barcode
                                initialDialogDosage = "1 capsule"
                                initialDialogNotes = "Scanned barcode: $barcode"
                                initialDialogNutrients = if (isNumeric) emptyMap() else viewModel.repository.estimateSupplementNutrients(barcode, "1 capsule")
                            }
                            showSupplementScanner = false
                            showAddDialog = true
                        },
                        onOcrScanned = { trackedNutrients ->
                            initialDialogName = "OCR Scanned Supplement Facts"
                            initialDialogDosage = "1 capsule"
                            initialDialogNotes = "OCR Scanned nutritional profile"
                            initialDialogNutrients = trackedNutrients
                            showSupplementScanner = false
                            showAddDialog = true
                        }
                    )
                }

                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 8.dp),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Button(
                        onClick = {
                            initialDialogName = ""
                            initialDialogDosage = ""
                            initialDialogNotes = ""
                            initialDialogNutrients = emptyMap()
                            showAddDialog = true
                        },
                        modifier = Modifier
                            .weight(1f)
                            .testTag("add_supplement_trigger_button"),
                        shape = RoundedCornerShape(12.dp)
                    ) {
                        Icon(imageVector = Icons.Default.Add, contentDescription = "Add")
                        Spacer(modifier = Modifier.width(6.dp))
                        Text("Add Manual")
                    }

                    Button(
                        onClick = { showSupplementScanner = true },
                        colors = ButtonDefaults.buttonColors(
                            containerColor = MaterialTheme.colorScheme.tertiaryContainer,
                            contentColor = MaterialTheme.colorScheme.onTertiaryContainer
                        ),
                        modifier = Modifier
                            .weight(1.1f)
                            .testTag("scan_supplement_trigger_button"),
                        shape = RoundedCornerShape(12.dp)
                    ) {
                        Icon(imageVector = Icons.Default.QrCode, contentDescription = "Scan")
                        Spacer(modifier = Modifier.width(6.dp))
                        Text("Scan QR / Barcode")
                    }
                }

                // Backup & Import Row
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(bottom = 8.dp),
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    OutlinedButton(
                        onClick = { showBackupImportDialog = true },
                        modifier = Modifier
                            .fillMaxWidth()
                            .testTag("backup_import_supplements_button"),
                        colors = ButtonDefaults.outlinedButtonColors(
                            contentColor = MaterialTheme.colorScheme.primary
                        ),
                        shape = RoundedCornerShape(12.dp),
                        border = BorderStroke(1.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.4f))
                    ) {
                        Icon(imageVector = Icons.Default.Share, contentDescription = "JSON Backup/Import")
                        Spacer(modifier = Modifier.width(6.dp))
                        Text("Backup & Import JSON")
                    }
                }
            }

            item {
                Spacer(modifier = Modifier.height(40.dp))
            }
        }

        if (showAddDialog) {
            AddSupplementDialog(
                initialName = initialDialogName,
                initialDosage = initialDialogDosage,
                initialNotes = initialDialogNotes,
                initialNutrients = initialDialogNutrients,
                onDismiss = { showAddDialog = false },
                onConfirm = { name, dosage, freq, days, time, notes, nutrients ->
                    viewModel.insertSupplement(name, dosage, freq, days, time, notes, nutrients)
                    showAddDialog = false
                }
            )
        }

        if (showBackupImportDialog) {
            var pasteInputVisible by remember { mutableStateOf(false) }
            var clipboardText by remember { mutableStateOf("") }

            AlertDialog(
                onDismissRequest = { showBackupImportDialog = false },
                title = {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Icon(imageVector = Icons.Default.Share, contentDescription = null, tint = MaterialTheme.colorScheme.primary)
                        Text("Supplement Backup / Import")
                    }
                },
                text = {
                    Column(
                        modifier = Modifier.fillMaxWidth(),
                        verticalArrangement = Arrangement.spacedBy(12.dp)
                    ) {
                        Text(
                            text = "Import or export your supplement schedules seamlessly as standard JSON files or copied text.",
                            style = MaterialTheme.typography.bodyMedium
                        )

                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Button(
                                onClick = {
                                    coroutineScope.launch {
                                        try {
                                            pendingExportJson = viewModel.getExportSupplementsString()
                                            exportLauncher.launch("nutriscribe-supplements-backup.json")
                                        } catch (e: Exception) {
                                            android.widget.Toast.makeText(context, "Export picker failed: ${e.localizedMessage}", android.widget.Toast.LENGTH_SHORT).show()
                                        }
                                    }
                                },
                                modifier = Modifier.weight(1f),
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = MaterialTheme.colorScheme.primaryContainer,
                                    contentColor = MaterialTheme.colorScheme.onPrimaryContainer
                                )
                            ) {
                                Text("Export File", style = MaterialTheme.typography.labelSmall)
                            }

                            OutlinedButton(
                                onClick = {
                                    try {
                                        importLauncher.launch(arrayOf("application/json", "text/plain", "*/*"))
                                    } catch (e: Exception) {
                                        android.widget.Toast.makeText(context, "System File Picker not available: ${e.localizedMessage}", android.widget.Toast.LENGTH_SHORT).show()
                                    }
                                },
                                modifier = Modifier.weight(1f)
                            ) {
                                Text("Import File", style = MaterialTheme.typography.labelSmall)
                            }
                        }

                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Button(
                                onClick = {
                                    coroutineScope.launch {
                                        val jsonString = viewModel.getExportSupplementsString()
                                        try {
                                            val clipboard = context.getSystemService(android.content.Context.CLIPBOARD_SERVICE) as android.content.ClipboardManager
                                            val clip = android.content.ClipData.newPlainText("Supplements Backup", jsonString)
                                            clipboard.setPrimaryClip(clip)
                                            android.widget.Toast.makeText(context, "Supplements copied to clipboard!", android.widget.Toast.LENGTH_SHORT).show()
                                        } catch (e: Exception) {
                                            android.widget.Toast.makeText(context, "Clipboard error: ${e.localizedMessage}", android.widget.Toast.LENGTH_LONG).show()
                                        }
                                    }
                                },
                                modifier = Modifier.weight(1f),
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = MaterialTheme.colorScheme.secondaryContainer,
                                    contentColor = MaterialTheme.colorScheme.onSecondaryContainer
                                )
                            ) {
                                Text("Copy JSON", style = MaterialTheme.typography.labelSmall)
                            }

                            OutlinedButton(
                                onClick = { pasteInputVisible = !pasteInputVisible },
                                modifier = Modifier.weight(1f)
                            ) {
                                Text(if (pasteInputVisible) "Close Paste" else "Paste JSON", style = MaterialTheme.typography.labelSmall)
                            }
                        }

                        if (pasteInputVisible) {
                            OutlinedTextField(
                                value = clipboardText,
                                onValueChange = { clipboardText = it },
                                label = { Text("Paste Supplements JSON here") },
                                textStyle = MaterialTheme.typography.bodySmall,
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(120.dp),
                                maxLines = 5,
                                placeholder = { Text("[ { \"name\": \"Vitamin D3\", ... } ]") }
                            )

                            Button(
                                onClick = {
                                    if (clipboardText.isNotBlank()) {
                                        viewModel.importSupplements(clipboardText) { success, msg ->
                                            if (success) {
                                                clipboardText = ""
                                                pasteInputVisible = false
                                                showBackupImportDialog = false
                                                android.widget.Toast.makeText(context, "Supplements imported successfully!", android.widget.Toast.LENGTH_SHORT).show()
                                            } else {
                                                android.widget.Toast.makeText(context, "Import failed: $msg", android.widget.Toast.LENGTH_LONG).show()
                                            }
                                        }
                                    }
                                },
                                modifier = Modifier.fillMaxWidth(),
                                colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.primary)
                            ) {
                                Text("Parse & Import", style = MaterialTheme.typography.labelMedium)
                            }
                        }
                    }
                },
                confirmButton = {
                    TextButton(onClick = { showBackupImportDialog = false }) {
                        Text("Close")
                    }
                }
            )
        }
    }
}

@Composable
fun AddSupplementDialog(
    initialName: String = "",
    initialDosage: String = "",
    initialFrequency: String = "Once Daily",
    initialNotes: String = "",
    initialNutrients: Map<String, Double> = emptyMap(),
    onDismiss: () -> Unit,
    onConfirm: (String, String, String, String, String, String, Map<String, Double>) -> Unit
) {
    var name by remember { mutableStateOf(initialName) }
    var dosage by remember { mutableStateOf(initialDosage) }
    var frequency by remember { mutableStateOf(initialFrequency) }
    var notes by remember { mutableStateOf(initialNotes) }
    val timeOfDay = "Morning"
    
    val daysList = listOf("Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday")
    val selectedDays = remember { mutableStateMapOf<String, Boolean>().apply {
        daysList.forEach { put(it, false) }
    } }
    
    var showFreqDropdown by remember { mutableStateOf(false) }
    val frequencies = listOf("Once Daily", "Twice Daily", "Weekly", "Alternate Days")

    // Custom nutrients tracking
    val activeNutrients = remember { mutableStateMapOf<String, Double>().apply {
        initialNutrients.forEach { (k, v) -> put(k, v) }
    } }
    
    val nutrientAmounts = remember { mutableStateMapOf<String, String>().apply {
        initialNutrients.forEach { (k, v) -> put(k, v.toString()) }
    } }

    var showNutrientDropdown by remember { mutableStateOf(false) }
    var selectedNutrientToAdd by remember { mutableStateOf<com.example.data.NutrientDefinition?>(null) }
    var nutrientToAddAmount by remember { mutableStateOf("") }

    val dialogTitleHtml = if (initialNotes.contains("Scanned") || name.any { it.isDigit() }) {
        "Tailor Scanned Supplement"
    } else {
        "Add Supplement Guideline"
    }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = {
            Text(
                text = dialogTitleHtml,
                style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold)
            )
        },
        text = {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .verticalScroll(rememberScrollState()),
                verticalArrangement = Arrangement.spacedBy(12.dp)
            ) {
                OutlinedTextField(
                    value = name,
                    onValueChange = { name = it },
                    label = { Text("Supplement Name") },
                    placeholder = { Text("e.g., Vitamin D3, Magnesium Glycinate") },
                    modifier = Modifier.fillMaxWidth().testTag("add_supplement_name_input"),
                    singleLine = true
                )

                OutlinedTextField(
                    value = dosage,
                    onValueChange = { dosage = it },
                    label = { Text("Dosage / Strength") },
                    placeholder = { Text("e.g. 5000 IU, 400 mg, 1 pill") },
                    modifier = Modifier.fillMaxWidth().testTag("add_supplement_dosage_input"),
                    singleLine = true
                )

                // Frequency Select Box
                Box(modifier = Modifier.fillMaxWidth()) {
                    OutlinedTextField(
                        value = frequency,
                        onValueChange = {},
                        label = { Text("Frequency") },
                        readOnly = true,
                        trailingIcon = {
                            IconButton(onClick = { showFreqDropdown = !showFreqDropdown }) {
                                Icon(imageVector = Icons.Default.Info, contentDescription = "Dropdown")
                            }
                        },
                        modifier = Modifier
                            .fillMaxWidth()
                            .clickable { showFreqDropdown = true }
                            .testTag("add_supplement_frequency_input")
                    )
                    
                    DropdownMenu(
                        expanded = showFreqDropdown,
                        onDismissRequest = { showFreqDropdown = false }
                    ) {
                        frequencies.forEach { freq ->
                            DropdownMenuItem(
                                text = { Text(freq) },
                                onClick = {
                                    frequency = freq
                                    showFreqDropdown = false
                                }
                            )
                        }
                    }
                }

                // If Weekly, display day select chips
                if (frequency == "Weekly") {
                    Text(
                        text = "Scheduled Days",
                        style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .horizontalScroll(rememberScrollState()),
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        daysList.forEach { day ->
                            val isSelected = selectedDays[day] == true
                            val chipBg = if (isSelected) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
                            val chipBorderColor = if (isSelected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface.copy(alpha = 0.12f)
                            val chipTextColor = if (isSelected) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant

                            Surface(
                                selected = isSelected,
                                onClick = { selectedDays[day] = !isSelected },
                                color = chipBg,
                                shape = RoundedCornerShape(8.dp),
                                modifier = Modifier
                                    .border(1.dp, chipBorderColor, RoundedCornerShape(8.dp))
                                    .testTag("day_chip_$day")
                            ) {
                                Text(
                                    text = day.take(3),
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = chipTextColor,
                                    modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp)
                                )
                            }
                        }
                    }
                }

                OutlinedTextField(
                    value = notes,
                    onValueChange = { notes = it },
                    label = { Text("Guideline Notes (Optional)") },
                    placeholder = { Text("e.g., Take with dinner") },
                    modifier = Modifier.fillMaxWidth().testTag("add_supplement_notes_input"),
                    singleLine = true
                )

                Spacer(modifier = Modifier.height(4.dp))
                
                // --- CUSTOM NUTRIENTS SECTION ---
                Text(
                    text = "Vitamins & Nutrients Content",
                    style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.primary
                )
                
                if (activeNutrients.isEmpty()) {
                    Text(
                        text = "No clinical ingredients listed. Use the builder below to add content (e.g. minerals or vitamin elements).",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                } else {
                    activeNutrients.keys.toList().forEach { nutrientKey ->
                        val def = com.example.data.Nutrients.getByKey(nutrientKey)
                        if (def != null) {
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f), RoundedCornerShape(8.dp))
                                    .padding(horizontal = 8.dp, vertical = 6.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                Text(
                                    text = "${def.name} (${def.unit})",
                                    style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                    modifier = Modifier.weight(1.2f)
                                )

                                OutlinedTextField(
                                    value = nutrientAmounts[nutrientKey] ?: "0.0",
                                    onValueChange = { newValue ->
                                        if (newValue.all { it.isDigit() || it == '.' }) {
                                            nutrientAmounts[nutrientKey] = newValue
                                            val parsed = newValue.toDoubleOrNull() ?: 0.0
                                            activeNutrients[nutrientKey] = parsed
                                        }
                                    },
                                    modifier = Modifier
                                        .width(90.dp)
                                        .height(52.dp)
                                        .testTag("nutrient_input_$nutrientKey"),
                                    singleLine = true,
                                    textStyle = MaterialTheme.typography.bodyMedium,
                                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
                                )

                                IconButton(
                                    onClick = {
                                        activeNutrients.remove(nutrientKey)
                                        nutrientAmounts.remove(nutrientKey)
                                    },
                                    modifier = Modifier.size(40.dp)
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Delete,
                                        contentDescription = "Remove nutrient",
                                        tint = MaterialTheme.colorScheme.error
                                    )
                                }
                            }
                        }
                    }
                }

                Spacer(modifier = Modifier.height(4.dp))

                // Build add nutrient widget
                Card(
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.secondaryContainer.copy(alpha = 0.3f)
                    ),
                    shape = RoundedCornerShape(12.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Column(
                        modifier = Modifier.padding(12.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Text(
                            text = "Add Nutrient Element:",
                            style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onSecondaryContainer
                        )

                        Box(modifier = Modifier.fillMaxWidth()) {
                            OutlinedButton(
                                onClick = { showNutrientDropdown = true },
                                modifier = Modifier.fillMaxWidth().testTag("add_custom_nutrient_dropdown_btn")
                            ) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Text(
                                        text = selectedNutrientToAdd?.let { "${it.name} (${it.unit})" } ?: "Select Vitamin/Nutrient to Add...",
                                        style = MaterialTheme.typography.bodyMedium
                                    )
                                    Icon(imageVector = Icons.Default.ArrowDropDown, contentDescription = "Dropdown")
                                }
                            }

                            DropdownMenu(
                                expanded = showNutrientDropdown,
                                onDismissRequest = { showNutrientDropdown = false },
                                modifier = Modifier.heightIn(max = 240.dp)
                            ) {
                                val availableDefs = com.example.data.Nutrients.DEFINITIONS.filter { it.key !in activeNutrients.keys }
                                if (availableDefs.isEmpty()) {
                                    DropdownMenuItem(
                                        text = { Text("All nutrients already added") },
                                        onClick = { showNutrientDropdown = false }
                                    )
                                } else {
                                    availableDefs.forEach { def ->
                                        DropdownMenuItem(
                                            text = { Text("${def.name} (${def.unit})") },
                                            onClick = {
                                                selectedNutrientToAdd = def
                                                showNutrientDropdown = false
                                            }
                                        )
                                    }
                                }
                            }
                        }

                        if (selectedNutrientToAdd != null) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                OutlinedTextField(
                                    value = nutrientToAddAmount,
                                    onValueChange = { newValue ->
                                        if (newValue.all { it.isDigit() || it == '.' }) {
                                            nutrientToAddAmount = newValue
                                        }
                                    },
                                    label = { Text("Amount (${selectedNutrientToAdd?.unit})") },
                                    placeholder = { Text("e.g. 100") },
                                    modifier = Modifier.weight(1f).testTag("custom_new_nutrient_amount_field"),
                                    singleLine = true,
                                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
                                )

                                Button(
                                    onClick = {
                                        val def = selectedNutrientToAdd
                                        if (def != null && nutrientToAddAmount.isNotBlank()) {
                                            val amt = nutrientToAddAmount.toDoubleOrNull() ?: 0.0
                                            activeNutrients[def.key] = amt
                                            nutrientAmounts[def.key] = nutrientToAddAmount
                                            // Reset selection
                                            selectedNutrientToAdd = null
                                            nutrientToAddAmount = ""
                                        }
                                    },
                                    enabled = nutrientToAddAmount.isNotBlank(),
                                    modifier = Modifier.height(52.dp).testTag("add_nutrient_item_button")
                                ) {
                                    Icon(imageVector = Icons.Default.Add, contentDescription = "Add Item")
                                    Spacer(modifier = Modifier.width(4.dp))
                                    Text("Add")
                                }
                            }
                        }
                    }
                }
            }
        },
        confirmButton = {
            Button(
                onClick = {
                    if (name.isNotEmpty() && dosage.isNotEmpty()) {
                        val daysString = if (frequency == "Weekly") {
                            selectedDays.filter { it.value }.keys.joinToString(",")
                        } else {
                            ""
                        }
                        val finalNutrients = activeNutrients.mapValues { (k, defaultAmt) ->
                            nutrientAmounts[k]?.toDoubleOrNull() ?: defaultAmt
                        }
                        onConfirm(name, dosage, frequency, daysString, timeOfDay, notes, finalNutrients)
                    }
                },
                enabled = name.isNotEmpty() && dosage.isNotEmpty(),
                modifier = Modifier.testTag("confirm_add_supplement_button")
            ) {
                Text("Confirm")
            }
        },
        dismissButton = {
            TextButton(
                onClick = onDismiss,
                modifier = Modifier.testTag("dismiss_add_supplement_button")
            ) {
                Text("Cancel")
            }
        }
    )
}

@Composable
fun CameraPlaceholderUI(cameraPermissionLauncher: androidx.activity.result.ActivityResultLauncher<String>) {
    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(Color(0xFF0F172A)),
        contentAlignment = Alignment.Center
    ) {
        Column(
            horizontalAlignment = Alignment.CenterHorizontally,
            modifier = Modifier.padding(24.dp)
        ) {
            Icon(
                imageVector = Icons.Default.Info,
                contentDescription = "Camera Required",
                tint = MaterialTheme.colorScheme.primary.copy(alpha = 0.5f),
                modifier = Modifier.size(64.dp)
            )
            Spacer(modifier = Modifier.height(16.dp))
            Text(
                text = "Camera Feed Unavailable",
                style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                color = Color.White
            )
            Spacer(modifier = Modifier.height(6.dp))
            Text(
                text = "Camera permission enables physical scanning. Tap below to launch permission prompt, or use our simulator below to scan virtual nutrition labels.",
                style = MaterialTheme.typography.bodySmall,
                color = Color.LightGray,
                textAlign = TextAlign.Center,
                modifier = Modifier.padding(horizontal = 16.dp)
            )
            Spacer(modifier = Modifier.height(16.dp))
            Button(
                onClick = { cameraPermissionLauncher.launch(android.Manifest.permission.CAMERA) }
            ) {
                Text("Request Camera Access")
            }
        }
    }
}

@kotlin.OptIn(androidx.compose.foundation.layout.ExperimentalLayoutApi::class)
@Composable
fun BarcodeQRScannerScreen(
    onDismiss: () -> Unit,
    onBarcodeScanned: (String) -> Unit,
    onOcrScanned: ((Map<String, Double>) -> Unit)? = null
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    
    // Check permission initially
    val initialGranted = remember {
        ContextCompat.checkSelfPermission(
            context,
            android.Manifest.permission.CAMERA
        ) == PackageManager.PERMISSION_GRANTED
    }
    
    var hasCameraPermission by remember { mutableStateOf(initialGranted) }
    
    // Launcher for camera permission request
    val cameraPermissionLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        hasCameraPermission = isGranted
    }
    
    // Laser line sweep animation
    val infiniteTransition = rememberInfiniteTransition(label = "laser")
    val laserFraction by infiniteTransition.animateFloat(
        initialValue = 0.05f,
        targetValue = 0.95f,
        animationSpec = infiniteRepeatable(
            animation = tween(2000, easing = LinearEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "laser_y"
    )

    var customBarcode by remember { mutableStateOf("") }
    var showExplanation by remember { mutableStateOf(false) }
    var isScannedAlready by remember { mutableStateOf(false) }
    var isOcrMode by remember { mutableStateOf(false) }
    var isCameraActive by remember { mutableStateOf(false) }

    // Touch-to-Map OCR Interactive State variables
    var detectedLines by remember { mutableStateOf(emptySet<String>()) }
    var mappedNutrients by remember { mutableStateOf(emptyMap<String, Double>()) }
    var showMappingDialogForLine by remember { mutableStateOf<String?>(null) }
    var selectedMappedNutrientKey by remember { mutableStateOf("") }
    var selectedMappedNutrientValueStr by remember { mutableStateOf("") }

    var userUnmappedKeys by remember { mutableStateOf(emptySet<String>()) }
    var lassoPoints by remember { mutableStateOf(emptyList<androidx.compose.ui.geometry.Offset>()) }
    var lassoSelectedLines by remember { mutableStateOf(emptySet<String>()) }
    var activePresetForDrawing by remember { mutableStateOf("B-Complex (PDF Supplement)") }
    var frozenSnapshotLines by remember { mutableStateOf(emptyList<String>()) }
    var isGeminiNlpParsing by remember { mutableStateOf(false) }
    var nlpParseMessage by remember { mutableStateOf<String?>(null) }

    val nutrientDropdownOptions = listOf(
        "vitamin_a" to "Vitamin A (mcg)",
        "vitamin_c" to "Vitamin C (mg)",
        "vitamin_d" to "Vitamin D (mcg)",
        "vitamin_e" to "Vitamin E (mg)",
        "vitamin_k" to "Vitamin K (mcg)",
        "vitamin_b6" to "Vitamin B6 (mg)",
        "vitamin_b12" to "Vitamin B12 (mcg)",
        "thiamin" to "Thiamin (B1) (mg)",
        "riboflavin" to "Riboflavin (B2) (mg)",
        "niacin" to "Niacin (B3) (mg)",
        "pantothenic_acid" to "Pantothenic Acid (B5) (mg)",
        "biotin" to "Biotin (B7) (mcg)",
        "folate" to "Folate (B9) (mcg)",
        "choline" to "Choline (mg)",
        "calcium" to "Calcium (mg)",
        "iron" to "Iron (mg)",
        "magnesium" to "Magnesium (mg)",
        "potassium" to "Potassium (mg)",
        "sodium" to "Sodium (mg)",
        "zinc" to "Zinc (mg)",
        "copper" to "Copper (mg)",
        "manganese" to "Manganese (mg)",
        "selenium" to "Selenium (mcg)",
        "chromium" to "Chromium (mcg)",
        "molybdenum" to "Molybdenum (mcg)",
        "iodine" to "Iodine (mcg)",
        "carbohydrates" to "Carbohydrates (g)",
        "protein" to "Protein (g)",
        "calories" to "Calories (kcal)",
        "fat" to "Fat (g)",
        "fiber" to "Fiber (g)"
    )

    // Pre-calculated preset text associations so users can test interactive mapper manually
    val ocrPresetRawTexts = mapOf(
        "B-Complex (PDF Supplement)" to listOf(
            "Thiamin (vitamin B1) (as thiamin mononitrate) 50 mg 4,167%",
            "Riboflavin (vitamin B2) 50 mg 3,846%",
            "Niacin (vitamin B3) (as niacinamide) 50 mg 313%",
            "Vitamin B6 (as pyridoxine HCl) 50 mg 2,941%",
            "Folate 666 mcg DFE (400 mcg folic acid) 167%",
            "Vitamin B12 (as cyanocobalamin) 50 mcg 2,083%"
        ),
        "Multi-Daily (10+ items)" to listOf(
            "Vitamin A 900 mcg 100%",
            "Vitamin C 120 mg 133%",
            "Vitamin D 20 mcg 100%",
            "Vitamin E 15 mg 100%",
            "Vitamin B6 2 mg 118%",
            "Vitamin B12 6 mcg 250%",
            "Calcium 150 mg 12%",
            "Zinc 11 mg 100%",
            "Magnesium 100 mg 24%",
            "Iron 18 mg 100%"
        ),
        "D3 + K2 Complex Table" to listOf(
            "Vitamin D3 125 mcg (5000 IU)",
            "Vitamin K2 90 mcg (as MK-7)",
            "Calcium 50 mg (as Carbonate)"
        ),
        "ZMA Recovery Tablet" to listOf(
            "Zinc (as L-Monomethionine) 30 mg",
            "Magnesium Aspartate 450 mg",
            "Vitamin B6 (as Pyridoxine) 10.5 mg"
        ),
        "Electrolytes Matrix" to listOf(
            "Sodium (as Chloride) 250 mg",
            "Potassium (as Citrate) 180 mg",
            "Magnesium (as Glycinate) 90 mg"
        )
    )

    Dialog(
        onDismissRequest = onDismiss,
        properties = androidx.compose.ui.window.DialogProperties(usePlatformDefaultWidth = false)
    ) {
        Surface(
            modifier = Modifier.fillMaxSize(),
            color = MaterialTheme.colorScheme.background
        ) {
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .systemBarsPadding()
            ) {
                // Header Area with Scanner Modes Tab Selector
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(MaterialTheme.colorScheme.surfaceVariant)
                        .padding(horizontal = 16.dp, vertical = 12.dp),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Row(verticalAlignment = Alignment.CenterVertically) {
                            Surface(
                                color = if (isOcrMode) Color(0xFF38BDF8) else Color(0xFF4ADE80),
                                shape = CircleShape,
                                modifier = Modifier.size(8.dp)
                            ) {}
                            Spacer(modifier = Modifier.width(8.dp))
                            Text(
                                text = if (isOcrMode) "SUPPLEMENT FACTS OCR" else "BARCODE / QR CODES",
                                style = MaterialTheme.typography.titleSmall.copy(
                                    fontWeight = FontWeight.Bold,
                                    letterSpacing = 1.5.sp
                                ),
                                color = MaterialTheme.colorScheme.onSurface
                            )
                        }

                        IconButton(
                            onClick = onDismiss,
                            modifier = Modifier
                                .background(MaterialTheme.colorScheme.surface.copy(alpha = 0.3f), CircleShape)
                                .testTag("scanner_close_button")
                        ) {
                            Icon(
                                imageVector = Icons.Default.Close,
                                contentDescription = "Close Scanner",
                                tint = MaterialTheme.colorScheme.onSurface
                            )
                        }
                    }

                    // TabRow switcher to change modes
                    TabRow(
                        selectedTabIndex = if (isOcrMode) 1 else 0,
                        containerColor = Color.Transparent,
                        contentColor = MaterialTheme.colorScheme.primary,
                        modifier = Modifier
                            .fillMaxWidth()
                            .height(40.dp)
                            .clip(RoundedCornerShape(8.dp))
                    ) {
                        Tab(
                            selected = !isOcrMode,
                            onClick = { isOcrMode = false },
                            text = { Text("Barcode Scan", style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold), color = MaterialTheme.colorScheme.onSurface) }
                        )
                        Tab(
                            selected = isOcrMode,
                            onClick = { isOcrMode = true },
                            text = { Text("OCR Table Scan", style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold), color = MaterialTheme.colorScheme.onSurface) }
                        )
                    }
                }

                // Dedicated sticky camera viewport at top
                var isCameraSupported by remember { mutableStateOf(true) }

                if (hasCameraPermission && isCameraSupported && isCameraActive) {
                    val lifecycleOwner = androidx.compose.ui.platform.LocalLifecycleOwner.current
                    val cameraProviderFuture = remember {
                        try {
                            ProcessCameraProvider.getInstance(context)
                        } catch (t: Throwable) {
                            android.util.Log.e("Scanner", "Failed to get ProcessCameraProvider", t)
                            isCameraSupported = false
                            null
                        }
                    }

                    if (cameraProviderFuture != null) {
                        androidx.compose.runtime.DisposableEffect(lifecycleOwner, cameraProviderFuture) {
                            onDispose {
                                try {
                                    if (cameraProviderFuture.isDone) {
                                        val provider = cameraProviderFuture.get()
                                        provider.unbindAll()
                                    }
                                } catch (t: Throwable) {
                                    android.util.Log.e("Scanner", "Clean up camera unbind failed", t)
                                }
                            }
                        }

                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(260.dp)
                                .background(Color.Black)
                                .padding(horizontal = 16.dp, vertical = 8.dp)
                                .clip(RoundedCornerShape(12.dp))
                                .border(BorderStroke(2.dp, if (isOcrMode) Color(0xFF38BDF8) else Color(0xFF4ADE80)), RoundedCornerShape(12.dp))
                        ) {
                            AndroidView(
                                factory = { ctx ->
                                    val previewView = PreviewView(ctx)
                                    previewView.scaleType = PreviewView.ScaleType.FILL_CENTER
                                    val executor = ContextCompat.getMainExecutor(ctx)
                                    cameraProviderFuture.addListener({
                                        try {
                                            val cameraProvider = cameraProviderFuture.get()
                                            val preview = androidx.camera.core.Preview.Builder().build().also {
                                                it.setSurfaceProvider(previewView.surfaceProvider)
                                            }

                                            val imageAnalysis = androidx.camera.core.ImageAnalysis.Builder()
                                                .setBackpressureStrategy(androidx.camera.core.ImageAnalysis.STRATEGY_KEEP_ONLY_LATEST)
                                                .build()

                                            val barcodeScanner = com.google.mlkit.vision.barcode.BarcodeScanning.getClient()
                                            val textRecognizer = com.google.mlkit.vision.text.TextRecognition.getClient(
                                                com.google.mlkit.vision.text.latin.TextRecognizerOptions.DEFAULT_OPTIONS
                                            )

                                            imageAnalysis.setAnalyzer(executor) { imageProxy ->
                                                @androidx.annotation.OptIn(androidx.camera.core.ExperimentalGetImage::class)
                                                val mediaImage = imageProxy.image
                                                if (mediaImage != null && !isScannedAlready) {
                                                    val image = com.google.mlkit.vision.common.InputImage.fromMediaImage(
                                                        mediaImage,
                                                        imageProxy.imageInfo.rotationDegrees
                                                    )
                                                    if (isOcrMode) {
                                                        textRecognizer.process(image)
                                                            .addOnSuccessListener { visionText ->
                                                                val newDetected = mutableSetOf<String>()
                                                                for (block in visionText.textBlocks) {
                                                                    for (line in block.lines) {
                                                                        val txt = line.text.trim()
                                                                        if (txt.length > 3 && !txt.all { !it.isLetterOrDigit() }) {
                                                                            newDetected.add(txt)
                                                                        }
                                                                    }
                                                                }
                                                                if (newDetected.isNotEmpty()) {
                                                                    detectedLines = (detectedLines + newDetected).take(30).toSet()

                                                                    val freshMap = mappedNutrients.toMutableMap()
                                                                    newDetected.forEach { lineText ->
                                                                        val parsed = parseNutrientFromLine(lineText)
                                                                        if (parsed != null && !freshMap.containsKey(parsed.first) && !userUnmappedKeys.contains(parsed.first)) {
                                                                            freshMap[parsed.first] = parsed.second
                                                                        }
                                                                    }
                                                                    mappedNutrients = freshMap
                                                                }
                                                            }
                                                            .addOnFailureListener { t ->
                                                                android.util.Log.e("Scanner", "OCR failure", t)
                                                            }
                                                            .addOnCompleteListener {
                                                                imageProxy.close()
                                                            }
                                                    } else {
                                                        barcodeScanner.process(image)
                                                            .addOnSuccessListener { barcodes ->
                                                                for (barcode in barcodes) {
                                                                    val rawValue = barcode.rawValue
                                                                    if (rawValue != null && rawValue.isNotBlank() && !isScannedAlready) {
                                                                        isScannedAlready = true
                                                                        onBarcodeScanned(rawValue)
                                                                        break
                                                                    }
                                                                }
                                                            }
                                                            .addOnFailureListener { t ->
                                                                android.util.Log.e("Scanner", "Analysis failure", t)
                                                            }
                                                            .addOnCompleteListener {
                                                                imageProxy.close()
                                                            }
                                                    }
                                                } else {
                                                    imageProxy.close()
                                                }
                                            }

                                            val cameraSelector = androidx.camera.core.CameraSelector.DEFAULT_BACK_CAMERA
                                            cameraProvider.unbindAll()
                                            cameraProvider.bindToLifecycle(
                                                lifecycleOwner,
                                                cameraSelector,
                                                preview,
                                                imageAnalysis
                                            )
                                        } catch (exc: Throwable) {
                                            android.util.Log.e("Scanner", "Use case binding failed", exc)
                                        }
                                    }, executor)
                                    previewView
                                },
                                modifier = Modifier.fillMaxSize()
                            )

                            // Overlay scope braces inside box
                            Box(modifier = Modifier.fillMaxSize()) {
                                Box(
                                    modifier = Modifier
                                        .size(160.dp)
                                        .align(Alignment.Center)
                                        .testTag("scanner_viewfinder_scope")
                                ) {
                                    val braceColor = if (isOcrMode) Color(0xFF38BDF8) else Color(0xFF4ADE80)
                                    val braceThickness = 4.dp
                                    val braceLength = 20.dp

                                    Box(modifier = Modifier.align(Alignment.TopStart).size(braceLength).border(BorderStroke(braceThickness, braceColor), shape = RoundedCornerShape(topStart = 8.dp)).clip(RoundedCornerShape(topStart = 8.dp)))
                                    Box(modifier = Modifier.align(Alignment.TopEnd).size(braceLength).border(BorderStroke(braceThickness, braceColor), shape = RoundedCornerShape(topEnd = 8.dp)).clip(RoundedCornerShape(topEnd = 8.dp)))
                                    Box(modifier = Modifier.align(Alignment.BottomStart).size(braceLength).border(BorderStroke(braceThickness, braceColor), shape = RoundedCornerShape(bottomStart = 8.dp)).clip(RoundedCornerShape(bottomStart = 8.dp)))
                                    Box(modifier = Modifier.align(Alignment.BottomEnd).size(braceLength).border(BorderStroke(braceThickness, braceColor), shape = RoundedCornerShape(bottomEnd = 8.dp)).clip(RoundedCornerShape(bottomEnd = 8.dp)))

                                    Box(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .height(3.dp)
                                            .offset(y = 160.dp * laserFraction)
                                            .background(
                                                Brush.horizontalGradient(
                                                    listOf(
                                                        Color.Transparent,
                                                        braceColor.copy(alpha = 0.5f),
                                                        braceColor,
                                                        braceColor.copy(alpha = 0.5f),
                                                        Color.Transparent
                                                    )
                                                )
                                            )
                                    )
                                }
                            }
                        }
                    }
                }

                // Lower section: Scrollable Content Column
                Column(
                    modifier = Modifier
                        .fillMaxSize()
                        .weight(1f)
                        .background(MaterialTheme.colorScheme.background)
                        .padding(horizontal = 16.dp, vertical = 12.dp)
                        .verticalScroll(rememberScrollState()),
                    verticalArrangement = Arrangement.spacedBy(16.dp)
                ) {
                    if (isCameraActive) {
                        Card(
                            colors = CardDefaults.cardColors(
                                containerColor = (if (isOcrMode) Color(0xFF38BDF8) else Color(0xFF4ADE80)).copy(alpha = 0.1f)
                            ),
                            border = BorderStroke(1.dp, (if (isOcrMode) Color(0xFF38BDF8) else Color(0xFF4ADE80)).copy(alpha = 0.3f)),
                            shape = RoundedCornerShape(12.dp),
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Row(
                                modifier = Modifier.padding(12.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Column(modifier = Modifier.weight(1f)) {
                                    Text(
                                        text = if (isOcrMode) "Table OCR Active" else "Barcode Scan Active",
                                        style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                                        color = if (isOcrMode) Color(0xFF0284C7) else Color(0xFF16A34A)
                                    )
                                    Text(
                                        text = if (isOcrMode) "Align supplement facts table to capture lines" else "Point at product barcode label",
                                        style = MaterialTheme.typography.bodySmall,
                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                                TextButton(
                                    onClick = { isCameraActive = false }
                                ) {
                                    Text("Pause Camera")
                                }
                            }
                        }
                    } else {
                        Card(
                            colors = CardDefaults.cardColors(
                                containerColor = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.4f)
                            ),
                            shape = RoundedCornerShape(16.dp),
                            border = BorderStroke(1.5.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.4f)),
                            modifier = Modifier.fillMaxWidth().testTag("scanner_camera_activation_card")
                        ) {
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(16.dp),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(16.dp)
                            ) {
                                Surface(
                                    color = MaterialTheme.colorScheme.primary,
                                    shape = CircleShape,
                                    modifier = Modifier.size(48.dp)
                                ) {
                                    Box(contentAlignment = Alignment.Center) {
                                        Icon(
                                            imageVector = Icons.Default.QrCode,
                                            contentDescription = "Camera",
                                            tint = MaterialTheme.colorScheme.onPrimary,
                                            modifier = Modifier.size(24.dp)
                                        )
                                    }
                                }

                                Column(modifier = Modifier.weight(1f)) {
                                    Text(
                                        text = "Live Camera Scanner Offline",
                                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                                        color = MaterialTheme.colorScheme.onPrimaryContainer
                                    )
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Text(
                                        text = "To preserve resources or scanner capability, use the Simulator/Manual tools below, or enable the live feed:",
                                        style = MaterialTheme.typography.bodySmall,
                                        color = MaterialTheme.colorScheme.onPrimaryContainer.copy(alpha = 0.8f)
                                    )
                                    Spacer(modifier = Modifier.height(12.dp))

                                    Button(
                                        onClick = {
                                            if (!hasCameraPermission) {
                                                cameraPermissionLauncher.launch(android.Manifest.permission.CAMERA)
                                            } else {
                                                isCameraActive = true
                                            }
                                        },
                                        modifier = Modifier.fillMaxWidth(),
                                        shape = RoundedCornerShape(8.dp)
                                    ) {
                                        Icon(imageVector = Icons.Default.QrCode, contentDescription = "CameraOn")
                                        Spacer(modifier = Modifier.width(6.dp))
                                        Text("Activate Live Camera")
                                    }
                                }
                            }
                        }
                    }

                    // BOTTOM INTERACTIVE LIVE SIMULATOR CONTROL PANEL
                    Card(
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.95f)
                        ),
                        shape = RoundedCornerShape(20.dp),
                        border = BorderStroke(1.5.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.6f)),
                        modifier = Modifier
                            .fillMaxWidth()
                            .testTag("emulator_scanner_control_panel")
                    ) {
                        Column(modifier = Modifier.padding(16.dp)) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Row(verticalAlignment = Alignment.CenterVertically) {
                                    Icon(
                                        imageVector = Icons.Default.Info,
                                        contentDescription = "Simulate",
                                        tint = MaterialTheme.colorScheme.primary,
                                        modifier = Modifier.size(20.dp)
                                    )
                                    Spacer(modifier = Modifier.width(8.dp))
                                    Text(
                                        text = if (isOcrMode) "Web OCR Table Scan Simulator" else "Web Barcode Scan Simulator",
                                        style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                                        color = MaterialTheme.colorScheme.onSurface
                                    )
                                }
                                
                                TextButton(
                                    onClick = { showExplanation = !showExplanation }
                                ) {
                                    Text(if (showExplanation) "Hide Info" else "How it works", style = MaterialTheme.typography.labelSmall)
                                }
                            }

                            if (showExplanation) {
                                Spacer(modifier = Modifier.height(8.dp))
                                Text(
                                    text = if (isOcrMode) 
                                        "Since this app runs inside a cloud browser, direct physical camera OCR is simulated here. Choose a pre-coded nutrition facts table preset, or copy-paste ingredient facts below to test the text extractor regex!" 
                                        else "Since this app runs inside a cloud browser, camera barcodes are simulated. Choose a supplement product preset or provide a custom barcode code to test auto-loggers.",
                                    style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }

                            Spacer(modifier = Modifier.height(12.dp))

                            if (isOcrMode) {
                                // OCR PRESETS ROW
                                Text(
                                    text = "Select Scanned Table Preset to Simulate OCR:",
                                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.primary,
                                    modifier = Modifier.padding(bottom = 6.dp)
                                )

                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .horizontalScroll(rememberScrollState()),
                                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    val ocrPresets = listOf(
                                        Pair("B-Complex (PDF Supplement)", mapOf(
                                            "thiamin" to 50.0,
                                            "riboflavin" to 50.0,
                                            "niacin" to 50.0,
                                            "vitamin_b6" to 50.0,
                                            "folate" to 666.0,
                                            "vitamin_b12" to 50.0
                                        )),
                                        Pair("Multi-Daily (10+ items)", mapOf(
                                            "vitamin_a" to 900.0,
                                            "vitamin_c" to 120.0,
                                            "vitamin_d" to 20.0,
                                            "vitamin_e" to 15.0,
                                            "vitamin_b6" to 2.0,
                                            "vitamin_b12" to 6.0,
                                            "calcium" to 150.0,
                                            "zinc" to 11.0,
                                            "magnesium" to 100.0,
                                            "iron" to 18.0
                                        )),
                                        Pair("D3 + K2 Complex Table", mapOf(
                                            "vitamin_d" to 125.0,
                                            "vitamin_k" to 90.0,
                                            "calcium" to 50.0
                                        )),
                                        Pair("ZMA Recovery Tablet", mapOf(
                                            "zinc" to 30.0,
                                            "magnesium" to 450.0,
                                            "vitamin_b6" to 10.5
                                        )),
                                        Pair("Electrolytes Matrix", mapOf(
                                            "sodium" to 250.0,
                                            "potassium" to 180.0,
                                            "magnesium" to 90.0
                                        ))
                                    )

                                    ocrPresets.forEach { (name, mapping) ->
                                        Button(
                                            onClick = {
                                                val rawList = ocrPresetRawTexts[name] ?: emptyList()
                                                activePresetForDrawing = name
                                                detectedLines = rawList.toSet()
                                                mappedNutrients = mapping
                                                userUnmappedKeys = emptySet()
                                                lassoPoints = emptyList()
                                                lassoSelectedLines = emptySet()
                                                nlpParseMessage = null
                                                if (name == "Multi-Daily (10+ items)") {
                                                    android.util.Log.d("NutritionScreens", "Multi-Daily (10+ items) selected. Flowing data mapping: $mapping")
                                                    println("[NutritionScreens] Multi-Daily (10+ items) selected. Flowing data mapping: $mapping")
                                                }
                                            },
                                            colors = ButtonDefaults.buttonColors(
                                                containerColor = MaterialTheme.colorScheme.primaryContainer,
                                                contentColor = MaterialTheme.colorScheme.onPrimaryContainer
