                                ),
                                mapOf(
                                    "key" to "Immune Booster",
                                    "name" to "Clinical Immune Support Protocol",
                                    "desc" to "Optimized to support white blood cell function and systemic resistance. Amplifies Zinc, Selenium, and Vitamins C and D.",
