                                        modifier = Modifier
                                            .width(170.dp)
                                            .testTag("dialog_preset_chip_$key")
                                    ) {
                                        Column(
                                            modifier = Modifier.padding(10.dp),
                                            verticalArrangement = Arrangement.spacedBy(4.dp)
