                                            color = MaterialTheme.colorScheme.primary
                                        )
                                        Text(
                                            text = currentPresetMap["desc"] ?: "",
                                            style = MaterialTheme.typography.bodySmall,
                                            color = MaterialTheme.colorScheme.onSurfaceVariant
                                        )
                                        HorizontalDivider(color = MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.4f))
                                        Text(
                                            text = "Target Modifications:",
                                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                            color = MaterialTheme.colorScheme.onSurface
                                        )
                                        Text(
                                            text = currentPresetMap["targets"] ?: "",
                                            style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Medium),
                                            color = MaterialTheme.colorScheme.primary
                                        )
                                    }
                                }
                            }

                            // Apply Button
                            val isSelectedActive = activePreset == localSelectedPresetKey
                            Button(
                                onClick = {
                                    viewModel.applyHealthGoalPreset(localSelectedPresetKey)
                                },
                                enabled = !isSelectedActive,
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = if (isSelectedActive) MaterialTheme.colorScheme.outlineVariant else MaterialTheme.colorScheme.primary
                                ),
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(44.dp)
                                    .testTag("dialog_apply_preset_button")
                            ) {
                                Text(
                                    text = if (isSelectedActive) "Protocol Currently Active" else "Apply Clinical Protocol Targets",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold)
                                )
                            }
                            
                            if (activePreset != "None") {
                                OutlinedButton(
                                    onClick = { viewModel.applyHealthGoalPreset("None") },
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .height(40.dp)
                                        .testTag("dialog_clear_preset_button")
                                ) {
                                    Text(
                                        text = "Restore Baseline Profiles (Deactivate Preset)",
                                        style = MaterialTheme.typography.labelSmall,
                                        color = MaterialTheme.colorScheme.error
                                    )
                                }
                            }
                        }
                    }
                    2 -> {
                        // TAB 2: Customize 41 RDAs
                    val dailyNutrients by viewModel.dailyNutrients.collectAsState()
                    val customRdaOverrides by viewModel.customRdaOverrides.collectAsState()
                    var nutrientSearchQuery by remember { mutableStateOf("") }
                    val dialogEditedTargets = remember { mutableStateMapOf<String, String>() }

                    LaunchedEffect(dailyNutrients, customRdaOverrides) {
                        dailyNutrients.forEach { status ->
                            val key = status.definition.key
                            val currentTarget = customRdaOverrides[key] ?: status.definition.rda
                            if (!dialogEditedTargets.containsKey(key) || dialogEditedTargets[key] != currentTarget.toInt().toString()) {
                                dialogEditedTargets[key] = currentTarget.toInt().toString()
                            }
                        }
                    }

                    Column(
                        modifier = Modifier.fillMaxWidth(),
                        verticalArrangement = Arrangement.spacedBy(10.dp)
                    ) {
                        Text(
                            text = "Search and adjust target allowances for all 41 tracked nutrients. Changes persist in real-time.",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )

                        // Compact search input inside dialog
                        OutlinedTextField(
                            value = nutrientSearchQuery,
                            onValueChange = { nutrientSearchQuery = it },
                            placeholder = { Text("Search 41 nutrients...") },
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(48.dp)
                                .testTag("dialog_nutrient_search"),
                            singleLine = true,
                            leadingIcon = {
                                Icon(Icons.Default.Search, contentDescription = "Search icon", modifier = Modifier.size(18.dp))
                            },
                            trailingIcon = {
                                if (nutrientSearchQuery.isNotEmpty()) {
                                    IconButton(onClick = { nutrientSearchQuery = "" }) {
                                        Icon(Icons.Default.Close, contentDescription = "Clear search", modifier = Modifier.size(18.dp))
                                    }
                                }
                            },
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedBorderColor = MaterialTheme.colorScheme.primary,
                                unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.3f)
                            )
                        )

                        val dialogFilteredList = dailyNutrients.filter { status ->
                            status.definition.name.contains(nutrientSearchQuery, ignoreCase = true)
                        }

                        // Scrollable target-adjuster widget list
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .heightIn(max = 280.dp)
                                .clip(RoundedCornerShape(8.dp))
                                .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.15f))
                                .border(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.05f), RoundedCornerShape(8.dp))
                        ) {
                            if (dialogFilteredList.isEmpty()) {
                                Box(
                                    modifier = Modifier.fillMaxSize().padding(16.dp),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(
                                        text = "No matching nutrients",
                                        style = MaterialTheme.typography.bodyMedium,
                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                            } else {
                                Column(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .verticalScroll(rememberScrollState())
                                        .padding(8.dp),
                                    verticalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    dialogFilteredList.forEach { status ->
                                        val def = status.definition
                                        val key = def.key
                                        val textVal = dialogEditedTargets[key] ?: def.rda.toInt().toString()
                                        val hasOverride = customRdaOverrides.containsKey(key)

                                        val badgeColor = when (def.group) {
                                            com.example.data.NutrientGroup.MACROS -> Color(0xFF6366F1)
                                            com.example.data.NutrientGroup.LIPIDS -> Color(0xFFF59E0B)
                                            com.example.data.NutrientGroup.VITAMINS -> Color(0xFF10B981)
                                            com.example.data.NutrientGroup.MINERALS -> Color(0xFF06B6D4)
                                            com.example.data.NutrientGroup.OTHERS -> Color(0xFFEC4899)
                                        }

                                        Card(
                                            colors = CardDefaults.cardColors(
                                                containerColor = if (hasOverride) MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.12f)
                                                else MaterialTheme.colorScheme.surface
                                            ),
                                            border = BorderStroke(
                                                width = if (hasOverride) 1.2.dp else 1.dp,
                                                color = if (hasOverride) MaterialTheme.colorScheme.primary.copy(alpha = 0.6f) else MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.3f)
                                            ),
                                            modifier = Modifier.fillMaxWidth().testTag("dialog_nutrient_card_$key")
                                        ) {
                                            Row(
                                                modifier = Modifier.padding(10.dp).fillMaxWidth(),
                                                verticalAlignment = Alignment.CenterVertically,
                                                horizontalArrangement = Arrangement.SpaceBetween
                                            ) {
                                                // Nutrient details
                                                Column(modifier = Modifier.weight(1f).padding(end = 4.dp)) {
                                                    Row(verticalAlignment = Alignment.CenterVertically) {
                                                        Text(
                                                            text = def.name,
                                                            style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.Bold),
                                                            color = MaterialTheme.colorScheme.onSurface,
                                                            maxLines = 1,
                                                            overflow = TextOverflow.Ellipsis
                                                        )
                                                        Spacer(modifier = Modifier.width(4.dp))
                                                        Text(
                                                            text = "(${def.unit})",
                                                            style = MaterialTheme.typography.labelSmall,
                                                            color = MaterialTheme.colorScheme.onSurfaceVariant
                                                        )
                                                    }
                                                    Spacer(modifier = Modifier.height(2.dp))
                                                    Row(
                                                        verticalAlignment = Alignment.CenterVertically,
                                                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                                                    ) {
                                                        Box(
                                                            modifier = Modifier
                                                                .clip(RoundedCornerShape(4.dp))
                                                                .background(badgeColor)
                                                                .padding(horizontal = 4.dp, vertical = 2.dp)
                                                        ) {
                                                            Text(
                                                                text = def.group.displayName,
                                                                style = MaterialTheme.typography.labelSmall.copy(fontSize = 7.sp, fontWeight = FontWeight.Bold),
                                                                color = Color.White
                                                            )
                                                        }
                                                        if (hasOverride) {
                                                            Box(
                                                                modifier = Modifier
                                                                    .clip(RoundedCornerShape(4.dp))
                                                                    .border(1.dp, MaterialTheme.colorScheme.primary, RoundedCornerShape(4.dp))
                                                                    .padding(horizontal = 4.dp, vertical = 1.dp)
                                                            ) {
                                                                Text(
                                                                    text = "Custom",
                                                                    style = MaterialTheme.typography.labelSmall.copy(fontSize = 7.sp, fontWeight = FontWeight.Bold),
                                                                    color = MaterialTheme.colorScheme.primary
                                                                )
                                                            }
                                                        }
                                                    }
                                                }

                                                // Numeric Fine-tuning with buttons
                                                Row(
                                                    verticalAlignment = Alignment.CenterVertically,
                                                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                                                ) {
                                                    val step = when (key) {
                                                        "calories" -> 50.0
                                                        "carbohydrates", "protein", "fat" -> 5.0
                                                        "water" -> 100.0
                                                        "saturated_fat", "trans_fat", "monounsaturated_fat", "polyunsaturated_fat", "omega6", "cholesterol", "fiber" -> 1.0
                                                        "omega3" -> 0.1
                                                        "vitamin_a", "vitamin_c", "calcium", "potassium", "sodium", "phosphorus", "magnesium", "choline" -> 10.0
                                                        "vitamin_d", "vitamin_e", "vitamin_k", "zinc", "manganese", "selenium", "iodine", "sugars" -> 1.0
                                                        else -> 0.1
                                                    }

                                                    // Decrease
                                                    IconButton(
                                                        onClick = {
                                                            val current = textVal.toDoubleOrNull() ?: def.rda
                                                            val newVal = (current - step).coerceAtLeast(1.0)
                                                            dialogEditedTargets[key] = newVal.toInt().toString()
                                                            viewModel.updateCustomRda(key, newVal)
                                                        },
                                                        modifier = Modifier
                                                            .size(28.dp)
                                                            .background(MaterialTheme.colorScheme.surfaceVariant, CircleShape)
                                                            .testTag("dialog_btn_dec_$key")
                                                    ) {
                                                        Text("-", style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.Bold))
                                                    }

                                                    // Edit text
                                                    OutlinedTextField(
                                                        value = textVal,
                                                        onValueChange = { newValStr ->
                                                            val filtered = newValStr.filter { it.isDigit() }
                                                            dialogEditedTargets[key] = filtered
                                                            val dVal = filtered.toDoubleOrNull()
                                                            if (dVal != null && dVal > 0) {
                                                                viewModel.updateCustomRda(key, dVal)
                                                            }
                                                        },
                                                        singleLine = true,
                                                        keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number),
                                                        textStyle = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold, textAlign = TextAlign.Center),
                                                        modifier = Modifier
                                                            .width(68.dp)
                                                            .height(52.dp)
                                                            .testTag("dialog_input_$key"),
                                                        colors = OutlinedTextFieldDefaults.colors(
                                                            focusedBorderColor = MaterialTheme.colorScheme.primary,
                                                            unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.3f),
                                                            focusedContainerColor = MaterialTheme.colorScheme.surface,
                                                            unfocusedContainerColor = MaterialTheme.colorScheme.surface
                                                        )
                                                    )

                                                    // Increase
                                                    IconButton(
                                                        onClick = {
                                                            val current = textVal.toDoubleOrNull() ?: def.rda
                                                            val newVal = current + step
                                                            dialogEditedTargets[key] = newVal.toInt().toString()
                                                            viewModel.updateCustomRda(key, newVal)
                                                        },
                                                        modifier = Modifier
                                                            .size(28.dp)
                                                            .background(MaterialTheme.colorScheme.surfaceVariant, CircleShape)
                                                            .testTag("dialog_btn_inc_$key")
                                                    ) {
                                                        Text("+", style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.Bold))
                                                    }

                                                    if (hasOverride) {
                                                        IconButton(
                                                            onClick = {
                                                                viewModel.updateCustomRda(key, 0.0) // Delete override
                                                                val stdRdaValue = com.example.data.Nutrients.DEFAULT_DEFINITIONS.find { it.key == key }?.rda ?: def.rda
                                                                dialogEditedTargets[key] = stdRdaValue.toInt().toString()
                                                            },
                                                            modifier = Modifier
                                                                .size(28.dp)
                                                                .testTag("dialog_btn_reset_$key")
                                                        ) {
                                                            Icon(
                                                                imageVector = Icons.Default.Refresh,
                                                                contentDescription = "Reset to default",
                                                                tint = MaterialTheme.colorScheme.error,
                                                                modifier = Modifier.size(16.dp)
                                                            )
                                                        }
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                    }
                    3 -> {
                        // TAB 3: API Integrations
                        Column(
                            modifier = Modifier
                                .fillMaxWidth()
                                .verticalScroll(rememberScrollState()),
                            verticalArrangement = Arrangement.spacedBy(12.dp)
                        ) {
                            Text(
                                text = "Your credentials are saved securely in your private device local storage. They are NOT stored in the compiled APK, preventing private key leaks when sharing or distributing your APK.",
                                style = MaterialTheme.typography.bodySmall.copy(
                                    fontWeight = FontWeight.Medium,
                                    color = MaterialTheme.colorScheme.primary
                                )
                            )

                            // USDA Key Input
                            Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                Text(
                                    text = "USDA FoodData Central API Key",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )
                                OutlinedTextField(
                                    value = usdaKeyInput,
                                    onValueChange = { usdaKeyInput = it },
                                    placeholder = { Text("e.g. DEMO_KEY or your USDA API Key") },
                                    singleLine = true,
                                    visualTransformation = if (usdaKeyVisible) androidx.compose.ui.text.input.VisualTransformation.None else androidx.compose.ui.text.input.PasswordVisualTransformation(),
                                    trailingIcon = {
                                        IconButton(onClick = { usdaKeyVisible = !usdaKeyVisible }) {
                                            Text(if (usdaKeyVisible) "Hide" else "Show", fontSize = 10.sp, color = MaterialTheme.colorScheme.primary)
                                        }
                                    },
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .testTag("settings_usda_key_input"),
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedBorderColor = MaterialTheme.colorScheme.primary,
                                        unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.4f)
                                    )
                                )
                                Text(
                                    text = "Defaults to public rate-limited DEMO_KEY if left blank.",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }

                            // Nutritionix App ID Input
                            Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                Text(
                                    text = "Nutritionix App ID",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )
                                OutlinedTextField(
                                    value = ixAppIdInput,
                                    onValueChange = { ixAppIdInput = it },
                                    placeholder = { Text("Enter Nutritionix App ID") },
                                    singleLine = true,
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .testTag("settings_ix_appid_input"),
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedBorderColor = MaterialTheme.colorScheme.primary,
                                        unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.4f)
                                    )
                                )
                            }

                            // Nutritionix API Key Input
                            Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                Text(
                                    text = "Nutritionix API Key",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )
                                OutlinedTextField(
                                    value = ixApiKeyInput,
                                    onValueChange = { ixApiKeyInput = it },
                                    placeholder = { Text("Enter Nutritionix API Key") },
                                    singleLine = true,
                                    visualTransformation = if (ixKeyVisible) androidx.compose.ui.text.input.VisualTransformation.None else androidx.compose.ui.text.input.PasswordVisualTransformation(),
                                    trailingIcon = {
                                        IconButton(onClick = { ixKeyVisible = !ixKeyVisible }) {
                                            Text(if (ixKeyVisible) "Hide" else "Show", fontSize = 10.sp, color = MaterialTheme.colorScheme.primary)
                                        }
                                    },
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .testTag("settings_ix_key_input"),
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedBorderColor = MaterialTheme.colorScheme.primary,
                                        unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.4f)
                                    )
                                )
                            }

                            Spacer(modifier = Modifier.height(4.dp))

                            Button(
                                onClick = {
                                    viewModel.saveApiCredentials(
                                        usdaKey = usdaKeyInput,
                                        ixAppId = ixAppIdInput,
                                        ixApiKey = ixApiKeyInput
                                    )
                                },
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .testTag("settings_save_api_credentials_button"),
                                shape = RoundedCornerShape(12.dp)
                            ) {
                                Text("Save Credentials")
                            }
                        }
                    }
                    4 -> {
                        // TAB 4: Gemini AI Settings & Diagnostics
                        val geminiActiveModel by viewModel.geminiActiveModel.collectAsState()
                        val geminiCustomApiKey by viewModel.geminiCustomApiKey.collectAsState()
                        val geminiDiagnosticResult by viewModel.geminiDiagnosticResult.collectAsState()
                        val geminiDiagnosticLoading by viewModel.geminiDiagnosticLoading.collectAsState()

                        var customKeyInput by remember(geminiCustomApiKey) { mutableStateOf(geminiCustomApiKey) }
                        var isCustomKeyVisible by remember { mutableStateOf(false) }

                        Column(
                            modifier = Modifier
                                .fillMaxWidth()
                                .verticalScroll(rememberScrollState()),
                            verticalArrangement = Arrangement.spacedBy(12.dp)
                        ) {
                            Text(
                                text = "Gemini AI Engine & Keys",
                                style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.primary
                            )

                            // 1. Engine / Model Selection
                            Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                                Text(
                                    text = "Select Gemini Engine",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )
                                Text(
                                    text = "Choose which intelligence level and speed profile to use across all AI nutrition services.",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                                
                                val engines = listOf(
                                    "gemini-3.5-flash" to "Default Fast & Smart",
                                    "gemini-2.5-flash" to "Latest generation (Flash)",
                                    "gemini-2.5-pro" to "Latest generation (Pro/Reasoning)",
                                    "gemini-2.0-flash" to "Experimental speed (2.0)",
                                    "gemini-1.5-flash" to "Legacy efficient (1.5)",
                                    "gemini-1.5-pro" to "Legacy reasoning (1.5)"
                                )
                                
                                engines.forEach { (modelId, desc) ->
                                    val isSelected = geminiActiveModel == modelId
                                    Row(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .clip(RoundedCornerShape(8.dp))
                                            .background(if (isSelected) MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.5f) else Color.Transparent)
                                            .clickable { viewModel.updateGeminiModel(modelId) }
                                            .padding(horizontal = 8.dp, vertical = 6.dp),
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        androidx.compose.material3.RadioButton(
                                            selected = isSelected,
                                            onClick = { viewModel.updateGeminiModel(modelId) }
                                        )
                                        Spacer(modifier = Modifier.width(4.dp))
                                        Column {
                                            Text(
                                                text = modelId,
                                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.SemiBold),
                                                color = if (isSelected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface
                                            )
                                            Text(
                                                text = desc,
                                                style = MaterialTheme.typography.labelSmall,
                                                color = MaterialTheme.colorScheme.onSurfaceVariant
                                            )
                                        }
                                    }
                                }
                            }

                            HorizontalDivider(color = MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.5f))

                            // 2. Custom Key Configuration
                            Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                                Text(
                                    text = "Custom Overridden Gemini API Key",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )
                                Text(
                                    text = "If your default or injected environment API key is flagged as leaked or blocked, you can paste your own secure API key here. It will override any system key securely inside your device local storage.",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )

                                OutlinedTextField(
                                    value = customKeyInput,
                                    onValueChange = { customKeyInput = it },
                                    placeholder = { Text("Enter custom secure API key (AIzaSy...)") },
                                    singleLine = true,
                                    visualTransformation = if (isCustomKeyVisible) androidx.compose.ui.text.input.VisualTransformation.None else androidx.compose.ui.text.input.PasswordVisualTransformation(),
                                    trailingIcon = {
                                        IconButton(onClick = { isCustomKeyVisible = !isCustomKeyVisible }) {
                                            Text(if (isCustomKeyVisible) "Hide" else "Show", fontSize = 10.sp, color = MaterialTheme.colorScheme.primary)
                                        }
                                    },
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .testTag("gemini_custom_key_input"),
                                    colors = OutlinedTextFieldDefaults.colors(
                                        focusedBorderColor = MaterialTheme.colorScheme.primary,
                                        unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.4f)
                                    )
                                )

                                Row(
                                    horizontalArrangement = Arrangement.spacedBy(8.dp),
                                    modifier = Modifier.fillMaxWidth()
                                ) {
                                    Button(
                                        onClick = { viewModel.updateGeminiCustomApiKey(customKeyInput) },
                                        modifier = Modifier
                                            .weight(1f)
                                            .testTag("gemini_save_custom_key_btn"),
                                        shape = RoundedCornerShape(12.dp)
                                    ) {
                                        Text("Save Custom Key")
                                    }
                                    
                                    if (geminiCustomApiKey.isNotEmpty()) {
                                        OutlinedButton(
                                            onClick = {
                                                viewModel.updateGeminiCustomApiKey("")
                                                customKeyInput = ""
                                            },
                                            modifier = Modifier
                                                .weight(1f)
                                                .testTag("gemini_clear_custom_key_btn"),
                                            shape = RoundedCornerShape(12.dp)
                                        ) {
                                            Text("Clear Custom Key")
                                        }
                                    }
                                }
                            }

                            HorizontalDivider(color = MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.5f))

                            // 3. API Key & Registry Diagnostics
                            Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                                Text(
                                    text = "Credential & Registry Diagnostics",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )
                                Text(
                                    text = "Check the current environment values and test your API key against the real Google AI model list registry to diagnose permission/leakage errors.",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )

                                Card(
                                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f)),
                                    modifier = Modifier.fillMaxWidth(),
                                    shape = RoundedCornerShape(12.dp)
                                ) {
                                    Column(
                                        modifier = Modifier.padding(12.dp),
                                        verticalArrangement = Arrangement.spacedBy(6.dp)
                                    ) {
                                        Text(
                                            text = "Environment Status (Masked):",
                                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                            color = MaterialTheme.colorScheme.primary
                                        )
                                        
                                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                            Text("System Environment Key:", style = MaterialTheme.typography.bodySmall)
                                            Text(
                                                text = com.example.data.GeminiAuthHandler.getMaskedEnvApiKey(),
                                                style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.SemiBold, fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace)
                                            )
                                        }
                                        
                                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                            Text("App BuildConfig Key:", style = MaterialTheme.typography.bodySmall)
                                            Text(
                                                text = com.example.data.GeminiAuthHandler.getMaskedBuildConfigApiKey(),
                                                style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.SemiBold, fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace)
                                            )
                                        }

                                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween) {
                                            Text("Resolved Active Key:", style = MaterialTheme.typography.bodySmall)
                                            Text(
                                                text = com.example.data.GeminiAuthHandler.getMaskedApiKey(),
                                                style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold, color = MaterialTheme.colorScheme.primary, fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace)
                                            )
                                        }
                                    }
                                }

                                Spacer(modifier = Modifier.height(4.dp))

                                Button(
                                    onClick = { viewModel.runGeminiDiagnostics() },
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .testTag("gemini_run_diagnostics_btn"),
                                    shape = RoundedCornerShape(12.dp),
                                    colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.secondary)
                                ) {
                                    if (geminiDiagnosticLoading) {
                                        CircularProgressIndicator(modifier = Modifier.size(20.dp), color = MaterialTheme.colorScheme.onSecondary, strokeWidth = 2.dp)
                                        Spacer(modifier = Modifier.width(8.dp))
                                        Text("Running Diagnostics...")
                                    } else {
                                        Text("Run API Key Diagnosis")
                                    }
                                }

                                geminiDiagnosticResult?.let { report ->
                                    Spacer(modifier = Modifier.height(4.dp))
                                    Card(
                                        colors = CardDefaults.cardColors(
                                            containerColor = if (report.contains("✅")) MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.3f) 
                                                              else MaterialTheme.colorScheme.errorContainer.copy(alpha = 0.2f)
                                        ),
                                        modifier = Modifier.fillMaxWidth(),
                                        shape = RoundedCornerShape(12.dp),
                                        border = BorderStroke(
                                            width = 1.dp, 
                                            color = if (report.contains("✅")) MaterialTheme.colorScheme.primary.copy(alpha = 0.5f) 
                                                    else MaterialTheme.colorScheme.error.copy(alpha = 0.5f)
                                        )
                                    ) {
                                        Column(modifier = Modifier.padding(12.dp)) {
                                            Text(
                                                text = report,
                                                style = MaterialTheme.typography.bodySmall.copy(fontFamily = androidx.compose.ui.text.font.FontFamily.Monospace),
                                                color = MaterialTheme.colorScheme.onSurface
                                            )
                                        }
                                    }
                                }
                            }
                        }
                    }
                }

                Spacer(modifier = Modifier.height(8.dp))

                // Shared Action Buttons Row
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    if (activeDialogTab == 2) {
                        TextButton(
                            onClick = {
                                viewModel.resetRdaToDefaults()
                            },
                            modifier = Modifier.testTag("dialog_reset_all_button")
                        ) {
                            Text(
                                text = "Reset All Custom",
                                color = MaterialTheme.colorScheme.error,
                                style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold)
                            )
                        }
                    } else {
                        Spacer(modifier = Modifier.width(1.dp))
                    }

                    Row(
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        TextButton(
                            onClick = onDismiss,
                            modifier = Modifier.testTag("settings_cancel_button")
                        ) {
                            Text(if (activeDialogTab == 0) "Cancel" else "Close")
                        }

                        if (activeDialogTab == 0) {
                            Button(
                                onClick = {
                                    val age = ageInput.toIntOrNull() ?: currentAge
                                    viewModel.applyRdaProfile(
                                        age = age,
                                        weight = currentWeight,
                                        activityLevel = currentActivity,
                                        sex = selectedSex
                                    )
                                    onDismiss()
                                },
                                enabled = ageInput.isNotBlank() && (ageInput.toIntOrNull() ?: 0) > 0,
                                shape = RoundedCornerShape(12.dp),
                                modifier = Modifier.testTag("settings_confirm_button")
                            ) {
                                Text("Save & Update")
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun FoodDatabaseLookupTab(viewModel: NutritionViewModel) {
    val context = androidx.compose.ui.platform.LocalContext.current
    var activeSubTab by remember { mutableStateOf(0) } // 0 = Clinical Database, 1 = USDA Live Search

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp)
    ) {
        // Sub-Tab Switcher - Elegant Segmented Control
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(bottom = 16.dp)
                .clip(RoundedCornerShape(12.dp))
                .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f))
        ) {
            Box(
                modifier = Modifier
                    .weight(1f)
                    .clip(RoundedCornerShape(12.dp))
                    .background(if (activeSubTab == 0) MaterialTheme.colorScheme.primaryContainer else Color.Transparent)
                    .clickable { activeSubTab = 0 }
                    .padding(vertical = 12.dp),
                contentAlignment = Alignment.Center
            ) {
                Text(
                    "Clinical Database",
                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                    color = if (activeSubTab == 0) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
            Box(
                modifier = Modifier
                    .weight(1f)
                    .clip(RoundedCornerShape(12.dp))
                    .background(if (activeSubTab == 1) MaterialTheme.colorScheme.primaryContainer else Color.Transparent)
                    .clickable { activeSubTab = 1 }
                    .padding(vertical = 12.dp),
                contentAlignment = Alignment.Center
            ) {
                Text(
                    "USDA Live Search",
                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                    color = if (activeSubTab == 1) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
        }

        if (activeSubTab == 0) {
            ClinicalDatabaseSection(viewModel, context)
        } else {
            UsdaSearchSection(viewModel, context)
        }
    }
}

@Composable
fun ClinicalDatabaseSection(viewModel: NutritionViewModel, context: android.content.Context) {
    var searchQuery by remember { mutableStateOf("") }
    var expandedFoodName by remember { mutableStateOf<String?>(null) }
    
    // Dialog state for adding food
    var showLogDialogForFood by remember { mutableStateOf<com.example.data.LookupFood?>(null) }
    var selectedMealType by remember { mutableStateOf("Lunch") }
    var servingMultiplier by remember { mutableStateOf("1.0") }

    val filteredFoods = remember(searchQuery) {
        if (searchQuery.isBlank()) {
            com.example.data.FoodLookupDatabase.ITEMS
        } else {
            com.example.data.FoodLookupDatabase.ITEMS.filter {
                it.name.contains(searchQuery, ignoreCase = true) ||
                it.category.contains(searchQuery, ignoreCase = true)
            }
        }
    }

    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .testTag("food_database_lookup_tab_list"),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        item {
            // Header Card
            Card(
                modifier = Modifier.fillMaxWidth(),
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.3f)
                ),
                border = BorderStroke(1.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.2f))
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text(
                        text = "🔎 Clinical Nutrient Database",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    Spacer(modifier = Modifier.height(4.dp))
                    Text(
                        text = "Browse or search peer-reviewed food items containing exact profiles for all 41 essential clinical nutrients.",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }
        }

        item {
            // Search field
            OutlinedTextField(
                value = searchQuery,
                onValueChange = { searchQuery = it },
                modifier = Modifier
                    .fillMaxWidth()
                    .testTag("food_db_search_input"),
                placeholder = { Text("Search from 41-nutrient directory...") },
                leadingIcon = {
                    Icon(
                        imageVector = Icons.Default.Search,
                        contentDescription = "Search"
                    )
                },
                trailingIcon = {
                    if (searchQuery.isNotEmpty()) {
                        IconButton(onClick = { searchQuery = "" }) {
                            Icon(imageVector = Icons.Default.Close, contentDescription = "Clear")
                        }
                    }
                },
                singleLine = true,
                colors = OutlinedTextFieldDefaults.colors(
                    focusedBorderColor = MaterialTheme.colorScheme.primary,
                    unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.4f),
                    focusedContainerColor = MaterialTheme.colorScheme.surface,
                    unfocusedContainerColor = MaterialTheme.colorScheme.surface
                )
            )
        }

        if (filteredFoods.isEmpty()) {
            item {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(24.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = "No matching clinical foods found.",
                        color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f),
                        style = MaterialTheme.typography.bodyMedium
                    )
                }
            }
        } else {
            items(filteredFoods) { food ->
                val isExpanded = expandedFoodName == food.name
                
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clickable { expandedFoodName = if (isExpanded) null else food.name }
                        .testTag("food_db_item_${food.name.replace(" ", "_").lowercase()}"),
                    colors = CardDefaults.cardColors(
                        containerColor = if (isExpanded) MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.35f) else MaterialTheme.colorScheme.surface
                    ),
                    border = BorderStroke(
                        1.dp, 
                        if (isExpanded) MaterialTheme.colorScheme.primary.copy(alpha = 0.35f) 
                        else MaterialTheme.colorScheme.outline.copy(alpha = 0.12f)
                    ),
                    shape = RoundedCornerShape(12.dp)
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Row(
                                modifier = Modifier.weight(1f),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(10.dp)
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(36.dp)
                                        .clip(CircleShape)
                                        .background(MaterialTheme.colorScheme.secondaryContainer.copy(alpha = 0.4f)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text(food.emoji, fontSize = 18.sp)
                                }
                                Column {
                                    Text(
                                        text = food.name,
                                        style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                        color = MaterialTheme.colorScheme.onSurface
                                    )
                                    Text(
                                        text = "Serving: ${food.servingSize} • ${food.category}",
                                        style = MaterialTheme.typography.bodySmall,
                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                            }

                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                Button(
                                    onClick = { showLogDialogForFood = food },
                                    modifier = Modifier
                                        .height(34.dp)
                                        .testTag("log_db_food_btn_${food.name.replace(" ", "_").lowercase()}"),
                                    contentPadding = PaddingValues(horizontal = 12.dp, vertical = 0.dp),
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = MaterialTheme.colorScheme.secondary
                                    ),
                                    shape = RoundedCornerShape(8.dp)
                                ) {
                                    Icon(Icons.Default.Add, contentDescription = null, modifier = Modifier.size(14.dp))
                                    Spacer(modifier = Modifier.width(4.dp))
                                    Text("Log", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold))
                                }

                                Icon(
                                    imageVector = if (isExpanded) Icons.Default.Close else Icons.Default.ArrowDropDown,
                                    contentDescription = if (isExpanded) "Collapse" else "Expand",
                                    tint = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }
                        }

                        if (isExpanded) {
                            Spacer(modifier = Modifier.height(16.dp))
                            HorizontalDivider(color = MaterialTheme.colorScheme.outline.copy(alpha = 0.15f))
                            Spacer(modifier = Modifier.height(12.dp))

                            Text(
                                text = "41 CLINICAL NUTRIENT PROFILE VALUES (100% PRE-MAPPED)",
                                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.ExtraBold),
                                color = MaterialTheme.colorScheme.primary,
                                modifier = Modifier.padding(bottom = 8.dp)
                            )

                            // Sort definitions by group
                            val groupedDefinitions = Nutrients.DEFINITIONS.groupBy { it.group }

                            groupedDefinitions.forEach { (group, definitions) ->
                                Card(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .padding(vertical = 4.dp),
                                    colors = CardDefaults.cardColors(
                                        containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.5f)
                                    ),
                                    border = BorderStroke(1.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.08f))
                                ) {
                                    Column(modifier = Modifier.padding(10.dp)) {
                                        Text(
                                            text = group.displayName,
                                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                            color = MaterialTheme.colorScheme.secondary,
                                            modifier = Modifier.padding(bottom = 6.dp)
                                        )

                                        Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                            definitions.forEach { def ->
                                                val value = food.getNutrientValue(def.key)
                                                Row(
                                                    modifier = Modifier.fillMaxWidth(),
                                                    horizontalArrangement = Arrangement.SpaceBetween,
                                                    verticalAlignment = Alignment.CenterVertically
                                                ) {
                                                    Text(
                                                        text = def.name,
                                                        style = MaterialTheme.typography.bodySmall,
                                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                                    )
                                                    Text(
                                                        text = "$value ${def.unit}",
                                                        style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                                                        color = MaterialTheme.colorScheme.onSurface
                                                    )
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    // Dialog for adding food to logs with multiplier
    if (showLogDialogForFood != null) {
        val food = showLogDialogForFood!!
        Dialog(onDismissRequest = { showLogDialogForFood = null }) {
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(16.dp)
                    .testTag("log_db_food_dialog"),
                shape = RoundedCornerShape(16.dp),
                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                elevation = CardDefaults.cardElevation(defaultElevation = 8.dp)
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text(
                        text = "Log ${food.name} to Journal",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    Spacer(modifier = Modifier.height(12.dp))

                    OutlinedTextField(
                        value = servingMultiplier,
                        onValueChange = { newValue ->
                            if (newValue.isEmpty() || newValue.matches(Regex("^\\d*\\.?\\d*$"))) {
                                servingMultiplier = newValue
                            }
                        },
                        label = { Text("Portions / Servings Factor") },
                        placeholder = { Text("1.0") },
                        keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                        singleLine = true,
                        modifier = Modifier
                            .fillMaxWidth()
                            .testTag("log_db_food_multiplier"),
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor = MaterialTheme.colorScheme.primary,
                            unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.4f)
                        )
                    )

                    Spacer(modifier = Modifier.height(12.dp))

                    // Meal Type Chip Row
                    Text(
                        text = "Select Meal Slice",
                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.secondary,
                        modifier = Modifier.padding(bottom = 6.dp)
                    )

                    val mealTypes = listOf("Breakfast", "Lunch", "Dinner", "Snack", "Supplement")
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        mealTypes.forEach { type ->
                            val isSelected = selectedMealType == type
                            Surface(
                                onClick = { selectedMealType = type },
                                modifier = Modifier
                                    .weight(1f)
                                    .height(34.dp)
                                    .testTag("log_db_meal_chip_$type"),
                                shape = RoundedCornerShape(8.dp),
                                color = if (isSelected) MaterialTheme.colorScheme.secondaryContainer else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f),
                                border = if (isSelected) BorderStroke(1.dp, MaterialTheme.colorScheme.secondary) else null
                            ) {
                                Box(
                                    contentAlignment = Alignment.Center,
                                    modifier = Modifier.fillMaxSize()
                                ) {
                                    Text(
                                        text = type,
                                        style = MaterialTheme.typography.labelSmall.copy(
                                            fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal,
                                            fontSize = 9.sp
                                        ),
                                        color = if (isSelected) MaterialTheme.colorScheme.onSecondaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.End,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        TextButton(
                            onClick = { showLogDialogForFood = null },
                            modifier = Modifier.testTag("log_db_dismiss_btn")
                        ) {
                            Text("Dismiss")
                        }
                        
                        Spacer(modifier = Modifier.width(8.dp))

                        Button(
                            onClick = {
                                val multiplier = servingMultiplier.toDoubleOrNull() ?: 1.0
                                viewModel.addManualFoodLog(
                                    foodName = food.name,
                                    servingSize = multiplier,
                                    mealType = selectedMealType
                                )
                                showLogDialogForFood = null
                                Toast.makeText(context, "Logged ${food.name} successfully with pre-mapped 41 nutrients!", Toast.LENGTH_SHORT).show()
                            },
                            enabled = servingMultiplier.isNotBlank() && (servingMultiplier.toDoubleOrNull() ?: 0.0) > 0.0,
                            modifier = Modifier.testTag("log_db_confirm_btn")
                        ) {
                            Text("Commit Entry")
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun UsdaSearchSection(viewModel: NutritionViewModel, context: android.content.Context) {
    var usdaSearchQuery by remember { mutableStateOf("") }
    var expandedUsdaFoodId by remember { mutableStateOf<String?>(null) }
    var showLogDialogForUsdaFood by remember { mutableStateOf<com.example.data.OnlineFoodResult?>(null) }
    var showUsdaBarcodeScanner by remember { mutableStateOf(false) }

    val onlineResults by viewModel.onlineSearchResults.collectAsState()
    val isSearchingOnline by viewModel.isOnlineSearching.collectAsState()

    var selectedMealType by remember { mutableStateOf("Lunch") }
    var servingMultiplier by remember { mutableStateOf("1.0") }

    if (showUsdaBarcodeScanner) {
        BarcodeQRScannerScreen(
            onDismiss = { showUsdaBarcodeScanner = false },
            onBarcodeScanned = { barcode ->
                usdaSearchQuery = barcode
                viewModel.performOnlineFoodSearch(barcode)
                showUsdaBarcodeScanner = false
            }
        )
    }

    LazyColumn(
        modifier = Modifier
            .fillMaxSize()
            .testTag("usda_database_tab_list"),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        item {
            // Header Card
            Card(
                modifier = Modifier.fillMaxWidth(),
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.tertiaryContainer.copy(alpha = 0.3f)
                ),
                border = BorderStroke(1.dp, MaterialTheme.colorScheme.tertiary.copy(alpha = 0.2f))
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text(
                        text = "🥦 Live USDA & Online Food Database",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.tertiary
                    )
                    Spacer(modifier = Modifier.height(4.dp))
                    Text(
                        text = "Search hundreds of thousands of branded and generic foods live from USDA FoodData Central and log them to your daily intake record.",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }
        }

        item {
            // Search Input Row
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                OutlinedTextField(
                    value = usdaSearchQuery,
                    onValueChange = { usdaSearchQuery = it },
                    modifier = Modifier
                        .weight(1f)
                        .testTag("usda_search_input"),
                    placeholder = { Text("Search USDA foods or scan barcode...") },
                    leadingIcon = {
                        Icon(
                            imageVector = Icons.Default.Search,
                            contentDescription = "Search"
                        )
                    },
                    trailingIcon = {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(4.dp)
                        ) {
                            if (usdaSearchQuery.isNotEmpty()) {
                                IconButton(onClick = { usdaSearchQuery = "" }) {
                                    Icon(imageVector = Icons.Default.Close, contentDescription = "Clear")
                                }
                            }
                            IconButton(
                                onClick = { showUsdaBarcodeScanner = true },
                                modifier = Modifier.testTag("usda_scan_barcode_btn")
                            ) {
                                Icon(
                                    imageVector = Icons.Default.QrCode,
                                    contentDescription = "Scan Barcode",
                                    tint = MaterialTheme.colorScheme.primary
                                )
                            }
                        }
                    },
                    singleLine = true,
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = MaterialTheme.colorScheme.primary,
                        unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.4f),
                        focusedContainerColor = MaterialTheme.colorScheme.surface,
                        unfocusedContainerColor = MaterialTheme.colorScheme.surface
                    )
                )

                Button(
                    onClick = { viewModel.performOnlineFoodSearch(usdaSearchQuery) },
                    modifier = Modifier
                        .height(54.dp)
                        .testTag("usda_search_button"),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = MaterialTheme.colorScheme.primary
                    ),
                    shape = RoundedCornerShape(8.dp)
                ) {
                    if (isSearchingOnline) {
                        CircularProgressIndicator(
                            modifier = Modifier.size(18.dp),
                            strokeWidth = 2.dp,
                            color = MaterialTheme.colorScheme.onPrimary
                        )
                    } else {
                        Text("Search", style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold))
                    }
                }
            }
        }

        if (onlineResults.isEmpty() && usdaSearchQuery.isNotBlank() && !isSearchingOnline) {
            item {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(24.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = "No online search results found. Try another query.",
                        color = MaterialTheme.colorScheme.error,
                        style = MaterialTheme.typography.bodyMedium
                    )
                }
            }
        } else if (onlineResults.isEmpty() && !isSearchingOnline) {
            item {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(32.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.Search,
                            contentDescription = null,
                            tint = MaterialTheme.colorScheme.primary.copy(alpha = 0.4f),
                            modifier = Modifier.size(48.dp)
                        )
                        Text(
                            text = "Enter a search term above to begin.",
                            color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f),
                            style = MaterialTheme.typography.bodyMedium
                        )
                    }
                }
            }
        } else {
            items(onlineResults) { food ->
                val isExpanded = expandedUsdaFoodId == food.id
                
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clickable { expandedUsdaFoodId = if (isExpanded) null else food.id }
                        .testTag("usda_food_item_${food.id}"),
                    colors = CardDefaults.cardColors(
                        containerColor = if (isExpanded) MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.35f) else MaterialTheme.colorScheme.surface
                    ),
                    border = BorderStroke(
                        1.dp, 
                        if (isExpanded) MaterialTheme.colorScheme.tertiary.copy(alpha = 0.35f) 
                        else MaterialTheme.colorScheme.outline.copy(alpha = 0.12f)
                    ),
                    shape = RoundedCornerShape(12.dp)
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Row(
                                modifier = Modifier.weight(1f),
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(10.dp)
                            ) {
                                Box(
                                    modifier = Modifier
                                        .size(36.dp)
                                        .clip(CircleShape)
                                        .background(MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.4f)),
                                    contentAlignment = Alignment.Center
                                ) {
                                    Text("🍎", fontSize = 18.sp)
                                }
                                Column(modifier = Modifier.weight(1f)) {
                                    Text(
                                        text = food.name,
                                        style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                        color = MaterialTheme.colorScheme.onSurface,
                                        maxLines = 2,
                                        overflow = TextOverflow.Ellipsis
                                    )
                                    Text(
                                        text = "Serving: ${food.servingSize} ${food.servingSizeUnit} ${if (!food.brandName.isNullOrBlank()) "• " + food.brandName else ""}",
                                        style = MaterialTheme.typography.bodySmall,
                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                            }

                            Row(
                                verticalAlignment = Alignment.CenterVertically,
                                horizontalArrangement = Arrangement.spacedBy(4.dp)
                            ) {
                                Button(
                                    onClick = { showLogDialogForUsdaFood = food },
                                    modifier = Modifier
                                        .height(34.dp)
                                        .testTag("log_usda_food_btn_${food.id}"),
                                    contentPadding = PaddingValues(horizontal = 12.dp, vertical = 0.dp),
                                    colors = ButtonDefaults.buttonColors(
                                        containerColor = MaterialTheme.colorScheme.tertiary
                                    ),
                                    shape = RoundedCornerShape(8.dp)
                                ) {
                                    Icon(Icons.Default.Add, contentDescription = null, modifier = Modifier.size(14.dp))
                                    Spacer(modifier = Modifier.width(4.dp))
                                    Text("Log", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold))
                                }

                                Icon(
                                    imageVector = if (isExpanded) Icons.Default.Close else Icons.Default.ArrowDropDown,
                                    contentDescription = if (isExpanded) "Collapse" else "Expand",
                                    tint = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }
                        }

                        // Macro quick indicator on card
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(top = 8.dp),
                            horizontalArrangement = Arrangement.spacedBy(12.dp)
                        ) {
                            val cals = food.nutrients["calories"] ?: 0.0
                            val prot = food.nutrients["protein"] ?: 0.0
                            val carb = food.nutrients["carbohydrates"] ?: 0.0
                            val fat = food.nutrients["fat"] ?: 0.0
                            
                            Text(
                                text = "%.0f kcal".format(cals),
                                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.primary
                            )
                            Text(
                                text = "P: %.1fg".format(prot),
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                            Text(
                                text = "C: %.1fg".format(carb),
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                            Text(
                                text = "F: %.1fg".format(fat),
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }

                        if (isExpanded) {
                            Spacer(modifier = Modifier.height(16.dp))
                            HorizontalDivider(color = MaterialTheme.colorScheme.outline.copy(alpha = 0.15f))
                            Spacer(modifier = Modifier.height(12.dp))

                            Text(
                                text = "DETAILED USDA NUTRIENT MAP",
                                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.ExtraBold),
                                color = MaterialTheme.colorScheme.primary,
                                modifier = Modifier.padding(bottom = 8.dp)
                            )

                            // Sort definitions by group and show non-zero/available nutrients
                            val groupedDefinitions = Nutrients.DEFINITIONS.groupBy { it.group }

                            groupedDefinitions.forEach { (group, definitions) ->
                                val availableInGroup = definitions.filter { def ->
                                    val value = food.nutrients[def.key] ?: 0.0
                                    value > 0.0
                                }

                                if (availableInGroup.isNotEmpty()) {
                                    Card(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .padding(vertical = 4.dp),
                                        colors = CardDefaults.cardColors(
                                            containerColor = MaterialTheme.colorScheme.surface.copy(alpha = 0.5f)
                                        ),
                                        border = BorderStroke(1.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.08f))
                                    ) {
                                        Column(modifier = Modifier.padding(10.dp)) {
                                            Text(
                                                text = group.displayName,
                                                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                                color = MaterialTheme.colorScheme.secondary,
                                                modifier = Modifier.padding(bottom = 6.dp)
                                            )

                                            Column(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                                                availableInGroup.forEach { def ->
                                                    val value = food.nutrients[def.key] ?: 0.0
                                                    Row(
                                                        modifier = Modifier.fillMaxWidth(),
                                                        horizontalArrangement = Arrangement.SpaceBetween,
                                                        verticalAlignment = Alignment.CenterVertically
                                                    ) {
                                                        Text(
                                                            text = def.name,
                                                            style = MaterialTheme.typography.bodySmall,
                                                            color = MaterialTheme.colorScheme.onSurfaceVariant
                                                        )
                                                        Text(
                                                            text = "%.2f %s".format(value, def.unit),
                                                            style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                                                            color = MaterialTheme.colorScheme.onSurface
                                                        )
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    // Dialog for adding USDA food to logs with multiplier
    val activeUsdaFood = showLogDialogForUsdaFood
    if (activeUsdaFood != null) {
        val food = activeUsdaFood
        Dialog(onDismissRequest = { showLogDialogForUsdaFood = null }) {
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(16.dp)
                    .testTag("log_usda_food_dialog"),
                shape = RoundedCornerShape(16.dp),
                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                elevation = CardDefaults.cardElevation(defaultElevation = 8.dp)
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text(
                        text = "Log USDA Food to Journal",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    Spacer(modifier = Modifier.height(4.dp))
                    Text(
                        text = food.name,
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                        maxLines = 2,
                        overflow = TextOverflow.Ellipsis
                    )
                    Spacer(modifier = Modifier.height(12.dp))

                    OutlinedTextField(
                        value = servingMultiplier,
                        onValueChange = { newValue ->
                            if (newValue.isEmpty() || newValue.matches(Regex("^\\d*\\.?\\d*$"))) {
                                servingMultiplier = newValue
                            }
                        },
                        label = { Text("Portions / Servings Factor") },
                        placeholder = { Text("1.0") },
                        keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                        singleLine = true,
                        modifier = Modifier
                            .fillMaxWidth()
                            .testTag("log_usda_food_multiplier"),
                        colors = OutlinedTextFieldDefaults.colors(
                            focusedBorderColor = MaterialTheme.colorScheme.primary,
                            unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.4f)
                        )
                    )

                    Spacer(modifier = Modifier.height(12.dp))

                    Text(
                        text = "Select Meal Slice",
                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.secondary,
                        modifier = Modifier.padding(bottom = 6.dp)
                    )

                    val mealTypes = listOf("Breakfast", "Lunch", "Dinner", "Snack", "Supplement")
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        mealTypes.forEach { type ->
                            val isSelected = selectedMealType == type
                            Surface(
                                onClick = { selectedMealType = type },
                                modifier = Modifier
                                    .weight(1f)
                                    .height(34.dp)
                                    .testTag("log_usda_meal_chip_$type"),
                                shape = RoundedCornerShape(8.dp),
                                color = if (isSelected) MaterialTheme.colorScheme.secondaryContainer else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f),
                                border = if (isSelected) BorderStroke(1.dp, MaterialTheme.colorScheme.secondary) else null
                            ) {
                                Box(
                                    contentAlignment = Alignment.Center,
                                    modifier = Modifier.fillMaxSize()
                                ) {
                                    Text(
                                        text = type,
                                        style = MaterialTheme.typography.labelSmall.copy(
                                            fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal,
                                            fontSize = 9.sp
                                        ),
                                        color = if (isSelected) MaterialTheme.colorScheme.onSecondaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                            }
                        }
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.End,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        TextButton(
                            onClick = { showLogDialogForUsdaFood = null },
                            modifier = Modifier.testTag("log_usda_dismiss_btn")
                        ) {
                            Text("Dismiss")
                        }
                        
                        Spacer(modifier = Modifier.width(8.dp))

                        Button(
                            onClick = {
                                val multiplier = servingMultiplier.toDoubleOrNull() ?: 1.0
                                viewModel.logOnlineFoodItem(
                                    foodName = food.name,
                                    mealType = selectedMealType,
                                    quantity = multiplier,
                                    unit = food.servingSizeUnit,
                                    nutrients = food.nutrients,
                                    source = food.source
                                )
                                showLogDialogForUsdaFood = null
                                Toast.makeText(context, "Logged ${food.name} successfully to your intake history!", Toast.LENGTH_SHORT).show()
                            },
                            enabled = servingMultiplier.isNotBlank() && (servingMultiplier.toDoubleOrNull() ?: 0.0) > 0.0,
                            modifier = Modifier.testTag("log_usda_confirm_btn")
                        ) {
                            Text("Commit Entry")
                        }
                    }
                }
            }
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun FoodNutrientBreakdownBottomSheet(
    entry: FoodLogEntry,
    viewModel: NutritionViewModel,
    onDismiss: () -> Unit
) {
    val state = rememberModalBottomSheetState(skipPartiallyExpanded = true)
    val rdaOverrides by viewModel.customRdaOverrides.collectAsState()
    
    var searchQuery by remember { mutableStateOf("") }
    var showOnlyPresent by remember { mutableStateOf(false) }

    ModalBottomSheet(
        onDismissRequest = onDismiss,
        sheetState = state,
        shape = RoundedCornerShape(topStart = 24.dp, topEnd = 24.dp),
        dragHandle = {
            Box(
                modifier = Modifier
                    .width(40.dp)
                    .height(4.dp)
                    .clip(CircleShape)
                    .background(MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.4f))
                    .padding(vertical = 8.dp)
            )
        }
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .fillMaxHeight(0.85f)
                .padding(horizontal = 20.dp)
                .navigationBarsPadding()
        ) {
            // Food Header
            Spacer(modifier = Modifier.height(12.dp))
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        text = "Detailed Breakdown",
                        style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    Text(
                        text = entry.foodName,
                        style = MaterialTheme.typography.titleLarge.copy(fontWeight = FontWeight.ExtraBold),
                        color = MaterialTheme.colorScheme.onSurface,
                        maxLines = 2,
                        overflow = TextOverflow.Ellipsis
                    )
                }
                
                // Meal Badge & Calories Circle
                val calVal = ((entry.nutrients["calories"] ?: 0.0) * entry.quantity).toInt()
                Column(
                    horizontalAlignment = Alignment.End,
                    verticalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    Card(
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.primaryContainer
                        ),
                        shape = RoundedCornerShape(8.dp)
                    ) {
                        Text(
                            text = "$calVal kcal",
                            modifier = Modifier.padding(horizontal = 10.dp, vertical = 6.dp),
                            style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onPrimaryContainer
                        )
                    }
                    Text(
                        text = "${if (entry.quantity % 1.0 == 0.0) entry.quantity.toInt().toString() else String.format(Locale.US, "%.1f", entry.quantity)} ${entry.unit}",
                        style = MaterialTheme.typography.labelSmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }

            Spacer(modifier = Modifier.height(16.dp))
            
            // Major Macros Summary Banner
            Card(
                modifier = Modifier.fillMaxWidth(),
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)
                ),
                border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.05f)),
                shape = RoundedCornerShape(12.dp)
            ) {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(14.dp),
                    horizontalArrangement = Arrangement.SpaceEvenly
                ) {
                    val carbsG = (entry.nutrients["carbohydrates"] ?: 0.0) * entry.quantity
                    val protG = (entry.nutrients["protein"] ?: 0.0) * entry.quantity
                    val fatG = (entry.nutrients["fat"] ?: 0.0) * entry.quantity
                    val fiberG = (entry.nutrients["fiber"] ?: 0.0) * entry.quantity

                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Text("Carbs", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                        Text("${String.format(Locale.US, "%.1f", carbsG)}g", style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold), color = Color(0xFF3897F5))
                    }
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Text("Protein", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                        Text("${String.format(Locale.US, "%.1f", protG)}g", style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold), color = Color(0xFFFF9800))
                    }
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Text("Fat", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                        Text("${String.format(Locale.US, "%.1f", fatG)}g", style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold), color = Color(0xFF4CAF50))
                    }
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Text("Fiber", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                        Text("${String.format(Locale.US, "%.1f", fiberG)}g", style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold), color = MaterialTheme.colorScheme.secondary)
                    }
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            // Search and Filter Controls Row
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                OutlinedTextField(
                    value = searchQuery,
                    onValueChange = { searchQuery = it },
                    placeholder = { Text("Filter 41 nutrients...", style = MaterialTheme.typography.bodyMedium) },
                    textStyle = MaterialTheme.typography.bodyMedium,
                    singleLine = true,
                    modifier = Modifier.weight(1f).testTag("dialog_nutrient_filter_search"),
                    leadingIcon = {
                        Icon(imageVector = Icons.Default.Search, contentDescription = "Search", modifier = Modifier.size(18.dp))
                    },
                    trailingIcon = {
                        if (searchQuery.isNotEmpty()) {
                            IconButton(onClick = { searchQuery = "" }) {
                                Icon(imageVector = Icons.Default.Close, contentDescription = "Clear search", modifier = Modifier.size(16.dp))
                            }
                        }
                    },
                    shape = RoundedCornerShape(10.dp)
                )

                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(20.dp))
                        .background(
                            if (showOnlyPresent) MaterialTheme.colorScheme.primaryContainer
                            else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
                        )
                        .clickable { showOnlyPresent = !showOnlyPresent }
                        .border(
                            1.dp,
                            if (showOnlyPresent) MaterialTheme.colorScheme.primary
                            else MaterialTheme.colorScheme.onSurface.copy(alpha = 0.1f),
                            RoundedCornerShape(20.dp)
                        )
                        .padding(horizontal = 14.dp, vertical = 10.dp)
                        .testTag("dialog_nutrient_present_chip"),
                    contentAlignment = Alignment.Center
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        if (showOnlyPresent) {
                            Icon(
                                imageVector = Icons.Default.CheckCircle,
                                contentDescription = null,
                                modifier = Modifier.size(16.dp),
                                tint = MaterialTheme.colorScheme.onPrimaryContainer
                            )
                        }
                        Text(
                            text = "Active Only",
                            style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.Bold),
                            color = if (showOnlyPresent) MaterialTheme.colorScheme.onPrimaryContainer
                                    else MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(12.dp))

            // Scrollable grouped list of 41 nutrients
            LazyColumn(
                modifier = Modifier.weight(1f).fillMaxWidth(),
                verticalArrangement = Arrangement.spacedBy(8.dp),
                contentPadding = PaddingValues(bottom = 24.dp)
            ) {
                val groupedNutrients = com.example.data.Nutrients.DEFINITIONS.groupBy { it.group }

                com.example.data.NutrientGroup.values().forEach { group ->
                    val allGroupDefs = groupedNutrients[group] ?: emptyList()
                    val filteredDefs = allGroupDefs.filter { def ->
                        val value = (entry.nutrients[def.key] ?: 0.0) * entry.quantity
                        val matchesSearch = def.name.contains(searchQuery, ignoreCase = true)
                        val matchesPresent = !showOnlyPresent || value > 0.1
                        matchesSearch && matchesPresent
                    }

                    if (filteredDefs.isNotEmpty()) {
                        // Section Header
                        item {
                            Text(
                                text = group.displayName,
                                style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.ExtraBold),
                                color = MaterialTheme.colorScheme.secondary,
                                modifier = Modifier.padding(top = 12.dp, bottom = 4.dp)
                            )
                        }

                        items(filteredDefs) { def ->
                            val rawValue = entry.nutrients[def.key] ?: 0.0
                            val actualValue = rawValue * entry.quantity
                            val targetRda = rdaOverrides[def.key] ?: def.rda
                            val percentage = if (targetRda > 0.0) (actualValue / targetRda) else 0.0

                            NutrientRowItem(
                                def = def,
                                actualValue = actualValue,
                                targetRda = targetRda,
                                percentage = percentage
                            )
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun NutrientRowItem(
    def: com.example.data.NutrientDefinition,
    actualValue: Double,
    targetRda: Double,
    percentage: Double
) {
    val progressPercent = (percentage * 100).toInt()
    val isLimit = def.isMaxLimit

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .testTag("nutrient_breakdown_row_${def.key}"),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.15f)
        ),
        border = BorderStroke(0.5.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.06f)),
        shape = RoundedCornerShape(8.dp)
    ) {
        Column(modifier = Modifier.padding(12.dp)) {
            // Nutrients label & values row
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column(modifier = Modifier.weight(1f)) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        Text(
                            text = def.name,
                            style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onSurface
                        )
                        if (isLimit) {
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(4.dp))
                                    .background(MaterialTheme.colorScheme.errorContainer.copy(alpha = 0.3f))
                                    .padding(horizontal = 4.dp, vertical = 2.dp)
                            ) {
                                Text(
                                    text = "LIMIT",
                                    color = MaterialTheme.colorScheme.error,
                                    style = MaterialTheme.typography.labelSmall.copy(fontSize = 8.sp, fontWeight = FontWeight.Bold)
                                )
                            }
                        }
                    }
                    if (def.description.isNotEmpty()) {
                        Text(
                            text = def.description,
                            style = MaterialTheme.typography.labelSmall.copy(fontSize = 11.sp),
                            color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f),
                            maxLines = 2,
                            overflow = TextOverflow.Ellipsis
                        )
                    }
                }

                Spacer(modifier = Modifier.width(8.dp))

                Column(horizontalAlignment = Alignment.End) {
                    Text(
                        text = "${if (actualValue % 1.0 == 0.0 || actualValue > 9.9) actualValue.toInt().toString() else String.format(Locale.US, "%.1f", actualValue)} ${def.unit}",
                        style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.ExtraBold),
                        color = if (isLimit && actualValue > targetRda) MaterialTheme.colorScheme.error else MaterialTheme.colorScheme.onSurface
                    )
                    Text(
                        text = "RDA: ${targetRda.toInt()} ${def.unit}",
                        style = MaterialTheme.typography.labelSmall.copy(fontSize = 9.sp),
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }

            Spacer(modifier = Modifier.height(8.dp))

            // Percentage & progress bar
            val barPercentFraction = percentage.coerceIn(0.0, 1.1).toFloat()
            val animatedBarPercentFraction by androidx.compose.animation.core.animateFloatAsState(
                targetValue = barPercentFraction,
                animationSpec = androidx.compose.animation.core.tween(
                    durationMillis = 800,
                    easing = androidx.compose.animation.core.FastOutSlowInEasing
                ),
                label = "nutrient_row_progress_${def.key}"
            )
            val barColor = when {
                isLimit && actualValue > targetRda -> MaterialTheme.colorScheme.error
                isLimit -> Color(0xFF2E7D32) // Safe under upper limit
                actualValue >= targetRda -> Color(0xFF2E7D32) // Satisfied green
                else -> MaterialTheme.colorScheme.error // Highlight nutrients falling below RDA in red to alert of potential deficiencies
            }

            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                LinearProgressIndicator(
                    progress = { animatedBarPercentFraction },
                    modifier = Modifier
                        .weight(1f)
                        .height(6.dp)
                        .clip(CircleShape),
                    color = barColor,
                    trackColor = MaterialTheme.colorScheme.surfaceVariant
                )

                Text(
                    text = "$progressPercent%",
                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.ExtraBold),
                    color = barColor
                )
            }
        }
    }
}

@Composable
fun RdaFilterChip(
    selected: Boolean,
    onClick: () -> Unit,
    label: String,
    modifier: Modifier = Modifier
) {
    Box(
        modifier = modifier
            .clip(RoundedCornerShape(20.dp))
            .background(
                if (selected) MaterialTheme.colorScheme.primary
                else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
            )
            .clickable { onClick() }
            .border(
                width = 1.dp,
                color = if (selected) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.outline.copy(alpha = 0.12f),
                shape = RoundedCornerShape(20.dp)
            )
            .padding(horizontal = 12.dp, vertical = 8.dp)
    ) {
        Text(
            text = label,
            style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
            color = if (selected) MaterialTheme.colorScheme.onPrimary else MaterialTheme.colorScheme.onSurfaceVariant
        )
    }
}

@Composable
fun NutrientDeficiencyIndicatorPanel(viewModel: NutritionViewModel) {
    val dailyNutrients by viewModel.dailyNutrients.collectAsState()
    
    val rdaNutrients = remember(dailyNutrients) {
        dailyNutrients.filter { !it.definition.isMaxLimit && it.definition.rda > 0.0 }
    }
    
    val totalCount = rdaNutrients.size
    val metCount = rdaNutrients.count { it.percentage >= 100.0 }
    val moderateCount = rdaNutrients.count { it.percentage in 50.0..99.9 }
    val severeCount = rdaNutrients.count { it.percentage < 50.0 }
    
    val rdaMatchPercentage = if (totalCount > 0) (metCount.toFloat() / totalCount) * 100 else 0f
    
    var scoreFilterState by remember { mutableStateOf(0) } // 0 = All Targets, 1 = Great (Met), 2 = Moderate (50-99%), 3 = Severe (<50%)
    
    val groupExpandStates = remember {
        mutableStateMapOf<com.example.data.NutrientGroup, Boolean>().apply {
            com.example.data.NutrientGroup.values().forEach { put(it, false) }
        }
    }
    
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .testTag("nutrient_deficiency_indicator_panel_card"),
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(
            containerColor = DistinctColorTheme.getGreenDataContainerColor()
        ),
        border = BorderStroke(1.5.dp, DistinctColorTheme.getGreenDataBorderColor())
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Box(
                        modifier = Modifier
                            .size(36.dp)
                            .background(DistinctColorTheme.getGreenDataContentColor().copy(alpha = 0.12f), CircleShape),
                        contentAlignment = Alignment.Center
                    ) {
                        Icon(
                            imageVector = Icons.Default.Info,
                            contentDescription = "Deficiency Tracking Indicator",
                            tint = DistinctColorTheme.getGreenDataContentColor(),
                            modifier = Modifier.size(20.dp)
                        )
                    }
                    Column {
                        Text(
                            text = "RDA Deficiency Center",
                            style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                            color = DistinctColorTheme.getGreenDataContentColor()
                        )
                        Text(
                            text = "41 Essential Nutrients RDA Matching Engine",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
                
                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(12.dp))
                        .background(
                            when {
                                rdaMatchPercentage >= 80f -> Color(0xFFE8F5E9)
                                rdaMatchPercentage >= 50f -> Color(0xFFFFF3E0)
                                else -> Color(0xFFFFEBEE)
                            }
                        )
                        .padding(horizontal = 10.dp, vertical = 4.dp)
                ) {
                    Text(
                        text = "Match Score: ${rdaMatchPercentage.toInt()}%",
                        style = MaterialTheme.typography.labelSmall.copy(
                            fontWeight = FontWeight.Bold,
                            color = when {
                                rdaMatchPercentage >= 80f -> Color(0xFF2E7D32)
                                rdaMatchPercentage >= 50f -> Color(0xFFE65100)
                                else -> Color(0xFFC62828)
                            }
                        )
                    )
                }
            }
            
            Spacer(modifier = Modifier.height(16.dp))
            
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(
                        MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.2f),
                        RoundedCornerShape(12.dp)
                    )
                    .border(
                        1.dp, 
                        MaterialTheme.colorScheme.outline.copy(alpha = 0.08f), 
                        RoundedCornerShape(12.dp)
                    )
                    .padding(16.dp),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(16.dp)
            ) {
                Box(
                    modifier = Modifier.size(76.dp),
                    contentAlignment = Alignment.Center
                ) {
                    CircularProgressIndicator(
                        progress = rdaMatchPercentage / 100f,
                        modifier = Modifier.fillMaxSize(),
                        color = when {
                            rdaMatchPercentage >= 80f -> Color(0xFF2E7D32)
                            rdaMatchPercentage >= 50f -> Color(0xFFF57C00)
                            else -> Color(0xFFD32F2F)
                        },
                        trackColor = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.06f),
                        strokeWidth = 8.dp
                    )
                    
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        Text(
                            text = "${metCount}/$totalCount",
                            style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Black),
                            color = MaterialTheme.colorScheme.onSurface
                        )
                        Text(
                            text = "Met Goal",
                            style = MaterialTheme.typography.labelSmall.copy(fontSize = 8.sp),
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
                
                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        text = when {
                            rdaMatchPercentage >= 90f -> "Superb coverage! Your diet is hitting almost all daily biochemical targets."
                            rdaMatchPercentage >= 70f -> "Healthy nutrition. Only minor micro-nutrient gaps exist."
                            rdaMatchPercentage >= 40f -> "Moderate deficiencies. Multiple vitamin/mineral targets are missing."
                            metCount > 0 -> "Critical gaps found. You are missing core regulatory nutritional benchmarks."
                            else -> "Inactive/Empty. Log food entries to calculate your daily RDA Match score."
                        },
                        style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Medium),
                        color = MaterialTheme.colorScheme.onSurface,
                        lineHeight = 15.sp
                    )
                    
                    Spacer(modifier = Modifier.height(8.dp))
                    
                    Row(
                        horizontalArrangement = Arrangement.spacedBy(4.dp),
                        verticalAlignment = Alignment.CenterVertically,
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        QuickStatsItem(
                            label = "Severe",
                            count = severeCount,
                            color = Color(0xFFD32F2F),
                            isSelected = scoreFilterState == 3,
                            onClick = { scoreFilterState = if (scoreFilterState == 3) 0 else 3 }
                        )
                        QuickStatsItem(
                            label = "Mod.",
                            count = moderateCount,
                            color = Color(0xFFF57C00),
                            isSelected = scoreFilterState == 2,
                            onClick = { scoreFilterState = if (scoreFilterState == 2) 0 else 2 }
                        )
                        QuickStatsItem(
                            label = "Met",
                            count = metCount,
                            color = Color(0xFF2E7D32),
                            isSelected = scoreFilterState == 1,
                            onClick = { scoreFilterState = if (scoreFilterState == 1) 0 else 1 }
                        )
                    }
                }
            }
            
            Spacer(modifier = Modifier.height(14.dp))
            
            if (scoreFilterState != 0) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    val filterLabel = when (scoreFilterState) {
                        1 -> "Showing Target Goals Met (>= 100% RDA)"
                        2 -> "Showing Moderate Deficiency (50% - 99% RDA)"
                        else -> "Showing Severe Deficiences (< 50% RDA)"
                    }
                    Text(
                        text = filterLabel,
                        style = MaterialTheme.typography.labelSmall.copy(
                            fontWeight = FontWeight.Bold,
                            color = MaterialTheme.colorScheme.primary
                        )
                    )
                    
                    TextButton(
                        onClick = { scoreFilterState = 0 },
                        modifier = Modifier.height(24.dp).padding(horizontal = 4.dp)
                    ) {
                        Text("Reset filter", style = MaterialTheme.typography.labelSmall)
                    }
                }
                Spacer(modifier = Modifier.height(8.dp))
            }
            
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                com.example.data.NutrientGroup.values().forEach { group ->
                    val groupItems = rdaNutrients.filter { it.definition.group == group }
                    if (groupItems.isNotEmpty()) {
                        val filteredGroupItems = groupItems.filter { item ->
                            when (scoreFilterState) {
                                1 -> item.percentage >= 100.0
                                2 -> item.percentage in 50.0..99.9
                                3 -> item.percentage < 50.0
                                else -> true
                            }
                        }
                        
                        if (filteredGroupItems.isNotEmpty()) {
                            val groupMetCount = groupItems.count { it.percentage >= 100.0 }
                            val groupTotal = groupItems.size
                            val groupProgressFraction = if (groupTotal > 0) groupMetCount.toFloat() / groupTotal else 0f
                            val animatedGroupProgressFraction by androidx.compose.animation.core.animateFloatAsState(
                                targetValue = groupProgressFraction,
                                animationSpec = androidx.compose.animation.core.tween(
                                    durationMillis = 800,
                                    easing = androidx.compose.animation.core.FastOutSlowInEasing
                                ),
                                label = "group_progress_${group.name}"
                            )
                            val isExpanded = groupExpandStates[group] ?: false
                            
                            Card(
                                modifier = Modifier.fillMaxWidth(),
                                colors = CardDefaults.cardColors(
                                    containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.12f)
                                ),
                                shape = RoundedCornerShape(12.dp),
                                border = BorderStroke(1.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.05f))
                            ) {
                                Column(modifier = Modifier.padding(12.dp)) {
                                    Row(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .clickable { groupExpandStates[group] = !isExpanded },
                                        horizontalArrangement = Arrangement.SpaceBetween,
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        Row(
                                            verticalAlignment = Alignment.CenterVertically,
                                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                                        ) {
                                            Icon(
                                                imageVector = if (isExpanded) Icons.Default.KeyboardArrowUp else Icons.Default.KeyboardArrowDown,
                                                contentDescription = "Expand details",
                                                tint = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f),
                                                modifier = Modifier.size(18.dp)
                                            )
                                            Text(
                                                text = group.displayName,
                                                style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                                                color = MaterialTheme.colorScheme.onSurface
                                            )
                                        }
                                        
                                        Row(
                                            verticalAlignment = Alignment.CenterVertically,
                                            horizontalArrangement = Arrangement.spacedBy(6.dp)
                                        ) {
                                            Text(
                                                text = "${groupMetCount}/${groupTotal} met",
                                                style = MaterialTheme.typography.labelSmall,
                                                color = MaterialTheme.colorScheme.onSurfaceVariant
                                            )
                                            LinearProgressIndicator(
                                                progress = { animatedGroupProgressFraction },
                                                modifier = Modifier
                                                    .width(48.dp)
                                                    .height(6.dp)
                                                    .clip(RoundedCornerShape(3.dp)),
                                                color = when {
                                                    groupMetCount == groupTotal -> Color(0xFF2E7D32)
                                                    groupMetCount.toFloat() / groupTotal >= 0.5f -> Color(0xFFF57C00)
                                                    else -> Color(0xFFD32F2F)
                                                },
                                                trackColor = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.1f)
                                            )
                                        }
                                    }
                                    
                                    if (isExpanded) {
                                        Spacer(modifier = Modifier.height(10.dp))
                                        HorizontalDivider(color = MaterialTheme.colorScheme.outline.copy(alpha = 0.06f))
                                        Spacer(modifier = Modifier.height(8.dp))
                                        
                                        Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                                            filteredGroupItems.sortedBy { it.percentage }.forEach { item ->
                                                Row(
                                                    modifier = Modifier.fillMaxWidth(),
                                                    verticalAlignment = Alignment.CenterVertically,
                                                    horizontalArrangement = Arrangement.SpaceBetween
                                                ) {
                                                    Row(
                                                        verticalAlignment = Alignment.CenterVertically,
                                                        horizontalArrangement = Arrangement.spacedBy(6.dp),
                                                        modifier = Modifier.weight(1f)
                                                    ) {
                                                        Box(
                                                            modifier = Modifier
                                                                .size(6.dp)
                                                                .background(
                                                                    when {
                                                                        item.percentage >= 100.0 -> Color(0xFF2E7D32)
                                                                        item.percentage >= 50.0 -> Color(0xFFF57C00)
                                                                        else -> Color(0xFFD32F2F)
                                                                    },
                                                                    CircleShape
                                                                )
                                                        )
                                                        Text(
                                                            text = item.definition.name,
                                                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.SemiBold),
                                                            color = MaterialTheme.colorScheme.onSurface
                                                        )
                                                    }
                                                    
                                                    Row(
                                                        verticalAlignment = Alignment.CenterVertically,
                                                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                                                    ) {
                                                        val intakeValueStr = if (item.definition.key == "calories") {
                                                            "${item.intake.toInt()} / ${item.definition.rda.toInt()}"
                                                        } else {
                                                            "${String.format(Locale.US, "%.1f", item.intake)} / ${String.format(Locale.US, "%.1f", item.definition.rda)}"
                                                        }
                                                        Text(
                                                            text = "$intakeValueStr ${item.definition.unit}",
                                                            style = MaterialTheme.typography.labelSmall.copy(fontSize = 10.sp),
                                                            color = MaterialTheme.colorScheme.onSurfaceVariant
                                                        )
                                                        Text(
                                                            text = "${item.percentage.toInt()}%",
                                                            style = MaterialTheme.typography.labelSmall.copy(
                                                                fontWeight = FontWeight.Bold,
                                                                color = when {
                                                                    item.percentage >= 100.0 -> Color(0xFF2E7D32)
                                                                    item.percentage >= 50.0 -> Color(0xFFE65100)
                                                                    else -> Color(0xFFC62828)
                                                                }
                                                            )
                                                        )
                                                    }
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun QuickStatsItem(
    label: String,
    count: Int,
    color: Color,
    isSelected: Boolean,
    onClick: () -> Unit
) {
    Box(
        modifier = Modifier
            .clip(RoundedCornerShape(8.dp))
            .background(
                if (isSelected) color.copy(alpha = 0.15f)
                else Color.Transparent
            )
            .clickable { onClick() }
            .border(
                1.dp,
                if (isSelected) color else Color.Transparent,
                RoundedCornerShape(8.dp)
            )
            .padding(horizontal = 6.dp, vertical = 4.dp)
    ) {
        Row(
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(4.dp)
        ) {
            Box(
                modifier = Modifier
                    .size(8.dp)
                    .background(color, CircleShape)
            )
            Text(
                text = "$count $label",
                style = MaterialTheme.typography.labelSmall.copy(
                    fontSize = 10.sp,
                    fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Medium,
                    color = if (isSelected) color else MaterialTheme.colorScheme.onSurfaceVariant
                )
            )
        }
    }
}

@Composable
fun DailyDeficiencyVisualAlerter(viewModel: NutritionViewModel) {
    val dailyNutrients by viewModel.dailyNutrients.collectAsState()
    val selectedGroundedNutrient by viewModel.selectedGroundedNutrient.collectAsState()
    val groundedBenefitText by viewModel.groundedBenefitText.collectAsState()
    val isGroundedBenefitLoading by viewModel.isGroundedBenefitLoading.collectAsState()
    val groundedBenefitSources by viewModel.groundedBenefitSources.collectAsState()
    val context = androidx.compose.ui.platform.LocalContext.current
    
    // Filter target nutrients falling below 100% daily RDA
    val deficiencies = remember(dailyNutrients) {
        dailyNutrients.filter { 
            !it.definition.isMaxLimit && 
            it.intake < it.definition.rda && 
            it.definition.rda > 0.0 
        }.sortedBy { it.percentage } // Sort by lowest percentage/most severe deficit first
    }

    var filterState by remember { mutableStateOf(0) } // 0 = All gaps, 1 = Critical (< 50% met)
    val filteredDeficiencies = remember(deficiencies, filterState) {
        if (filterState == 1) {
            deficiencies.filter { it.percentage < 50.0 }
        } else {
            deficiencies
        }
    }
    
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .testTag("deficiency_visual_alerter_card"),
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.errorContainer.copy(alpha = 0.08f)
        ),
        border = BorderStroke(1.5.dp, MaterialTheme.colorScheme.error.copy(alpha = 0.35f))
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            // Header
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Box(
                        modifier = Modifier
                            .size(28.dp)
                            .background(MaterialTheme.colorScheme.error.copy(alpha = 0.15f), CircleShape),
                        contentAlignment = Alignment.Center
                    ) {
                        Icon(
                            imageVector = Icons.Default.Warning,
                            contentDescription = "Deficiencies Warning Alert",
                            tint = MaterialTheme.colorScheme.error,
                            modifier = Modifier.size(16.dp)
                        )
                    }
                    Column {
                        Text(
                            text = "RDA Deficiency Alerts Plan",
                            style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.ExtraBold),
                            color = MaterialTheme.colorScheme.error
                        )
                        Text(
                            text = "Daily nutrients and active gaps below 100% RDA",
                            style = MaterialTheme.typography.bodySmall.copy(fontSize = 11.sp),
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
                
                // Badge for count of deficiencies
                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(8.dp))
                        .background(MaterialTheme.colorScheme.error)
                        .padding(horizontal = 8.dp, vertical = 2.dp)
                ) {
                    Text(
                        text = "${deficiencies.size} Gaps",
                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold, fontSize = 10.sp),
                        color = MaterialTheme.colorScheme.onError
                    )
                }
            }
            
            Spacer(modifier = Modifier.height(10.dp))
            
            Text(
                text = "These nutrients fall below your daily recommended targets. Click any alert card below to inspect its biological benefits, clinical pathways, and recommended wellness foods powered by Google Search grounding.",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
                lineHeight = 15.sp
            )
            
            Spacer(modifier = Modifier.height(10.dp))
            
            // Toggle Filter Row (Chips)
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                // All Gaps
                Surface(
                    onClick = { filterState = 0 },
                    modifier = Modifier
                        .weight(1f)
                        .height(32.dp)
                        .testTag("deficiency_filter_all"),
                    shape = RoundedCornerShape(8.dp),
                    color = if (filterState == 0) MaterialTheme.colorScheme.errorContainer else MaterialTheme.colorScheme.surface,
                    contentColor = if (filterState == 0) MaterialTheme.colorScheme.onErrorContainer else MaterialTheme.colorScheme.onSurface,
                    border = BorderStroke(1.dp, if (filterState == 0) MaterialTheme.colorScheme.error else MaterialTheme.colorScheme.outline.copy(alpha = 0.2f))
                ) {
                    Box(contentAlignment = Alignment.Center, modifier = Modifier.fillMaxSize()) {
                        Text(
                            text = "All Gaps (${deficiencies.size})",
                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold)
                        )
                    }
                }
                
                // Critical Gaps (<50%)
                val criticalCount = remember(deficiencies) { deficiencies.count { it.percentage < 50.0 } }
                Surface(
                    onClick = { filterState = 1 },
                    modifier = Modifier
                        .weight(1f)
                        .height(32.dp)
                        .testTag("deficiency_filter_critical"),
                    shape = RoundedCornerShape(8.dp),
                    color = if (filterState == 1) MaterialTheme.colorScheme.error else MaterialTheme.colorScheme.surface,
                    contentColor = if (filterState == 1) MaterialTheme.colorScheme.onError else MaterialTheme.colorScheme.onSurface,
                    border = BorderStroke(1.dp, if (filterState == 1) MaterialTheme.colorScheme.error else MaterialTheme.colorScheme.outline.copy(alpha = 0.2f))
                ) {
                    Box(contentAlignment = Alignment.Center, modifier = Modifier.fillMaxSize()) {
                        Text(
                            text = "Critical (<50% RDA)",
                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold)
                        )
                    }
                }
            }
            
            Spacer(modifier = Modifier.height(10.dp))
            
            if (filteredDeficiencies.isEmpty()) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(MaterialTheme.colorScheme.surface, RoundedCornerShape(12.dp))
                        .border(1.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.15f), RoundedCornerShape(12.dp))
                        .padding(14.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Row(
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Icon(
                            imageVector = Icons.Default.CheckCircle,
                            contentDescription = "Success",
                            tint = Color(0xFF2E7D32),
                            modifier = Modifier.size(18.dp)
                        )
                        Text(
                            text = if (filterState == 1) "Zero critical deficiencies left!" else "Perfect! Zero RDA gaps left today!",
                            style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                            color = Color(0xFF2E7D32)
                        )
                    }
                }
            } else {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .heightIn(max = 240.dp)
                        .verticalScroll(rememberScrollState()),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    filteredDeficiencies.forEach { status ->
                        val def = status.definition
                        val isCritical = status.percentage < 50.0
                        val animatedDeficiencyPercentage by androidx.compose.animation.core.animateFloatAsState(
                            targetValue = status.percentage.coerceIn(0.0, 100.0).toFloat() / 100.0f,
                            animationSpec = androidx.compose.animation.core.tween(
                                durationMillis = 800,
                                easing = androidx.compose.animation.core.FastOutSlowInEasing
                            ),
                            label = "deficiency_percentage_${def.key}"
                        )
                        
                        Card(
                            modifier = Modifier
                                .fillMaxWidth()
                                .clip(RoundedCornerShape(12.dp))
                                .clickable {
                                    viewModel.queryNutrientBenefitGrounding(
                                        nutrientName = def.name,
                                        nutrientKey = def.key,
                                        fallbackText = def.description.ifEmpty { "Essential critical nutrient supporting metabolic pathways, energetic resilience, cellular development, and physiological balance." }
                                    )
                                }
                                .testTag("deficiency_visual_row_${def.key}"),
                            colors = CardDefaults.cardColors(
                                containerColor = MaterialTheme.colorScheme.surface
                            ),
                            border = BorderStroke(1.dp, MaterialTheme.colorScheme.error.copy(alpha = if (isCritical) 0.35f else 0.15f)),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            Column(modifier = Modifier.padding(12.dp)) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.Top
                                ) {
                                    Column(modifier = Modifier.weight(1f)) {
                                        Row(
                                            verticalAlignment = Alignment.CenterVertically,
                                            horizontalArrangement = Arrangement.spacedBy(6.dp)
                                        ) {
                                            Text(
                                                text = def.name,
                                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                                color = MaterialTheme.colorScheme.onSurface
                                            )
                                            
                                            Icon(
                                                imageVector = Icons.Default.Info,
                                                contentDescription = "Show benefits",
                                                tint = MaterialTheme.colorScheme.primary.copy(alpha = 0.6f),
                                                modifier = Modifier.size(14.dp)
                                            )
                                            
                                            // Red Label
                                            Box(
                                                modifier = Modifier
                                                    .clip(RoundedCornerShape(4.dp))
                                                    .background(
                                                        if (isCritical) MaterialTheme.colorScheme.errorContainer
                                                        else MaterialTheme.colorScheme.errorContainer.copy(alpha = 0.5f)
                                                    )
                                                    .padding(horizontal = 4.dp, vertical = 2.dp)
                                            ) {
                                                Text(
                                                    text = if (isCritical) "CRITICAL GAP" else "RDA GAP",
                                                    color = MaterialTheme.colorScheme.error,
                                                    style = MaterialTheme.typography.labelSmall.copy(fontSize = 8.sp, fontWeight = FontWeight.ExtraBold)
                                                )
                                            }
                                        }
                                        
                                        // Recommendation source Text:
                                        val foodSourceTip = remember(def.key) {
                                            when (def.key) {
                                                "calories" -> "Include wholesome oats, avocados, whole grains, and lean ribeye steaks."
                                                "protein" -> "Greek yogurt, turkey breast slices, raw chicken eggs, or soybeans."
                                                "carbohydrates" -> "Sweet potatoes, brown wild rice, organic quinoa, and berries."
                                                "fat" -> "Extra virgin olive oil, premium raw nuts, chia seeds, and fresh salmon."
                                                "fiber" -> "Chia seeds, split peas, black organic beans, flax seeds, or whole pears."
                                                "water" -> "Drink filtered water, clean bone broths, herbal teas, or hydration infusions."
                                                "calcium" -> "Greek yogurt, fortified unsweetened almond milk, dark kale, or sesame."
                                                "iron" -> "Tender baby spinach, lentils, high-quality black beans, or red steak with lemon."
                                                "vitamin_c" -> "Fresh sweet oranges, organic red bell peppers, clean strawberries, or kiwi."
                                                "potassium" -> "Medium fresh bananas, sweet avocados, gold baked potatoes, or coconut water."
                                                "vitamin_d" -> "Fortified grass-fed dairy, whole organic egg yolks, fresh salmon, or direct sun."
                                                "magnesium" -> "Quinoa, raw pumpkin seeds, raw almonds, and premium 70%+ dark chocolate."
                                                "zinc" -> "Shellfish oysters, grass-fed beef, organic pumpkin seeds, or rich lentils."
                                                else -> "Focus on fresh unprocessed leafy vegetable greens, organic meats, seeds, and nuts."
                                            }
                                        }
                                        Text(
                                            text = "Best sources: $foodSourceTip",
                                            style = MaterialTheme.typography.labelSmall.copy(fontStyle = androidx.compose.ui.text.font.FontStyle.Italic),
                                            color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.8f),
                                            maxLines = 2,
                                            overflow = TextOverflow.Ellipsis,
                                            modifier = Modifier.padding(top = 2.dp)
                                        )
                                    }
                                    
                                    Column(horizontalAlignment = Alignment.End) {
                                        Text(
                                            text = "${status.intake.toInt()} / ${def.rda.toInt()} ${def.unit}",
                                            style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.ExtraBold),
                                            color = MaterialTheme.colorScheme.error
                                        )
                                        Text(
                                            text = "Need ${(def.rda - status.intake).toInt()} ${def.unit} more",
                                            style = MaterialTheme.typography.labelSmall.copy(fontSize = 10.sp),
                                            color = MaterialTheme.colorScheme.onSurfaceVariant
                                        )
                                    }
                                }
                                
                                Spacer(modifier = Modifier.height(8.dp))
                                
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    LinearProgressIndicator(
                                        progress = { animatedDeficiencyPercentage },
                                        modifier = Modifier
                                            .weight(1f)
                                            .height(8.dp)
                                            .clip(CircleShape),
                                        color = MaterialTheme.colorScheme.error,
                                        trackColor = MaterialTheme.colorScheme.error.copy(alpha = 0.1f)
                                    )
                                    
                                    Text(
                                        text = "${status.percentage.toInt()}% met",
                                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.ExtraBold),
                                        color = MaterialTheme.colorScheme.error
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    // Google Search Grounding Benefit Popup Dialog
    if (selectedGroundedNutrient != null) {
        AlertDialog(
            onDismissRequest = { viewModel.clearNutrientBenefitGrounding() },
            title = {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Icon(
                        imageVector = Icons.Default.Info,
                        contentDescription = "Clinical Nutrient Benefits",
                        tint = MaterialTheme.colorScheme.primary,
                        modifier = Modifier.size(24.dp)
                    )
                    Text(
                        text = "$selectedGroundedNutrient Benefits",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.onSurface
                    )
                }
            },
            text = {
                Column(
                    verticalArrangement = Arrangement.spacedBy(14.dp),
                    modifier = Modifier.fillMaxWidth()
                ) {
                    if (isGroundedBenefitLoading) {
                        Column(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(vertical = 24.dp),
                            horizontalAlignment = Alignment.CenterHorizontally,
                            verticalArrangement = Arrangement.spacedBy(12.dp)
                        ) {
                            CircularProgressIndicator(
                                modifier = Modifier.size(32.dp),
                                strokeWidth = 3.dp,
                                color = MaterialTheme.colorScheme.primary
                            )
                            Text(
                                text = "Grounding via Google Search...",
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }
                    } else {
                        Text(
                            text = groundedBenefitText ?: "No coverage data loaded from clinical sources.",
                            style = MaterialTheme.typography.bodyMedium,
                            lineHeight = 20.sp,
                            color = MaterialTheme.colorScheme.onSurface
                        )

                        if (groundedBenefitSources.isNotEmpty()) {
                            HorizontalDivider(color = MaterialTheme.colorScheme.outline.copy(alpha = 0.15f))
                            
                            Text(
                                text = "Verified Grounded Sources & Clinician References:",
                                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.primary
                            )

                            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                                groundedBenefitSources.forEach { (title, uri) ->
                                    Row(
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .clip(RoundedCornerShape(8.dp))
                                            .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f))
                                            .clickable {
                                                try {
                                                    val intent = android.content.Intent(
                                                        android.content.Intent.ACTION_VIEW,
                                                        android.net.Uri.parse(uri)
                                                    )
                                                    context.startActivity(intent)
                                                } catch (e: Exception) {
                                                    android.widget.Toast.makeText(context, "Link unavailable offline", android.widget.Toast.LENGTH_SHORT).show()
                                                }
                                            }
                                            .padding(horizontal = 12.dp, vertical = 10.dp),
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.SpaceBetween
                                    ) {
                                        Text(
                                            text = title,
                                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.SemiBold),
                                            color = MaterialTheme.colorScheme.primary,
                                            maxLines = 1,
                                            overflow = TextOverflow.Ellipsis,
                                            modifier = Modifier.weight(1f)
                                        )
                                        Icon(
                                            imageVector = Icons.Default.Share,
                                            contentDescription = "Open medical reference source URL",
                                            tint = MaterialTheme.colorScheme.secondary,
                                            modifier = Modifier.size(14.dp)
                                        )
                                    }
                                }
                            }
                        }
                    }
                }
            },
            confirmButton = {
                TextButton(
                    onClick = { viewModel.clearNutrientBenefitGrounding() },
                    modifier = Modifier.testTag("dismiss_benefit_dialog_btn")
                ) {
                    Text(
                        text = "Dismiss",
                        style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                }
            },
            shape = RoundedCornerShape(20.dp),
            tonalElevation = 6.dp
        )
    }
}

@Composable
fun ContextualNutritionTipCard(viewModel: NutritionViewModel) {
    val dailyNutrients by viewModel.dailyNutrients.collectAsState()
    
    val belowRdaNutrients = remember(dailyNutrients) {
        dailyNutrients.filter { 
            !it.definition.isMaxLimit && 
            it.intake < it.definition.rda && 
            it.definition.rda > 0.0 
        }.sortedBy { it.percentage }
    }
    
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .testTag("contextual_nutrition_tips_card"),
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.08f)
        ),
        border = BorderStroke(1.2.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.25f))
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                Box(
                    modifier = Modifier
                        .size(36.dp)
                        .background(MaterialTheme.colorScheme.primary.copy(alpha = 0.12f), CircleShape),
                    contentAlignment = Alignment.Center
                ) {
                    Icon(
                        imageVector = Icons.Default.Info,
                        contentDescription = "Tips Icon",
                        tint = MaterialTheme.colorScheme.primary,
                        modifier = Modifier.size(18.dp)
                    )
                }
                Column {
                    Text(
                        text = "💡 Contextual Nutrition Tips",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.onSurface
                    )
                    Text(
                        text = "Real food suggestions high in your currently flagged RDA gaps",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }
            
            Spacer(modifier = Modifier.height(12.dp))
            
            if (belowRdaNutrients.isEmpty()) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color(0xFFE8F5E9), RoundedCornerShape(12.dp))
                        .padding(12.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Row(
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Icon(
                            imageVector = Icons.Default.CheckCircle,
                            contentDescription = "Success",
                            tint = Color(0xFF2E7D32),
                            modifier = Modifier.size(18.dp)
                        )
                        Text(
                            text = "A perfect day! All RDA targets fully completed.",
                            style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                            color = Color(0xFF2E7D32)
                        )
                    }
                }
            } else {
                val topGaps = belowRdaNutrients.take(4)
                
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    topGaps.forEach { gap ->
                        val def = gap.definition
                        val percent = gap.percentage.toInt()
                        val isCritical = percent < 50
                        
                        Card(
                            colors = CardDefaults.cardColors(
                                containerColor = MaterialTheme.colorScheme.surface
                            ),
                            border = BorderStroke(
                                1.dp, 
                                if (isCritical) MaterialTheme.colorScheme.error.copy(alpha = 0.25f)
                                else Color(0xFFF0932B).copy(alpha = 0.25f)
                            ),
                            shape = RoundedCornerShape(12.dp),
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Column(modifier = Modifier.padding(12.dp)) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Row(
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                                    ) {
                                        Box(
                                            modifier = Modifier
                                                .size(8.dp)
                                                .background(
                                                    if (isCritical) MaterialTheme.colorScheme.error
                                                    else Color(0xFFF0932B),
                                                    CircleShape
                                                )
                                        )
                                        Text(
                                            text = def.name,
                                            style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.Bold),
                                            color = MaterialTheme.colorScheme.onSurface
                                        )
                                    }
                                    
                                    Box(
                                        modifier = Modifier
                                            .clip(RoundedCornerShape(8.dp))
                                            .background(
                                                if (isCritical) MaterialTheme.colorScheme.errorContainer.copy(alpha = 0.5f)
                                                else Color(0xFFFDF2E9)
                                            )
                                            .padding(horizontal = 8.dp, vertical = 2.dp)
                                    ) {
                                        Text(
                                            text = "$percent% met",
                                            style = MaterialTheme.typography.labelSmall.copy(
                                                fontWeight = FontWeight.Bold,
                                                color = if (isCritical) MaterialTheme.colorScheme.error else Color(0xFFD35400)
                                            )
                                        )
                                    }
                                }
                                
                                Spacer(modifier = Modifier.height(6.dp))
                                
                                Text(
                                    text = "💡 Superfoods: " + getDenseFoodSources(def.key),
                                    style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Medium),
                                    color = MaterialTheme.colorScheme.primary
                                )
                                
                                Spacer(modifier = Modifier.height(6.dp))
                                
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.End
                                ) {
                                    TextButton(
                                        onClick = {
                                            viewModel.setOnlineSearchQuery(def.name)
                                            viewModel.performOnlineFoodSearch(def.name)
                                        },
                                        modifier = Modifier.height(32.dp).testTag("quick_search_${def.key}_button")
                                    ) {
                                        Icon(
                                            imageVector = Icons.Default.Search,
                                            contentDescription = "Search ${def.name}",
                                            modifier = Modifier.size(14.dp)
                                        )
                                        Spacer(modifier = Modifier.width(4.dp))
                                        Text(
                                            text = "Search USDA Foods",
                                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold)
                                        )
                                    }
                                }
                            }
                        }
                    }
                    
                    if (belowRdaNutrients.size > 4) {
                        Text(
                            text = "+ ${belowRdaNutrients.size - 4} more active RDA gaps detected. Achieve 100% across all 41 tracked nutrient boundaries to fully complete daily targets.",
                            style = MaterialTheme.typography.labelSmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant,
                            modifier = Modifier.padding(horizontal = 4.dp, vertical = 2.dp)
                        )
                    }
                }
            }
        }
    }
}

@OptIn(androidx.compose.material3.ExperimentalMaterial3Api::class)
@Composable
fun AiDrivenRecipeRecommenderCard(viewModel: NutritionViewModel) {
    val recipes by viewModel.aiSuggestedRecipes.collectAsState()
    val isLoading by viewModel.isRecipesLoading.collectAsState()
    val error by viewModel.recipesError.collectAsState()
    val onlineResults by viewModel.onlineSearchResults.collectAsState()
    val isSearchingOnline by viewModel.isOnlineSearching.collectAsState()

    var searchQuery by remember { mutableStateOf("") }
    var selectedIngredientForUsda by remember { mutableStateOf<String?>(null) }
    var activeMealType by remember { mutableStateOf("Lunch") }
    var ingredientServingText by remember { mutableStateOf("100.0") }

    val context = androidx.compose.ui.platform.LocalContext.current

    // Trigger an initial recipe load when the screen is shown and no recipes are loaded yet
    LaunchedEffect(Unit) {
        if (recipes.isEmpty()) {
            viewModel.fetchRecipeSuggestions("")
        }
    }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .testTag("ai_recipe_recommender_card"),
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
        border = BorderStroke(1.dp, MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.5f))
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            // Header
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(10.dp)
            ) {
                Box(
                    modifier = Modifier
                        .size(36.dp)
                        .background(MaterialTheme.colorScheme.primary.copy(alpha = 0.12f), CircleShape),
                    contentAlignment = Alignment.Center
                ) {
                    Icon(
                        imageVector = Icons.Default.Menu,
                        contentDescription = "Recipe Icon",
                        tint = MaterialTheme.colorScheme.primary,
                        modifier = Modifier.size(18.dp)
                    )
                }
                Column {
                    Text(
                        text = "🍳 AI Recipe Recommender (USDA Integrated)",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    Text(
                        text = "Get customized recipes that replenish your active RDA gaps",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }

            Spacer(modifier = Modifier.height(12.dp))

            // Search Bar Row
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                OutlinedTextField(
                    value = searchQuery,
                    onValueChange = { searchQuery = it },
                    placeholder = { Text("Search recipes e.g., dinner, smoothie, low carb...", fontSize = 12.sp) },
                    singleLine = true,
                    textStyle = MaterialTheme.typography.bodySmall,
                    modifier = Modifier
                        .weight(1f)
                        .height(48.dp)
                        .testTag("recipe_search_input"),
                    trailingIcon = {
                        if (searchQuery.isNotEmpty()) {
                            IconButton(onClick = { searchQuery = "" }) {
                                Icon(
                                    imageVector = Icons.Default.Close,
                                    contentDescription = "Clear search",
                                    modifier = Modifier.size(16.dp)
                                )
                            }
                        }
                    },
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = MaterialTheme.colorScheme.primary,
                        unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.3f)
                    )
                )

                Button(
                    onClick = { viewModel.fetchRecipeSuggestions(searchQuery, forceGemini = true) },
                    modifier = Modifier
                        .height(44.dp)
                        .testTag("recipe_search_button"),
                    contentPadding = PaddingValues(horizontal = 16.dp)
                ) {
                    if (isLoading) {
                        CircularProgressIndicator(
                            modifier = Modifier.size(16.dp),
                            strokeWidth = 2.dp,
                            color = MaterialTheme.colorScheme.onPrimary
                        )
                    } else {
                        Text("Search", style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold))
                    }
                }
            }

            if (error != null) {
                Spacer(modifier = Modifier.height(8.dp))
                val context = androidx.compose.ui.platform.LocalContext.current
                val clipboardManager = androidx.compose.ui.platform.LocalClipboardManager.current
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clickable {
                            clipboardManager.setText(androidx.compose.ui.text.AnnotatedString(error ?: ""))
                            android.widget.Toast.makeText(context, "Error copied!", android.widget.Toast.LENGTH_SHORT).show()
                        }
                        .padding(horizontal = 4.dp, vertical = 4.dp),
                    verticalAlignment = androidx.compose.ui.Alignment.CenterVertically
                ) {
                    Icon(
                        imageVector = Icons.Default.Share,
                        contentDescription = "Copy Error",
                        tint = MaterialTheme.colorScheme.error,
                        modifier = Modifier.size(14.dp)
                    )
                    Spacer(modifier = Modifier.width(6.dp))
                    Text(
                        text = "${error ?: ""} (Tap to copy)",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.error
                    )
                }
            }

            Spacer(modifier = Modifier.height(12.dp))

            // Recipes List
            if (recipes.isEmpty() && !isLoading) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 16.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = "No custom recipe matches found. Try searching another category or ingredient.",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            } else {
                Column(verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    recipes.forEachIndexed { recipeIdx, recipe ->
                        Card(
                            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.2f)),
                            shape = RoundedCornerShape(12.dp),
                            border = BorderStroke(1.dp, MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.3f)),
                            modifier = Modifier.fillMaxWidth().testTag("suggested_recipe_card_$recipeIdx")
                        ) {
                            Column(modifier = Modifier.padding(12.dp)) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Text(
                                        text = recipe.recipeName,
                                        style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                                        color = MaterialTheme.colorScheme.onSurface,
                                        modifier = Modifier.weight(1f)
                                    )
                                    
                                    Box(
                                        modifier = Modifier
                                            .clip(RoundedCornerShape(8.dp))
                                            .background(MaterialTheme.colorScheme.primaryContainer)
                                            .padding(horizontal = 8.dp, vertical = 2.dp)
                                    ) {
                                        Text(
                                            text = recipe.prepTime,
                                            style = MaterialTheme.typography.labelSmall.copy(
                                                fontWeight = FontWeight.Bold,
                                                color = MaterialTheme.colorScheme.onPrimaryContainer
                                            )
                                        )
                                    }
                                }

                                Spacer(modifier = Modifier.height(6.dp))

                                // Targeted nutrients badge
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.spacedBy(4.dp),
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Icon(
                                        imageVector = Icons.Default.Favorite,
                                        contentDescription = "Targeted Nutrients",
                                        tint = MaterialTheme.colorScheme.error,
                                        modifier = Modifier.size(12.dp)
                                    )
                                    Text(
                                        text = "Targets: " + recipe.targetedNutrients,
                                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                        color = MaterialTheme.colorScheme.error
                                    )
                                }

                                Spacer(modifier = Modifier.height(8.dp))

                                Text(
                                    text = recipe.description,
                                    style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )

                                Spacer(modifier = Modifier.height(10.dp))

                                HorizontalDivider(color = MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.4f))

                                Spacer(modifier = Modifier.height(8.dp))

                                // Ingredients
                                Text(
                                    text = "Ingredients (USDA Search Available):",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )

                                Spacer(modifier = Modifier.height(4.dp))

                                Column(verticalArrangement = Arrangement.spacedBy(6.dp)) {
                                    recipe.ingredients.forEachIndexed { ingIdx, ingredient ->
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.SpaceBetween,
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Text(
                                                text = "• $ingredient",
                                                style = MaterialTheme.typography.bodySmall,
                                                color = MaterialTheme.colorScheme.onSurface,
                                                modifier = Modifier.weight(1f)
                                            )

                                            // Search USDA button
                                            val cleanIngredient = remember(ingredient) {
                                                ingredient.replace(Regex("[0-9]|g|tbsp|tsp|cup|ml|oz|Serving|Medium|Fresh|Organic|Wild-Caught|Plain|Whole|Cooked|Brown|Baby|Slice|Mini|clove|cup\\(s\\)"), "").trim()
                                            }

                                            TextButton(
                                                onClick = {
                                                    selectedIngredientForUsda = cleanIngredient
                                                    viewModel.performOnlineFoodSearch(cleanIngredient)
                                                    ingredientServingText = "100.0"
                                                },
                                                modifier = Modifier
                                                    .height(28.dp)
                                                    .testTag("recipe_${recipeIdx}_ingredient_search_${ingIdx}"),
                                                contentPadding = PaddingValues(horizontal = 6.dp)
                                            ) {
                                                Icon(
                                                    imageVector = Icons.Default.Search,
                                                    contentDescription = "Search USDA for $cleanIngredient",
                                                    modifier = Modifier.size(10.dp)
                                                )
                                                Spacer(modifier = Modifier.width(2.dp))
                                                Text(
                                                    text = "Search USDA",
                                                    style = MaterialTheme.typography.labelSmall.copy(fontSize = 10.sp)
                                                )
                                            }
                                        }
                                    }
                                }

                                Spacer(modifier = Modifier.height(10.dp))

                                // Instructions
                                Text(
                                    text = "Cooking Steps:",
                                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )

                                Spacer(modifier = Modifier.height(4.dp))

                                recipe.instructions.forEachIndexed { instIdx, instruction ->
                                    Text(
                                        text = "${instIdx + 1}. $instruction",
                                        style = MaterialTheme.typography.bodySmall,
                                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                                        modifier = Modifier.padding(vertical = 2.dp)
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    // USDA Ingredient Search Results Dialog
    if (selectedIngredientForUsda != null) {
        AlertDialog(
            onDismissRequest = { selectedIngredientForUsda = null },
            title = {
                Text(
                    text = "USDA Matches: ${selectedIngredientForUsda}",
                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold)
                )
            },
            text = {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .heightIn(max = 400.dp),
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    Text(
                        text = "Match real nutritional content directly from the USDA database and log it instantly to your daily food journal.",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )

                    // Meal Type selector
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(
                            text = "Meal:",
                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold)
                        )
                        
                        listOf("Breakfast", "Lunch", "Dinner", "Snack").forEach { meal ->
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(8.dp))
                                    .background(
                                        if (activeMealType == meal) MaterialTheme.colorScheme.primaryContainer
                                        else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
                                    )
                                    .clickable { activeMealType = meal }
                                    .padding(horizontal = 8.dp, vertical = 4.dp)
                            ) {
                                Text(
                                    text = meal,
                                    style = MaterialTheme.typography.labelSmall.copy(
                                        fontWeight = FontWeight.Bold,
                                        color = if (activeMealType == meal) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                )
                            }
                        }
                    }

                    // Serving size textfield
                    OutlinedTextField(
                        value = ingredientServingText,
                        onValueChange = { ingredientServingText = it },
                        label = { Text("Log serving weight (grams/servings)", fontSize = 11.sp) },
                        singleLine = true,
                        textStyle = MaterialTheme.typography.bodySmall,
                        modifier = Modifier.fillMaxWidth().height(52.dp).testTag("dialog_serving_input")
                    )

                    HorizontalDivider(color = MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.3f))

                    if (isSearchingOnline) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(150.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            CircularProgressIndicator(color = MaterialTheme.colorScheme.primary)
                        }
                    } else if (onlineResults.isEmpty()) {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(150.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            Text(
                                text = "No matching USDA ingredients found.",
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }
                    } else {
                        LazyColumn(
                            verticalArrangement = Arrangement.spacedBy(8.dp),
                            modifier = Modifier.weight(1f)
                        ) {
                            items(onlineResults.size) { index ->
                                val result = onlineResults[index]
                                Card(
                                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.15f)),
                                    border = BorderStroke(1.dp, MaterialTheme.colorScheme.outlineVariant.copy(alpha = 0.25f)),
                                    modifier = Modifier.fillMaxWidth().testTag("dialog_search_result_card_$index")
                                ) {
                                    Column(modifier = Modifier.padding(10.dp)) {
                                        Text(
                                            text = result.name,
                                            style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                            color = MaterialTheme.colorScheme.onSurface
                                        )
                                        if (!result.brandName.isNullOrBlank()) {
                                            Text(
                                                text = "Brand: ${result.brandName}",
                                                style = MaterialTheme.typography.labelSmall,
                                                color = MaterialTheme.colorScheme.onSurfaceVariant
                                            )
                                        }

                                        Spacer(modifier = Modifier.height(4.dp))

                                        val cals = result.nutrients["calories"] ?: 0.0
                                        val prot = result.nutrients["protein"] ?: 0.0
                                        val carb = result.nutrients["carbohydrates"] ?: 0.0
                                        val fat = result.nutrients["fat"] ?: 0.0
                                        
                                        Text(
                                            text = "%.0f kcal | P: %.1fg C: %.1fg F: %.1fg (per %s)".format(
                                                cals, prot, carb, fat, "${result.servingSize}${result.servingSizeUnit}"
                                            ),
                                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Medium),
                                            color = MaterialTheme.colorScheme.primary
                                        )

                                        Spacer(modifier = Modifier.height(8.dp))

                                        Button(
                                            onClick = {
                                                val qty = ingredientServingText.toDoubleOrNull() ?: result.servingSize
                                                viewModel.logOnlineFoodItem(
                                                    foodName = result.name,
                                                    mealType = activeMealType,
                                                    quantity = qty,
                                                    unit = result.servingSizeUnit,
                                                    nutrients = result.nutrients,
                                                    source = result.source
                                                )
                                                Toast.makeText(
                                                    context,
                                                    "Successfully logged ${result.name} to $activeMealType!",
                                                    Toast.LENGTH_SHORT
                                                ).show()
                                                selectedIngredientForUsda = null
                                            },
                                            modifier = Modifier
                                                .align(Alignment.End)
                                                .height(30.dp)
                                                .testTag("dialog_log_button_$index"),
                                            colors = ButtonDefaults.buttonColors(containerColor = MaterialTheme.colorScheme.primary),
                                            contentPadding = PaddingValues(horizontal = 10.dp)
                                        ) {
                                            Text("Log Item", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold, color = Color.White))
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            },
            confirmButton = {
                TextButton(onClick = { selectedIngredientForUsda = null }) {
                    Text("Close")
                }
            }
        )
    }
}

@OptIn(androidx.compose.material3.ExperimentalMaterial3Api::class)
@Composable
fun InteractiveRdaNutrientRechartsChartCard(viewModel: NutritionViewModel) {
    val dailyNutrients by viewModel.dailyNutrients.collectAsState()
    
    // Manage which group of nutrients is currently selected
    var selectedGroup by remember { mutableStateOf(com.example.data.NutrientGroup.MACROS) }
    
    // Hover/drag interaction state
    var activeNutrientIndex by remember { mutableStateOf<Int?>(null) }
    var touchPosition by remember { mutableStateOf(androidx.compose.ui.geometry.Offset.Zero) }
    
    // Filter the daily nutrients to only display the selected group
    val groupNutrients = remember(dailyNutrients, selectedGroup) {
        dailyNutrients.filter { it.definition.group == selectedGroup }
    }
    
    val density = androidx.compose.ui.platform.LocalDensity.current
    
    // Dynamic height based on number of nutrients to prevent cramming or stretching
    val rowHeightDp = 42.dp
    val topPaddingDp = 20.dp
    val bottomPaddingDp = 30.dp
    val leftMarginDp = 110.dp
    val rightMarginDp = 48.dp
    
    val canvasHeightDp = rowHeightDp * groupNutrients.size + topPaddingDp + bottomPaddingDp
    
    // Theme colors & settings
    val isDark = androidx.compose.foundation.isSystemInDarkTheme()
    val gridColor = if (isDark) androidx.compose.ui.graphics.Color(0xFF444444) else androidx.compose.ui.graphics.Color(0xFFE2E8F0)
    val rdaLineColor = if (isDark) androidx.compose.ui.graphics.Color(0xFFEF4444) else androidx.compose.ui.graphics.Color(0xFFEF4444)
    val textColor = if (isDark) androidx.compose.ui.graphics.Color(0xFFE2E8F0) else androidx.compose.ui.graphics.Color(0xFF334155)
    val valueTextColor = if (isDark) androidx.compose.ui.graphics.Color(0xFF94A3B8) else androidx.compose.ui.graphics.Color(0xFF64748B)
    
    // Theme color representing each group
    val themeColor = when (selectedGroup) {
        com.example.data.NutrientGroup.MACROS -> androidx.compose.ui.graphics.Color(0xFF3B82F6) // Blue
        com.example.data.NutrientGroup.LIPIDS -> androidx.compose.ui.graphics.Color(0xFFF43F5E) // Rose/Red
        com.example.data.NutrientGroup.VITAMINS -> androidx.compose.ui.graphics.Color(0xFFF59E0B) // Amber
        com.example.data.NutrientGroup.MINERALS -> androidx.compose.ui.graphics.Color(0xFF0D9488) // Teal
        com.example.data.NutrientGroup.OTHERS -> androidx.compose.ui.graphics.Color(0xFF8B5CF6) // Purple
    }
    
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .testTag("interactive_rda_recharts_card"),
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(
            containerColor = if (isDark) androidx.compose.ui.graphics.Color(0xFF1E293B) else androidx.compose.ui.graphics.Color(0xFFF8FAFC)
        ),
        border = BorderStroke(1.5.dp, if (isDark) androidx.compose.ui.graphics.Color(0xFF334155) else androidx.compose.ui.graphics.Color(0xFFE2E8F0))
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            // Header
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Box(
                        modifier = Modifier
                            .size(36.dp)
                            .background(themeColor.copy(alpha = 0.12f), CircleShape),
                        contentAlignment = Alignment.Center
                    ) {
                        Icon(
                            imageVector = Icons.Default.Info,
                            contentDescription = null,
                            tint = themeColor,
                            modifier = Modifier.size(18.dp)
                        )
                    }
                    Column {
                        Text(
                            text = "Interactive Nutrient Chart",
                            style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onSurface
                        )
                        Text(
                            text = "Drag or tap the bars to inspect details",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            }
            
            Spacer(modifier = Modifier.height(14.dp))
            
            // Group Selection Tabs
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .horizontalScroll(rememberScrollState()),
                horizontalArrangement = Arrangement.spacedBy(6.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                com.example.data.NutrientGroup.values().forEach { group ->
                    val isSelected = selectedGroup == group
                    val gColor = when (group) {
                        com.example.data.NutrientGroup.MACROS -> androidx.compose.ui.graphics.Color(0xFF3B82F6)
                        com.example.data.NutrientGroup.LIPIDS -> androidx.compose.ui.graphics.Color(0xFFF43F5E)
                        com.example.data.NutrientGroup.VITAMINS -> androidx.compose.ui.graphics.Color(0xFFF59E0B)
                        com.example.data.NutrientGroup.MINERALS -> androidx.compose.ui.graphics.Color(0xFF0D9488)
                        com.example.data.NutrientGroup.OTHERS -> androidx.compose.ui.graphics.Color(0xFF8B5CF6)
                    }
                    
                    Box(
                        modifier = Modifier
                            .clip(RoundedCornerShape(8.dp))
                            .background(
                                if (isSelected) gColor else gColor.copy(alpha = 0.08f)
                            )
                            .clickable {
                                selectedGroup = group
                                activeNutrientIndex = null
                            }
                            .padding(horizontal = 10.dp, vertical = 6.dp)
                    ) {
                        Text(
                            text = group.displayName,
                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                            color = if (isSelected) androidx.compose.ui.graphics.Color.White else gColor
                        )
                    }
                }
            }
            
            Spacer(modifier = Modifier.height(16.dp))
            
            // The Interactive Chart Area
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(canvasHeightDp)
            ) {
                val textMeasurer = androidx.compose.ui.text.rememberTextMeasurer()
                
                Canvas(
                    modifier = Modifier
                        .fillMaxSize()
                        .testTag("interactive_rda_recharts_canvas")
                        .pointerInput(groupNutrients) {
                            detectDragGestures(
                                onDragStart = { offset ->
                                    val topPaddingPx = with(density) { topPaddingDp.toPx() }
                                    val rowHeightPx = with(density) { rowHeightDp.toPx() }
                                    val rowIdx = ((offset.y - topPaddingPx) / rowHeightPx).toInt()
                                    if (rowIdx in 0..groupNutrients.lastIndex) {
                                        activeNutrientIndex = rowIdx
                                        touchPosition = offset
                                    }
                                },
                                onDrag = { change, dragAmount ->
                                    val topPaddingPx = with(density) { topPaddingDp.toPx() }
                                    val rowHeightPx = with(density) { rowHeightDp.toPx() }
                                    val rowIdx = ((change.position.y - topPaddingPx) / rowHeightPx).toInt()
                                    if (rowIdx in 0..groupNutrients.lastIndex) {
                                        activeNutrientIndex = rowIdx
                                        touchPosition = change.position
                                    } else {
                                        activeNutrientIndex = null
                                    }
                                },
                                onDragEnd = { activeNutrientIndex = null },
                                onDragCancel = { activeNutrientIndex = null }
                            )
                        }
                        .pointerInput(groupNutrients) {
                            detectTapGestures(
                                onPress = { offset ->
                                    val topPaddingPx = with(density) { topPaddingDp.toPx() }
                                    val rowHeightPx = with(density) { rowHeightDp.toPx() }
                                    val rowIdx = ((offset.y - topPaddingPx) / rowHeightPx).toInt()
                                    if (rowIdx in 0..groupNutrients.lastIndex) {
                                        activeNutrientIndex = rowIdx
                                        touchPosition = offset
                                    }
                                    tryAwaitRelease()
                                    activeNutrientIndex = null
                                }
                            )
                        }
                ) {
                    val w = size.width
                    val h = size.height
                    
                    val leftMarginPx = with(density) { leftMarginDp.toPx() }
                    val rightMarginPx = with(density) { rightMarginDp.toPx() }
                    val topPaddingPx = with(density) { topPaddingDp.toPx() }
                    val bottomPaddingPx = with(density) { bottomPaddingDp.toPx() }
                    val rowHeightPx = with(density) { rowHeightDp.toPx() }
                    
                    val chartWidth = w - leftMarginPx - rightMarginPx
                    
                    // 1. Draw Grid Lines at 50%, 100%, 150%
                    val ticks = listOf(0.5f, 1.0f, 1.5f)
                    ticks.forEach { tick ->
                        val x = leftMarginPx + chartWidth * (tick / 1.5f)
                        drawLine(
                            color = if (tick == 1.0f) rdaLineColor.copy(alpha = 0.5f) else gridColor.copy(alpha = 0.3f),
                            start = androidx.compose.ui.geometry.Offset(x, topPaddingPx),
                            end = androidx.compose.ui.geometry.Offset(x, h - bottomPaddingPx),
                            strokeWidth = if (tick == 1.0f) 2.dp.toPx() else 1.dp.toPx(),
                            pathEffect = androidx.compose.ui.graphics.PathEffect.dashPathEffect(floatArrayOf(10f, 10f), 0f)
                        )
                        
                        // Tick text at bottom
                        val tickText = "${(tick * 100).toInt()}%"
                        val measuredText = textMeasurer.measure(
                            text = tickText,
                            style = androidx.compose.ui.text.TextStyle(
                                color = valueTextColor,
                                fontSize = 9.sp,
                                fontWeight = FontWeight.Bold
                            )
                        )
                        drawText(
                            textLayoutResult = measuredText,
                            topLeft = androidx.compose.ui.geometry.Offset(x - measuredText.size.width / 2, h - bottomPaddingPx + 4.dp.toPx())
                        )
                    }
                    
                    // Draw Label "RDA Target" above 100% tick
                    val rdaTargetX = leftMarginPx + chartWidth * (1.0f / 1.5f)
                    val rdaLabelText = textMeasurer.measure(
                        text = "RDA Target",
                        style = androidx.compose.ui.text.TextStyle(
                            color = rdaLineColor,
                            fontSize = 8.sp,
                            fontWeight = FontWeight.ExtraBold
                        )
                    )
                    drawText(
                        textLayoutResult = rdaLabelText,
                        topLeft = androidx.compose.ui.geometry.Offset(rdaTargetX - rdaLabelText.size.width / 2, 2.dp.toPx())
                    )
                    
                    // 2. Draw Rows & Bars
                    groupNutrients.forEachIndexed { idx, status ->
                        val yRowTop = topPaddingPx + idx * rowHeightPx
                        val yCenter = yRowTop + rowHeightPx / 2
                        
                        // If active, draw highlight background block
                        if (activeNutrientIndex == idx) {
                            drawRoundRect(
                                color = themeColor.copy(alpha = 0.08f),
                                topLeft = androidx.compose.ui.geometry.Offset(0f, yRowTop),
                                size = androidx.compose.ui.geometry.Size(w, rowHeightPx),
                                cornerRadius = androidx.compose.ui.geometry.CornerRadius(8.dp.toPx(), 8.dp.toPx())
                            )
                        }
                        
                        // Draw Left Label (Nutrient Name)
                        val nameText = textMeasurer.measure(
                            text = status.definition.name,
                            style = androidx.compose.ui.text.TextStyle(
                                color = textColor,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.SemiBold
                            )
                        )
                        drawText(
                            textLayoutResult = nameText,
                            topLeft = androidx.compose.ui.geometry.Offset(8.dp.toPx(), yCenter - nameText.size.height / 2)
                        )
                        
                        // Draw Bar Track
                        val barH = 14.dp.toPx()
                        val barY = yCenter - barH / 2
                        
                        drawRoundRect(
                            color = if (isDark) androidx.compose.ui.graphics.Color(0xFF334155) else androidx.compose.ui.graphics.Color(0xFFE2E8F0),
                            topLeft = androidx.compose.ui.geometry.Offset(leftMarginPx, barY),
                            size = androidx.compose.ui.geometry.Size(chartWidth, barH),
                            cornerRadius = androidx.compose.ui.geometry.CornerRadius(6.dp.toPx(), 6.dp.toPx())
                        )
                        
                        // Draw Bar Fill
                        val percentage = status.percentage
                        val barFillWidthFraction = (percentage / 150.0).coerceIn(0.0, 1.0).toFloat()
                        val barFillWidth = barFillWidthFraction * chartWidth
                        
                        // Decide color of bar (Limit exceeding or deficiency coloring)
                        val isLimit = status.definition.isMaxLimit
                        val fillColor = if (isLimit && percentage > 100.0) {
                            androidx.compose.ui.graphics.Color(0xFFEF4444) // Over Limit is Red
                        } else if (!isLimit && percentage < 50.0) {
                            androidx.compose.ui.graphics.Color(0xFFEF4444) // Critical deficit is Red
                        } else if (!isLimit && percentage >= 100.0) {
                            androidx.compose.ui.graphics.Color(0xFF10B981) // Completed is bright Emerald Green
                        } else {
                            themeColor // Standard themed group color
                        }
                        
                        if (barFillWidth > 0f) {
                            drawRoundRect(
                                color = fillColor,
                                topLeft = androidx.compose.ui.geometry.Offset(leftMarginPx, barY),
                                size = androidx.compose.ui.geometry.Size(barFillWidth, barH),
                                cornerRadius = androidx.compose.ui.geometry.CornerRadius(6.dp.toPx(), 6.dp.toPx())
                            )
                        }
                        
                        // Draw Value text at the end of the bar (if space permits)
                        val valueStr = "${percentage.toInt()}%"
                        val valueText = textMeasurer.measure(
                            text = valueStr,
                            style = androidx.compose.ui.text.TextStyle(
                                color = if (percentage >= 100.0 && !isLimit) androidx.compose.ui.graphics.Color(0xFF10B981) else textColor,
                                fontSize = 10.sp,
                                fontWeight = FontWeight.Bold
                            )
                        )
                        drawText(
                            textLayoutResult = valueText,
                            topLeft = androidx.compose.ui.geometry.Offset(w - rightMarginPx + 6.dp.toPx(), yCenter - valueText.size.height / 2)
                        )
                    }
                }
                
                // Floating Tooltip Card overlay
                if (activeNutrientIndex != null && activeNutrientIndex!! in groupNutrients.indices) {
                    val status = groupNutrients[activeNutrientIndex!!]
                    val def = status.definition
                    val percentage = status.percentage
                    val isLimit = def.isMaxLimit
                    
                    // Constrain tooltip coordinate within canvas box
                    val tooltipWidthDp = 220.dp
                    val tooltipHeightDp = 170.dp
                    
                    val densityMultiplier = density.density
                    
                    // Position tooltip horizontally and vertically relative to touch
                    val touchXDp = touchPosition.x / densityMultiplier
                    val touchYDp = touchPosition.y / densityMultiplier
                    
                    // Center the tooltip horizontally above the touch
                    var posX = touchXDp - (tooltipWidthDp.value / 2)
                    var posY = touchYDp - (tooltipHeightDp.value + 12)
                    
                    // Prevent horizontal clipping (assume parent width constraints or typical screen widths)
                    if (posX < 8) posX = 8f
                    
                    // Prevent vertical clipping (if too close to top, show below the touch)
                    if (posY < 4) {
                        posY = touchYDp + 16
                    }
                    
                    Card(
                        modifier = Modifier
                            .size(width = tooltipWidthDp, height = tooltipHeightDp)
                            .offset(x = posX.dp, y = posY.dp)
                            .testTag("interactive_rda_tooltip"),
                        colors = CardDefaults.cardColors(
                            containerColor = MaterialTheme.colorScheme.inverseSurface.copy(alpha = 0.96f)
                        ),
                        elevation = CardDefaults.cardElevation(defaultElevation = 8.dp),
                        shape = RoundedCornerShape(12.dp),
                        border = BorderStroke(1.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.2f))
                    ) {
                        Column(
                            modifier = Modifier
                                .fillMaxSize()
                                .padding(10.dp),
                            verticalArrangement = Arrangement.spacedBy(4.dp)
                        ) {
                            // Title & Group
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween,
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Text(
                                    text = def.name,
                                    style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.ExtraBold),
                                    color = MaterialTheme.colorScheme.inverseOnSurface,
                                    maxLines = 1,
                                    overflow = TextOverflow.Ellipsis,
                                    modifier = Modifier.weight(1f)
                                )
                                
                                // Mini status badge
                                val (statusText, statusColor) = when {
                                    isLimit -> if (percentage <= 100.0) "SAFE" to androidx.compose.ui.graphics.Color(0xFF10B981) else "EXCEEDED" to androidx.compose.ui.graphics.Color(0xFFEF4444)
                                    percentage >= 100.0 -> "MET" to androidx.compose.ui.graphics.Color(0xFF10B981)
                                    percentage >= 50.0 -> "SUBOPTIMAL" to androidx.compose.ui.graphics.Color(0xFFF59E0B)
                                    else -> "CRITICAL" to androidx.compose.ui.graphics.Color(0xFFEF4444)
                                }
                                
                                Box(
                                    modifier = Modifier
                                        .clip(RoundedCornerShape(4.dp))
                                        .background(statusColor.copy(alpha = 0.2f))
                                        .padding(horizontal = 4.dp, vertical = 2.dp)
                                ) {
                                    Text(
                                        text = statusText,
                                        style = MaterialTheme.typography.labelSmall.copy(
                                            fontSize = 8.sp,
                                            fontWeight = FontWeight.ExtraBold,
                                            color = statusColor
                                        )
                                    )
                                }
                            }
                            
                            // Group label
                            Text(
                                text = "Group: ${def.group.displayName}",
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.inverseOnSurface.copy(alpha = 0.6f)
                            )
                            
                            HorizontalDivider(
                                color = MaterialTheme.colorScheme.inverseOnSurface.copy(alpha = 0.12f),
                                thickness = 0.5.dp,
                                modifier = Modifier.padding(vertical = 2.dp)
                            )
                            
                            // Values Comparison
                            Text(
                                text = "Logged: ${String.format(Locale.US, "%.1f", status.intake)} ${def.unit}",
                                style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.inverseOnSurface
                            )
                            Text(
                                text = "Target RDA: ${String.format(Locale.US, "%.1f", def.rda)} ${def.unit} (${percentage.toInt()}% met)",
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.inverseOnSurface.copy(alpha = 0.8f)
                            )
                            
                            // Role
                            Text(
                                text = def.description,
                                style = MaterialTheme.typography.labelSmall.copy(fontSize = 10.sp),
                                color = MaterialTheme.colorScheme.inverseOnSurface.copy(alpha = 0.7f),
                                maxLines = 2,
                                overflow = TextOverflow.Ellipsis,
                                modifier = Modifier.padding(top = 2.dp)
                            )
                            
                            // Best Food Sources
                            Text(
                                text = "💡 Superfoods: ${getDenseFoodSources(def.key)}",
                                style = MaterialTheme.typography.labelSmall.copy(fontSize = 10.sp, fontStyle = androidx.compose.ui.text.font.FontStyle.Italic),
                                color = themeColor,
                                maxLines = 2,
                                overflow = TextOverflow.Ellipsis,
                                modifier = Modifier.padding(top = 2.dp)
                            )
                        }
                    }
                }
            }
        }
    }
}

@OptIn(androidx.compose.material3.ExperimentalMaterial3Api::class)
@Composable
fun AllNutrientsRdaDashboardPanel(viewModel: NutritionViewModel) {
    val dailyNutrients by viewModel.dailyNutrients.collectAsState()
    
    val totalCount = dailyNutrients.size
    
    val metCount = dailyNutrients.count { status ->
        if (status.definition.isMaxLimit) {
            status.percentage <= 100.0
        } else {
            status.percentage >= 100.0
        }
    }
    
    val criticalCount = dailyNutrients.count { !it.definition.isMaxLimit && it.percentage < 50.0 }
    val suboptimalCount = dailyNutrients.count { !it.definition.isMaxLimit && it.percentage in 50.0..99.9 }
    val exceededCount = dailyNutrients.count { it.definition.isMaxLimit && it.percentage > 100.0 }
    
    var searchQuery by remember { mutableStateOf("") }
    var selectedGroupFilter by remember { mutableStateOf<com.example.data.NutrientGroup?>(null) }
    
    var statusFilterState by remember { mutableStateOf(0) }
    
    val filteredList = remember(dailyNutrients, searchQuery, selectedGroupFilter, statusFilterState) {
        dailyNutrients.filter { status ->
            val def = status.definition
            val matchesSearch = def.name.contains(searchQuery, ignoreCase = true) ||
                    def.group.displayName.contains(searchQuery, ignoreCase = true) ||
                    def.description.contains(searchQuery, ignoreCase = true)
            
            val matchesGroup = selectedGroupFilter == null || def.group == selectedGroupFilter
            
            val matchesStatus = when (statusFilterState) {
                0 -> true
                1 -> if (def.isMaxLimit) status.percentage <= 100.0 else status.percentage >= 100.0
                2 -> !def.isMaxLimit && status.percentage in 50.0..99.9
                3 -> !def.isMaxLimit && status.percentage < 50.0
                4 -> def.isMaxLimit && status.percentage > 100.0
                else -> true
            }
            
            matchesSearch && matchesGroup && matchesStatus
        }.sortedWith(
            compareBy<NutrientStatus> { status ->
                when {
                    !status.definition.isMaxLimit && status.percentage < 50.0 -> 0
                    !status.definition.isMaxLimit && status.percentage < 100.0 -> 1
                    status.definition.isMaxLimit && status.percentage > 100.0 -> 2
                    else -> 3
                }
            }.thenBy { it.percentage }
        )
    }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .testTag("all_nutrients_rda_dashboard_panel_card"),
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(
            containerColor = DistinctColorTheme.getCreamDataContainerColor()
        ),
        border = BorderStroke(1.5.dp, DistinctColorTheme.getCreamDataBorderColor())
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    Box(
                        modifier = Modifier
                            .size(38.dp)
                            .background(DistinctColorTheme.getCreamDataContentColor().copy(alpha = 0.12f), CircleShape),
                        contentAlignment = Alignment.Center
                    ) {
                        Icon(
                            imageVector = Icons.Default.Info,
                            contentDescription = "41 Essential Nutrients Dashboard Icon",
                            tint = DistinctColorTheme.getCreamDataContentColor(),
                            modifier = Modifier.size(20.dp)
                        )
                    }
                    Column {
                        Text(
                            text = "41 Nutrients RDA Dashboard",
                            style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                            color = DistinctColorTheme.getCreamDataContentColor()
                        )
                        Text(
                            text = "Comprehensive daily bio-nutrient comparison against RDA",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
                
                Box(
                    modifier = Modifier
                        .clip(RoundedCornerShape(12.dp))
                        .background(
                            if (metCount == totalCount) Color(0xFFE8F5E9)
                            else MaterialTheme.colorScheme.secondaryContainer.copy(alpha = 0.8f)
                        )
                        .padding(horizontal = 10.dp, vertical = 4.dp)
                ) {
                    Text(
                        text = "$metCount / $totalCount Met",
                        style = MaterialTheme.typography.labelSmall.copy(
                            fontWeight = FontWeight.Bold,
                            color = if (metCount == totalCount) Color(0xFF2E7D32) else MaterialTheme.colorScheme.onSecondaryContainer
                        )
                    )
                }
            }
            
            Spacer(modifier = Modifier.height(14.dp))
            
            Column(modifier = Modifier.fillMaxWidth()) {
                val overallFraction = if (totalCount > 0) metCount.toFloat() / totalCount else 0f
                val animatedOverallFraction by androidx.compose.animation.core.animateFloatAsState(
                    targetValue = overallFraction,
                    animationSpec = androidx.compose.animation.core.tween(
                        durationMillis = 800,
                        easing = androidx.compose.animation.core.FastOutSlowInEasing
                    ),
                    label = "overall_fraction_progress"
                )
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        text = "Daily Biochemical Targets Met",
                        style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.SemiBold),
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                    Text(
                        text = "${(overallFraction * 100).toInt()}% Met",
                        style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                }
                Spacer(modifier = Modifier.height(6.dp))
                LinearProgressIndicator(
                    progress = { animatedOverallFraction },
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(8.dp)
                        .clip(CircleShape),
                    color = MaterialTheme.colorScheme.primary,
                    trackColor = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f)
                )
            }
            
            Spacer(modifier = Modifier.height(14.dp))
            
            OutlinedTextField(
                value = searchQuery,
                onValueChange = { searchQuery = it },
                modifier = Modifier
                    .fillMaxWidth()
                    .height(52.dp)
                    .testTag("all_nutrients_search_input"),
                placeholder = { Text("Search 41 nutrients, groups, benefits...", style = MaterialTheme.typography.bodyMedium) },
                leadingIcon = { Icon(Icons.Default.Search, contentDescription = "Search icon", modifier = Modifier.size(18.dp)) },
                trailingIcon = {
                    if (searchQuery.isNotEmpty()) {
                        IconButton(onClick = { searchQuery = "" }) {
                            Icon(Icons.Default.Close, contentDescription = "Clear search", modifier = Modifier.size(16.dp))
                        }
                    }
                },
                singleLine = true,
                colors = OutlinedTextFieldDefaults.colors(
                    focusedBorderColor = MaterialTheme.colorScheme.primary,
                    unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.2f),
                    focusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.15f),
                    unfocusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.15f)
                ),
                shape = RoundedCornerShape(10.dp)
            )
            
            Spacer(modifier = Modifier.height(10.dp))
            
            ScrollableTabRow(
                selectedTabIndex = statusFilterState,
                edgePadding = 0.dp,
                indicator = {},
                divider = {},
                modifier = Modifier.fillMaxWidth().height(36.dp)
            ) {
                val statuses = listOf(
                    "All 41" to totalCount,
                    "Met/Safe" to metCount,
                    "Sub-optimal" to suboptimalCount,
                    "Critical" to criticalCount,
                    "Exceeded Limit" to exceededCount
                )
                statuses.forEachIndexed { idx, (label, count) ->
                    Tab(
                        selected = statusFilterState == idx,
                        onClick = { statusFilterState = idx },
                        modifier = Modifier.padding(end = 4.dp)
                    ) {
                        Box(
                            modifier = Modifier
                                .clip(RoundedCornerShape(8.dp))
                                .background(
                                    if (statusFilterState == idx) MaterialTheme.colorScheme.primary
                                    else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f)
                                )
                                .padding(horizontal = 10.dp, vertical = 6.dp)
                        ) {
                            Text(
                                text = "$label ($count)",
                                style = MaterialTheme.typography.labelSmall.copy(
                                    fontWeight = FontWeight.Bold,
                                    color = if (statusFilterState == idx) MaterialTheme.colorScheme.onPrimary else MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            )
                        }
                    }
                }
            }
            
            Spacer(modifier = Modifier.height(8.dp))
            
            ScrollableTabRow(
                selectedTabIndex = if (selectedGroupFilter == null) 0 else selectedGroupFilter!!.ordinal + 1,
                edgePadding = 0.dp,
                indicator = {},
                divider = {},
                modifier = Modifier.fillMaxWidth().height(36.dp)
            ) {
                Tab(
                    selected = selectedGroupFilter == null,
                    onClick = { selectedGroupFilter = null },
                    modifier = Modifier.padding(end = 4.dp)
                ) {
                    Box(
                        modifier = Modifier
                            .clip(RoundedCornerShape(8.dp))
                            .background(
                                if (selectedGroupFilter == null) MaterialTheme.colorScheme.secondary
                                else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f)
                            )
                            .padding(horizontal = 10.dp, vertical = 6.dp)
                    ) {
                        Text(
                            text = "All Groups",
                            style = MaterialTheme.typography.labelSmall.copy(
                                fontWeight = FontWeight.Bold,
                                color = if (selectedGroupFilter == null) MaterialTheme.colorScheme.onSecondary else MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        )
                    }
                }
                
                com.example.data.NutrientGroup.values().forEach { group ->
                    val groupCount = dailyNutrients.count { it.definition.group == group }
                    Tab(
                        selected = selectedGroupFilter == group,
                        onClick = { selectedGroupFilter = group },
                        modifier = Modifier.padding(end = 4.dp)
                    ) {
                        Box(
                            modifier = Modifier
                                .clip(RoundedCornerShape(8.dp))
                                .background(
                                    if (selectedGroupFilter == group) MaterialTheme.colorScheme.secondary
                                    else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f)
                                )
                                .padding(horizontal = 10.dp, vertical = 6.dp)
                        ) {
                            Text(
                                text = "${group.displayName} ($groupCount)",
                                style = MaterialTheme.typography.labelSmall.copy(
                                    fontWeight = FontWeight.Bold,
                                    color = if (selectedGroupFilter == group) MaterialTheme.colorScheme.onSecondary else MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            )
                        }
                    }
                }
            }
            
            Spacer(modifier = Modifier.height(12.dp))
            
            if (filteredList.isEmpty()) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 32.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.Search,
                            contentDescription = "No results",
                            tint = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.4f),
                            modifier = Modifier.size(36.dp)
                        )
                        Text(
                            text = "No matching nutrients found.",
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            } else {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .heightIn(max = 420.dp)
                        .verticalScroll(rememberScrollState()),
                    verticalArrangement = Arrangement.spacedBy(10.dp)
                ) {
                    filteredList.forEach { status ->
                        val def = status.definition
                        val isLimit = def.isMaxLimit
                        val percentage = status.percentage
                        
                        val progressColor: Color
                        val statusText: String
                        val statusBg: Color
                        val statusTextCol: Color
                        val isCritical = !isLimit && percentage < 50.0
                        val animatedAllNutrientsProgress by androidx.compose.animation.core.animateFloatAsState(
                            targetValue = percentage.coerceIn(0.0, 100.0).toFloat() / 100.0f,
                            animationSpec = androidx.compose.animation.core.tween(
                                durationMillis = 800,
                                easing = androidx.compose.animation.core.FastOutSlowInEasing
                            ),
                            label = "all_nutrients_progress_${def.key}"
                        )
                        
                        if (isLimit) {
                            if (percentage <= 100.0) {
                                progressColor = MaterialTheme.colorScheme.primary
                                statusText = "SAFE LIMIT"
                                statusBg = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.5f)
                                statusTextCol = MaterialTheme.colorScheme.onPrimaryContainer
                            } else {
                                progressColor = MaterialTheme.colorScheme.error
                                statusText = "⚠️ OVER LIMIT"
                                statusBg = MaterialTheme.colorScheme.errorContainer
                                statusTextCol = MaterialTheme.colorScheme.onErrorContainer
                            }
                        } else {
                            if (percentage >= 100.0) {
                                progressColor = Color(0xFF4CAF50)
                                statusText = "TARGET MET"
                                statusBg = Color(0xFFE8F5E9)
                                statusTextCol = Color(0xFF2E7D32)
                            } else if (percentage >= 50.0) {
                                progressColor = Color(0xFFF0932B)
                                statusText = "SUBOPTIMAL"
                                statusBg = Color(0xFFFFF3E0)
                                statusTextCol = Color(0xFFE65100)
                            } else {
                                progressColor = MaterialTheme.colorScheme.error
                                statusText = "CRITICAL GAP"
                                statusBg = MaterialTheme.colorScheme.errorContainer
                                statusTextCol = MaterialTheme.colorScheme.onErrorContainer
                            }
                        }
                        
                        Card(
                            modifier = Modifier
                                .fillMaxWidth()
                                .clip(RoundedCornerShape(12.dp))
                                .clickable {
                                    viewModel.queryNutrientBenefitGrounding(
                                        nutrientName = def.name,
                                        nutrientKey = def.key,
                                        fallbackText = def.description.ifEmpty { "Essential critical nutrient supporting metabolic pathways, energetic resilience, cellular development, and physiological balance." }
                                    )
                                }
                                .testTag("all_rda_dashboard_row_${def.key}"),
                            colors = CardDefaults.cardColors(
                                containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.12f)
                            ),
                            border = BorderStroke(
                                1.dp, 
                                if (isCritical || (isLimit && percentage > 100.0)) progressColor.copy(alpha = 0.4f)
                                else MaterialTheme.colorScheme.outline.copy(alpha = 0.08f)
                            ),
                            shape = RoundedCornerShape(12.dp)
                        ) {
                            Column(modifier = Modifier.padding(12.dp)) {
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.Top
                                ) {
                                    Column(modifier = Modifier.weight(1f)) {
                                        Row(
                                            verticalAlignment = Alignment.CenterVertically,
                                            horizontalArrangement = Arrangement.spacedBy(6.dp)
                                        ) {
                                            Text(
                                                text = def.name,
                                                style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                                color = MaterialTheme.colorScheme.onSurface
                                            )
                                            
                                            Box(
                                                modifier = Modifier
                                                    .clip(RoundedCornerShape(4.dp))
                                                    .background(statusBg)
                                                    .padding(horizontal = 4.dp, vertical = 2.dp)
                                            ) {
                                                Text(
                                                    text = statusText,
                                                    color = statusTextCol,
                                                    style = MaterialTheme.typography.labelSmall.copy(fontSize = 8.sp, fontWeight = FontWeight.ExtraBold)
                                                )
                                            }
                                        }
                                        
                                        val foodTip = remember(def.key) { getDenseFoodSources(def.key) }
                                        Text(
                                            text = "Best sources: $foodTip",
                                            style = MaterialTheme.typography.labelSmall.copy(
                                                fontStyle = androidx.compose.ui.text.font.FontStyle.Italic,
                                                fontSize = 11.sp
                                            ),
                                            color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.8f),
                                            maxLines = 1,
                                            overflow = TextOverflow.Ellipsis,
                                            modifier = Modifier.padding(top = 2.dp)
                                        )
                                    }
                                    
                                    Column(horizontalAlignment = Alignment.End) {
                                        Text(
                                            text = "${String.format(Locale.US, "%.1f", status.intake)} / ${String.format(Locale.US, "%.1f", def.rda)} ${def.unit}",
                                            style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                            color = if (isCritical || (isLimit && percentage > 100.0)) progressColor else MaterialTheme.colorScheme.onSurface
                                        )
                                        Text(
                                            text = if (isLimit) {
                                                if (percentage > 100.0) "Over by ${String.format(Locale.US, "%.1f", status.intake - def.rda)} ${def.unit}"
                                                else "Safe under RDA"
                                            } else {
                                                if (percentage >= 100.0) "Completed target!"
                                                else "Need ${String.format(Locale.US, "%.1f", def.rda - status.intake)} ${def.unit} more"
                                            },
                                            style = MaterialTheme.typography.labelSmall.copy(fontSize = 10.sp),
                                            color = if (isCritical || (isLimit && percentage > 100.0)) progressColor.copy(alpha = 0.8f) else MaterialTheme.colorScheme.onSurfaceVariant
                                        )
                                    }
                                }
                                
                                Spacer(modifier = Modifier.height(8.dp))
                                
                                Row(
                                    modifier = Modifier.fillMaxWidth(),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                                ) {
                                    LinearProgressIndicator(
                                        progress = { animatedAllNutrientsProgress },
                                        modifier = Modifier
                                            .weight(1f)
                                            .height(6.dp)
                                            .clip(CircleShape),
                                        color = progressColor,
                                        trackColor = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.06f)
                                    )
                                    
                                    Text(
                                        text = "${percentage.toInt()}% met",
                                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.ExtraBold),
                                        color = progressColor
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

private fun getDenseFoodSources(key: String): String {
    return when (key) {
        "calories" -> "Whole oats, rich avocados, wild-caught salmon, grass-fed beef."
        "protein" -> "Greek yogurt, organic eggs, pasture-raised chicken breasts, lean beef."
        "carbohydrates" -> "Sweet potatoes, wild organic rice, raw honey, rolled oats."
        "fat" -> "Extra virgin olive oil, raw macadamia nuts, organic butter, ripe avocados."
        "fiber" -> "Chia seeds, flaxseeds, organic split peas, dark black beans, pears."
        "water" -> "Structured filtered water, organic herbal infusions, fresh cucumbers."
        "saturated_fat" -> "Organic coconut oil, grass-fed butter, high-fat grass-fed cheeses."
        "omega3" -> "Wild-caught sockeye salmon, fresh sardines, chia seeds, walnuts."
        "omega6" -> "Organic sunflower seeds, sesame seeds, hemp seeds, raw pumpkin seeds."
        "vitamin_a" -> "Pasture-raised beef liver, organic sweet potatoes, fresh carrots, spinach."
        "vitamin_c" -> "Organic red bell peppers, acerola cherries, sweet oranges, strawberries."
        "vitamin_d" -> "Direct sun exposure, wild salmon, cod liver oil, pasture eggs."
        "vitamin_e" -> "Raw almonds, raw sunflower seeds, avocado oil, organic spinach."
        "vitamin_k" -> "Fresh curly kale, raw spinach, collard greens, natto fermented beans."
        "thiamin" -> "Nutritional yeast, organic sunflower seeds, grass-fed pork, black beans."
        "riboflavin" -> "Pasture eggs, grass-fed beef liver, raw almonds, organic mushrooms."
        "niacin" -> "Pasture-raised chicken, wild tuna, grass-fed beef, brown rice."
        "pantothenic_acid" -> "Fresh avocados, organic mushrooms, pasture eggs, sunflower seeds."
        "vitamin_b6" -> "Wild tuna, grass-fed beef, organic bananas, fresh chickpeas."
        "biotin" -> "Pasture egg yolks, raw almonds, sweet potatoes, organic liver."
        "folate" -> "Fresh baby spinach, organic asparagus, brussels sprouts, pasture eggs."
        "vitamin_b12" -> "Grass-fed beef, wild clams, sockeye salmon, nutritional yeast."
        "choline" -> "Pasture egg yolks, grass-fed beef liver, wild cod, brussels sprouts."
        "calcium" -> "Raw grass-fed milk, high-quality yogurt, raw almonds, dark leafy greens."
        "iron" -> "Pasture beef, spinach cooked with lemon, cooked lentils, dark cocoa."
        "magnesium" -> "Raw pumpkin seeds, 85% dark chocolate, raw spinach, black beans."
        "phosphorus" -> "Grass-fed beef, raw pumpkin seeds, wild salmon, organic eggs."
        "potassium" -> "Sweet avocados, medium bananas, coconut water, gold baked potatoes."
        "zinc" -> "Fresh oysters, grass-fed beef, raw pumpkin seeds, cooked chickpeas."
        "copper" -> "Grass-fed beef liver, 85% dark chocolate, raw cashews, raw seeds."
        "manganese" -> "Raw hazelnuts, raw pecans, organic brown rice, raw oats."
        "selenium" -> "Brazil nuts (just 1-2), wild yellowfin tuna, grass-fed pork, pasture eggs."
        "chromium" -> "Organic broccoli, pasture-raised grapes, grass-fed beef, brewer's yeast."
        "molybdenum" -> "Organic black beans, cooked lentils, split peas, organic oats."
        "iodine" -> "Organic kelp powder, seaweeds, wild cod, organic cranberries, yogurt."
        else -> "Unprocessed leafy greens, wild-caught meats, organic seeds, and raw nuts."
    }
}

@Composable
fun RdaCrossReferenceUtility(viewModel: NutritionViewModel) {
    val currentDateEntries by viewModel.currentDateEntries.collectAsState()
    val dailyNutrients by viewModel.dailyNutrients.collectAsState()
    
    var selectedSourceIndex by remember { mutableStateOf(-1) } // -1 = Today's Cumulative, -2 = Premium Balanced Breakfast Preset, -3 = Sockeye Salmon Plate Preset, other = entry index
    var searchQuery by remember { mutableStateOf("") }
    
    // Simulating Preset nutrients contribution
    val breakfastPreset = remember {
        mapOf(
            "calories" to 420.0,
            "protein" to 28.0,
            "carbohydrates" to 45.0,
            "fat" to 14.0,
            "fiber" to 6.0,
            "water" to 250.0,
            "calcium" to 300.0,
            "iron" to 4.5,
            "vitamin_c" to 45.0,
            "potassium" to 550.0,
            "magnesium" to 120.0,
            "vitamin_d" to 5.0,
            "zinc" to 3.0
        )
    }

    val salmonPreset = remember {
        mapOf(
            "calories" to 580.0,
            "protein" to 45.0,
            "carbohydrates" to 10.0,
            "fat" to 22.0,
            "fiber" to 8.0,
            "water" to 150.0,
            "calcium" to 180.0,
            "iron" to 5.2,
            "vitamin_c" to 60.0,
            "potassium" to 850.0,
            "magnesium" to 160.0,
            "vitamin_d" to 12.0,
            "zinc" to 4.8
        )
    }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .testTag("rda_cross_reference_utility_card"),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.surface
        ),
        border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f)),
        shape = RoundedCornerShape(16.dp)
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            // Title Info
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Icon(
                    imageVector = Icons.Default.List,
                    contentDescription = null,
                    tint = MaterialTheme.colorScheme.primary,
                    modifier = Modifier.size(22.dp)
                )
                Text(
                    text = "RDA Cross-Reference & Warning Utility",
                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.onSurface
                )
            }
            
            Spacer(modifier = Modifier.height(4.dp))
            
            Text(
                text = "Interactively select daily logs or preset combinations to instantly map nutrient contributions against RDA standards and trigger visual deficit highlights.",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )

            Spacer(modifier = Modifier.height(12.dp))

            // Scrollable chips row to select source
            Text(
                text = "Select Cross-Reference Source:",
                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                color = MaterialTheme.colorScheme.primary
            )
            
            Spacer(modifier = Modifier.height(6.dp))

            LazyRow(
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                modifier = Modifier.fillMaxWidth().testTag("source_chips_row")
            ) {
                // Today's cumulative
                item {
                    val isSelected = selectedSourceIndex == -1
                    RdaFilterChip(
                        selected = isSelected,
                        onClick = { selectedSourceIndex = -1 },
                        label = "Today's Cumulative",
                        modifier = Modifier.testTag("chip_cumulative")
                    )
                }

                // If user doesn't have custom logs or even if they have, offer samples for rich previewing
                item {
                    val isSelected = selectedSourceIndex == -2
                    RdaFilterChip(
                        selected = isSelected,
                        onClick = { selectedSourceIndex = -2 },
                        label = "Sample: Balanced Breakfast",
                        modifier = Modifier.testTag("chip_sample_breakfast")
                    )
                }

                item {
                    val isSelected = selectedSourceIndex == -3
                    RdaFilterChip(
                        selected = isSelected,
                        onClick = { selectedSourceIndex = -3 },
                        label = "Sample: Sockeye Salmon Plate",
                        modifier = Modifier.testTag("chip_sample_salmon")
                    )
                }

                // Custom Log entries
                itemsIndexed(currentDateEntries) { idx, log ->
                    val isSelected = selectedSourceIndex == idx
                    RdaFilterChip(
                        selected = isSelected,
                        onClick = { selectedSourceIndex = idx },
                        label = "${log.mealType}: ${log.foodName}",
                        modifier = Modifier.testTag("chip_log_${idx}")
                    )
                }
            }

            Spacer(modifier = Modifier.height(12.dp))

            // Search Bar for Nutrient Comparison Table
            OutlinedTextField(
                value = searchQuery,
                onValueChange = { searchQuery = it },
                placeholder = { Text("Filter cross-referenced nutrients...", style = MaterialTheme.typography.bodySmall) },
                modifier = Modifier.fillMaxWidth().height(48.dp).testTag("rda_util_search_input"),
                singleLine = true,
                textStyle = MaterialTheme.typography.bodySmall,
                trailingIcon = {
                    if (searchQuery.isNotEmpty()) {
                        IconButton(onClick = { searchQuery = "" }) {
                            Icon(Icons.Default.Close, contentDescription = "Clear", modifier = Modifier.size(16.dp))
                        }
                    }
                },
                colors = OutlinedTextFieldDefaults.colors(
                    focusedBorderColor = MaterialTheme.colorScheme.primary,
                    unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.2f),
                    focusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.1f),
                    unfocusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.05f)
                )
            )

            Spacer(modifier = Modifier.height(12.dp))

            // Nutrient Cross-Reference Header Table Label
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f), RoundedCornerShape(8.dp))
                    .padding(horizontal = 8.dp, vertical = 6.dp),
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                Text("Nutrient (RDA Target)", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold), modifier = Modifier.weight(1.3f))
                Text("Contrib.", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold), modifier = Modifier.weight(0.9f), textAlign = TextAlign.End)
                Text("Total Today Status", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold), modifier = Modifier.weight(1.2f), textAlign = TextAlign.End)
            }

            Spacer(modifier = Modifier.height(8.dp))

            // Filtrate and Display comparison list
            val crossReferenceRows = remember(dailyNutrients, selectedSourceIndex, currentDateEntries, searchQuery) {
                dailyNutrients.filter {
                    it.definition.name.contains(searchQuery, ignoreCase = true)
                }.map { status ->
                    val def = status.definition
                    // Calculate selected source contribution
                    val contribution = when (selectedSourceIndex) {
                        -1 -> status.intake // For Cumulative, the contribution is the whole intake
                        -2 -> breakfastPreset[def.key] ?: 0.0
                        -3 -> salmonPreset[def.key] ?: 0.0
                        else -> {
                            if (selectedSourceIndex in currentDateEntries.indices) {
                                currentDateEntries[selectedSourceIndex].nutrients[def.key] ?: 0.0
                            } else 0.0
                        }
                    }
                    val contributionPercentage = if (def.rda > 0) (contribution / def.rda * 100.0) else 0.0
                    Triple(status, contribution, contributionPercentage)
                }
            }

            if (crossReferenceRows.isEmpty()) {
                Box(
                    modifier = Modifier.fillMaxWidth().padding(16.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text("No matching nutrients found.", style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                }
            } else {
                Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    // Show a maximum of 6 nutrients initially, with a "Show All matched" toggle if list is long
                    var isExpandedList by remember { mutableStateOf(false) }
                    val displayRows = if (isExpandedList) crossReferenceRows else crossReferenceRows.take(6)

                    displayRows.forEach { (status, contrib, contribPct) ->
                        val def = status.definition
                        val isLimit = def.isMaxLimit
                        val currentPct = status.percentage
                        
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(horizontal = 4.dp, vertical = 2.dp),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            // Column 1: Nutrient details
                            Column(modifier = Modifier.weight(1.3f)) {
                                Text(
                                    text = def.name,
                                    style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurface
                                )
                                Text(
                                    text = "RDA: ${def.rda.toInt()}${def.unit}",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }

                            // Column 2: Selection Contribution Contribution
                            Column(modifier = Modifier.weight(0.9f), horizontalAlignment = Alignment.End) {
                                Text(
                                    text = "+${contrib.toInt()}${def.unit}",
                                    style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                                    color = if (contrib > 0) MaterialTheme.colorScheme.secondary else MaterialTheme.colorScheme.onSurfaceVariant
                                )
                                Text(
                                    text = "(${contribPct.toInt()}% RDA)",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = if (contrib > 0) MaterialTheme.colorScheme.secondary.copy(alpha = 0.8f) else MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f)
                                )
                            }

                            // Column 3: Cumulative & warning visual highlight tag
                            Column(modifier = Modifier.weight(1.2f), horizontalAlignment = Alignment.End) {
                                val (bgCol, textCol, labelText) = when {
                                    isLimit -> {
                                        if (currentPct > 100.0) {
                                            Triple(Color(0xFFFFECEB), Color(0xFFC53030), "⚠️ OVER LIMIT (${currentPct.toInt()}%)")
                                        } else {
                                            Triple(Color(0xFFE6FFFA), Color(0xFF234E52), "✅ SAFE LOWER (${currentPct.toInt()}%)")
                                        }
                                    }
                                    currentPct >= 100.0 -> {
                                        Triple(Color(0xFFF0FFF4), Color(0xFF22543D), "✅ MET (${currentPct.toInt()}%)")
                                    }
                                    currentPct < 50.0 -> {
                                        Triple(Color(0xFFFFECEB), Color(0xFFC53030), "⚠️ CRITICAL LOW (${currentPct.toInt()}%)")
                                    }
                                    else -> {
                                        Triple(Color(0xFFFEFCBF), Color(0xFF744210), "⚠️ DEFICIT (${currentPct.toInt()}%)")
                                    }
                                }

                                Box(
                                    modifier = Modifier
                                        .clip(RoundedCornerShape(6.dp))
                                        .background(bgCol)
                                        .padding(horizontal = 6.dp, vertical = 3.dp)
                                        .testTag("rda_highlight_${def.key}")
                                ) {
                                    Text(
                                        text = labelText,
                                        style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.ExtraBold, fontSize = 9.sp),
                                        color = textCol
                                    )
                                }
                                
                                Spacer(modifier = Modifier.height(2.dp))
                                
                                Text(
                                    text = "Total: ${status.intake.toInt()} ${def.unit}",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }
                        }
                    }

                    if (crossReferenceRows.size > 6) {
                        TextButton(
                            onClick = { isExpandedList = !isExpandedList },
                            modifier = Modifier.align(Alignment.CenterHorizontally).testTag("toggle_cross_reference_expanded_button")
                        ) {
                            Text(
                                text = if (isExpandedList) "Show Less" else "Show All ${crossReferenceRows.size} Matched Nutrients",
                                style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold)
                            )
                        }
                    }
                }
            }
        }
    }
}

enum class DataGridSortOrder {
    ASCENDING, DESCENDING
}

enum class DataGridSortColumn {
    NUTRIENT_NAME,
    RDA_TARGET,
    TOTAL_INTAKE,
    ADHERENCE,
    FOOD_ENTRY
}

@Composable
fun DataGridHeaderCell(
    text: String,
    width: androidx.compose.ui.unit.Dp,
    sortable: Boolean = true,
    activeSort: Boolean = false,
    order: DataGridSortOrder = DataGridSortOrder.ASCENDING,
    onClick: () -> Unit = {}
) {
    Box(
        modifier = Modifier
            .width(width)
            .fillMaxHeight()
            .clickable(enabled = sortable) { onClick() }
            .padding(horizontal = 8.dp, vertical = 6.dp),
        contentAlignment = Alignment.CenterEnd
    ) {
        Row(
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(4.dp)
        ) {
            Text(
                text = text,
                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                color = if (activeSort) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant,
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )
            if (sortable) {
                Icon(
                    imageVector = if (activeSort) {
                        if (order == DataGridSortOrder.ASCENDING) Icons.Default.KeyboardArrowUp else Icons.Default.KeyboardArrowDown
                    } else {
                        Icons.Default.ArrowDropDown
                    },
                    contentDescription = "Sort Icon",
                    tint = if (activeSort) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.4f),
                    modifier = Modifier.size(12.dp)
                )
            }
        }
    }
}

@Composable
fun DataGridCell(
    text: String,
    width: androidx.compose.ui.unit.Dp,
    contentColor: Color = MaterialTheme.colorScheme.onSurface,
    bgColor: Color = Color.Transparent,
    alignToEnd: Boolean = true
) {
    Box(
        modifier = Modifier
            .width(width)
            .fillMaxHeight()
            .background(bgColor)
            .padding(horizontal = 8.dp, vertical = 4.dp),
        contentAlignment = if (alignToEnd) Alignment.CenterEnd else Alignment.CenterStart
    ) {
        Text(
            text = text,
            style = MaterialTheme.typography.bodySmall,
            color = contentColor,
            maxLines = 1,
            overflow = TextOverflow.Ellipsis
        )
    }
}

@Composable
fun CustomCompactSegmentedButton(
    text: String,
    isSelected: Boolean,
    onClick: () -> Unit
) {
    Box(
        modifier = Modifier
            .clip(RoundedCornerShape(6.dp))
            .background(if (isSelected) MaterialTheme.colorScheme.primary else Color.Transparent)
            .clickable { onClick() }
            .padding(horizontal = 10.dp, vertical = 5.dp)
    ) {
        Text(
            text = text,
            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
            color = if (isSelected) MaterialTheme.colorScheme.onPrimary else MaterialTheme.colorScheme.onSurfaceVariant
        )
    }
}

@Composable
fun CustomFilterGridChip(
    text: String,
    isSelected: Boolean,
    onClick: () -> Unit
) {
    val containerBg = if (isSelected) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)
    val contentColor = if (isSelected) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
    val borderColor = if (isSelected) MaterialTheme.colorScheme.primary.copy(alpha = 0.4f) else MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f)
    
    Box(
        modifier = Modifier
            .border(1.dp, borderColor, RoundedCornerShape(20.dp))
            .clip(RoundedCornerShape(20.dp))
            .background(containerBg)
            .clickable { onClick() }
            .padding(horizontal = 12.dp, vertical = 6.dp)
    ) {
        Text(
            text = text,
            style = MaterialTheme.typography.labelSmall.copy(fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal),
            color = contentColor
        )
    }
}

@Composable
fun NutrientRow(
    rowIdx: Int,
    item: com.example.ui.NutrientStatus,
    horizontalScrollState: androidx.compose.foundation.ScrollState,
    displayEntries: List<com.example.data.FoodLogEntry>
) {
    val rowBg = if (rowIdx % 2 == 0) MaterialTheme.colorScheme.surface else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.10f)
    
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .height(44.dp)
            .background(rowBg),
        verticalAlignment = Alignment.CenterVertically
    ) {
        Box(
            modifier = Modifier
                .width(135.dp)
                .fillMaxHeight()
                .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.08f))
                .padding(horizontal = 8.dp, vertical = 4.dp),
            contentAlignment = Alignment.CenterStart
        ) {
            Column {
                Text(
                    text = item.definition.name,
                    style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.onSurface,
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis
                )
                Text(
                    text = item.definition.group.displayName,
                    style = MaterialTheme.typography.labelSmall.copy(fontSize = 8.sp, color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f)),
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis
                )
            }
        }

        Box(
            modifier = Modifier
                .fillMaxHeight()
                .width(1.dp)
                .background(MaterialTheme.colorScheme.onSurface.copy(alpha = 0.12f))
        )

        Row(
            modifier = Modifier
                .weight(1f)
                .fillMaxHeight()
                .horizontalScroll(horizontalScrollState),
            verticalAlignment = Alignment.CenterVertically
        ) {
            val rdaStr = if (item.definition.key == "calories") {
                "${item.definition.rda.toInt()} ${item.definition.unit}"
            } else {
                "${String.format(Locale.US, "%.1f", item.definition.rda)} ${item.definition.unit}"
            }
            DataGridCell(text = rdaStr, width = 85.dp)

            val intakeStr = if (item.definition.key == "calories") {
                "${item.intake.toInt()} ${item.definition.unit}"
            } else {
                "${String.format(Locale.US, "%.1f", item.intake)} ${item.definition.unit}"
            }
            
            val adherenceColor = when (item.status) {
                com.example.ui.StatusColor.GREEN -> Color(0xFF2E7D32)
                com.example.ui.StatusColor.YELLOW -> Color(0xFFB7791F)
                com.example.ui.StatusColor.RED -> Color(0xFFC53030)
            }
            
            DataGridCell(
                text = intakeStr, 
                width = 90.dp,
                contentColor = adherenceColor
            )

            val adherenceStr = if (item.definition.isMaxLimit) {
                if (item.intake > item.definition.rda) "⚠️ OVER" else "✅ SAFE"
            } else {
                "${item.percentage.toInt()}%"
            }
            
            DataGridCell(
                text = adherenceStr, 
                width = 85.dp,
                contentColor = adherenceColor
            )

            displayEntries.forEach { entry ->
                val entryValue = entry.nutrients[item.definition.key] ?: 0.0
                val foodCellStr = if (entryValue == 0.0) {
                    "-"
                } else if (item.definition.key == "calories") {
                    "${entryValue.toInt()}"
                } else {
                    String.format(Locale.US, "%.1f", entryValue)
                }
                
                DataGridCell(
                    text = foodCellStr, 
                    width = 120.dp,
                    contentColor = if (entryValue > 0.0) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.5f)
                )
            }
        }
    }
    HorizontalDivider(
        color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.05f),
        thickness = 1.dp
    )
}

@Composable
fun NutrientDataGrid(viewModel: NutritionViewModel) {
    val currentDateEntries by viewModel.currentDateEntries.collectAsState()
    val dailyNutrients by viewModel.dailyNutrients.collectAsState()
    
    var searchQuery by remember { mutableStateOf("") }
    var sortColumn by remember { mutableStateOf(DataGridSortColumn.NUTRIENT_NAME) }
    var sortOrder by remember { mutableStateOf(DataGridSortOrder.ASCENDING) }
    var sortFoodIndex by remember { mutableStateOf(-1) }
    
    // Grouping & Filtering States
    var filterGroup by remember { mutableStateOf<com.example.data.NutrientGroup?>(null) }
    var groupByCategory by remember { mutableStateOf(true) }
    val groupExpansionStates = remember { 
        mutableStateMapOf<com.example.data.NutrientGroup, Boolean>().apply {
            com.example.data.NutrientGroup.values().forEach { put(it, true) }
        }
    }

    val displayEntries = if (currentDateEntries.isNotEmpty()) {
        currentDateEntries
    } else {
        listOf(
            com.example.data.FoodLogEntry(
                id = -10,
                date = "",
                foodName = "Sample Breakfast",
                mealType = "Breakfast",
                quantity = 1.0,
                unit = "serving",
                nutrients = mapOf(
                    "calories" to 420.0,
                    "protein" to 28.0,
                    "carbohydrates" to 45.0,
                    "fat" to 14.0,
                    "fiber" to 6.0,
                    "water" to 250.0,
                    "calcium" to 300.0,
                    "iron" to 4.5,
                    "vitamin_c" to 45.0,
                    "potassium" to 550.0,
                    "magnesium" to 120.0,
                    "zinc" to 3.0
                )
            ),
            com.example.data.FoodLogEntry(
                id = -11,
                date = "",
                foodName = "Sample Salmon Plate",
                mealType = "Dinner",
                quantity = 1.0,
                unit = "serving",
                nutrients = mapOf(
                    "calories" to 580.0,
                    "protein" to 45.0,
                    "carbohydrates" to 10.0,
                    "fat" to 22.0,
                    "fiber" to 8.0,
                    "water" to 150.0,
                    "calcium" to 180.0,
                    "iron" to 5.2,
                    "vitamin_c" to 60.0,
                    "potassium" to 850.0,
                    "magnesium" to 160.0,
                    "zinc" to 4.8
                )
            )
        )
    }

    fun toggleSort(col: DataGridSortColumn, foodIdx: Int = -1) {
        if (sortColumn == col && sortFoodIndex == foodIdx) {
            sortOrder = if (sortOrder == DataGridSortOrder.ASCENDING) DataGridSortOrder.DESCENDING else DataGridSortOrder.ASCENDING
        } else {
            sortColumn = col
            sortFoodIndex = foodIdx
            sortOrder = if (col == DataGridSortColumn.NUTRIENT_NAME) DataGridSortOrder.ASCENDING else DataGridSortOrder.DESCENDING
        }
    }
    
    val processedNutrients = remember(dailyNutrients, searchQuery, filterGroup) {
        dailyNutrients.filter {
            val matchesSearch = it.definition.name.contains(searchQuery, ignoreCase = true) ||
                    it.definition.group.name.contains(searchQuery, ignoreCase = true)
            val matchesGroup = filterGroup == null || it.definition.group == filterGroup
            matchesSearch && matchesGroup
        }
    }

    fun sortList(list: List<com.example.ui.NutrientStatus>): List<com.example.ui.NutrientStatus> {
        val sorted = when (sortColumn) {
            DataGridSortColumn.NUTRIENT_NAME -> list.sortedBy { it.definition.name.lowercase() }
            DataGridSortColumn.RDA_TARGET -> list.sortedBy { it.definition.rda }
            DataGridSortColumn.TOTAL_INTAKE -> list.sortedBy { it.intake }
            DataGridSortColumn.ADHERENCE -> list.sortedBy { it.percentage }
            DataGridSortColumn.FOOD_ENTRY -> {
                list.sortedBy { status ->
                    if (sortFoodIndex in displayEntries.indices) {
                        displayEntries[sortFoodIndex].nutrients[status.definition.key] ?: 0.0
                    } else {
                        0.0
                    }
                }
            }
        }
        return if (sortOrder == DataGridSortOrder.DESCENDING) sorted.reversed() else sorted
    }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .testTag("nutrient_datagrid_card"),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.surface
        ),
        border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f)),
        shape = RoundedCornerShape(16.dp)
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Row(
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                modifier = Modifier.fillMaxWidth()
            ) {
                Icon(
                    imageVector = Icons.Default.List,
                    contentDescription = null,
                    tint = MaterialTheme.colorScheme.primary,
                    modifier = Modifier.size(22.dp)
                )
                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        text = "41 Nutrient Interactive DataGrid",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.onSurface
                    )
                    Text(
                        text = "Real-time query, filter, sort, and group macronutrients, minerals, and vitamins with collapsible lists.",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }
            
            Spacer(modifier = Modifier.height(12.dp))

            // 1. Text Search Input
            OutlinedTextField(
                value = searchQuery,
                onValueChange = { searchQuery = it },
                placeholder = { Text("Search 41 essential nutrients...", style = MaterialTheme.typography.bodySmall) },
                modifier = Modifier.fillMaxWidth().height(48.dp).testTag("datagrid_search_input"),
                singleLine = true,
                textStyle = MaterialTheme.typography.bodySmall,
                leadingIcon = {
                    Icon(Icons.Default.Search, contentDescription = "Search", modifier = Modifier.size(16.dp), tint = MaterialTheme.colorScheme.onSurfaceVariant)
                },
                trailingIcon = {
                    if (searchQuery.isNotEmpty()) {
                        IconButton(onClick = { searchQuery = "" }) {
                            Icon(Icons.Default.Close, contentDescription = "Clear", modifier = Modifier.size(16.dp))
                        }
                    }
                },
                colors = OutlinedTextFieldDefaults.colors(
                    focusedBorderColor = MaterialTheme.colorScheme.primary,
                    unfocusedBorderColor = MaterialTheme.colorScheme.outline.copy(alpha = 0.2f),
                    focusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.1f),
                    unfocusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.05f)
                )
            )

            Spacer(modifier = Modifier.height(10.dp))

            // 2. Group & Filter Control Bar
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(4.dp),
                    modifier = Modifier
                        .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f), RoundedCornerShape(8.dp))
                        .padding(3.dp)
                ) {
                    CustomCompactSegmentedButton(
                        text = "Grouped View",
                        isSelected = groupByCategory,
                        onClick = { groupByCategory = true }
                    )
                    CustomCompactSegmentedButton(
                        text = "Flat View",
                        isSelected = !groupByCategory,
                        onClick = { groupByCategory = false }
                    )
                }

                Text(
                    text = "${processedNutrients.size} of 41 Nutrients",
                    style = MaterialTheme.typography.labelSmall,
                    color = MaterialTheme.colorScheme.primary,
                    fontWeight = FontWeight.Bold
                )
            }

            Spacer(modifier = Modifier.height(8.dp))

            // 3. Horizontal Scroll Filter Chips
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .horizontalScroll(rememberScrollState()),
                horizontalArrangement = Arrangement.spacedBy(6.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                CustomFilterGridChip(
                    text = "All Groups",
                    isSelected = filterGroup == null,
                    onClick = { filterGroup = null }
                )
                com.example.data.NutrientGroup.values().forEach { g ->
                    CustomFilterGridChip(
                        text = g.displayName,
                        isSelected = filterGroup == g,
                        onClick = { filterGroup = g }
                    )
                }
            }

            Spacer(modifier = Modifier.height(12.dp))

            if (currentDateEntries.isEmpty()) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clip(RoundedCornerShape(8.dp))
                        .background(MaterialTheme.colorScheme.secondaryContainer.copy(alpha = 0.15f))
                        .padding(horizontal = 12.dp, vertical = 8.dp)
                ) {
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        Icon(
                            imageVector = Icons.Default.Info,
                            contentDescription = "Sample Data info",
                            tint = MaterialTheme.colorScheme.secondary,
                            modifier = Modifier.size(14.dp)
                        )
                        Text(
                            text = "No custom logs saved today. Displaying high-fidelity interactive preset meals in grid columns for comparison.",
                            style = MaterialTheme.typography.labelSmall,
                            color = MaterialTheme.colorScheme.onSecondaryContainer
                        )
                    }
                }
                Spacer(modifier = Modifier.height(12.dp))
            }

            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .border(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f), RoundedCornerShape(8.dp))
                    .clip(RoundedCornerShape(8.dp))
            ) {
                val horizontalScrollState = rememberScrollState()
                
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(44.dp)
                        .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.35f)),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Box(
                        modifier = Modifier
                            .width(135.dp)
                            .fillMaxHeight()
                            .clickable { toggleSort(DataGridSortColumn.NUTRIENT_NAME) }
                            .padding(horizontal = 8.dp, vertical = 6.dp),
                        contentAlignment = Alignment.CenterStart
                    ) {
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(4.dp)
                        ) {
                            Text(
                                text = "Nutrient",
                                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                color = if (sortColumn == DataGridSortColumn.NUTRIENT_NAME) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurface
                            )
                            Icon(
                                imageVector = if (sortColumn == DataGridSortColumn.NUTRIENT_NAME) {
                                    if (sortOrder == DataGridSortOrder.ASCENDING) Icons.Default.KeyboardArrowUp else Icons.Default.KeyboardArrowDown
                                } else {
                                    Icons.Default.ArrowDropDown
                                },
                                contentDescription = "Sort name",
                                tint = if (sortColumn == DataGridSortColumn.NUTRIENT_NAME) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.4f),
                                modifier = Modifier.size(12.dp)
                            )
                        }
                    }

                    Box(
                        modifier = Modifier
                            .fillMaxHeight()
                            .width(1.dp)
                            .background(MaterialTheme.colorScheme.onSurface.copy(alpha = 0.12f))
                    )

                    Row(
                        modifier = Modifier
                            .weight(1f)
                            .fillMaxHeight()
                            .horizontalScroll(horizontalScrollState),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        DataGridHeaderCell(
                            text = "RDA Target",
                            width = 85.dp,
                            activeSort = (sortColumn == DataGridSortColumn.RDA_TARGET),
                            order = sortOrder,
                            onClick = { toggleSort(DataGridSortColumn.RDA_TARGET) }
                        )
                        DataGridHeaderCell(
                            text = "Total Intake",
                            width = 90.dp,
                            activeSort = (sortColumn == DataGridSortColumn.TOTAL_INTAKE),
                            order = sortOrder,
                            onClick = { toggleSort(DataGridSortColumn.TOTAL_INTAKE) }
                        )
                        DataGridHeaderCell(
                            text = "Adherence",
                            width = 85.dp,
                            activeSort = (sortColumn == DataGridSortColumn.ADHERENCE),
                            order = sortOrder,
                            onClick = { toggleSort(DataGridSortColumn.ADHERENCE) }
                        )
                        displayEntries.forEachIndexed { fIdx, entry ->
                            val capName = if (entry.foodName.length > 15) entry.foodName.take(13) + "..." else entry.foodName
                            DataGridHeaderCell(
                                text = capName,
                                width = 120.dp,
                                activeSort = (sortColumn == DataGridSortColumn.FOOD_ENTRY && sortFoodIndex == fIdx),
                                order = sortOrder,
                                onClick = { toggleSort(DataGridSortColumn.FOOD_ENTRY, fIdx) }
                            )
                        }
                    }
                }

                HorizontalDivider(
                    color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f),
                    thickness = 1.dp
                )

                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(350.dp)
                        .verticalScroll(rememberScrollState())
                ) {
                    if (groupByCategory) {
                        com.example.data.NutrientGroup.values().forEach { group ->
                            val groupItems = processedNutrients.filter { it.definition.group == group }
                            if (groupItems.isNotEmpty()) {
                                val sortedGroupItems = sortList(groupItems)
                                val isExpanded = groupExpansionStates[group] ?: true
                                
                                // Group Header Row
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .height(38.dp)
                                        .background(MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.22f))
                                        .clickable { groupExpansionStates[group] = !isExpanded }
                                        .padding(horizontal = 8.dp),
                                    verticalAlignment = Alignment.CenterVertically,
                                    horizontalArrangement = Arrangement.SpaceBetween
                                ) {
                                    Row(
                                        verticalAlignment = Alignment.CenterVertically,
                                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                                    ) {
                                        Icon(
                                            imageVector = if (isExpanded) Icons.Default.KeyboardArrowUp else Icons.Default.KeyboardArrowDown,
                                            contentDescription = "Expand/Collapse Group",
                                            tint = MaterialTheme.colorScheme.primary,
                                            modifier = Modifier.size(16.dp)
                                        )
                                        Text(
                                            text = group.displayName,
                                            style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                                            color = MaterialTheme.colorScheme.onPrimaryContainer
                                        )
                                    }
                                    Text(
                                        text = "${groupItems.size} items",
                                        style = MaterialTheme.typography.labelSmall,
                                        color = MaterialTheme.colorScheme.onPrimaryContainer.copy(alpha = 0.6f)
                                    )
                                }
                                
                                HorizontalDivider(
                                    color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f),
                                    thickness = 1.dp
                                )
                                
                                if (isExpanded) {
                                    sortedGroupItems.forEachIndexed { rowIdx, item ->
                                        NutrientRow(
                                            rowIdx = rowIdx,
                                            item = item,
                                            horizontalScrollState = horizontalScrollState,
                                            displayEntries = displayEntries
                                        )
                                    }
                                }
                            }
                        }
                    } else {
                        val sortedFlatList = sortList(processedNutrients)
                        sortedFlatList.forEachIndexed { rowIdx, item ->
                            NutrientRow(
                                rowIdx = rowIdx,
                                item = item,
                                horizontalScrollState = horizontalScrollState,
                                displayEntries = displayEntries
                            )
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun LogPresetDialog(
    meal: com.example.data.FavoriteMeal,
    onDismiss: () -> Unit,
    onLog: (String) -> Unit
) {
    var selectedMealType by remember { mutableStateOf("Breakfast") }
    val mealTypes = listOf("Breakfast", "Lunch", "Dinner", "Snack", "Supplement")

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Log Favorite Preset Meal") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(12.dp)) {
                Text(
                    text = "Add all ${meal.foods.size} items of '${meal.name}' to today's journal.",
                    style = MaterialTheme.typography.bodyMedium,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
                
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f))
                ) {
                    Column(modifier = Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                        meal.foods.forEach { food ->
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.SpaceBetween
                            ) {
                                Text(
                                    text = food.foodName,
                                    style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.SemiBold),
                                    maxLines = 1,
                                    modifier = Modifier.weight(1f)
                                )
                                Text(
                                    text = "${if (food.quantity % 1.0 == 0.0) food.quantity.toInt().toString() else food.quantity} ${food.unit}",
                                    style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }
                        }
                    }
                }

                Text(
                    text = "Select Daily Meal Category:",
                    style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.primary
                )

                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(6.dp)
                ) {
                    mealTypes.forEach { type ->
                        val isSelected = selectedMealType == type
                        Surface(
                            onClick = { selectedMealType = type },
                            modifier = Modifier
                                .weight(1f)
                                .height(32.dp)
                                .testTag("log_preset_category_chip_${type.lowercase()}"),
                            shape = RoundedCornerShape(6.dp),
                            color = if (isSelected) MaterialTheme.colorScheme.primaryContainer else MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f),
                            border = if (isSelected) BorderStroke(1.2.dp, MaterialTheme.colorScheme.primary) else null
                        ) {
                            Box(
                                contentAlignment = Alignment.Center,
                                modifier = Modifier.fillMaxSize()
                            ) {
                                Text(
                                    text = type,
                                    style = MaterialTheme.typography.labelSmall.copy(
                                        fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Normal,
                                        fontSize = 10.sp
                                    ),
                                    color = if (isSelected) MaterialTheme.colorScheme.onPrimaryContainer else MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }
                        }
                    }
                }
            }
        },
        confirmButton = {
            Button(
                onClick = { onLog(selectedMealType) },
                modifier = Modifier.testTag("log_preset_confirm_button")
            ) {
                Text("Log Meal")
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text("Cancel")
            }
        }
    )
}

@Composable
fun SavePresetDialog(
    entries: List<com.example.data.FoodLogEntry>,
    onDismiss: () -> Unit,
    onSaveClicked: (String, List<com.example.data.FoodLogEntry>) -> Unit
) {
    var presetName by remember { mutableStateOf("") }
    val selectionStates = remember {
        mutableStateMapOf<Int, Boolean>().apply {
            entries.forEachIndexed { index, _ -> put(index, true) }
        }
    }

    val selectedEntries = entries.filterIndexed { index, _ -> selectionStates[index] ?: false }
    val totalCalories = selectedEntries.sumOf { (it.nutrients["calories"] ?: 0.0) * it.quantity }
    val totalProtein = selectedEntries.sumOf { (it.nutrients["protein"] ?: 0.0) * it.quantity }
    val totalCarbs = selectedEntries.sumOf { (it.nutrients["carbohydrates"] ?: 0.0) * it.quantity }
    val totalFat = selectedEntries.sumOf { (it.nutrients["fat"] ?: 0.0) * it.quantity }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Save Favorite Meal Preset") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(12.dp)) {
                Text(
                    text = "Name your custom preset and choose which foods from today's journal to bundle together.",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )

                OutlinedTextField(
                    value = presetName,
                    onValueChange = { presetName = it },
                    label = { Text("Favorite Meal Name") },
                    placeholder = { Text("My Clean Breakfast") },
                    singleLine = true,
                    modifier = Modifier
                        .fillMaxWidth()
                        .testTag("save_preset_name_input"),
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = MaterialTheme.colorScheme.primary,
                        unfocusedBorderColor = MaterialTheme.colorScheme.outline
                    )
                )

                Text(
                    text = "Select Foods to Save:",
                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.primary
                )

                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .heightIn(max = 200.dp),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)),
                    border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f))
                ) {
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .verticalScroll(rememberScrollState())
                            .padding(6.dp),
                        verticalArrangement = Arrangement.spacedBy(4.dp)
                    ) {
                        entries.forEachIndexed { index, entry ->
                            val isChecked = selectionStates[index] ?: false
                            Row(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .clickable { selectionStates[index] = !isChecked }
                                    .padding(vertical = 4.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Checkbox(
                                    checked = isChecked,
                                    onCheckedChange = { selectionStates[index] = it },
                                    modifier = Modifier.testTag("preset_select_checkbox_$index")
                                )
                                Column(modifier = Modifier.weight(1f).padding(start = 4.dp)) {
                                    Text(
                                        text = entry.foodName,
                                        style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.SemiBold),
                                        maxLines = 1
                                    )
                                    Text(
                                        text = "${entry.mealType} • ${if (entry.quantity % 1.0 == 0.0) entry.quantity.toInt() else entry.quantity} ${entry.unit}",
                                        style = MaterialTheme.typography.labelSmall,
                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                            }
                        }
                    }
                }

                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.secondaryContainer.copy(alpha = 0.3f))
                ) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(10.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column {
                            Text("Totals Selected", style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold))
                            Text(
                                text = "${totalCalories.toInt()} kcal",
                                style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.primary
                            )
                        }
                        
                        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                Text("P", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                                Text("${totalProtein.toInt()}g", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold))
                            }
                            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                Text("C", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                                Text("${totalCarbs.toInt()}g", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold))
                            }
                            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                Text("F", style = MaterialTheme.typography.labelSmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
                                Text("${totalFat.toInt()}g", style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold))
                            }
                        }
                    }
                }
            }
        },
        confirmButton = {
            Button(
                onClick = { onSaveClicked(presetName, selectedEntries) },
                enabled = presetName.isNotBlank() && selectedEntries.isNotEmpty(),
                modifier = Modifier.testTag("save_preset_dialog_confirm_button")
            ) {
                Text("Save Preset")
            }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) {
                Text("Cancel")
            }
        }
    )
}

@Composable
fun FavoriteMealsLibrarySection(
    viewModel: NutritionViewModel,
    modifier: Modifier = Modifier
) {
    val favoriteMeals by viewModel.allFavoriteMeals.collectAsState()
    var isExpanded by remember { mutableStateOf(false) }
    var mealToLogPreset by remember { mutableStateOf<com.example.data.FavoriteMeal?>(null) }

    if (mealToLogPreset != null) {
        LogPresetDialog(
            meal = mealToLogPreset!!,
            onDismiss = { mealToLogPreset = null },
            onLog = { mealType ->
                viewModel.logFavoriteMeal(mealToLogPreset!!, mealType)
                mealToLogPreset = null
            }
        )
    }

    Card(
        modifier = modifier
            .fillMaxWidth()
            .testTag("favorite_meals_library_card"),
        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.15f)),
        border = BorderStroke(1.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.15f))
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .clickable { isExpanded = !isExpanded },
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Row(
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Icon(
                        imageVector = Icons.Default.Favorite,
                        contentDescription = "Favorite Meals",
                        tint = MaterialTheme.colorScheme.primary,
                        modifier = Modifier.size(20.dp)
                    )
                    Column {
                        Text(
                            text = "Favorite Meals Preset Library",
                            style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onSurface
                        )
                        Text(
                            text = "Save combinations & log with 1-click",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
                IconButton(onClick = { isExpanded = !isExpanded }) {
                    Icon(
                        imageVector = if (isExpanded) Icons.Default.KeyboardArrowUp else Icons.Default.KeyboardArrowDown,
                        contentDescription = if (isExpanded) "Collapse" else "Expand"
                    )
                }
            }

            if (isExpanded) {
                Spacer(modifier = Modifier.height(12.dp))

                if (favoriteMeals.isEmpty()) {
                    Box(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(vertical = 16.dp),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = "No saved meal presets. Tap 'Save Favorite' in your logged journal to bundle and reuse foods.",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant,
                            textAlign = TextAlign.Center,
                            modifier = Modifier.padding(horizontal = 16.dp)
                        )
                    }
                } else {
                    Column(verticalArrangement = Arrangement.spacedBy(10.dp)) {
                        favoriteMeals.forEach { meal ->
                            val presetCal = meal.foods.sumOf { (it.nutrients["calories"] ?: 0.0) * it.quantity }
                            val presetProtein = meal.foods.sumOf { (it.nutrients["protein"] ?: 0.0) * it.quantity }
                            val presetCarbs = meal.foods.sumOf { (it.nutrients["carbohydrates"] ?: 0.0) * it.quantity }
                            val presetFat = meal.foods.sumOf { (it.nutrients["fat"] ?: 0.0) * it.quantity }

                            Card(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .testTag("preset_meal_item_${meal.id}"),
                                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                                border = BorderStroke(0.5.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f))
                            ) {
                                Row(
                                    modifier = Modifier
                                        .fillMaxWidth()
                                        .padding(12.dp),
                                    horizontalArrangement = Arrangement.SpaceBetween,
                                    verticalAlignment = Alignment.CenterVertically
                                ) {
                                    Column(modifier = Modifier.weight(1f)) {
                                        Text(
                                            text = meal.name,
                                            style = MaterialTheme.typography.bodyMedium.copy(fontWeight = FontWeight.Bold),
                                            color = MaterialTheme.colorScheme.onSurface
                                        )
                                        
                                        Text(
                                            text = meal.foods.joinToString(", ") { it.foodName },
                                            style = MaterialTheme.typography.bodySmall,
                                            color = MaterialTheme.colorScheme.onSurfaceVariant,
                                            maxLines = 1,
                                            overflow = androidx.compose.ui.text.style.TextOverflow.Ellipsis
                                        )

                                        Spacer(modifier = Modifier.height(4.dp))

                                        Row(
                                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Surface(
                                                shape = RoundedCornerShape(4.dp),
                                                color = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.4f),
                                                contentColor = MaterialTheme.colorScheme.onPrimaryContainer
                                            ) {
                                                Text(
                                                    text = "${presetCal.toInt()} cal",
                                                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                                    modifier = Modifier.padding(horizontal = 6.dp, vertical = 2.dp)
                                                )
                                            }
                                            Text(
                                                text = "P: ${presetProtein.toInt()}g • C: ${presetCarbs.toInt()}g • F: ${presetFat.toInt()}g",
                                                style = MaterialTheme.typography.labelSmall,
                                                color = MaterialTheme.colorScheme.onSurfaceVariant
                                            )
                                        }
                                    }

                                    Row(
                                        horizontalArrangement = Arrangement.spacedBy(4.dp),
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        Button(
                                            onClick = { mealToLogPreset = meal },
                                            colors = ButtonDefaults.buttonColors(
                                                containerColor = MaterialTheme.colorScheme.primary,
                                                contentColor = MaterialTheme.colorScheme.onPrimary
                                            ),
                                            contentPadding = PaddingValues(horizontal = 12.dp, vertical = 6.dp),
                                            shape = RoundedCornerShape(8.dp),
                                            modifier = Modifier
                                                .height(36.dp)
                                                .testTag("preset_meal_log_button_${meal.id}")
                                        ) {
                                            Icon(
                                                imageVector = Icons.Default.Add,
                                                contentDescription = "Log Preset",
                                                modifier = Modifier.size(14.dp)
                                            )
                                            Spacer(modifier = Modifier.width(4.dp))
                                            Text("Log", style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold))
                                        }

                                        IconButton(
                                            onClick = { viewModel.deleteFavoriteMeal(meal) },
                                            modifier = Modifier.testTag("preset_meal_delete_button_${meal.id}")
                                        ) {
                                            Icon(
                                                imageVector = Icons.Default.Delete,
                                                contentDescription = "Delete Preset",
                                                tint = MaterialTheme.colorScheme.error,
                                                modifier = Modifier.size(18.dp)
                                            )
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun AiDirectedMenuTab(viewModel: NutritionViewModel) {
    val plannedMenu by viewModel.plannedMenu.collectAsState()
    val isPlanningLoading by viewModel.isPlanningLoading.collectAsState()
    val planningError by viewModel.planningError.collectAsState()
    val favoriteMeals by viewModel.allFavoriteMeals.collectAsState()
    
    val context = androidx.compose.ui.platform.LocalContext.current
    
    val smartDefaults = remember {
        listOf(
            "Greek Yogurt & Berries (Breakfast)",
            "Grilled Chicken Quinoa Salad (Lunch)",
            "Sliced Apple with Almond Butter (Snack)",
            "Pan-seared Salmon with Asparagus (Dinner)"
        )
    }
    
    val selectedUsuals = remember { mutableStateListOf<String>() }
    
    LaunchedEffect(favoriteMeals) {
        if (selectedUsuals.isEmpty()) {
            if (favoriteMeals.isNotEmpty()) {
                favoriteMeals.take(4).forEach { meal ->
                    val name = meal.name
                    val slot = when {
                        name.lowercase().contains("breakfast") -> "Breakfast"
                        name.lowercase().contains("lunch") -> "Lunch"
                        name.lowercase().contains("dinner") -> "Dinner"
                        else -> "Snack"
                    }
                    selectedUsuals.add("${meal.name} ($slot)")
                }
            } else {
                selectedUsuals.addAll(smartDefaults)
            }
        }
    }
    
    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(MaterialTheme.colorScheme.background)
            .padding(16.dp)
            .verticalScroll(rememberScrollState())
    ) {
        Card(
            modifier = Modifier
                .fillMaxWidth()
                .padding(bottom = 16.dp),
            colors = CardDefaults.cardColors(
                containerColor = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.65f)
            ),
            shape = RoundedCornerShape(16.dp)
        ) {
            Column(
                modifier = Modifier.padding(20.dp)
            ) {
                Text(
                    text = "✨ AI Directed Daily Menu Planner",
                    style = MaterialTheme.typography.titleLarge.copy(
                        fontWeight = FontWeight.Bold,
                        fontSize = 22.sp
                    ),
                    color = MaterialTheme.colorScheme.onPrimaryContainer
                )
                Spacer(modifier = Modifier.height(6.dp))
                Text(
                    text = "Establish your standard staple 'usuals' first, then let Gemini 3.5 Flash design a targeted menu covering micro-nutrient gaps (and we won't forget the snacks!).",
                    style = MaterialTheme.typography.bodyMedium,
                    color = MaterialTheme.colorScheme.onPrimaryContainer.copy(alpha = 0.85f)
                )
            }
        }

        Card(
            modifier = Modifier
                .fillMaxWidth()
                .padding(bottom = 16.dp),
            colors = CardDefaults.cardColors(
                containerColor = MaterialTheme.colorScheme.surface
            ),
            border = BorderStroke(1.dp, MaterialTheme.colorScheme.outlineVariant),
            shape = RoundedCornerShape(12.dp)
        ) {
            Column(
                modifier = Modifier.padding(16.dp)
            ) {
                Text(
                    text = "1. Select Baseline Usuals",
                    style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                    color = MaterialTheme.colorScheme.primary
                )
                Text(
                    text = "Choose which of your standard staple meals are set as today's baseline. Unselected slots will be planned by AI.",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant,
                    modifier = Modifier.padding(bottom = 12.dp)
                )

                val usualsToRender = if (favoriteMeals.isNotEmpty()) {
                    favoriteMeals.map { meal ->
                        val slot = when {
                            meal.name.lowercase().contains("breakfast") -> "Breakfast"
                            meal.name.lowercase().contains("lunch") -> "Lunch"
                            meal.name.lowercase().contains("dinner") -> "Dinner"
                            else -> "Snack"
                        }
                        "${meal.name} ($slot)"
                    }
                } else {
                    smartDefaults
                }

                usualsToRender.forEach { usual ->
                    val isChecked = selectedUsuals.contains(usual)
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .clickable {
                                if (isChecked) {
                                    selectedUsuals.remove(usual)
                                } else {
                                    selectedUsuals.add(usual)
                                }
                            }
                            .padding(vertical = 8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Checkbox(
                            checked = isChecked,
                            onCheckedChange = { checked ->
                                if (checked) {
                                    selectedUsuals.add(usual)
                                } else {
                                    selectedUsuals.remove(usual)
                                }
                            }
                        )
                        Spacer(modifier = Modifier.width(8.dp))
                        Text(
                            text = usual,
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurface
                        )
                    }
                }

                Spacer(modifier = Modifier.height(16.dp))

                Button(
                    onClick = {
                        viewModel.generateDirectedMenu(selectedUsuals.toList())
                    },
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(48.dp)
                        .testTag("generate_menu_btn"),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = MaterialTheme.colorScheme.primary
                    ),
                    shape = RoundedCornerShape(10.dp),
                    enabled = !isPlanningLoading
                ) {
                    if (isPlanningLoading) {
                        CircularProgressIndicator(
                            color = MaterialTheme.colorScheme.onPrimary,
                            modifier = Modifier.size(24.dp)
                        )
                    } else {
                        Icon(imageVector = Icons.Default.Star, contentDescription = "Plan")
                        Spacer(modifier = Modifier.width(8.dp))
                        Text(
                            text = "Generate AI Directed Plan",
                            style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.Bold)
                        )
                    }
                }
            }
        }

        if (planningError != null) {
            val context = androidx.compose.ui.platform.LocalContext.current
            val clipboardManager = androidx.compose.ui.platform.LocalClipboardManager.current
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .clickable {
                        clipboardManager.setText(androidx.compose.ui.text.AnnotatedString(planningError ?: ""))
                        android.widget.Toast.makeText(context, "Planning error copied!", android.widget.Toast.LENGTH_SHORT).show()
                    }
                    .padding(bottom = 16.dp),
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.errorContainer
                )
            ) {
                Text(
                    text = "⚠️ Planning Error: $planningError. Reverting to smart fallback plan. (Tap to copy)",
                    style = MaterialTheme.typography.bodyMedium,
                    color = MaterialTheme.colorScheme.onErrorContainer,
                    modifier = Modifier.padding(16.dp)
                )
            }
        }

        Text(
            text = "2. Your Planned Daily Menu",
            style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
            color = MaterialTheme.colorScheme.primary,
            modifier = Modifier.padding(vertical = 8.dp)
        )

        if (plannedMenu.isEmpty()) {
            Card(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(bottom = 24.dp),
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
                ),
                shape = RoundedCornerShape(12.dp)
            ) {
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(32.dp),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    Text(
                        text = "🍽️ No Menu Generated Yet",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                    Spacer(modifier = Modifier.height(4.dp))
                    Text(
                        text = "Customize your baseline usuals and tap 'Generate' to see your personalized AI directed plan.",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                        textAlign = TextAlign.Center
                    )
                }
            }
        } else {
            plannedMenu.forEach { meal ->
                Card(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(bottom = 12.dp),
                    colors = CardDefaults.cardColors(
                        containerColor = if (meal.isUsual) {
                            MaterialTheme.colorScheme.secondaryContainer.copy(alpha = 0.45f)
                        } else {
                            MaterialTheme.colorScheme.tertiaryContainer.copy(alpha = 0.45f)
                        }
                    ),
                    shape = RoundedCornerShape(12.dp)
                ) {
                    Column(
                        modifier = Modifier.padding(16.dp)
                    ) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            val iconStr = when (meal.mealType) {
                                "Breakfast" -> "🍳 Breakfast"
                                "Lunch" -> "🥗 Lunch"
                                "Dinner" -> "🍲 Dinner"
                                else -> "🍎 Snack"
                            }
                            Text(
                                text = iconStr,
                                style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                                color = MaterialTheme.colorScheme.onSurface
                            )
                            
                            Box(
                                modifier = Modifier
                                    .clip(RoundedCornerShape(6.dp))
                                    .background(
                                        if (meal.isUsual) MaterialTheme.colorScheme.secondary
                                        else MaterialTheme.colorScheme.tertiary
                                    )
                                    .padding(horizontal = 8.dp, vertical = 4.dp)
                            ) {
                                Text(
                                    text = if (meal.isUsual) "⭐️ Usual" else "✨ AI Suggestion",
                                    style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                    color = if (meal.isUsual) MaterialTheme.colorScheme.onSecondary
                                            else MaterialTheme.colorScheme.onTertiary
                                )
                            }
                        }

                        Spacer(modifier = Modifier.height(8.dp))

                        Text(
                            text = meal.foodName,
                            style = MaterialTheme.typography.bodyLarge.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onSurface
                        )

                        Spacer(modifier = Modifier.height(6.dp))

                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(12.dp)
                        ) {
                            MacroBadge(label = "Calories", value = "${meal.calories} kcal")
                            MacroBadge(label = "Protein", value = "${meal.protein}g")
                            MacroBadge(label = "Carbs", value = "${meal.carbs}g")
                            MacroBadge(label = "Fat", value = "${meal.fat}g")
                        }

                        Spacer(modifier = Modifier.height(8.dp))

                        Text(
                            text = meal.reason,
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )

                        Spacer(modifier = Modifier.height(12.dp))

                        Button(
                            onClick = {
                                viewModel.logPlannedMeal(meal.id)
                                android.widget.Toast.makeText(context, "Logged ${meal.foodName} for ${meal.mealType}!", android.widget.Toast.LENGTH_SHORT).show()
                            },
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(38.dp)
                                .testTag("log_planned_meal_btn_${meal.id}"),
                            colors = ButtonDefaults.buttonColors(
                                containerColor = if (meal.isLogged) Color.Gray
                                                else MaterialTheme.colorScheme.primary
                            ),
                            shape = RoundedCornerShape(8.dp),
                            enabled = !meal.isLogged
                        ) {
                            Icon(
                                imageVector = if (meal.isLogged) Icons.Default.Check else Icons.Default.Add,
                                contentDescription = if (meal.isLogged) "Logged" else "Log"
                            )
                            Spacer(modifier = Modifier.width(6.dp))
                            Text(
                                text = if (meal.isLogged) "Added to Journal" else "Log into Journal",
                                style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold)
                            )
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun MacroBadge(label: String, value: String) {
    Box(
        modifier = Modifier
            .clip(RoundedCornerShape(6.dp))
            .background(MaterialTheme.colorScheme.onSurface.copy(alpha = 0.05f))
            .border(BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f)), RoundedCornerShape(6.dp))
            .padding(horizontal = 8.dp, vertical = 4.dp)
    ) {
        Column(horizontalAlignment = Alignment.CenterHorizontally) {
            Text(
                text = label,
                style = MaterialTheme.typography.labelSmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
                fontSize = 9.sp
            )
            Text(
                text = value,
                style = MaterialTheme.typography.bodySmall.copy(fontWeight = FontWeight.Bold),
                color = MaterialTheme.colorScheme.onSurface,
                fontSize = 11.sp
            )
        }
    }
}

@OptIn(ExperimentalLayoutApi::class, ExperimentalMaterial3Api::class)
@Composable
fun SevenDayTrendsLineChartCard(viewModel: NutritionViewModel) {
    val trends by viewModel.sevenDayTrends.collectAsState()
    val currentDate by viewModel.currentDate.collectAsState()
    
    // Toggles for visible metrics on the chart
    var showCalories by remember { mutableStateOf(true) }
    var showCarbs by remember { mutableStateOf(false) }
    var showProtein by remember { mutableStateOf(false) }
    var showFat by remember { mutableStateOf(false) }
    
    var activeIndex by remember { mutableStateOf<Int?>(null) }
    
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .testTag("seven_day_trends_line_chart_card"),
        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
        border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f))
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            // Header
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column {
                    Text(
                        text = "7-Day Progress Insights",
                        style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                        color = MaterialTheme.colorScheme.primary
                    )
                    Text(
                        text = "Interactive line chart of energy & macronutrients",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
                Icon(
                    imageVector = Icons.Default.Info,
                    contentDescription = "Trending Icon",
                    tint = MaterialTheme.colorScheme.primary,
                    modifier = Modifier.size(20.dp)
                )
            }
            
            Spacer(modifier = Modifier.height(14.dp))
            
            // Toggle Selector Legend / Chips (Recharts Legend Style)
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(6.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Calories
                LegendToggleChip(
                    label = "Calories",
                    valueSuffix = "kcal",
                    color = MaterialTheme.colorScheme.primary,
                    isSelected = showCalories,
                    onClick = { 
                        showCalories = !showCalories 
                        // Keep at least one checked
                        if (!showCalories && !showCarbs && !showProtein && !showFat) {
                            showCalories = true
                        }
                    }
                )
                
                // Carbs
                LegendToggleChip(
                    label = "Carbs",
                    valueSuffix = "g",
                    color = Color(0xFFF59E0B), // Amber
                    isSelected = showCarbs,
                    onClick = { 
                        showCarbs = !showCarbs 
                        if (!showCalories && !showCarbs && !showProtein && !showFat) {
                            showCarbs = true
                        }
                    }
                )
                
                // Protein
                LegendToggleChip(
                    label = "Protein",
                    valueSuffix = "g",
                    color = Color(0xFF10B981), // Emerald Green
                    isSelected = showProtein,
                    onClick = { 
                        showProtein = !showProtein 
                        if (!showCalories && !showCarbs && !showProtein && !showFat) {
                            showProtein = true
                        }
                    }
                )
                
                // Fat
                LegendToggleChip(
                    label = "Fat",
                    valueSuffix = "g",
                    color = Color(0xFFEC4899), // Pink
                    isSelected = showFat,
                    onClick = { 
                        showFat = !showFat 
                        if (!showCalories && !showCarbs && !showProtein && !showFat) {
                            showFat = true
                        }
                    }
                )
            }
            
            Spacer(modifier = Modifier.height(16.dp))
            
            if (trends.isEmpty()) {
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(180.dp),
                    contentAlignment = Alignment.Center
                ) {
                    CircularProgressIndicator(modifier = Modifier.size(24.dp))
                }
            } else {
                // Calculate max values to scale coordinates beautifully
                val maxCal = trends.maxOfOrNull { it.calories }?.coerceAtLeast(100.0) ?: 2000.0
                val maxCarb = trends.maxOfOrNull { it.carbsGrams }?.coerceAtLeast(10.0) ?: 200.0
                val maxProtein = trends.maxOfOrNull { it.proteinGrams }?.coerceAtLeast(10.0) ?: 100.0
                val maxFat = trends.maxOfOrNull { it.fatGrams }?.coerceAtLeast(10.0) ?: 100.0
                
                val activeCount = listOf(showCalories, showCarbs, showProtein, showFat).count { it }
                val useGradients = activeCount == 1
                
                BoxWithConstraints(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(180.dp)
                        .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.1f), RoundedCornerShape(8.dp))
                        .border(BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.04f)), RoundedCornerShape(8.dp))
                        .padding(8.dp)
                ) {
                    val totalWidth = maxWidth
                    val totalHeight = maxHeight
                    
                    val leftMargin = 32.dp
                    val rightMargin = 12.dp
                    val topMargin = 16.dp
                    val bottomMargin = 20.dp
                    
                    val density = androidx.compose.ui.platform.LocalDensity.current
                    val leftMarginPx = with(density) { leftMargin.toPx() }
                    val rightMarginPx = with(density) { rightMargin.toPx() }
                    val topMarginPx = with(density) { topMargin.toPx() }
                    val bottomMarginPx = with(density) { bottomMargin.toPx() }
                    
                    val drawW = totalWidth - leftMargin - rightMargin
                    val drawH = totalHeight - topMargin - bottomMargin
                    
                    val drawWPx = with(density) { drawW.toPx() }
                    val drawHPx = with(density) { drawH.toPx() }
                    
                    Box(
                        modifier = Modifier
                            .fillMaxSize()
                            .pointerInput(trends) {
                                detectDragGestures(
                                    onDragStart = { offset ->
                                        val xFraction = ((offset.x - leftMarginPx) / drawWPx).coerceIn(0f, 1f)
                                        activeIndex = (xFraction * (trends.size - 1)).toInt().coerceIn(0, trends.size - 1)
                                    },
                                    onDrag = { change, _ ->
                                        val xFraction = ((change.position.x - leftMarginPx) / drawWPx).coerceIn(0f, 1f)
                                        activeIndex = (xFraction * (trends.size - 1)).toInt().coerceIn(0, trends.size - 1)
                                    },
                                    onDragEnd = { activeIndex = null },
                                    onDragCancel = { activeIndex = null }
                                )
                            }
                            .pointerInput(trends) {
                                detectTapGestures(
                                    onPress = { offset ->
                                        val xFraction = ((offset.x - leftMarginPx) / drawWPx).coerceIn(0f, 1f)
                                        val index = (xFraction * (trends.size - 1)).toInt().coerceIn(0, trends.size - 1)
                                        activeIndex = index
                                        tryAwaitRelease()
                                        activeIndex = null
                                    }
                                )
                            }
                    ) {
                        val caloriesColor = MaterialTheme.colorScheme.primary
                        val carbsColor = Color(0xFFF59E0B)
                        val proteinColor = Color(0xFF10B981)
                        val fatColor = Color(0xFFEC4899)
                        
                        Canvas(modifier = Modifier.fillMaxSize()) {
                            // 1. Draw Grid Lines (Horizontal reference grid)
                            val steps = 3
                            for (i in 0..steps) {
                                val fraction = i.toFloat() / steps.toFloat()
                                val gridY = topMarginPx + drawHPx - (fraction * drawHPx)
                                drawLine(
                                    color = Color.LightGray.copy(alpha = 0.25f),
                                    start = Offset(leftMarginPx, gridY),
                                    end = Offset(leftMarginPx + drawWPx, gridY),
                                    strokeWidth = 1.dp.toPx(),
                                    pathEffect = PathEffect.dashPathEffect(floatArrayOf(10f, 10f))
                                )
                            }
                            
                            // 2. Draw each active trend line
                            fun drawTrendLine(
                                values: List<Double>,
                                maxValue: Double,
                                lineColor: Color,
                                drawGradient: Boolean
                            ) {
                                if (values.isEmpty()) return
                                val path = Path()
                                val fillPath = Path()
                                
                                values.forEachIndexed { idx, valItem ->
                                    val x = leftMarginPx + idx * (drawWPx / (values.size - 1))
                                    val fraction = (valItem / maxValue).coerceIn(0.0, 1.0).toFloat()
                                    val y = topMarginPx + drawHPx - (fraction * drawHPx)
                                    
                                    if (idx == 0) {
                                        path.moveTo(x, y)
                                        fillPath.moveTo(x, topMarginPx + drawHPx)
                                        fillPath.lineTo(x, y)
                                    } else {
                                        path.lineTo(x, y)
                                        fillPath.lineTo(x, y)
                                    }
                                }
                                
                                fillPath.lineTo(leftMarginPx + drawWPx, topMarginPx + drawHPx)
                                fillPath.close()
                                
                                if (drawGradient) {
                                    drawPath(
                                        path = fillPath,
                                        brush = Brush.verticalGradient(
                                            colors = listOf(lineColor.copy(alpha = 0.15f), lineColor.copy(alpha = 0.0f)),
                                            startY = topMarginPx,
                                            endY = topMarginPx + drawHPx
                                        )
                                    )
                                }
                                
                                drawPath(
                                    path = path,
                                    color = lineColor,
                                    style = Stroke(
                                        width = 2.dp.toPx(),
                                        cap = StrokeCap.Round,
                                        join = StrokeJoin.Round
                                    )
                                )
                                
                                // Draw small dots
                                values.forEachIndexed { idx, valItem ->
                                    val x = leftMarginPx + idx * (drawWPx / (values.size - 1))
                                    val fraction = (valItem / maxValue).coerceIn(0.0, 1.0).toFloat()
                                    val y = topMarginPx + drawHPx - (fraction * drawHPx)
                                    
                                    drawCircle(
                                        color = Color.White,
                                        radius = 3.dp.toPx(),
                                        center = Offset(x, y)
                                    )
                                    drawCircle(
                                        color = lineColor,
                                        radius = 2.dp.toPx(),
                                        style = Stroke(width = 1.dp.toPx()),
                                        center = Offset(x, y)
                                    )
                                }
                            }
                            
                            if (showCalories) {
                                drawTrendLine(trends.map { it.calories }, maxCal, caloriesColor, useGradients)
                            }
                            if (showCarbs) {
                                drawTrendLine(trends.map { it.carbsGrams }, maxCarb, carbsColor, useGradients)
                            }
                            if (showProtein) {
                                drawTrendLine(trends.map { it.proteinGrams }, maxProtein, proteinColor, useGradients)
                            }
                            if (showFat) {
                                drawTrendLine(trends.map { it.fatGrams }, maxFat, fatColor, useGradients)
                            }
                            
                            // Draw hover guideline
                            if (activeIndex != null) {
                                val x = leftMarginPx + activeIndex!! * (drawWPx / (trends.size - 1))
                                drawLine(
                                    color = Color.Gray.copy(alpha = 0.3f),
                                    start = Offset(x, topMarginPx),
                                    end = Offset(x, topMarginPx + drawHPx),
                                    strokeWidth = 1.dp.toPx()
                                )
                                
                                // Draw concentric circles on active point intersections
                                fun drawIntersectCircle(valItem: Double, maxValue: Double, color: Color) {
                                    val fraction = (valItem / maxValue).coerceIn(0.0, 1.0).toFloat()
                                    val y = topMarginPx + drawHPx - (fraction * drawHPx)
                                    drawCircle(
                                        color = color.copy(alpha = 0.2f),
                                        radius = 7.dp.toPx(),
                                        center = Offset(x, y)
                                    )
                                    drawCircle(
                                        color = Color.White,
                                        radius = 3.5.dp.toPx(),
                                        center = Offset(x, y)
                                    )
                                    drawCircle(
                                        color = color,
                                        radius = 2.dp.toPx(),
                                        style = Stroke(width = 1.dp.toPx()),
                                        center = Offset(x, y)
                                    )
                                }
                                
                                val activeTrend = trends[activeIndex!!]
                                if (showCalories) drawIntersectCircle(activeTrend.calories, maxCal, caloriesColor)
                                if (showCarbs) drawIntersectCircle(activeTrend.carbsGrams, maxCarb, carbsColor)
                                if (showProtein) drawIntersectCircle(activeTrend.proteinGrams, maxProtein, proteinColor)
                                if (showFat) drawIntersectCircle(activeTrend.fatGrams, maxFat, fatColor)
                            }
                        }
                        
                        // Y Axis Numbers Overlay
                        Column(
                            modifier = Modifier
                                .fillMaxHeight()
                                .width(leftMargin)
                                .padding(top = topMargin, bottom = bottomMargin),
                            verticalArrangement = Arrangement.SpaceBetween,
                            horizontalAlignment = Alignment.End
                        ) {
                            val mainMax = when {
                                showCalories && activeCount == 1 -> maxCal
                                showCarbs && activeCount == 1 -> maxCarb
                                showProtein && activeCount == 1 -> maxProtein
                                showFat && activeCount == 1 -> maxFat
                                else -> 100.0 // Normalized scale
                            }
                            
                            val isNormalized = activeCount > 1
                            
                            for (i in 3 downTo 0) {
                                val fraction = i.toFloat() / 3f
                                val labelVal = mainMax * fraction
                                val labelText = if (isNormalized) {
                                    "${(fraction * 100).toInt()}%"
                                } else {
                                    String.format(java.util.Locale.US, "%.0f", labelVal)
                                }
                                Text(
                                    text = "$labelText ",
                                    style = MaterialTheme.typography.labelSmall.copy(fontSize = 7.sp, fontWeight = FontWeight.Bold),
                                    color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.5f)
                                )
                                if (i > 0) Spacer(modifier = Modifier.weight(1f))
                            }
                        }
                        
                        // X Axis Labels Overlay
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .align(Alignment.BottomStart)
                                .padding(start = leftMargin, end = rightMargin)
                                .height(bottomMargin),
                            horizontalArrangement = Arrangement.SpaceBetween,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            trends.forEachIndexed { idx, trend ->
                                val isCurrent = trend.dateString == currentDate
                                Text(
                                    text = trend.displayDate,
                                    style = MaterialTheme.typography.labelSmall.copy(
                                        fontSize = 8.sp,
                                        fontWeight = if (isCurrent) FontWeight.Bold else FontWeight.Normal
                                    ),
                                    color = if (isCurrent) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f)
                                )
                            }
                        }
                        
                        // Hover Tooltip overlay popup
                        if (activeIndex != null) {
                            val activeTrend = trends[activeIndex!!]
                            val isLeftHalf = activeIndex!! < 4
                            
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .padding(start = leftMargin + 4.dp, end = rightMargin + 4.dp, top = topMargin)
                            ) {
                                Card(
                                    shape = RoundedCornerShape(8.dp),
                                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surface),
                                    border = BorderStroke(1.dp, MaterialTheme.colorScheme.outline.copy(alpha = 0.12f)),
                                    elevation = CardDefaults.cardElevation(defaultElevation = 4.dp),
                                    modifier = Modifier
                                        .align(if (isLeftHalf) Alignment.TopEnd else Alignment.TopStart)
                                        .width(135.dp)
                                        .padding(horizontal = 4.dp)
                                ) {
                                    Column(modifier = Modifier.padding(8.dp), verticalArrangement = Arrangement.spacedBy(3.dp)) {
                                        Text(
                                            text = if (activeTrend.dateString == currentDate) "Today (${activeTrend.displayDate})" else activeTrend.displayDate,
                                            style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                            color = MaterialTheme.colorScheme.onSurfaceVariant
                                        )
                                        
                                        HorizontalDivider(color = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.04f))
                                        
                                        if (showCalories) {
                                            TooltipRow(label = "Calories", value = "${activeTrend.calories.toInt()} kcal", color = caloriesColor)
                                        }
                                        if (showCarbs) {
                                            TooltipRow(label = "Carbs", value = "${activeTrend.carbsGrams.toInt()}g", color = carbsColor)
                                        }
                                        if (showProtein) {
                                            TooltipRow(label = "Protein", value = "${activeTrend.proteinGrams.toInt()}g", color = proteinColor)
                                        }
                                        if (showFat) {
                                            TooltipRow(label = "Fat", value = "${activeTrend.fatGrams.toInt()}g", color = fatColor)
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

@Composable
fun LegendToggleChip(
    label: String,
    valueSuffix: String,
    color: Color,
    isSelected: Boolean,
    onClick: () -> Unit
) {
    Box(
        modifier = Modifier
            .clip(RoundedCornerShape(12.dp))
            .background(if (isSelected) color.copy(alpha = 0.08f) else Color.Transparent)
            .border(
                BorderStroke(
                    width = 1.dp,
                    color = if (isSelected) color else MaterialTheme.colorScheme.outline.copy(alpha = 0.12f)
                ),
                RoundedCornerShape(12.dp)
            )
            .clickable(onClick = onClick)
            .padding(horizontal = 8.dp, vertical = 4.dp)
    ) {
        Row(
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(4.dp)
        ) {
            Box(
                modifier = Modifier
                    .size(6.dp)
                    .clip(CircleShape)
                    .background(if (isSelected) color else MaterialTheme.colorScheme.outline.copy(alpha = 0.25f))
            )
            Text(
                text = "$label ($valueSuffix)",
                style = MaterialTheme.typography.labelSmall.copy(
                    fontSize = 9.sp,
                    fontWeight = if (isSelected) FontWeight.Bold else FontWeight.Medium
                ),
                color = if (isSelected) color else MaterialTheme.colorScheme.onSurfaceVariant
            )
        }
    }
}

@Composable
fun TooltipRow(label: String, value: String, color: Color) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Row(
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(4.dp)
        ) {
            Box(modifier = Modifier.size(5.dp).clip(CircleShape).background(color))
            Text(
                text = label,
                style = MaterialTheme.typography.labelSmall.copy(fontSize = 8.sp),
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )
        }
        Text(
            text = value,
            style = MaterialTheme.typography.labelSmall.copy(fontSize = 8.5.sp, fontWeight = FontWeight.Bold),
            color = color
        )
    }
}

data class KeyNutrientInfo(
    val key: String,
    val name: String,
    val emoji: String,
    val color: Color
)

data class MealStats(
    val name: String,
    val emoji: String,
    val color: Color,
    val calories: Double,
    val carbs: Double,
    val protein: Double,
    val fat: Double,
    val items: List<com.example.data.FoodLogEntry>
)

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun DailyRdaSummaryModal(
    currentDate: String,
    dailyNutrients: List<NutrientStatus>,
    currentDateEntries: List<com.example.data.FoodLogEntry>,
    onDismiss: () -> Unit
) {
    val context = androidx.compose.ui.platform.LocalContext.current
    var selectedTabIndex by remember { mutableStateOf(0) } // 0 for Vitamins, 1 for Minerals, 2 for Meals

    val keyVitamins = remember {
        listOf(
            KeyNutrientInfo("vitamin_a", "Vitamin A", "👁️", Color(0xFFF59E0B)),
            KeyNutrientInfo("vitamin_c", "Vitamin C", "🍊", Color(0xFFEF4444)),
            KeyNutrientInfo("vitamin_d", "Vitamin D", "☀️", Color(0xFFFBBF24)),
            KeyNutrientInfo("vitamin_e", "Vitamin E", "🛡️", Color(0xFF10B981)),
            KeyNutrientInfo("vitamin_k", "Vitamin K", "🥬", Color(0xFF0D9488)),
            KeyNutrientInfo("vitamin_b12", "Vitamin B12", "🥩", Color(0xFFEC4899))
        )
    }

    val keyMinerals = remember {
        listOf(
            KeyNutrientInfo("calcium", "Calcium", "🦴", Color(0xFF3B82F6)),
            KeyNutrientInfo("iron", "Iron", "🔬", Color(0xFF9E2A2B)),
            KeyNutrientInfo("magnesium", "Magnesium", "🌰", Color(0xFF8B5CF6)),
            KeyNutrientInfo("potassium", "Potassium", "🍌", Color(0xFF6366F1)),
            KeyNutrientInfo("zinc", "Zinc", "🧬", Color(0xFF0F766E))
        )
    }

    val vitaminStatuses = remember(dailyNutrients) {
        keyVitamins.mapNotNull { keyInfo ->
            dailyNutrients.find { it.definition.key == keyInfo.key }?.let { status ->
                Pair(keyInfo, status)
            }
        }
    }

    val mineralStatuses = remember(dailyNutrients) {
        keyMinerals.mapNotNull { keyInfo ->
            dailyNutrients.find { it.definition.key == keyInfo.key }?.let { status ->
                Pair(keyInfo, status)
            }
        }
    }

    val totalKeyNutrients = vitaminStatuses.size + mineralStatuses.size
    val metKeyNutrients = (vitaminStatuses + mineralStatuses).count { it.second.percentage >= 100.0 }
    
    val metVitamins = vitaminStatuses.count { it.second.percentage >= 100.0 }
    val totalVitamins = vitaminStatuses.size
    
    val metMinerals = mineralStatuses.count { it.second.percentage >= 100.0 }
    val totalMinerals = mineralStatuses.size

    val displayDateFormatted = remember(currentDate) {
        try {
            val parser = SimpleDateFormat("yyyy-MM-dd", Locale.US)
            val formatter = SimpleDateFormat("EEEE, MMMM d, yyyy", Locale.US)
            parser.parse(currentDate)?.let { formatter.format(it) } ?: currentDate
        } catch (e: Exception) {
            currentDate
        }
    }

    val mealStatsList = remember(currentDateEntries) {
        val meals = listOf(
            Triple("Breakfast", "🍳", Color(0xFFF59E0B)),
            Triple("Lunch", "🍗", Color(0xFF10B981)),
            Triple("Dinner", "🐟", Color(0xFF3B82F6)),
            Triple("Snack", "🍎", Color(0xFFEC4899)),
            Triple("Supplement", "💊", Color(0xFF8B5CF6))
        )
        
        meals.map { (name, emoji, color) ->
            val items = currentDateEntries.filter { it.mealType.equals(name, ignoreCase = true) }
            val calories = items.sumOf { (it.nutrients["calories"] ?: 0.0) * it.quantity }
            val carbs = items.sumOf { (it.nutrients["carbohydrates"] ?: 0.0) * it.quantity }
            val protein = items.sumOf { (it.nutrients["protein"] ?: 0.0) * it.quantity }
            val fat = items.sumOf { (it.nutrients["fat"] ?: 0.0) * it.quantity }
            
            MealStats(name, emoji, color, calories, carbs, protein, fat, items)
        }
    }

    val shareText = remember(vitaminStatuses, mineralStatuses, metKeyNutrients, totalKeyNutrients, currentDate, currentDateEntries) {
        buildString {
            appendLine("🌟 My End-of-Day RDA Achievement Report - $currentDate 🌟")
            appendLine("Total Key Goals Met: $metKeyNutrients of $totalKeyNutrients vital micronutrients!")
            appendLine()
            appendLine("--- MEAL BREAKDOWN ---")
            val meals = listOf("Breakfast", "Lunch", "Dinner", "Snack", "Supplement")
            meals.forEach { name ->
                val items = currentDateEntries.filter { it.mealType.equals(name, ignoreCase = true) }
                if (items.isNotEmpty()) {
                    val cals = items.sumOf { (it.nutrients["calories"] ?: 0.0) * it.quantity }.toInt()
                    val protein = items.sumOf { (it.nutrients["protein"] ?: 0.0) * it.quantity }.toInt()
                    val carbs = items.sumOf { (it.nutrients["carbohydrates"] ?: 0.0) * it.quantity }.toInt()
                    val fat = items.sumOf { (it.nutrients["fat"] ?: 0.0) * it.quantity }.toInt()
                    appendLine("📍 $name ($cals kcal | C: ${carbs}g, P: ${protein}g, F: ${fat}g):")
                    items.forEach { entry ->
                        appendLine("  • ${entry.foodName} (${if (entry.quantity % 1.0 == 0.0) entry.quantity.toInt() else entry.quantity} ${entry.unit})")
                    }
                }
            }
            appendLine()
            appendLine("--- VITAMINS ---")
            vitaminStatuses.forEach { (info, status) ->
                val symbol = if (status.percentage >= 100.0) "✅" else if (status.percentage >= 50.0) "⚠️" else "❌"
                appendLine("$symbol ${info.name}: ${status.percentage.toInt()}% met (${status.intake.toInt()}/${status.definition.rda.toInt()} ${status.definition.unit})")
            }
            appendLine()
            appendLine("--- MINERALS ---")
            mineralStatuses.forEach { (info, status) ->
                val symbol = if (status.percentage >= 100.0) "✅" else if (status.percentage >= 50.0) "⚠️" else "❌"
                appendLine("$symbol ${info.name}: ${status.percentage.toInt()}% met (${status.intake.toInt()}/${status.definition.rda.toInt()} ${status.definition.unit})")
            }
            appendLine()
            appendLine("Logged with Nutrition & Deficiency Analyzer")
        }
    }

    Dialog(onDismissRequest = onDismiss) {
        Surface(
            shape = RoundedCornerShape(24.dp),
            tonalElevation = 8.dp,
            color = MaterialTheme.colorScheme.surface,
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 4.dp, vertical = 24.dp)
                .heightIn(max = 580.dp)
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(20.dp),
                verticalArrangement = Arrangement.spacedBy(16.dp)
            ) {
                // Header with Title and Close Button
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column(modifier = Modifier.weight(1f)) {
                        Text(
                            text = "Daily RDA Summary",
                            style = MaterialTheme.typography.titleLarge.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.primary
                        )
                        Text(
                            text = displayDateFormatted,
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                    IconButton(
                        onClick = onDismiss,
                        modifier = Modifier.testTag("close_summary_modal_btn")
                    ) {
                        Icon(
                            imageVector = Icons.Default.Close, 
                            contentDescription = "Close Summary Modal",
                            tint = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }

                // Overall Celebration circular ring panel
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.2f), RoundedCornerShape(16.dp))
                        .border(BorderStroke(1.dp, MaterialTheme.colorScheme.primary.copy(alpha = 0.1f)), RoundedCornerShape(16.dp))
                        .padding(16.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(16.dp)
                ) {
                    Box(
                        contentAlignment = Alignment.Center, 
                        modifier = Modifier.size(64.dp)
                    ) {
                        CircularProgressIndicator(
                            progress = { if (totalKeyNutrients > 0) metKeyNutrients.toFloat() / totalKeyNutrients.toFloat() else 0f },
                            color = MaterialTheme.colorScheme.primary,
                            strokeWidth = 6.dp,
                            trackColor = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.08f),
                            modifier = Modifier.fillMaxSize()
                        )
                        Text(
                            text = "$metKeyNutrients/$totalKeyNutrients",
                            style = MaterialTheme.typography.titleMedium.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.primary
                        )
                    }
                    Column(modifier = Modifier.weight(1f)) {
                        val headerText = when {
                            metKeyNutrients == totalKeyNutrients -> "Ultimate Perfection!"
                            metKeyNutrients >= 8 -> "Phenomenal Progress!"
                            metKeyNutrients >= 5 -> "Superb Effort!"
                            else -> "Keep Growing!"
                        }
                        Text(
                            text = headerText,
                            style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                            color = MaterialTheme.colorScheme.onSurface
                        )
                        Text(
                            text = "You fully met the daily RDA target for $metKeyNutrients of $totalKeyNutrients key micronutrients.",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }

                // Custom Segmented Button Selector
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .clip(RoundedCornerShape(12.dp))
                        .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.4f))
                        .padding(4.dp),
                    horizontalArrangement = Arrangement.spacedBy(4.dp)
                ) {
                    // Vitamins Tab
                    Box(
                        modifier = Modifier
                            .weight(1f)
                            .clip(RoundedCornerShape(8.dp))
                            .background(if (selectedTabIndex == 0) MaterialTheme.colorScheme.primary else Color.Transparent)
                            .clickable { selectedTabIndex = 0 }
                            .padding(vertical = 10.dp)
                            .testTag("summary_vitamins_tab"),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = "Vitamins ($metVitamins/$totalVitamins)",
                            style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                            color = if (selectedTabIndex == 0) MaterialTheme.colorScheme.onPrimary else MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                    
                    // Minerals Tab
                    Box(
                        modifier = Modifier
                            .weight(1f)
                            .clip(RoundedCornerShape(8.dp))
                            .background(if (selectedTabIndex == 1) MaterialTheme.colorScheme.primary else Color.Transparent)
                            .clickable { selectedTabIndex = 1 }
                            .padding(vertical = 10.dp)
                            .testTag("summary_minerals_tab"),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = "Minerals ($metMinerals/$totalMinerals)",
                            style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                            color = if (selectedTabIndex == 1) MaterialTheme.colorScheme.onPrimary else MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }

                    // Meals Tab
                    Box(
                        modifier = Modifier
                            .weight(1f)
                            .clip(RoundedCornerShape(8.dp))
                            .background(if (selectedTabIndex == 2) MaterialTheme.colorScheme.primary else Color.Transparent)
                            .clickable { selectedTabIndex = 2 }
                            .padding(vertical = 10.dp)
                            .testTag("summary_meals_tab"),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = "Meals",
                            style = MaterialTheme.typography.labelMedium.copy(fontWeight = FontWeight.Bold),
                            color = if (selectedTabIndex == 2) MaterialTheme.colorScheme.onPrimary else MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }

                // Scrollable Content Area
                Column(
                    modifier = Modifier
                        .weight(1f)
                        .verticalScroll(rememberScrollState()),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    if (selectedTabIndex == 0 || selectedTabIndex == 1) {
                        val currentCategoryList = if (selectedTabIndex == 0) vitaminStatuses else mineralStatuses
                        currentCategoryList.forEach { (info, status) ->
                            Card(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .testTag("summary_nutrient_item_${info.key}"),
                                colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.15f)),
                                border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.05f))
                            ) {
                                Column(modifier = Modifier.padding(12.dp)) {
                                    val pct = status.percentage
                                    Row(
                                        modifier = Modifier.fillMaxWidth(),
                                        horizontalArrangement = Arrangement.SpaceBetween,
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        Row(
                                            verticalAlignment = Alignment.CenterVertically,
                                            horizontalArrangement = Arrangement.spacedBy(8.dp),
                                            modifier = Modifier.weight(1f)
                                        ) {
                                            Box(
                                                modifier = Modifier
                                                    .size(32.dp)
                                                    .clip(CircleShape)
                                                    .background(info.color.copy(alpha = 0.12f)),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Text(text = info.emoji, style = MaterialTheme.typography.bodyLarge)
                                            }
                                            Column {
                                                Text(
                                                    text = info.name,
                                                    style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                                                    color = MaterialTheme.colorScheme.onSurface
                                                )
                                                Text(
                                                    text = "${status.intake.toInt()} / ${status.definition.rda.toInt()} ${status.definition.unit}",
                                                    style = MaterialTheme.typography.bodySmall,
                                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                                )
                                            }
                                        }

                                        // Custom Met Status Badge
                                        val (badgeBg, badgeText, label) = when {
                                            pct >= 100.0 -> Triple(Color(0xFFE6F4EA), Color(0xFF137333), "Met")
                                            pct >= 50.0 -> Triple(Color(0xFFFEF7E0), Color(0xFFB06000), "${pct.toInt()}%")
                                            else -> Triple(Color(0xFFFCE8E6), Color(0xFFC5221F), "${pct.toInt()}%")
                                        }

                                        Box(
                                            modifier = Modifier
                                                .clip(RoundedCornerShape(8.dp))
                                                .background(badgeBg)
                                                .padding(horizontal = 8.dp, vertical = 4.dp)
                                        ) {
                                            Text(
                                                text = label,
                                                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                                color = badgeText
                                            )
                                        }
                                    }

                                    Spacer(modifier = Modifier.height(8.dp))

                                    val progressFraction = (pct / 100.0).coerceIn(0.0, 1.0).toFloat()
                                     val animatedModalProgressFraction by androidx.compose.animation.core.animateFloatAsState(
                                         targetValue = progressFraction,
                                         animationSpec = androidx.compose.animation.core.tween(
                                             durationMillis = 800,
                                             easing = androidx.compose.animation.core.FastOutSlowInEasing
                                         ),
                                         label = "modal_nutrient_progress_${info.key}"
                                     )
                                    LinearProgressIndicator(
                                        progress = { animatedModalProgressFraction },
                                        modifier = Modifier
                                            .fillMaxWidth()
                                            .height(5.dp)
                                            .clip(RoundedCornerShape(2.5.dp)),
                                        color = info.color,
                                        trackColor = MaterialTheme.colorScheme.onSurface.copy(alpha = 0.05f)
                                    )
                                }
                            }
                        }
                    } else {
                        // Meal breakdown list
                        mealStatsList.forEach { mealStats ->
                            Card(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .testTag("summary_meal_card_${mealStats.name.lowercase()}"),
                                colors = CardDefaults.cardColors(
                                    containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.15f)
                                ),
                                border = BorderStroke(1.dp, MaterialTheme.colorScheme.onSurface.copy(alpha = 0.05f))
                            ) {
                                Column(modifier = Modifier.padding(12.dp)) {
                                    // Meal Header
                                    Row(
                                        modifier = Modifier.fillMaxWidth(),
                                        horizontalArrangement = Arrangement.SpaceBetween,
                                        verticalAlignment = Alignment.CenterVertically
                                    ) {
                                        Row(
                                            verticalAlignment = Alignment.CenterVertically,
                                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                                        ) {
                                            Box(
                                                modifier = Modifier
                                                    .size(32.dp)
                                                    .clip(CircleShape)
                                                    .background(mealStats.color.copy(alpha = 0.12f)),
                                                contentAlignment = Alignment.Center
                                            ) {
                                                Text(text = mealStats.emoji, style = MaterialTheme.typography.bodyLarge)
                                            }
                                            Text(
                                                text = mealStats.name,
                                                style = MaterialTheme.typography.titleSmall.copy(fontWeight = FontWeight.Bold),
                                                color = MaterialTheme.colorScheme.onSurface
                                            )
                                        }
                                        
                                        // Calories badge
                                        Box(
                                            modifier = Modifier
                                                .clip(RoundedCornerShape(8.dp))
                                                .background(mealStats.color.copy(alpha = 0.15f))
                                                .padding(horizontal = 8.dp, vertical = 4.dp)
                                        ) {
                                            Text(
                                                text = "${mealStats.calories.toInt()} kcal",
                                                style = MaterialTheme.typography.labelSmall.copy(fontWeight = FontWeight.Bold),
                                                color = mealStats.color
                                            )
                                        }
                                    }
                                    
                                    Spacer(modifier = Modifier.height(8.dp))
                                    
                                    if (mealStats.calories > 0.0) {
                                        Row(
                                            modifier = Modifier.fillMaxWidth(),
                                            horizontalArrangement = Arrangement.SpaceBetween,
                                            verticalAlignment = Alignment.CenterVertically
                                        ) {
                                            Text(
                                                text = "Carbs: ${mealStats.carbs.toInt()}g  •  Protein: ${mealStats.protein.toInt()}g  •  Fat: ${mealStats.fat.toInt()}g",
                                                style = MaterialTheme.typography.bodySmall,
                                                color = MaterialTheme.colorScheme.onSurfaceVariant
                                            )
                                        }
                                        
                                        Spacer(modifier = Modifier.height(8.dp))
                                        
                                        // List items
                                        Column(
                                            verticalArrangement = Arrangement.spacedBy(4.dp),
                                            modifier = Modifier.padding(start = 4.dp)
                                        ) {
                                            mealStats.items.forEach { entry ->
                                                Row(
                                                    modifier = Modifier.fillMaxWidth(),
                                                    horizontalArrangement = Arrangement.SpaceBetween,
                                                    verticalAlignment = Alignment.CenterVertically
                                                ) {
                                                    Text(
                                                        text = "• ${entry.foodName}",
                                                        style = MaterialTheme.typography.bodySmall,
                                                        color = MaterialTheme.colorScheme.onSurface,
                                                        maxLines = 1,
                                                        overflow = androidx.compose.ui.text.style.TextOverflow.Ellipsis,
                                                        modifier = Modifier.weight(1f)
                                                    )
                                                    Text(
                                                        text = "${if (entry.quantity % 1.0 == 0.0) entry.quantity.toInt() else entry.quantity} ${entry.unit}",
                                                        style = MaterialTheme.typography.bodySmall,
                                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                                    )
                                                }
                                            }
                                        }
                                    } else {
                                        Text(
                                            text = "No logs recorded for ${mealStats.name}.",
                                            style = MaterialTheme.typography.bodySmall,
                                            color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f),
                                            modifier = Modifier.padding(start = 4.dp, top = 2.dp)
                                        )
                                    }
                                }
                            }
                        }
                    }
                }

                // Dynamic contextual insights card
                val insightMessage = remember(metKeyNutrients) {
                    when {
                        metKeyNutrients == totalKeyNutrients -> 
                            "Flawless micronutrient balance today! Your body is completely fortified with every single key vitamin and mineral."
                        metKeyNutrients >= 7 -> 
                            "Excellent dietary variety today! To top off the remaining goals, consider snacking on pumpkin seeds, citrus, or avocado."
                        metKeyNutrients >= 4 -> 
                            "Solid foundation. Try bringing in more dark leafy greens, whole grains, and colorful bell peppers to meet remaining limits."
                        else -> 
                            "A brand new learning cycle! Focus on adding high-density vegetables, fresh fruits, and proteins to steadily elevate your daily RDAs."
                    }
                }

                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.secondaryContainer.copy(alpha = 0.2f)),
                    border = BorderStroke(1.dp, MaterialTheme.colorScheme.secondary.copy(alpha = 0.1f))
                ) {
                    Row(
                        modifier = Modifier.padding(12.dp),
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Icon(
                            imageVector = Icons.Default.Info,
                            contentDescription = "RDA Insight Icon",
                            tint = MaterialTheme.colorScheme.secondary,
                            modifier = Modifier.size(16.dp)
                        )
                        Text(
                            text = insightMessage,
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSecondaryContainer,
                            modifier = Modifier.weight(1f)
                        )
                    }
                }

                // Action Buttons Row
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.spacedBy(12.dp),
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    // Outlined Share Button
                    androidx.compose.material3.OutlinedButton(
                        onClick = {
                            try {
                                val intent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                                    type = "text/plain"
                                    putExtra(android.content.Intent.EXTRA_SUBJECT, "My Daily Micronutrient RDA Report")
                                    putExtra(android.content.Intent.EXTRA_TEXT, shareText)
                                }
                                context.startActivity(android.content.Intent.createChooser(intent, "Share End-of-Day Summary"))
                            } catch (e: Exception) {
                                Toast.makeText(context, "Share failed: ${e.localizedMessage}", Toast.LENGTH_SHORT).show()
                            }
                        },
                        modifier = Modifier
                            .weight(1f)
                            .testTag("share_summary_modal_btn"),
                        shape = RoundedCornerShape(12.dp),
                        border = BorderStroke(1.dp, MaterialTheme.colorScheme.primary)
                    ) {
                        Icon(
                            imageVector = Icons.Default.Share, 
                            contentDescription = "Share",
                            modifier = Modifier.size(16.dp)
                        )
                        Spacer(modifier = Modifier.width(6.dp))
                        Text(
                            text = "Share",
                            style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.Bold)
                        )
                    }

                    // Primary solid close button
                    Button(
                        onClick = onDismiss,
                        modifier = Modifier
                            .weight(1f)
                            .testTag("dismiss_summary_modal_btn"),
                        shape = RoundedCornerShape(12.dp)
                    ) {
                        Text(
                            text = "Close",
                            style = MaterialTheme.typography.labelLarge.copy(fontWeight = FontWeight.Bold)
                        )
                    }
                }
            }
        }
    }
}

